(8, '', 'ELEVATE YOUR BAR CART', 'ELEVATE YOUR BAR CART', '17168971111486.jpg', 'Here you’ll find the right mix of top-shelf spirits to create and inspire your home bar that screams, “I’ve made it.”', 'Here you’ll find the right mix of top-shelf spirits to create and inspire your home bar that screams, “I’ve made it.”', '<p>Here you&rsquo;ll find the right mix of top-shelf spirits to create and inspire your home bar that screams, &ldquo;I&rsquo;ve made it.&rdquo;</p>', '<p>Here you&rsquo;ll find the right mix of top-shelf spirits to create and inspire your home bar that screams, &ldquo;I&rsquo;ve made it.&rdquo;</p>', 1, '2023-11-08 14:17:02', '2024-05-28 11:53:27'),
(9, '', 'BEST GRADUATION GIFTS', 'BEST GRADUATION GIFTS', '17168965327892.jpg', 'All the countless nights spent in the library have paid off.', 'All the countless nights spent in the library have paid off.', '<div class=\"c-text-block__title\" style=\"box-sizing: border-box; color: rgb(53, 53, 53); font-family: proxima-nova, sans-serif; font-size: 16px; text-align: center; background-color: rgb(249, 255, 234);\">\r\n<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 1rem;\"><span style=\"box-sizing: border-box; font-weight: bolder;\">CELEBRATE THEIR ACHIEVEMENTS&nbsp;</span></p>\r\n</div>\r\n\r\n<div class=\"c-text-block__description\" style=\"box-sizing: border-box; margin-top: 20px; color: rgb(53, 53, 53); font-family: proxima-nova, sans-serif; font-size: 16px; text-align: center; background-color: rgb(249, 255, 234);\">\r\n<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 1rem;\">All the countless nights spent in the library have paid off. Our curated Graduation gift guide showcases the finest presents to congratulate and reward their hard work.</p>\r\n</div>', '<div class=\"c-text-block__title\" style=\"box-sizing: border-box; color: rgb(53, 53, 53); font-family: proxima-nova, sans-serif; font-size: 16px; text-align: center; background-color: rgb(249, 255, 234);\">\r\n<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 1rem;\"><span style=\"box-sizing: border-box; font-weight: bolder;\">CELEBRATE THEIR ACHIEVEMENTS&nbsp;</span></p>\r\n</div>\r\n\r\n<div class=\"c-text-block__description\" style=\"box-sizing: border-box; margin-top: 20px; color: rgb(53, 53, 53); font-family: proxima-nova, sans-serif; font-size: 16px; text-align: center; background-color: rgb(249, 255, 234);\">\r\n<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 1rem;\">All the countless nights spent in the library have paid off. Our curated Graduation gift guide showcases the finest presents to congratulate and reward their hard work.</p>\r\n</div>', 1, '2023-11-28 10:11:41', '2024-05-28 11:42:12'),
(10, '', 'CORPORATE GIFTING', 'CORPORATE GIFTING', '17168953494584.jpg', 'Gifting bottles to your business clients or team members is the ultimate holiday toast to tell them they\'re appreciated.', 'Gifting bottles to your business clients or team members is the ultimate holiday toast to tell them they\'re appreciated.', '<p>THINK CELEBRATION, THINK LIQUOR JUCTION Are you looking for ways to say thank you to clients or employees? We can help. Build a surprise and delight program for key customers. Set milestones for clients and we will help you deliver an appreciation gift of wine. Let them pick their own wine from a list you create. We take care of the rest. Perfect program for those special clients and supporters. Incentive programs for your high achievers. We will design and manage an incentive program for your company or association. Number of bottles, themes or even a trip to any location, all be designed into the perfect incentive program. Plan for your Holiday and Send-Off gifts. A unique experience to bring a group together to create a blend to bottle. A fun experience for your company that results in a meaningful gift for your clients, employees and friends.</p>', 'THINK CELEBRATION, THINK LIQUOR JUCTION Are you looking for ways to say thank you to clients or employees? We can help. Build a surprise and delight program for key customers. Set milestones for clients and we will help you deliver an appreciation gift of wine. Let them pick their own wine from a list you create. We take care of the rest. Perfect program for those special clients and supporters. Incentive programs for your high achievers. We will design and manage an incentive program for your company or association. Number of bottles, themes or even a trip to any location, all be designed into the perfect incentive program. Plan for your Holiday and Send-Off gifts. A unique experience to bring a group together to create a blend to bottle. A fun experience for your company that results in a meaningful gift for your clients, employees and friends.', 1, '2023-11-28 10:23:48', '2024-06-10 10:06:03'),
(11, '', 'Wee have an annual tradition in our hous', 'Wee have an annual tradition in our hous', '17048924037607.png', 'Wee have an annual tradition in our house where we celebrate everything that’s great about American overindulgence on a single day — typically around some American football game. I think it’s the championship or somethingWee have an annual tradition', 'Wee have an annual tradition in our house where we celebrate everything that’s great about American overindulgence on a single day — typically around some American football game. I think it’s the championship or somethingWee have an annual tradition', '<p><span style=\"color: rgb(0, 0, 0); font-family: Roboto, &quot;Helvetica Neue&quot;, Helvetica, Arial, sans-serif; font-size: 16px;\">Wee have an annual tradition in our house where we celebrate everything that&rsquo;s great about American overindulgence on a single day &mdash; typically around some American football game. I think it&rsquo;s the championship or somethingWee have an annual tradition in our house where we celebrate everything that&rsquo;s great about American overindulgence on a single day &mdash; typically around some American football game. I think it&rsquo;s the championship or something</span></p>', '<p><span style=\"color: rgb(0, 0, 0); font-family: Roboto, &quot;Helvetica Neue&quot;, Helvetica, Arial, sans-serif; font-size: 16px;\">Wee have an annual tradition in our house where we celebrate everything that&rsquo;s great about American overindulgence on a single day &mdash; typically around some American football game. I think it&rsquo;s the championship or somethingWee have an annual tradition in our house where we celebrate everything that&rsquo;s great about American overindulgence on a single day &mdash; typically around some American football game. I think it&rsquo;s the championship or something</span></p>', 2, '2024-01-10 13:13:23', '2024-01-10 13:15:01'),
(12, '', 'Wee have an annual tradition in our hous', 'Wee have an annual tradition in our hous', '17048924679247.png', 'wWee have an annual tradition in our house where we celebrate everything that’s great about American overindulgence on a single day — typically around some American football game. I think it’s the championship or somethingWee have an annual tradit', 'wWee have an annual tradition in our house where we celebrate everything that’s great about American overindulgence on a single day — typically around some American football game. I think it’s the championship or somethingWee have an annual tradit', '<p>Wee have an annual tradition in our house where we celebrate everything that&rsquo;s great about American overindulgence on a single day &mdash; typically around some American football game. I think it&rsquo;s the championship or somethingWee have an annual tradition&nbsp;</p>', '<p>Wee have an annual tradition in our house where we celebrate everything that&rsquo;s great about American overindulgence on a single day &mdash; typically around some American football game. I think it&rsquo;s the championship or somethingWee have an annual tradition&nbsp;</p>', 2, '2024-01-10 13:14:00', '2024-01-10 13:16:10');
