(1, 2, 'Liquor : Forgot Password Email', 'Liquor : Forgot Password Email', '<title></title>\r\n<meta charset=\"UTF-8\"><meta http-equiv=\"X-UA-Compatible\" content=\"IE=edge\"><meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n<link href=\"https://fonts.googleapis.com/css2?family=Outfit:wght@100;200;300;400;500;600;700;800;900&amp;display=swap\" rel=\"stylesheet\" />\r\n<table align=\"center\" cellpadding=\"0\" cellspacing=\"0\" width=\"800px\">\r\n	<tbody><!-- Top Image -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">&nbsp;</td>\r\n		</tr>\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\" bgcolor=\"#0000\" style=\"height:100;\" valign=\"top\">&nbsp;</td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n			<!-- Logo -->\r\n		</tr>\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFF7D5\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" style=\"padding: 40px;\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\" valign=\"top\"><a href=\"javascript:void(0)\" style=\"display: block;\" target=\"_blank\"><img alt=\"top-image\" src=\"{{$logo}}\" style=\"display: block;\" /> </a></td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n		<!-- Details -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" style=\"padding: 32px 40px; border-bottom: 2px solid #F6F5EF;\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\">\r\n						<h1 style=\"line-height: 60px; font-weight: 500; margin: 0px; padding: 0px 0px 32px;\"><span style=\"font-size:36px;\">Forgot Password</span></h1>\r\n						</td>\r\n					</tr>\r\n					<tr>\r\n						<td align=\"left\">\r\n						<h5 style=\"line-height: 36px; font-size: 24px; color: rgb(0, 0, 0); margin: 0px; padding: 0px 0px 8px;\"><span style=\"font-size:26px;\"><font color=\"#333333\">Hello {{$name}}</font></span></h5>\r\n\r\n						<p style=\"font-size: 20px; line-height: 30px; letter-spacing: 0.04em; color: rgb(0, 0, 0); margin: 0px; padding: 0px 0px 32px;\"><font color=\"#333333\"><span style=\"letter-spacing: normal;\">Your password has been reset successfully, Please find login details below.</span></font></p>\r\n						<span style=\"font-size:14px;\"><span style=\"line-height: 27px; margin: 0px; padding: 0px 0px 16px; display: block;\">Here&#39;s your login information:</span></span></td>\r\n					</tr>\r\n					<tr>\r\n						<td align=\"left\">\r\n						<table cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\r\n							<tbody>\r\n								<tr>\r\n									<td align=\"left\"><span style=\"font-size:14px;\"><span align=\"left\" style=\"line-height: 21px; display: inline-block; margin: 0px 57px 0px 0px;\">Email :</span> <span align=\"left\" style=\"margin: 0px; line-height: 24px; display: inline-block;\">{{$email}}</span></span></td>\r\n								</tr>\r\n								<tr>\r\n									<td height=\"16px\">&nbsp;</td>\r\n								</tr>\r\n								<tr>\r\n									<td align=\"left\"><span style=\"font-size:14px;\"><span align=\"left\" style=\"line-height: 21px; display: inline-block; margin: 0px 32px 0px 0px;\">Password :</span> <span align=\"left\" style=\"margin: 0px; line-height: 24px; display: inline-block;\">{{$password}}</span><br />\r\n									<br />\r\n									Best regards,<br />\r\n									Liquor team</span></td>\r\n								</tr>\r\n							</tbody>\r\n						</table>\r\n						</td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n		<!-- Footer -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" style=\"padding: 32px 40px;\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\" style=\"padding: 0 0 22px;\"><span style=\"display: inline-block;\"><a href=\"{{$settingfacebook}}\" style=\"vertical-align: middle; margin: 0px 23px 0px 0px; text-align: center; display: inline-block;\" target=\"_blank\"><img alt=\"linkedIn\" src=\"{{$facebook_logo}}\" style=\"vertical-align: middle;\" /> </a> <a href=\"{{$settingtwitter}}\" style=\"vertical-align: middle; margin: 0px 23px 0px 0px; text-align: center; display: inline-block;\" target=\"_blank\"> <img alt=\"twitter\" src=\"{{$in_logo}}\" style=\"vertical-align: middle;\" /> </a> <a href=\"{{$settinginstagram}}\" style=\"vertical-align: middle; margin: 0px; text-align: center; display: inline-block;\" target=\"_blank\"> <img alt=\"instagram\" src=\"{{$insta_logo}}\" style=\"vertical-align: middle;\" /> </a> </span></td>\r\n					</tr>\r\n					<tr>\r\n						<td align=\"center\">\r\n						<p style=\"font-size: 14px; line-height: 21px; font-weight: 300; color: #000000; margin: 0;\"><font color=\"#333333\"><span style=\"font-size: 13px;\">Get in touch with us at<a href=\"mailto:info@liquor.com\" style=\"margin: 0px 0px 0px 4px; line-height: 24px; display: inline-block;\">info@liquor.com</a></span></font></p>\r\n						</td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n		<!-- Bottom Image -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\" bgcolor=\"#0000\" style=\"height:100;\" valign=\"top\">&nbsp;</td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>', 1, NULL, '2022-07-05 05:06:47', '2023-12-15 09:48:15'),
(2, 2, 'Only Dance : Instructor Request', 'OnlyDance : Instructor Request Sent', '<link href=\"https://fonts.googleapis.com/css?family=Montserrat\" rel=\"stylesheet\" type=\"text/css\" />\r\n<style id=\"media-query\" type=\"text/css\">body {\r\nmargin: 0;\r\npadding: 0; }\r\ntable, tr, td {\r\nvertical-align: top;\r\nborder-collapse: collapse; }\r\n.ie-browser table, .mso-container table {\r\ntable-layout: fixed; }\r\n* {\r\nline-height: inherit; }\r\na[x-apple-data-detectors=true] {\r\ncolor: inherit !important;\r\ntext-decoration: none !important; }\r\n[owa] .img-container div, [owa] .img-container button {\r\ndisplay: block !important; }\r\n[owa] .fullwidth button {\r\nwidth: 100% !important; }\r\n[owa] .block-grid .col {\r\ndisplay: table-cell;\r\nfloat: none !important;\r\nvertical-align: top; }\r\n.ie-browser .num12, .ie-browser .block-grid, [owa] .num12, [owa] .block-grid {\r\nwidth: 600px !important; }\r\n.ExternalClass, .ExternalClass p, .ExternalClass span, .ExternalClass font, .ExternalClass td, .ExternalClass div {\r\nline-height: 100%; }\r\n.ie-browser .mixed-two-up .num4, [owa] .mixed-two-up .num4 {\r\nwidth: 200px !important; }\r\n.ie-browser .mixed-two-up .num8, [owa] .mixed-two-up .num8 {\r\nwidth: 400px !important; }\r\n.ie-browser .block-grid.two-up .col, [owa] .block-grid.two-up .col {\r\nwidth: 300px !important; }\r\n.ie-browser .block-grid.three-up .col, [owa] .block-grid.three-up .col {\r\nwidth: 200px !important; }\r\n.ie-browser .block-grid.four-up .col, [owa] .block-grid.four-up .col {\r\nwidth: 150px !important; }\r\n.ie-browser .block-grid.five-up .col, [owa] .block-grid.five-up .col {\r\nwidth: 120px !important; }\r\n.ie-browser .block-grid.six-up .col, [owa] .block-grid.six-up .col {\r\nwidth: 100px !important; }\r\n.ie-browser .block-grid.seven-up .col, [owa] .block-grid.seven-up .col {\r\nwidth: 85px !important; }\r\n.ie-browser .block-grid.eight-up .col, [owa] .block-grid.eight-up .col {\r\nwidth: 75px !important; }\r\n.ie-browser .block-grid.nine-up .col, [owa] .block-grid.nine-up .col {\r\nwidth: 66px !important; }\r\n.ie-browser .block-grid.ten-up .col, [owa] .block-grid.ten-up .col {\r\nwidth: 60px !important; }\r\n.ie-browser .block-grid.eleven-up .col, [owa] .block-grid.eleven-up .col {\r\nwidth: 54px !important; }\r\n.ie-browser .block-grid.twelve-up .col, [owa] .block-grid.twelve-up .col {\r\nwidth: 50px !important; }\r\n@media only screen and (min-width: 620px) {\r\n.block-grid {\r\nwidth: 100% !important; }\r\n.block-grid .col {\r\nvertical-align: top; }\r\n.block-grid .col.num12 {\r\nwidth: 600px !important; }\r\n.block-grid.mixed-two-up .col.num4 {\r\nwidth: 200px !important; }\r\n.block-grid.mixed-two-up .col.num8 {\r\nwidth: 400px !important; }\r\n.block-grid.two-up .col {\r\nwidth: 300px !important; }\r\n.block-grid.three-up .col {\r\nwidth: 200px !important; }\r\n.block-grid.four-up .col {\r\nwidth: 150px !important; }\r\n.block-grid.five-up .col {\r\nwidth: 120px !important; }\r\n.block-grid.six-up .col {\r\nwidth: 100px !important; }\r\n.block-grid.seven-up .col {\r\nwidth: 85px !important; }\r\n.block-grid.eight-up .col {\r\nwidth: 75px !important; }\r\n.block-grid.nine-up .col {\r\nwidth: 66px !important; }\r\n.block-grid.ten-up .col {\r\nwidth: 60px !important; }\r\n.block-grid.eleven-up .col {\r\nwidth: 54px !important; }\r\n.block-grid.twelve-up .col {\r\nwidth: 50px !important; } }\r\n@media (max-width: 620px) {\r\n.block-grid, .col {\r\nmin-width: 320px !important;\r\nmax-width: 100% !important;\r\ndisplay: block !important; }\r\n.block-grid {\r\nwidth: calc(100% - 40px) !important; }\r\n.col {\r\nwidth: 100% !important; }\r\n.col > div {\r\nmargin: 0 auto; }\r\nimg.fullwidth, img.fullwidthOnMobile {\r\nmax-width: 100% !important; }\r\n.no-stack .col {\r\nmin-width: 0 !important;\r\ndisplay: table-cell !important; }\r\n.no-stack.two-up .col {\r\nwidth: 50% !important; }\r\n.no-stack.mixed-two-up .col.num4 {\r\nwidth: 33% !important; }\r\n.no-stack.mixed-two-up .col.num8 {\r\nwidth: 66% !important; }\r\n.no-stack.three-up .col.num4 {\r\nwidth: 33% !important; }\r\n.no-stack.four-up .col.num3 {\r\nwidth: 25% !important; }\r\n.mobile_hide {\r\nmin-height: 0px;\r\nmax-height: 0px;\r\nmax-width: 0px;\r\ndisplay: none;\r\noverflow: hidden;\r\nfont-size: 0px; } }\r\n</style>\r\n<style id=\"media-query-bodytag\" type=\"text/css\">@media (max-width: 520px) {\r\n.block-grid {\r\nmin-width: 320px!important;\r\nmax-width: 100%!important;\r\nwidth: 100%!important;\r\ndisplay: block!important;\r\n}\r\n.col {\r\nmin-width: 320px!important;\r\nmax-width: 100%!important;\r\nwidth: 100%!important;\r\ndisplay: block!important;\r\n}\r\n.col > div {\r\nmargin: 0 auto;\r\n}\r\nimg.fullwidth {\r\nmax-width: 100%!important;\r\n}\r\nimg.fullwidthOnMobile {\r\nmax-width: 100%!important;\r\n}\r\n.no-stack .col {\r\nmin-width: 0!important;\r\ndisplay: table-cell!important;\r\n}\r\n.no-stack.two-up .col {\r\nwidth: 50%!important;\r\n}\r\n.no-stack.mixed-two-up .col.num4 {\r\nwidth: 33%!important;\r\n}\r\n.no-stack.mixed-two-up .col.num8 {\r\nwidth: 66%!important;\r\n}\r\n.no-stack.three-up .col.num4 {\r\nwidth: 33%!important;\r\n}\r\n.no-stack.four-up .col.num3 {\r\nwidth: 25%!important;\r\n}\r\n.mobile_hide {\r\nmin-height: 0px!important;\r\nmax-height: 0px!important;\r\nmax-width: 0px!important;\r\ndisplay: none!important;\r\noverflow: hidden!important;\r\nfont-size: 0px!important;\r\n}\r\n}\r\n</style>\r\n<table cellpadding=\"0\" cellspacing=\"0\" class=\"nl-container\" style=\"border-collapse: collapse;table-layout: fixed;border-spacing: 0;mso-table-lspace: 0pt;mso-table-rspace: 0pt;vertical-align: top;min-width: 320px;Margin: 0 auto;background-color: #dfd8c3;width: 100%\">\r\n	<tbody>\r\n		<tr style=\"vertical-align: top\">\r\n			<td style=\"word-break: break-word;border-collapse: collapse !important;vertical-align: top\">\r\n			<div style=\"background-color:transparent;\">\r\n			<div class=\"block-grid \" style=\"Margin: 0 auto;min-width: 320px;max-width: 600px;overflow-wrap: break-word;word-wrap: break-word;word-break: break-word;background-color: transparent;\">\r\n			<div style=\"border-collapse: collapse;display: table;width: 100%;background-color:transparent;\">\r\n			<div class=\"col num12\" style=\"min-width: 320px;max-width: 600px;display: table-cell;vertical-align: top;\">\r\n			<div style=\"background-color: transparent; width: 100% !important;\">\r\n			<div style=\"border-top: 0px solid transparent; border-left: 0px solid transparent; border-bottom: 0px solid transparent; border-right: 0px solid transparent; padding-top:5px; padding-bottom:0px; padding-right: 0px; padding-left: 0px;\">\r\n			<div align=\"center\" class=\"img-container center autowidth fullwidth \" style=\"padding-right: 0px; padding-left: 0px;\">\r\n			<div style=\"line-height:25px;font-size:1px\">&nbsp;</div>\r\n			<img align=\"middle\" alt=\"Image\" border=\"0\" class=\"center autowidth fullwidth\" src=\"https://d1oco4z2z1fhwp.cloudfront.net/templates/default/20/rounder-up.png\" style=\"outline: none;text-decoration: none;-ms-interpolation-mode: bicubic;clear: both;display: block !important;border: 0;height: auto;float: none;width: 100%;max-width: 600px\" title=\"Image\" width=\"600\" /></div>\r\n			</div>\r\n			</div>\r\n			</div>\r\n			</div>\r\n			</div>\r\n			</div>\r\n\r\n			<div style=\"background-color:transparent;\">\r\n			<div class=\"block-grid \" style=\"Margin: 0 auto;min-width: 320px;max-width: 600px;overflow-wrap: break-word;word-wrap: break-word;word-break: break-word;background-color: #FFFFFF;\">\r\n			<div style=\"border-collapse: collapse;display: table;width: 100%;background-color:#FFFFFF;\">\r\n			<div class=\"col num12\" style=\"min-width: 320px;max-width: 600px;display: table-cell;vertical-align: top;\">\r\n			<div style=\"background-color: transparent; width: 100% !important;\">\r\n			<div style=\"border-top: 0px solid transparent; border-left: 0px solid transparent; border-bottom: 0px solid transparent; border-right: 0px solid transparent; padding-top:5px; padding-bottom:5px; padding-right: 0px; padding-left: 0px;\">\r\n			<div align=\"center\" class=\"img-container center fixedwidth \" style=\"padding-right: 0px; padding-left: 0px;\"><img src=\"{{$logo}}\" style=\"width: 50px; height: 50px;\" title=\"logo\" />&nbsp;</div>\r\n\r\n			<div>\r\n			<div style=\"color:#555555;font-family:Arial, \'Helvetica Neue\', Helvetica, sans-serif;line-height:150%; padding-right: 10px; padding-left: 10px; padding-top: 10px; padding-bottom: 10px;\">\r\n			<div style=\"font-size:12px;line-height:18px;font-family:Arial, \'Helvetica Neue\', Helvetica, sans-serif;color:#555555;text-align:left;\">\r\n			<p style=\"margin: 0;font-size: 14px;line-height: 21px;text-align: center\"><span style=\"font-size: 30px; line-height: 45px;\">Welcome to Only Dance!&nbsp;</span></p>\r\n			</div>\r\n			</div>\r\n			</div>\r\n			</div>\r\n			</div>\r\n			</div>\r\n			</div>\r\n			</div>\r\n			</div>\r\n\r\n			<div style=\"background-color:transparent;\">\r\n			<div class=\"block-grid \" style=\"Margin: 0 auto;min-width: 320px;max-width: 600px;overflow-wrap: break-word;word-wrap: break-word;word-break: break-word;background-color: #FFFFFF;\">\r\n			<div style=\"border-collapse: collapse;display: table;width: 100%;background-color:#FFFFFF;\">\r\n			<div class=\"col num12\" style=\"min-width: 320px;max-width: 600px;display: table-cell;vertical-align: top;\">\r\n			<div style=\"background-color: transparent; width: 100% !important;\">\r\n			<div style=\"border-top: 0px solid transparent; border-left: 0px solid transparent; border-bottom: 0px solid transparent; border-right: 0px solid transparent; padding-top:0px; padding-bottom:5px; padding-right: 0px; padding-left: 0px;\">\r\n			<div>\r\n			<div style=\"line-height:120%;color:#0D0D0D;font-family:\'Montserrat\', \'Trebuchet MS\', \'Lucida Grande\', \'Lucida Sans Unicode\', \'Lucida Sans\', Tahoma, sans-serif; padding-right: 10px; padding-left: 10px; padding-top: 10px; padding-bottom: 10px;\">\r\n			<div style=\"font-size:12px;line-height:14px;color:#0D0D0D;font-family:\'Montserrat\', \'Trebuchet MS\', \'Lucida Grande\', \'Lucida Sans Unicode\', \'Lucida Sans\', Tahoma, sans-serif;text-align:left;\">\r\n			<p style=\"margin: 0;font-size: 14px;line-height: 17px;text-align: center\"><span style=\"font-size: 28px; line-height: 33px;\"><strong><span style=\"line-height: 33px; font-size: 28px;\">Hello</span></strong><span style=\"line-height: 33px; font-size: 28px;\">&nbsp;<strong>{{$name}},</strong></span></span></p>\r\n\r\n			<p style=\"margin: 0;font-size: 14px;line-height: 17px;text-align: center\"><br />\r\n			<span style=\"color: rgb(13, 13, 13); font-family: Montserrat, &quot;Trebuchet MS&quot;, &quot;Lucida Grande&quot;, &quot;Lucida Sans Unicode&quot;, &quot;Lucida Sans&quot;, Tahoma, sans-serif; font-size: 14px; text-align: center;\">Your instructor request has been approved successfully</span></p>\r\n			</div>\r\n			</div>\r\n			</div>\r\n\r\n			<div style=\"line-height:150%;color:#555555;font-family:\'Montserrat\', \'Trebuchet MS\', \'Lucida Grande\', \'Lucida Sans Unicode\', \'Lucida Sans\', Tahoma, sans-serif; padding-right: 10px; padding-left: 10px; padding-top: 10px; padding-bottom: 10px;\">\r\n			<div style=\"font-size:12px;line-height:18px;color:#555555;font-family:\'Montserrat\', \'Trebuchet MS\', \'Lucida Grande\', \'Lucida Sans Unicode\', \'Lucida Sans\', Tahoma, sans-serif;text-align:left;\">\r\n			<p style=\"margin: 0;font-size: 14px;line-height: 21px;text-align: center\">&nbsp;</p>\r\n			</div>\r\n			</div>\r\n			</div>\r\n			</div>\r\n			</div>\r\n			</div>\r\n			</div>\r\n			</div>\r\n\r\n			<div style=\"background-color:transparent; text-align: center;\">\r\n			<div class=\"block-grid three-up \" style=\"Margin: 0 auto;min-width: 320px;max-width: 600px;overflow-wrap: break-word;word-wrap: break-word;word-break: break-word;background-color: #0b0055; border-radius: 0 0 10px 10px; padding: 20px 0; \">\r\n			