(8, 2, 'Customer OTP verification', 'Your One-Time Password (OTP) for verification', '<title></title>\r\n<meta charset=\"UTF-8\"><meta http-equiv=\"X-UA-Compatible\" content=\"IE=edge\"><meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n<link href=\"https://fonts.googleapis.com/css2?family=Outfit:wght@100;200;300;400;500;600;700;800;900&amp;display=swap\" rel=\"stylesheet\" />\r\n<table align=\"center\" cellpadding=\"0\" cellspacing=\"0\" width=\"800px\">\r\n	<tbody><!-- Top Image -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#0000\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\" bgcolor=\"#0000\" style=\"height:100;\" valign=\"top\">&nbsp;</td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n		<!-- Logo -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFF7D5\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" style=\"padding: 40px;\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\" valign=\"top\"><a href=\"javascript:void(0)\" style=\"display: block;\" target=\"_blank\"><img alt=\"top-image\" src=\"{{$logo}}\" style=\"display: block;\" /> </a></td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n		<!-- Details -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" style=\"padding: 32px 40px; border-bottom: 2px solid #F6F5EF;\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\">\r\n						<h2 style=\"font-size: 42px; line-height: 60px; font-weight: 500; color: #000000; margin: 0; padding: 0 0 32px;\">Welcome to Liquor!</h2>\r\n						</td>\r\n					</tr>\r\n					<tr>\r\n						<td align=\"left\">\r\n						<p style=\"font-size: 24px; line-height: 36px; font-weight: 500; color: rgb(0, 0, 0); margin: 0px; padding: 0px 0px 8px;\"><span style=\"font-size:20px;\">Hello {{$name}}</span></p>\r\n\r\n						<p style=\"font-size: 20px; line-height: 30px; font-weight: 300; letter-spacing: 0.04em; color: rgb(0, 0, 0); margin: 0px; padding: 0px 0px 32px;\"><span style=\"font-size:20px;\"><span style=\"color: rgb(0, 0, 0); font-family: Arial; white-space-collapse: preserve;\">Thank you for registering with Liquor. To complete your registration and to ensure the security of your account, we require a one-time password (OTP) verification. </span></span></p>\r\n						</td>\r\n					</tr>\r\n					<tr>\r\n						<td align=\"left\">\r\n						<table cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\r\n							<tbody>\r\n								<tr>\r\n									<td align=\"left\">\r\n									<p><span style=\"font-size:20px;\"><span fontscheme=\"2\">Please use the following OTP to verify your account</span></span></p>\r\n\r\n									<p><span style=\"font-size:20px;\"><span align=\"left\" style=\"line-height: 21px; font-weight: 300; color: rgb(0, 0, 0); display: inline-block; margin: 0px 32px 0px 0px;\">OTP : {{$otp}}</span><br />\r\n									<br />\r\n									<span style=\"color: rgb(0, 0, 0); letter-spacing: 0.8px;\">Best regards,<br />\r\n									Liquor team</span></span></p>\r\n									</td>\r\n								</tr>\r\n							</tbody>\r\n						</table>\r\n						</td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n		<!-- Footer -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" style=\"padding: 32px 40px;\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\" style=\"padding: 0 0 22px;\"><span style=\"display: inline-block;\"><a href=\"{{$settingfacebook}}\" style=\"text-decoration: none; vertical-align: middle; margin: 0 23px 0 0; text-align: center; display: inline-block;\" target=\"_blank\"><img alt=\"linkedIn\" src=\"{{$facebook_logo}}\" style=\"vertical-align: middle;\" /> </a> <a href=\"{{$settingtwitter}}\" style=\"text-decoration: none; vertical-align: middle; margin: 0 23px 0 0; text-align: center; display: inline-block;\" target=\"_blank\"> <img alt=\"twitter\" src=\"{{$in_logo}}\" style=\"vertical-align: middle;\" /> </a> <a href=\"{{$settinginstagram}}\" style=\"text-decoration: none; vertical-align: middle; margin: 0; text-align: center; display: inline-block;\" target=\"_blank\"> <img alt=\"instagram\" src=\"{{$insta_logo}}\" style=\"vertical-align: middle;\" /> </a> </span></td>\r\n					</tr>\r\n					<tr>\r\n						<td align=\"center\">\r\n						<p style=\"font-size: 14px; line-height: 21px; font-weight: 300; color: #000000; margin: 0;\"><span style=\"font-size:14px;\">Get in touch with us at<a href=\"mailto:info@liquor.com\" style=\"margin: 0; font-size: 16px; line-height: 24px; font-weight: 500; color: #232B44; margin-left: 4px; display: inline-block; text-decoration: none;\">info@liquor.com</a></span></p>\r\n						</td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n		<!-- Bottom Image -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\" bgcolor=\"#0000\" style=\"height:100;\" valign=\"top\">&nbsp;</td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>', 1, NULL, '2023-01-18 04:45:27', '2024-01-10 13:05:50'),
(9, 2, 'New User Registration', 'Welcome to Liquor – Registration Successful!', '<title></title>\r\n<meta charset=\"UTF-8\"><meta http-equiv=\"X-UA-Compatible\" content=\"IE=edge\"><meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n<link href=\"https://fonts.googleapis.com/css2?family=Outfit:wght@100;200;300;400;500;600;700;800;900&amp;display=swap\" rel=\"stylesheet\" />\r\n<p><!-- Footer --><!-- Footer --></p>\r\n\r\n<table align=\"center\" cellpadding=\"0\" cellspacing=\"0\" width=\"800px\">\r\n	<tbody><!-- Top Image -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\" bgcolor=\"#0000\" style=\"height:100;\" valign=\"top\">&nbsp;</td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n		<!-- Logo -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFF7D5\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" style=\"padding: 40px;\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\" valign=\"top\"><a href=\"javascript:void(0)\" style=\"display: block;\" target=\"_blank\"><img alt=\"top-image\" src=\"{{$logo}}\" style=\"display: block;\" /> </a></td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n		<!-- Details -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" style=\"padding: 32px 40px; border-bottom: 2px solid #F6F5EF;\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\">\r\n						<h2 style=\"font-size: 42px; line-height: 60px; font-weight: 500; color: #000000; margin: 0; padding: 0 0 32px;\"><span style=\"font-size:36px;\">Welcome to Liquor!</span></h2>\r\n						</td>\r\n					</tr>\r\n					<tr>\r\n						<td align=\"left\">\r\n						<p style=\"font-size: 24px; line-height: 36px; font-weight: 500; color: rgb(0, 0, 0); margin: 0px; padding: 0px 0px 8px;\"><span style=\"font-size:20px;\">Hello {{$name}},</span></p>\r\n\r\n						<p style=\"font-size: 20px; line-height: 30px; font-weight: 300; letter-spacing: 0.04em; color: rgb(0, 0, 0); margin: 0px; padding: 0px;\"><span style=\"font-size:20px;\">Congratulations! We are happy to inform you that your account has been successfully created on Liquor.<br />\r\n						<br />\r\n						<span style=\"letter-spacing: 0.8px;\">Best regards,</span><br style=\"color: rgb(0, 0, 0); font-size: 20px; letter-spacing: 0.8px;\" />\r\n						<span style=\"letter-spacing: 0.8px;\">Liquor team</span></span></p>\r\n						</td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" style=\"padding: 32px 40px;\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\" style=\"padding: 0 0 22px;\">\r\n						<p><span style=\"display: inline-block;\"><a href=\"{{$settingfacebook}}\" style=\"text-decoration: none; vertical-align: middle; margin: 0 23px 0 0; text-align: center; display: inline-block;\" target=\"_blank\"><img alt=\"linkedIn\" src=\"{{$facebook_logo}}\" style=\"vertical-align: middle;\" /> </a> <a href=\"{{$settingtwitter}}\" style=\"text-decoration: none; vertical-align: middle; margin: 0 23px 0 0; text-align: center; display: inline-block;\" target=\"_blank\"> <img alt=\"twitter\" src=\"{{$in_logo}}\" style=\"vertical-align: middle;\" /> </a> <a href=\"{{$settinginstagram}}\" style=\"text-decoration: none; vertical-align: middle; margin: 0; text-align: center; display: inline-block;\" target=\"_blank\"> <img alt=\"instagram\" src=\"{{$insta_logo}}\" style=\"vertical-align: middle;\" /> </a> </span></p>\r\n						</td>\r\n					</tr>\r\n					<tr>\r\n						<td align=\"center\">\r\n						<p style=\"font-size: 14px; line-height: 21px; font-weight: 300; color: #000000; margin: 0;\"><span style=\"font-size:14px;\">Get in touch with us at<a href=\"mailto:info@liquor.com\" style=\"margin: 0; font-size: 16px; line-height: 24px; font-weight: 500; color: #232B44; margin-left: 4px; display: inline-block; text-decoration: none;\">info@liquor.com</a></span></p>\r\n						</td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n		<!-- Bottom Image -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\" bgcolor=\"#0000\" style=\"height:100;\" valign=\"top\">&nbsp;</td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>', 1, NULL, '2023-01-18 06:38:33', '2024-01-10 13:02:18'),
(10, 2, 'Quote Request', 'Quote Request', '<title></title>\r\n<meta charset=\"UTF-8\"><meta http-equiv=\"X-UA-Compatible\" content=\"IE=edge\"><meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n<link href=\"https://fonts.googleapis.com/css2?family=Outfit:wght@100;200;300;400;500;600;700;800;900&amp;display=swap\" rel=\"stylesheet\" />\r\n<table align=\"center\" cellpadding=\"0\" cellspacing=\"0\" width=\"800px\">\r\n	<tbody><!-- Top Image -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\" valign=\"top\"><img alt=\"top-image\" src=\"{{$graphic_image}}\" style=\"display: block;\" /></td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n		<!-- Logo -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFF7D5\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" style=\"padding: 40px;\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\" valign=\"top\"><a href=\"javascript:void(0)\" style=\"display: block;\" target=\"_blank\"><img alt=\"top-image\" src=\"{{$logo}}\" style=\"display: block;\" /> </a></td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n		<!-- Details -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" style=\"padding: 32px 40px; border-bottom: 2px solid #F6F5EF;\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\">\r\n						<h2 style=\"font-size: 42px; line-height: 60px; font-weight: 500; color: #000000; margin: 0; padding: 0 0 32px;\">Welcome to Trade25!</h2>\r\n						</td>\r\n					</tr>\r\n					<tr>\r\n						<td align=\"left\">\r\n						<h5 style=\"font-size: 24px; line-height: 36px; font-weight: 500; color: #000000; margin: 0; padding: 0 0 8px;\"><span style=\"font-size:14px;\"><span style=\"font-size:26px;\">Hello</span> <span style=\"font-size:22px;\">{{$sendname}}</span>,</span></h5>\r\n\r\n						<h5 style=\"font-size: 24px; line-height: 36px; font-weight: 500; color: #000000; margin: 0; padding: 0 0 8px;\"><span style=\"font-size:14px;\">I am sending you a quote request for service, I would greatly appreciate it if you could provide me with the availability and pricing information for the requested service.</span></h5>\r\n						<!-- <p style=\"font-size: 20px; line-height: 30px; font-weight: 300; letter-spacing: 0.04em; color: #000000; margin: 0; padding: 0 0 32px;\">Your Account has been Created Successfully.</p>\r\n                                <span style=\"font-size: 18px; line-height: 27px; font-weight: 300; color: #000000; margin: 0; padding: 0 0 16px; display: block;\">Here\'s your login information:</span> --></td>\r\n					</tr>\r\n					<tr>\r\n						<td align=\"left\">\r\n						<table cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\r\n							<tbody>\r\n								<tr>\r\n									<td align=\"left\"><span style=\"font-size:14px;\"><span align=\"left\" style=\"line-height: 21px; font-weight: 300; color: rgb(0, 0, 0); display: inline-block; margin: 0px 40px 0px 0px;\">Username :</span> <span align=\"left\" style=\"margin: 0px; line-height: 24px; font-weight: 500; color: rgb(0, 0, 0); display: inline-block;\">{{$user_name}}</span></span></td>\r\n								</tr>\r\n								<tr>\r\n									<td height=\"16px\">&nbsp;</td>\r\n								</tr>\r\n								<tr>\r\n									<td align=\"left\"><span style=\"font-size:14px;\"><span align=\"left\" style=\"line-height: 21px; font-weight: 300; color: rgb(0, 0, 0); display: inline-block; margin: 0px 45px 0px 0px;\">Category :</span> <span align=\"left\" style=\"margin: 0px; line-height: 24px; font-weight: 500; color: rgb(0, 0, 0); display: inline-block;\">{{$category_name}}</span></span></td>\r\n								</tr>\r\n								<tr>\r\n									<td height=\"16px\">&nbsp;</td>\r\n								</tr>\r\n								<tr>\r\n									<td align=\"left\"><span style=\"font-size:14px;\"><span align=\"left\" style=\"line-height: 21px; font-weight: 300; color: rgb(0, 0, 0); display: inline-block; margin: 0px 45px 0px 0px;\">Postcode :</span> <span align=\"left\" style=\"margin: 0px; line-height: 24px; font-weight: 500; color: rgb(0, 0, 0); display: inline-block;\">{{$post_code}}</span></span></td>\r\n								</tr>\r\n								<tr>\r\n									<td height=\"16px\">&nbsp;</td>\r\n								</tr>\r\n								<tr>\r\n									<td align=\"left\"><span style=\"font-size:14px;\"><span align=\"left\" style=\"line-height: 21px; font-weight: 300; color: rgb(0, 0, 0); display: inline-block; margin: 0px 32px 0px 0px;\">Description :</span> <span align=\"left\" style=\"margin: 0px; line-height: 24px; font-weight: 500; color: rgb(0, 0, 0); display: inline-block;\">{{$description}}</span></span></td>\r\n								</tr>\r\n								<tr>\r\n									<td align=\"left\"><span style=\"font-size:14px;\"><span align=\"left\" style=\"line-height: 21px; font-weight: 300; color: rgb(0, 0, 0); display: inline-block; margin: 0px 32px 0px 0px;\">Quote Image :</span></span> <span align=\"left\" style=\"margin: 0; font-size: 16px; line-height: 24px; font-weight: 500; color: #000000; display: inline-block;\"><a href=\"{{$image_name}}\" target=\"_blank\"><img src=\"{{$image_name}}\" style=\"width: 50px; height: 50px; margin-bottom: -20px margin-top: 10px;\" title=\"Quote image\" /></a></span>\r\n									<p>&nbsp;</p>\r\n									</td>\r\n								</tr>\r\n								<tr>\r\n									<td height=\"16px\">\r\n									<h5 style=\"line-height: 36px; font-size: 24px; color: rgb(0, 0, 0); margin: 0px; padding: 0px 0px 8px;\"><span style=\"font-size:14px;\">Best regards,<br />\r\n									Trade25 team</span></h5>\r\n									</td>\r\n								</tr>\r\n							</tbody>\r\n						</table>\r\n						</td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n		<!-- Footer -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">\r\