(16, 2, 'Order Delivered', 'Your order has been delivered', '<title></title>\r\n<meta charset=\"UTF-8\"><meta http-equiv=\"X-UA-Compatible\" content=\"IE=edge\"><meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n<link href=\"https://fonts.googleapis.com/css2?family=Outfit:wght@100;200;300;400;500;600;700;800;900&amp;display=swap\" rel=\"stylesheet\" />\r\n<table align=\"center\" cellpadding=\"0\" cellspacing=\"0\" width=\"800px\">\r\n	<tbody><!-- Top Image -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\" bgcolor=\"#0000\" style=\"height:100;\" valign=\"top\">&nbsp;</td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n		<!-- Logo -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFF7D5\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" style=\"padding: 40px;\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\" valign=\"top\"><a href=\"javascript:void(0)\" style=\"display: block;\" target=\"_blank\"><img alt=\"top-image\" src=\"{{$logo}}\" style=\"display: block;\" /> </a></td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n		<!-- Details -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" style=\"padding: 32px 40px; border-bottom: 2px solid #F6F5EF;\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\">\r\n						<h2 style=\"font-size: 42px; line-height: 60px; font-weight: 500; color: #000000; margin: 0; padding: 0 0 32px;\"><span style=\"font-size:20px;\">Hello</span> <span style=\"font-size:18px;\">{{$sendname}}</span></h2>\r\n						</td>\r\n					</tr>\r\n					<tr>\r\n						<td align=\"left\">\r\n						<p style=\"font-size: 20px; line-height: 30px; font-weight: 300; letter-spacing: 0.04em; color: #000000; margi