INSERT INTO `faqs` (`id`, `language_id`, `question_name`, `question_name_fr`, `answer`, `answer_fr`, `create_by`, `update_by`, `status`, `remember_token`, `created_at`, `updated_at`) VALUES
(17, NULL, 'Is cash on delivery available ?', 'Le paiement à la livraison est-il disponible ?', 'Yes – just place your order as normal, select cash on delivery as Payment Method.', 'Oui, passez simplement votre commande comme d\'habitude, sélectionnez le paiement à la livraison comme mode de paiement.', '1', NULL, 1, NULL, '2024-02-13 13:14:34', '2024-02-13 13:14:34'),
(18, NULL, 'How can i order by telephone ?', 'Comment puis-je commander par téléphone ?', 'Yes. Please call us during office hours on  0555667788  (Ghana Customers)\r\n\r\nOur Office is open between Monday to Saturday  ( 9 AM - 11 PM )\r\n                                                        Sunday    ( 9 AM - 00 AM Midnight)', 'Oui. Veuillez nous appeler pendant les heures de bureau au 0555667788 (clients du Ghana)\r\n\r\nNotre bureau est ouvert du lundi au samedi (9h - 23h)\r\n                                      Dimanche (9h00 - 00h00 minuit)', '1', NULL, 1, NULL, '2024-02-13 13:10:20', '2024-02-13 13:10:20'),
(19, NULL, 'Is my privacy assured?', 'Ma vie privée est-elle assurée ?', 'Yes – we take your privacy very seriously and will only use any information you supply to us lawfully and for the purposes of your transaction with us, in accordance with the Data Protection Act 1998. Your details will never be sold or supplied by us to any other companies.', 'Oui, nous prenons votre vie privée très au sérieux et n\'utiliserons que les informations que vous nous fournissez légalement et aux fins de votre transaction avec nous, conformément à la loi sur la protection des données de 1998. Vos coordonnées ne seront jamais vendues ou fournies par nous à aucun d\'autres entreprises.', '1', NULL, 1, NULL, '2024-02-13 13:07:07', '2024-02-13 13:07:07'),
(20, NULL, 'What is your favorite template from BRIX Templatess?	What is your favorite template from BRIX Templatess?	What is your favorite template from BRIX Templatess?', 'What is your favorite template from BRIX Templatess?', 'What is your favorite template from BRIX Templatess?	What is your favorite template from BRIX Templatess?	\r\nWhat is your favorite template from BRIX Templatess?	\r\nWhat is your favorite template from BRIX Templatess?	\r\nWhat is your favorite template from BRIX Templatess?	\r\nWhat is your favorite template from BRIX Templatess?	\r\nWhat is your favorite template from BRIX Templatess?', 'What is your favorite template from BRIX Templatess?', '1', NULL, 2, NULL, '2024-01-10 13:17:13', '2024-01-19 06:08:48'),
