(22, NULL, 'dc What is your favorite template from BRIX Templatess?	What is your favorite template from BRIX Templatess?	What is your favorite template from BRIX Templatess?	What is your favorite template from BRIX Templatess?	What is your favorite template from BRIX', 'What is your favorite template from BRIX Templatess?	What is your favorite template from BRIX Templatess?', 'What is your favorite template from BRIX Templatess?	\r\nWhat is your favorite template from BRIX Templatess?	\r\nWhat is your favorite template from BRIX Templatess?	\r\nWhat is your favorite template from BRIX Templatess?	\r\nWhat is your favorite template from BRIX Templatess?	\r\nWhat is your favorite template from BRIX Templatess?	\r\nWhat is your favorite template from BRIX Templatess?	\r\nWhat is your favorite template from BRIX Templatess?', 'What is your favorite template from BRIX Templatess?	\r\nWhat is your favorite template from BRIX Templatess?	\r\nWhat is your favorite template from BRIX Templatess?	\r\nWhat is your favorite template from BRIX Templatess?	\r\nWhat is your favorite template from BRIX Templatess?	\r\nWhat is your favorite template from BRIX Templatess?', '1', NULL, 2, NULL, '2024-01-10 13:18:14', '2024-01-19 06:08:51'),
(23, NULL, 'Is your site secure?', 'Votre site est-il sécurisé ?', 'Yes – Liquor Junction has put in place a number of foolproof security measures to protect our users, some of which we may not be able to disclose. SSL protects our buyers\' transactions and provides visitors with proof of our digital identity.', 'Oui – Liquor Junction a mis en place un certain nombre de mesures de sécurité infaillibles pour protéger nos utilisateurs, dont certaines que nous ne pourrons peut-être pas divulguer. SSL protège les transactions de nos acheteurs et fournit aux visiteurs une preuve de notre identité numérique.', '1', NULL, 1, NULL, '2024-02-13 13:05:12', '2024-02-13 13:05:12'),
(24, NULL, 'Is available free delivery for this Is available free delivery for thisIs available free delivery for thisIs available free delivery for thisIs available free delivery for thisIs available free delivery for thisIs available free delivery for this', 'What is a cocktails & mocktails?', 'What is a cocktails & mocktails?', 'Is available free delivery for this Is available free delivery for thisIs available free delivery for thisIs available free delivery for thisIs available free delivery for thisIs available free delivery for thisIs available free delivery for this', '1', NULL, 2, NULL, '2024-01-19 06:08:28', '2024-01-19 06:08:41'),
(25, NULL, 'Is it possible to send order on different address ?', 'Est-il possible d\'envoyer la commande à une adresse différente ?', 'Yes - on check out page , just enter the name and address of the person you want us to deliver to in the \'New Address\' section.', 'Oui - sur la page de paiement, entrez simplement le nom et l\'adresse de la personne à qui vous souhaitez que nous livrions dans la section « Nouvelle adresse ».', '1', NULL, 1, NULL, '2024-02-13 13:22:02', '2024-02-13 13:22:02'),
(26, NULL, 'How do I redeem discount codes?', 'Comment puis-je utiliser des codes de réduction ?', 'To redeem a discount code, just type it into the coupon box over checkout page and press \'Apply\'.', 'Pour utiliser un code de réduction, saisissez-le simplement dans la case du coupon sur la page de paiement et appuyez sur « Appliquer ».', '1', NULL, 1, NULL, '2024-02-13 13:26:33', '2024-02-13 13:26:33'),
(27, NULL, 'Is there a minimum order?', 'Y a-t-il un minimum de commande ?', 'No we are happy to ship a single bottle.', 'Non, nous sommes heureux d\'expédier une seule bouteille.', '1', NULL, 1, NULL, '2024-02-13 13:28:12', '2024-02-13 13:28:12');
