(195, '65718c2e68d8d', 'PRO000195', 0, 'Hennessy Cognac VS', '<p>Matured in new oak barrels, Hennessy V.S is bold and fragrant. Its beguiling character is uniquely Hennessy, a timeless choice with an intensity all its own. Hennessy V.S offers toasted and fruit notes, with a rich, clearly defined palate and a welcoming exuberanc</p>', 'Hennessy V.S is bold and fragrant. Its beguiling character is uniquely Hennessy, a timeless choice with an intensity all its own.', 21, '', NULL, 43, 72, '', 'Hennessy Cognac VS', 'Hennessy V.S est audacieux et parfumé. Son caractère séduisant est propre à Hennessy, un choix intemporel avec une intensité qui lui est propre.', '<p>&Eacute;lev&eacute; en f&ucirc;ts de ch&ecirc;ne neufs, Hennessy V.S est audacieux et parfum&eacute;. Son caract&egrave;re s&eacute;duisant est propre &agrave; Hennessy, un choix intemporel avec une intensit&eacute; qui lui est propre. Hennessy V.S offre des notes grill&eacute;es et fruit&eacute;es, avec une bouche riche et clairement d&eacute;finie et une exub&eacute;rance accueillante.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000195', 0, 0, 1, NULL, NULL, '2023-12-07 09:11:10', '2024-02-05 06:59:50'),
(196, '65718ca5d2a2f', 'PRO000196', 0, 'Hennessy Cognac Vs Gift Box', '<p>Matured in new oak barrels, Hennessy V.S is bold and fragrant. Its beguiling character is uniquely Hennessy, a timeless choice with an intensity all its own. Hennessy V.S offers toasted and fruit notes, with a rich, clearly defined palate and a welcoming exuberanc</p>', 'Hennessy V.S is bold and fragrant. Its beguiling character is uniquely Hennessy, a timeless choice with an intensity all its own.', 21, '', NULL, 43, 72, '', 'Hennessy Cognac Vs Gift Box', 'Hennessy V.S est audacieux et parfumé. Son caractère séduisant est propre à Hennessy, un choix intemporel avec une intensité qui lui est propre.', '<p>&Eacute;lev&eacute; en f&ucirc;ts de ch&ecirc;ne neufs, Hennessy V.S est audacieux et parfum&eacute;. Son caract&egrave;re s&eacute;duisant est propre &agrave; Hennessy, un choix intemporel avec une intensit&eacute; qui lui est propre. Hennessy V.S offre des notes grill&eacute;es et fruit&eacute;es, avec une bouche riche et clairement d&eacute;finie et une exub&eacute;rance accueillante.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000196', 0, 0, 1, NULL, NULL, '2023-12-07 09:13:09', '2024-05-08 06:14:55');
INSERT INTO `product` (`id`, `uniqid`, `product_item_id`, `supplier_id`, `product_name`, `description`, `short_description`, `category_id`, `product_image`, `images`, `subcategory_id`, `brand_id`, `video`, `product_name_fr`, `short_description_fr`, `page_content_fr`, `product_qty`, `tech_data_sheet`, `retail_price`, `discount_price`, `is_admin_approve`, `most_view`, `is_product_bestseller`, `sku`, `average_rating`, `offer`, `status`, `in_store`, `in_online`, `created_at`, `updated_at`) VALUES
(197, '65718d1029f2d', 'PRO000197', 0, 'Hennessy VSOP', '<p>Aged for up to 15 years and blended from over 60 different &#39;eaux-de-vie,&#39; this exquisite cognac offers the perfect balance of sweetness and spice. The delicate aroma of vanilla and oak is complemented by notes of dried fruit and cinnamon, creating a warm and inviting palate.</p>', 'Hennesey VSOP Privilege offers a natural balance of strength and smoothness with a long-lasting finish.', 21, '', NULL, 43, 72, '', 'Hennessy VSOP', 'Hennesey VSOP Privilege offre un équilibre naturel entre force et douceur avec une finition longue durée.', '<p>Vieilli jusqu&#39;&agrave; 15 ans et assembl&eacute; &agrave; partir de plus de 60 eaux-de-vie diff&eacute;rentes, ce cognac exquis offre l&#39;&eacute;quilibre parfait entre douceur et &eacute;pices. L&#39;ar&ocirc;me d&eacute;licat de vanille et de ch&ecirc;ne est compl&eacute;t&eacute; par des notes de fruits secs et de cannelle, cr&eacute;ant une bouche chaleureuse et invitante.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000197', 0, 0, 1, NULL, NULL, '2023-12-07 09:14:56', '2024-02-05 06:59:50'),
(198, '65718d6e8c58b', 'PRO000198', 0, 'Hennessy  VSOP', '<p>Aged for up to 15 years and blended from over 60 different &#39;eaux-de-vie,&#39; this exquisite cognac offers the perfect balance of sweetness and spice. The delicate aroma of vanilla and oak is complemented by notes of dried fruit and cinnamon, creating a warm and inviting palate.</p>', 'Hennesey VSOP Privilege offers a natural balance of strength and smoothness with a long-lasting finish.', 21, '', NULL, 43, 72, '', 'Hennessy  VSOP', 'Hennesey VSOP Privilege offre un équilibre naturel entre force et douceur avec une finition longue durée.', '<p>Vieilli jusqu&#39;&agrave; 15 ans et assembl&eacute; &agrave; partir de plus de 60 eaux-de-vie diff&eacute;rentes, ce cognac exquis offre l&#39;&eacute;quilibre parfait entre douceur et &eacute;pices. L&#39;ar&ocirc;me d&eacute;licat de vanille et de ch&ecirc;ne est compl&eacute;t&eacute; par des notes de fruits secs et de cannelle, cr&eacute;ant une bouche chaleureuse et invitante.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000198', 0, 0, 1, NULL, NULL, '2023-12-07 09:16:30', '2024-02-05 06:59:50'),
(199, '6571a37570da9', 'PRO000199', 0, 'Hennessy Cognac Vs Les Twins', '<p>Notes of fresh toast, roasted almond and brown sugar are complemented by fragrances of subtle vine fruits. Palate: Its aromatic intensity are reflected in a rich creamy palate, which brings an added dimension of vanilla, all rounded off by an exuberantly fresh and floral finish.</p>', 'Only the most distinctive eaux-de-vie comprise this cognac, which then matures for several years in oak casks expertly blended.', 21, '', NULL, 43, 72, '', 'Hennessy Cognac Vs Les Twins', 'Seules les eaux-de-vie les plus typées composent ce cognac, qui vieillit ensuite plusieurs années dans des fûts de chêne savamment assemblés.', '<p>Des notes de pain grill&eacute; frais, d&#39;amande grill&eacute;e et de cassonade sont compl&eacute;t&eacute;es par des parfums subtils de fruits de vigne. Bouche : Son intensit&eacute; aromatique se refl&egrave;te dans une bouche riche et cr&eacute;meuse, qui apporte une dimension vanill&eacute;e suppl&eacute;mentaire, le tout compl&eacute;t&eacute; par une finale exub&eacute;rante fra&icirc;che et florale.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000199', 0, 0, 1, NULL, NULL, '2023-12-07 10:50:29', '2024-02-05 06:59:50'),
(200, '6571a3fbc1f7c', 'PRO000200', 0, 'Hennessy Vs With Box Nba', '<p>Vs Cognac Nba Edition. Hennessy Very Special (V.S) is one of the most popular cognacs in the world. Its beguiling character is uniquely Hennessy, a timeless choice with an intensity all its own with toasted and fruit notes, and a rich, clearly defined palate and a welcoming exuberance.</p>', 'collaborates with the NBA again with a collector\'s edition of its V.S.O.P cognac. Presented in a themed gift box.', 21, '', NULL, 43, 72, '', 'Hennessy Vs With Box Nba', 'collabore à nouveau avec la NBA avec une édition collector de son cognac V.S.O.P. Présenté dans un coffret cadeau à thème.', '<p>Vs Cognac Nba &Eacute;dition. Hennessy Very Special (V.S) est l&#39;un des cognacs les plus populaires au monde. Son caract&egrave;re s&eacute;duisant est propre &agrave; Hennessy, un choix intemporel avec une intensit&eacute; qui lui est propre avec des notes grill&eacute;es et fruit&eacute;es, une bouche riche et clairement d&eacute;finie et une exub&eacute;rance accueillante.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000200', 0, 0, 1, NULL, NULL, '2023-12-07 10:52:43', '2024-02-05 06:59:50'),
(201, '6571a43d62397', 'PRO000201', 0, 'Hennessy VSOP', '<p>Aged for up to 15 years and blended from over 60 different &#39;eaux-de-vie,&#39; this exquisite cognac offers the perfect balance of sweetness and spice. The delicate aroma of vanilla and oak is complemented by notes of dried fruit and cinnamon, creating a warm and inviting palate.</p>', 'New exclusive Hennessy V.S Limited Edition bottle, specially designed to commemorate the partnership between Hennessy and the NBA', 21, '', NULL, 43, 72, '', 'Hennessy VSOP', 'Nouvelle bouteille exclusive Hennessy V.S Limited Edition, spécialement conçue pour commémorer le partenariat entre Hennessy et la NBA', '<p>Vieilli jusqu&#39;&agrave; 15 ans et assembl&eacute; &agrave; partir de plus de 60 eaux-de-vie diff&eacute;rentes, ce cognac exquis offre l&#39;&eacute;quilibre parfait entre douceur et &eacute;pices. L&#39;ar&ocirc;me d&eacute;licat de vanille et de ch&ecirc;ne est compl&eacute;t&eacute; par des notes de fruits secs et de cannelle, cr&eacute;ant une bouche chaleureuse et invitante.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000201', 0, 0, 1, NULL, NULL, '2023-12-07 10:53:49', '2024-05-08 06:16:14'),
(202, '6571a5186dc79', 'PRO000202', 0, 'L Lindeman\'s Bin 40 Merlot 2019', '<p>Ruby red colour; floral, cassis and bell pepper on the nose; soft, round berry-plummy flavours with a chocolate and cedar notes in the finish.</p>\r\n\r\n<p>&nbsp;</p>', 'This Lindeman\'s Bin 40 Merlot is a soft and elegant, medium-bodied Merlot with delicious red berry aromas, dark red berry fruit.', 22, '', NULL, 33, 73, '', 'L Lindeman\'s Bin 40 Merlot 2019', 'Ce merlot Lindeman\'s Bin 40 est un merlot doux et élégant, moyennement corsé, avec de délicieux arômes de petits fruits rouges et', '<p>Couleur rouge rubis; nez floral, cassis et poivron; saveurs douces et rondes de petits fruits et de prune avec des notes de chocolat et de c&egrave;dre en finale.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000202', 0, 0, 1, NULL, NULL, '2023-12-07 10:57:28', '2024-02-05 06:59:50'),
(203, '6571a6483ada0', 'PRO000203', 0, 'L Lindeman\'S Crisp & Fresh White Wine', '<p>Lindeman&#39;s Winemakers Release White Wine 750ml Wine of Spain Crisp &amp; fresh This Spanish white wine comes from a blend of Verdejo and Macabeo. The result is crisp and fresh with hints of peach and a long soft finish. Brief content visible, double tap to read full content.</p>', 'This Spanish white wine comes from a blend of Verdejo and Macabeo.', 22, '', NULL, 40, 73, '', 'L Lindeman\'S Crisp & Fresh White Wine', 'Ce vin blanc espagnol est issu d\'un assemblage de Verdejo et de Macabeo.', '<p>Les vignerons de Lindeman lancent du vin blanc 750 ml Vin d&#39;Espagne Croustillant et frais Ce vin blanc espagnol est issu d&#39;un assemblage de Verdejo et de Macabeo. Le r&eacute;sultat est vif et frais avec des notes de p&ecirc;che et une longue finale douce. Bref contenu visible, appuyez deux fois pour lire le contenu complet.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000203', 0, 0, 1, NULL, NULL, '2023-12-07 11:02:32', '2024-02-05 06:59:50'),
(204, '6572e617bca0f', 'PRO000204', 0, 'Lindeman\'S Bin 35 Rose 2020', '<p>Lindemans Bin 35 Rose is made using the saign&eacute;e method, which entails bleeding off a portion of the grapes&#39; liquid soon after they have been crushed. Because of the shorter maceration period made possible by this, the wine&#39;s colour and taste profile is lighter and fruitier.</p>', 'Lindemans Bin 35 Rose is made using the saignée method, which entails bleeding off a portion of the grapes\' liquid soon after they have been crushed', 22, '', NULL, 46, 73, '', 'Lindeman\'S Bin 35 Rose 2020', 'Lindemans Bin 35 Rose est élaboré selon la méthode de saignée, qui consiste à purger une partie du liquide des raisins peu après leur foulage.', '<p>Lindemans Bin 35 Rose est &eacute;labor&eacute; selon la m&eacute;thode de saign&eacute;e, qui consiste &agrave; purger une partie du liquide des raisins peu apr&egrave;s leur foulage. En raison de la p&eacute;riode de mac&eacute;ration plus courte rendue possible, la couleur et le profil gustatif du vin sont plus l&eacute;gers et plus fruit&eacute;s.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000204', 0, 0, 1, NULL, NULL, '2023-12-08 09:47:03', '2024-02-05 06:59:50'),
(205, '6572e786e7011', 'PRO000205', 0, 'Lindeman\'s Bin45 Carbernet Sauvignon2019', '<p>This is a juicy upfront and extremely rounded-in-flavors wine with a nice black-fruit component dominated by cassis, crushed blackberries, some cherry liqueur, slight hints of oak and extremely balanced through the midpalate, which also shows supple fine tannins that are harmonious and render the wine completely ...</p>', 'This Lindeman\'s Bin 45 Cabernet Sauvignon is bursting with classic dark berry and cassis characters with hints of chocolate and mint.', 22, '', NULL, 33, 73, '', 'Lindeman\'s Bin45 Carbernet Sauvignon2019', 'Ce cabernet sauvignon Lindeman\'s Bin 45 regorge de caractères classiques de baies noires et de cassis avec des notes de chocolat et de menthe.', '<p>C&#39;est un vin juteux &agrave; l&#39;attaque et extr&ecirc;mement rond en saveurs avec une belle composante de fruits noirs domin&eacute;e par le cassis, les m&ucirc;res &eacute;cras&eacute;es, un peu de liqueur de cerise, de l&eacute;g&egrave;res notes de ch&ecirc;ne et extr&ecirc;mement &eacute;quilibr&eacute; en milieu de bouche, qui montre &eacute;galement des tanins fins et souples qui sont harmonieux et restitue pleinement le vin...</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000205', 0, 0, 1, NULL, NULL, '2023-12-08 09:53:10', '2024-05-08 06:18:34'),
(206, '6572e8164180b', 'PRO000206', 0, 'Long Mountain Merlot', '<p>The wine was matured on French Oak for 4 months to add weight and complexity. Rich, dark red colour with ripe, punchy, plum flavours, sweet black cherry and a velvet finish. Delicate wood does not mask the ripe fruit. Enjoy now with roast chicken, beef, lamb, pasta and steak.</p>', 'long mountain a dry red  wine ,made of merlot grapes ,comes from south africa', 22, '', NULL, 33, 74, '', 'Long Mountain Merlot', 'Long Mountain un vin rouge sec, à base de raisins merlot, vient d\'Afrique du Sud', '<p>Le vin a &eacute;t&eacute; &eacute;lev&eacute; sur ch&ecirc;ne fran&ccedil;ais pendant 4 mois pour ajouter du poids et de la complexit&eacute;. Robe riche et rouge fonc&eacute; avec des saveurs de prune m&ucirc;re et percutante, de cerise noire douce et une finale velout&eacute;e. Le bois d&eacute;licat ne masque pas le fruit m&ucirc;r. &Agrave; d&eacute;guster d&egrave;s maintenant avec le poulet r&ocirc;ti, le b&oelig;uf, l&#39;agneau, les p&acirc;tes et le steak.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000206', 0, 0, 1, NULL, NULL, '2023-12-08 09:55:34', '2024-02-05 06:59:50'),
(207, '6572e969293ff', 'PRO000207', 0, 'Moet & Chandon Nectar Imperial', '<p>Wine Enthusiast 88 Points A good benchmark for a sweeter Champagne. In fact, not extravagantly sweet, because the fruit remains fresh, giving pear and apricot flavors, and a pure line in fresh acidity. An Intense Colour: Bold yellow with golden highlights.</p>', 'Moët & Chandon style, a style distinguished by its bright fruitiness, its seductive palate and its elegant maturity.', 23, '', NULL, 37, 75, '', 'Moet & Chandon Nectar Imperial', 'Le style Moët & Chandon, un style qui se distingue par son fruité éclatant, sa bouche séduisante et sa maturité élégante.', '<p>Wine Enthusiast 88 points Une bonne r&eacute;f&eacute;rence pour un champagne plus doux. En fait, pas extravagant sucr&eacute;, car le fruit reste frais, donnant des ar&ocirc;mes de poire et d&#39;abricot, et une ligne pure d&#39;acidit&eacute; fra&icirc;che. Une couleur intense : Jaune vif aux reflets dor&eacute;s.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000207', 0, 0, 1, NULL, NULL, '2023-12-08 10:01:13', '2024-02-05 06:59:50'),
(208, '6572ea319a154', 'PRO000208', 0, 'Moet Nectar Rose Imperial', '<p>Mo&euml;t &amp; Chandon Nectar Imp&egrave;rial Ros&egrave; is a spontaneous, radiant, romantic expression of the Mo&euml;t &amp; Chandon style, a style distinguished by its bright fruitiness, its seductive palate and its elegant maturity. This ros&eacute;&#39;s sweet strawberry flavours balance a kick of spice and rich undertones of nuts.</p>', 'MOET & CHANDON; Country of Origin: France Champagne; Contents: 25.4 fl oz (750 ml); Grape Seed Composition', 23, '', NULL, 37, 75, '', 'Moet Nectar Rose Imperial', 'Moët & Chandon ; Pays d\'origine : France Champagne ; Contenu : 25,4 fl oz (750 ml) ; Composition des pépins de raisin', '<p>Mo&euml;t &amp; Chandon Nectar Imp&egrave;rial Ros&egrave; est une expression spontan&eacute;e, rayonnante et romantique du style Mo&euml;t &amp; Chandon, un style qui se distingue par son fruit&eacute; &eacute;clatant, sa bouche s&eacute;duisante et son &eacute;l&eacute;gante maturit&eacute;. Les douces saveurs de fraise de ce ros&eacute; &eacute;quilibrent une touche d&#39;&eacute;pices et de riches nuances de noix.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000208', 0, 0, 1, NULL, NULL, '2023-12-08 10:04:33', '2024-02-05 06:59:50'),
(209, '6572eb419c7ce', 'PRO000209', 0, 'Moet Brut Mini Imperial Champagne', '<p>Mo&euml;t &amp; Chandon Brut Imp&eacute;rial is elegant golden straw yellow with green highlights. With a bouquet of vibrant intensity of green apple and citrus fruit, the freshness of mineral nuances and white flowers, the elegance of blond notes (brioche, cereal, fresh nuts).</p>', 'Moët Impérial is the House\'s iconic champagne. It has unique style, a style distinguished by its bright fruitiness, its seductive palate.', 23, '', NULL, 37, 75, '', 'Moet Brut Mini Imperial Champagne', 'Moët Impérial est le champagne emblématique de la Maison. Il a un style unique, un style qui se distingue par son fruit', '<p>Mo&euml;t &amp; Chandon Brut Imp&eacute;rial est un &eacute;l&eacute;gant jaune paille dor&eacute; aux reflets verts. Avec un bouquet d&#39;une intensit&eacute; vibrante de pomme verte et d&#39;agrumes, la fra&icirc;cheur des nuances min&eacute;rales et de fleurs blanches, l&#39;&eacute;l&eacute;gance des notes blondes (brioche, c&eacute;r&eacute;ales, noix fra&icirc;ches).</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000209', 0, 0, 1, NULL, NULL, '2023-12-08 10:09:05', '2024-02-05 06:59:50'),
(210, '6572ec2d76072', 'PRO000210', 0, 'Moet & Chandon Imperial Brut', '<p>Toasted cashew and brioche aromas add complexity and a vanilla-rich elegance. Palate: Sumptuous pear, white peach and apple flavours are followed by refreshing bubbles that soften to reveal cirus fruit and gooseberry.</p>', 'A streak of smoke-tinged minerality underscores flavors of almond madeleine, poached pear, anise and preserved lemon.', 23, '', NULL, 37, 75, '', 'Moet & Chandon Imperial Brut', 'Une touche de minéralité teintée de fumée souligne des saveurs de madeleine à l\'amande, de poire pochée, d\'anis et de citron confit.', '<p>Les ar&ocirc;mes de noix de cajou grill&eacute;e et de brioche ajoutent de la complexit&eacute; et une &eacute;l&eacute;gance riche en vanille. Bouche : De somptueuses saveurs de poire, de p&ecirc;che blanche et de pomme sont suivies de bulles rafra&icirc;chissantes qui s&#39;adoucissent pour r&eacute;v&eacute;ler des fruits de cirus et de groseille.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000210', 0, 0, 1, NULL, NULL, '2023-12-08 10:13:01', '2024-05-08 06:25:44'),
(211, '6572ec9315018', 'PRO000211', 0, 'Moet Ice Imperial', '<p>The Ice Imperial is composed of 40%-50% Pinot Noir for fruitiness and structure, 30%-40% Pinot Meunier for richness and mid-palate sensation and 10%-20% Chardonnay to enhance the refreshing acidity.</p>', 'the first champagne especially created to be enjoyed over ice. A champagne experience combining fun and fresh sensations.', 23, '', NULL, 37, 75, '', 'Moet Ice Imperial', 'le premier champagne spécialement créé pour être dégusté sur glace. Une expérience champenoise alliant plaisir et sensations fraîches.', '<p>L&#39;Ice Imperial est compos&eacute; de 40 &agrave; 50 % de pinot noir pour le fruit&eacute; et la structure, de 30 &agrave; 40 % de pinot meunier pour la richesse et la sensation en milieu de bouche et de 10 &agrave; 20 % de chardonnay pour rehausser l&#39;acidit&eacute;</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000211', 0, 0, 1, NULL, NULL, '2023-12-08 10:14:43', '2024-02-05 06:59:50'),
(212, '6572ed25c4106', 'PRO000212', 0, 'Moet & Chandon Rose Imperial Champagne', '<p>AROMA AND PALATE: Ros&eacute; Imperial displays a pink color with amber highlights. Lively and intense, the bouquet exudes red fruits (wild strawberry, raspberry, cherry) with floral nuances of rose and a slight hint of pepper.</p>', 'The Imperial Rosé Brut by Moët & Chandon has a very seductive colour, a deep and brilliant pink, embellished with amber nuances of rare visual beauty.', 23, '', NULL, 37, 75, '', 'Moet & Chandon Rose Imperial Champagne', 'L\'Impérial Rosé Brut de Moët & Chandon possède une robe très séduisante, un rose profond et brillant, agrémenté de nuances', '<p>AR&Ocirc;ME ET BOUCHE : Le Ros&eacute; Imp&eacute;rial pr&eacute;sente une robe rose aux reflets ambr&eacute;s. Vif et intense, le bouquet exhale les fruits rouges (fraise des bois, framboise, cerise) avec des nuances florales de rose et une l&eacute;g&egrave;re pointe de poivre.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000212', 0, 0, 1, NULL, NULL, '2023-12-08 10:17:09', '2024-02-05 06:59:50'),
(213, '6572eddd3e4bd', 'PRO000213', 0, 'Moet & Chandon Rose Imperial Brut 12.5%', '<p>Mo&euml;t &amp; Chandon Ros&eacute; Imp&eacute;rial is characterized by a fruity and floral aroma, slightly spiced up with mint and pepper. It goes well with simple dishes with intense flavours. The Magnum format is a large 1.5 litres bottle, which represents 2 bottles of champagne or 12 glasses.</p>', 'It has a very seductive colour, a deep and brilliant pink, embellished with amber nuances of rare visual beauty.', 23, '', NULL, 37, 75, '', 'Moet & Chandon Rose Imperial Brut 12.5%', 'Il présente une couleur très séduisante, un rose profond et brillant, agrémenté de nuances ambrées d\'une rare beauté visuelle.', '<p>Mo&euml;t &amp; Chandon Ros&eacute; Imp&eacute;rial se caract&eacute;rise par un ar&ocirc;me fruit&eacute; et floral, l&eacute;g&egrave;rement &eacute;pic&eacute; de menthe et de poivre. Il s&#39;accorde bien avec des plats simples aux saveurs intenses. Le format Magnum est une grande bouteille de 1,5 litre, ce qui repr&eacute;sente 2 bouteilles de champagne ou 12 verres.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000213', 0, 0, 1, NULL, NULL, '2023-12-08 10:20:13', '2024-05-17 13:16:08'),
(214, '6572efde11fb3', 'PRO000214', 0, 'Monin Mojito Mint Sirup', '<p>MONIN Mojito Mint is a refreshing mint and lime flavour that can be used beyond the bar in countless non-alcoholic applications. Also suitable as flavouring syrup for SodaStream and other soda makers. Sugar, water, natural mint aroma.</p>\r\n\r\n<p>&nbsp;</p>', 'Mild mint aroma, refreshing and sweet herbal mint flavor with a citrus accent', 25, '', NULL, 47, 14, '', 'Monin Mojito Mint Sirup', 'Arôme de menthe doux, saveur de menthe à base de plantes rafraîchissante et sucrée avec un accent d\'agrumes', '<p>MONIN Mojito Mint est une saveur rafra&icirc;chissante de menthe et de citron vert qui peut &ecirc;tre utilis&eacute;e au-del&agrave; du bar dans d&#39;innombrables applications sans alcool. Convient &eacute;galement comme sirop aromatisant pour SodaStream et autres fabricants de soda. Sucre, eau, ar&ocirc;me naturel de menthe.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000214', 0, 0, 1, NULL, NULL, '2023-12-08 10:28:46', '2024-02-05 07:10:02'),
(215, '6572f07733a2f', 'PRO000215', 0, 'Monin Grenadine Sirup', '<p>Monin Grenadine, 1 Ltr. Grenadine is the most common ingredient used for flavouring purpose in the classic bar mixology. Monin Grenadine comes in a nice red colour. It contains flavour of red berries with a touch of vanilla.</p>', 'his distinctive red syrup is full of red berry notes with a hit of vanilla. Monin Grenadine Syrup is the perfect addition to a multitude of cocktails.', 25, '', NULL, 47, 14, '', 'Monin Grenadine Sirup', 'son sirop rouge distinctif regorge de notes de fruits rouges avec une touche de vanille. Le sirop de grenadine Monin est le', '<p>Monin Grenadine, 1 litre. La grenadine est l&rsquo;ingr&eacute;dient le plus couramment utilis&eacute; &agrave; des fins aromatisantes dans la mixologie classique des barres. Monin Grenadine se pr&eacute;sente dans une jolie couleur rouge. Il contient des ar&ocirc;mes de fruits rouges avec une touche de vanille.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000215', 0, 0, 1, NULL, NULL, '2023-12-08 10:31:19', '2024-05-08 06:33:59'),
(216, '6572f0cad04af', 'PRO000216', 0, 'Monin Lemon Tea Sirup', '<p>Monin Lemon Tea syrup contains a high concentration of crisp, tart lemon and black tea and is pre-sweetened with pure cane sugar. The easiest, most convenient way to create refreshing lemon tea beverages. Comes in a 700ml 100% recyclable glass bottle.</p>', 'Syrup with taste of lemon tea to create authentic, refreshing iced teas', 25, '', NULL, 47, 14, '', 'Monin Lemon Tea Sirup', 'Sirop au goût de thé au citron pour créer des thés glacés authentiques et rafraîchissants', '<p>Le sirop de th&eacute; au citron Monin contient une forte concentration de citron croquant et acidul&eacute; et de th&eacute; noir et est pr&eacute;-sucr&eacute; avec du sucre de canne pur. Le moyen le plus simple et le plus pratique de cr&eacute;er des boissons rafra&icirc;chissantes au th&eacute; au citron. Livr&eacute; dans une bouteille en verre 100% recyclable de 700 ml.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000216', 0, 0, 1, NULL, NULL, '2023-12-08 10:32:42', '2024-02-05 06:59:50'),
(217, '6572f1a380d6d', 'PRO000217', 0, 'Mosketto Delicate Sweet Pink(Rose)', '<p>Mosketto is the essence of the most well known Italian grape varieties. The pleasant bubbles come from a natural carbonation process without any addition of artificial flavors or CO2. Refreshingly sweet with substle flavors of cherry, raspberry, and rose petals.</p>', 'Refreshingly sweet with substle flavors of cherry, raspberry, and rose petals.', 22, '', NULL, 46, 46, '', 'Mosketto Delicate Sweet Pink(Rose)', 'Doux et rafraîchissant avec des saveurs subtiles de cerise, de framboise et de pétales de rose.', '<p>Le Mosketto est l&#39;essence des c&eacute;pages italiens les plus connus. Les bulles agr&eacute;ables sont issues d&#39;un processus de carbonatation naturelle sans aucun ajout d&#39;ar&ocirc;mes artificiels ni de CO2. Doux et rafra&icirc;chissant avec des saveurs subtiles de cerise, de framboise et de p&eacute;tales de rose.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000217', 0, 0, 1, NULL, NULL, '2023-12-08 10:36:19', '2024-02-05 06:59:50'),
(218, '6572f2148da16', 'PRO000218', 0, 'Mosketto Delicate Sweet White', '<p>Mosketto is the essence of the most well known Italian grape varieties. The pleasant bubbles come from a natural carbonation process without any addition of artificial flavors or CO2. Tastes &amp; delights. Refreshingly sweet with a scent of white flowers, peaches and a zesty citrus finish</p>\r\n\r\n<p>&nbsp;</p>', 'Tastes & delights. Refreshingly sweet with a scent of white flowers, peaches and a zesty citrus finish.', 22, '', NULL, 40, 76, '', 'Mosketto Delicate Sweet White', 'Goûts et délices. Doux et rafraîchissant avec un parfum de fleurs blanches, de pêches et une finale piquante d\'agrumes.', '<p>Le Mosketto est l&#39;essence des c&eacute;pages italiens les plus connus. Les bulles agr&eacute;ables sont issues d&#39;un processus de carbonatation naturelle sans aucun ajout d&#39;ar&ocirc;mes artificiels ni de CO2. Go&ucirc;ts et d&eacute;lices. Douce et rafra&icirc;chissante avec un parfum de fleurs blanches, de p&ecirc;ches et une finale piquante d&#39;agrumes</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000218', 0, 0, 1, NULL, NULL, '2023-12-08 10:38:12', '2024-02-05 06:59:50'),
(219, '6572f290b7e9e', 'PRO000219', 0, 'Mosketto Sweet Red Wine', '<p>Mosketto Sweet Red Blend Dessert Wine is refreshingly sweet with an intriguing raspberry and strawberry aromas getting a seductive smooth taste. Mosketto produces this Mosketto Sweet Red Frizzante, a red wine from Piedmont that contains Moscato Bianco grapes.</p>', ', a red wine from Piedmont that contains Moscato Bianco grapes. Mosketto is the essence of the most well known Italian grape varieties.', 22, '', NULL, 33, 76, '', 'Mosketto Sweet Red Wine', ', un vin rouge du Piémont qui contient des raisins Moscato Bianco. Le Mosketto est l\'essence des cépages italiens les plus connus.', '<p>Le vin de dessert Mosketto Sweet Red Blend est d&#39;une douceur rafra&icirc;chissante avec des ar&ocirc;mes intrigants de framboise et de fraise pour un go&ucirc;t doux et s&eacute;duisant. Mosketto nous offre ce Mosketto Sweet Red Frizzante , un vin rouge de l&#39;appellation Pi&eacute;mont &agrave; base de raisins s&eacute;lectionn&eacute;s de Moscato Bianco.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000219', 0, 0, 1, NULL, NULL, '2023-12-08 10:40:16', '2024-02-05 06:59:50'),
(220, '6572f40c99176', 'PRO000220', 0, 'Royal Challenge Finest Premium Whiskey', '<p>This Premium Whisky comes with a Golden yellow colour, Blended with rare Scotch &amp; Matured Indian Malt. It has strong sweet Aroma like Brown Sugar, Molasses, Fig &amp; Bit Malty. Mouth feel is Woody, Oaky character, Milk Chocolate, Vanilla, Caramel, Artificial Sweetener, Bit fruity &amp; a Neutral finish.</p>', 'royal challenge whisky blend of rare scoth & matured indian malts', 15, '', NULL, 48, 77, '', 'Royal Challenge Finest Premium Whiskey', 'Mélange de whisky Royal Challenge de malts écossais rares et indiens mûris', '<p>Ce whisky haut de gamme a une couleur jaune dor&eacute;, m&eacute;lang&eacute; avec du malt indien &eacute;cossais et m&ucirc;ri rare. Il a un fort ar&ocirc;me sucr&eacute; comme la cassonade, la m&eacute;lasse, la figue et le peu de malt&eacute;. La sensation en bouche est bois&eacute;e, caract&egrave;re bois&eacute;, chocolat au lait, vanille, caramel, &eacute;dulcorant artificiel, peu fruit&eacute; et finale neutre.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000220', 0, 0, 1, NULL, NULL, '2023-12-08 10:46:36', '2024-02-12 13:16:24'),
(221, '6572f4f921c04', 'PRO000221', 0, 'Santa Cristina Chianti Superiore', '<p>Chianti Superiore Santa Cristina is ruby red with purplish highlights. On the nose it is rich with fruity notes of morello cherries, aromatic herbs and balsamic sensations. Its palate is soft, mouth filling with velvety tannins and a long savory finish.</p>', 'The wine expresses intense and ample aromas of red fruit along with notes of vanilla, white chocolate, and coffee.', 22, '', NULL, 33, 78, '', 'Santa Cristina Chianti Superiore', 'Le vin exprime des arômes intenses et amples de fruits rouges accompagnés de notes de vanille, de chocolat blanc et de café.', '<p>Le Chianti Superiore Santa Cristina est rouge rubis avec des reflets violac&eacute;s. Au nez, il est riche de notes fruit&eacute;es de griottes, d&#39;herbes aromatiques et de sensations balsamiques. Sa bouche est douce, ample avec des tanins velout&eacute;s et une longue finale savoureuse.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000221', 0, 0, 1, NULL, NULL, '2023-12-08 10:50:33', '2024-02-05 06:59:50'),
(222, '6572f5c930699', 'PRO000222', 0, 'Sky Infusions Citrus Vodka', '<p>Skyy Vodka Infusions Citrus is 100% all-natural infused experience made with Skyy Vodka and succulent real fruit. It is bright and fruity vodka with a fresh beginning and a harmonious blend of lemon and lime at the end.</p>', 'With its bitter and lemony flavor, SKYY INFUSIONS CITRUS has a bold and full taste.', 21, '', NULL, 29, 79, '', 'Sky Infusions Citrus Vodka', 'Avec sa saveur amère et citronnée, SKYY INFUSIONS CITRUS a un goût audacieux et plein.', '<p>Skyy Vodka Infusions Citrus est une exp&eacute;rience infus&eacute;e 100 % naturelle &agrave; base de Skyy Vodka et de vrais fruits succulents. C&#39;est une vodka lumineuse et fruit&eacute;e avec un d&eacute;but frais et un m&eacute;lange harmonieux de citron et de citron vert &agrave; la fin.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000222', 0, 0, 1, NULL, NULL, '2023-12-08 10:54:01', '2024-02-05 06:59:50'),
(223, '6572f63f1d340', 'PRO000223', 0, 'Sky vodka', '<p>It has a decidedly dry, warm and very pleasant taste. Skyy Vodka is the number one premium vodka in the United States and the fifth premium vodka in the world. Through the process of quadruple distillation and triple filtration, it is a Vodka of exceptional quality and softness.</p>', 'San Francisco in every drop, SKYY Vodka is made with water enriched with local Pacific minerals from the San Francisco Bay.', 21, '', NULL, 29, 79, '', 'Sky vodka', 'San Francisco dans chaque goutte, la vodka SKYY est fabriquée avec de l\'eau enrichie en minéraux locaux du Pacifique provenant', '<p>Il a un go&ucirc;t r&eacute;solument sec, chaleureux et tr&egrave;s agr&eacute;able. Skyy Vodka est la vodka premium num&eacute;ro un aux &Eacute;tats-Unis et la cinqui&egrave;me vodka premium au monde. Gr&acirc;ce au processus de quadruple distillation et de triple filtration, c&#39;est une Vodka d&#39;une qualit&eacute; et d&#39;une douceur exceptionnelles.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000223', 0, 0, 1, NULL, NULL, '2023-12-08 10:55:59', '2024-05-08 06:38:07'),
(224, '6572f7105838c', 'PRO000224', 0, 'Veuve Du Vernay Ice', '<p>Veuve du Vernay ICE is a blend specially designed to be served and enjoyed on ice, in a large wine glass. Pale yellow with green tints, it sparkles under generous foam and fine and numerous bubbles. Fruity, floral, fresh notes blend with refreshing citrus fruits scents.</p>', 'Pale yellow with green tints, it sparkles under generous foam and fine and numerous bubbles. Fruity, floral, fresh notes.', 22, '', NULL, 45, 80, '', 'Veuve Du Vernay Ice', 'Jaune pâle aux reflets verts, il pétille sous une mousse généreuse et des bulles fines et nombreuses. Notes fruitées, florales et fraîches.', '<p>Veuve du Vernay ICE est un m&eacute;lange sp&eacute;cialement con&ccedil;u pour &ecirc;tre servi et d&eacute;gust&eacute; sur glace, dans un grand verre &agrave; vin. Jaune p&acirc;le aux reflets verts, il p&eacute;tille sous une mousse g&eacute;n&eacute;reuse et des bulles fines et nombreuses. Des notes fruit&eacute;es, florales et fra&icirc;ches se m&ecirc;lent &agrave; des senteurs d&#39;agrumes rafra&icirc;chissantes.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000224', 0, 0, 1, NULL, NULL, '2023-12-08 10:59:28', '2024-02-05 06:59:50'),
(225, '6572f78834da1', 'PRO000225', 0, 'Veuve Du Vernay Ice Rose', '<p>Veuve du Vernay Ice Rose is the ultimate festive drink! Crafted to be enjoyed over ice, this wine is fresh and delicate on the nose, revealing pronounced fruity scents and raspberry aromas with an enticing Demi-Sec finish. An elegant wine, well-balanced and pleasant, to be enjoyed on every occasion.</p>', 'Ice Rose is well-balanced, full-bodied with good fruit and a fine acidic aftertaste which gives a lovely freshness.', 22, '', NULL, 45, 80, '', 'Veuve Du Vernay Ice Rose', 'Ice Rose est bien équilibrée, corsée avec un bon fruit et un arrière-goût acidulé fin qui donne une belle fraîcheur.', '<p>La Veuve du Vernay Ice Rose est la boisson festive par excellence ! &Eacute;labor&eacute; pour &ecirc;tre d&eacute;gust&eacute; sur glace, ce vin pr&eacute;sente un nez frais et d&eacute;licat, r&eacute;v&eacute;lant des parfums fruit&eacute;s prononc&eacute;s et des ar&ocirc;mes de framboise avec une finale Demi-Sec envo&ucirc;tante. Un vin &eacute;l&eacute;gant, &eacute;quilibr&eacute; et agr&eacute;able, &agrave; d&eacute;guster en toute occasion.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000225', 0, 0, 1, NULL, NULL, '2023-12-08 11:01:28', '2024-02-05 06:59:50'),
(226, '6572f85056131', 'PRO000226', 0, 'Veuve Du Vernay Brut', '<p>Pale straw in color, this easy drinking bubble is fresh, fruity and floral on the nose. The palate shows apple and pear fruit flavours complemented by smooth velvety bubbles. This wine is perfect served as an aperitif or with soft cheeses.</p>', 'Nice pale yellow color in the glass with numerous fine bubbles. Fresh and delicate on the nose, this wine sports nice yellow fruits aromas.', 22, '', NULL, 45, 80, '', 'Veuve Du Vernay Brut', 'Belle robe jaune pâle dans le verre avec de nombreuses bulles fines. Au nez frais et délicat, ce vin arbore de jolis arômes de fruits jaunes.', '<p>De couleur paille p&acirc;le, cette bulle facile &agrave; boire est fra&icirc;che, fruit&eacute;e et florale au nez. La bouche pr&eacute;sente des saveurs de pomme et de poire compl&eacute;t&eacute;es par des bulles douces et velout&eacute;es. Ce vin est parfait servi &agrave; l&#39;ap&eacute;ritif ou avec des fromages &agrave; p&acirc;te molle.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000226', 0, 0, 1, NULL, NULL, '2023-12-08 11:04:48', '2024-02-05 06:59:50'),
(227, '6572f8c3597a0', 'PRO000227', 0, 'Veuve Du Vernay Brut Rose', '<p>Veuve du Vernay Brut Rose a sparkling wine with aromas of berries, subtle and delicate, it brings festivity and glamour to you table with its nice pink color. Fresh and fruity to the nose complemented by smooth, velvety bubbles and raspberry and red fruit flavours on the palate.</p>', 'Intensely aromatic on the nose with hints of strawberry, cranberry and lemony citrus hints and as a refreshing and clean palate.', 22, '', NULL, 45, 80, '', 'Veuve Du Vernay Brut Rose', 'Intensément aromatique au nez avec des notes de fraise, de canneberge et d\'agrumes citronnés et en bouche rafraîchissante et nette.', '<p>Veuve du Vernay Brut Rose un vin effervescent aux ar&ocirc;mes de petits fruits, subtil et d&eacute;licat, il apporte de la f&ecirc;te et du glamour &agrave; votre table avec sa jolie couleur rose. Le nez frais et fruit&eacute; est compl&eacute;t&eacute; par des bulles douces et velout&eacute;es et des saveurs de framboise et de fruits rouges en bouche.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000227', 0, 0, 1, NULL, NULL, '2023-12-08 11:06:43', '2024-02-05 06:59:50'),
(228, '6572f90ac954f', 'PRO000228', 0, 'Veuve Du Vernay Brut Limited Edition', '<p>Tres French and lively on the nose, Veuve du Vernay Brut Limited Edition it is a unique blend of chardonnay, colombard, and ugni blanc, light and just off-dry. Tastring notes Classic and refined, it exhibits a light yellow hue and gives off aromas of yellow fruits and sweet floral notes.</p>', 'Veuve du Vernay Brut Limited Edition it is a unique blend of chardonnay, colombard, and ugni blanc, light and just off-dry', 22, '', NULL, 45, 80, '', 'Veuve Du Vernay Brut Limited Edition', 'Veuve du Vernay Brut Edition Limitée c\'est un assemblage unique de chardonnay, colombard et ugni blanc, léger et juste demi-sec', '<p>Tr&egrave;s fran&ccedil;ais et vif au nez, la Veuve du Vernay Brut Edition Limit&eacute;e c&#39;est un assemblage unique de chardonnay, colombard et ugni blanc, l&eacute;ger et juste demi-sec. Notes de d&eacute;gustation Classique et raffin&eacute;, il pr&eacute;sente une teinte jaune clair et d&eacute;gage des ar&ocirc;mes de fruits jaunes et de douces notes florales.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000228', 0, 0, 1, NULL, NULL, '2023-12-08 11:07:54', '2024-02-05 06:59:50'),
(229, '657300f7ec572', 'PRO000229', 0, 'Vina Maipo Cabernet Sauvignon 2019', '<p>Thick skins lead to classicly high tannins, and strong red and black fruit-forward characteristics on both the nose and palate.</p>', 'vina maipo,red dry wine,made of cabernet sauvignon grape &', 22, '', NULL, 33, 15, '', 'Vina Maipo Cabernet Sauvignon 2019', 'Vina Maipo, vin rouge sec, à base de raisin cabernet sauvignon et', '<p>Les peaux &eacute;paisses conduisent &agrave; des tanins classiquement &eacute;lev&eacute;s et &agrave; de fortes caract&eacute;ristiques de fruits rouges et noirs au nez et en bouche.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000229', 0, 0, 1, NULL, NULL, '2023-12-08 11:41:43', '2024-02-05 06:59:50'),
(230, '657301d9387e2', 'PRO000230', 0, 'Maipo Cabernet Sauvignon Merlot 2018', '<p>It is a deep ruby red wine with cherry and pepper aromas that delivers a soft finish. Palate: It has notes of dark chocolate, cherry, and black currant on the palate and is full-bodied and rich. Firm tannins and excellent acidity give it a lengthy finish.</p>', 'vina maipo,a wine from chile,dry red wine,blend of 2 different grapes cabernet sauvignon and merlot', 22, '', NULL, 33, 15, '', 'Maipo Cabernet Sauvignon Merlot 2018', 'Vina Maipo,un vin du Chili,vin rouge sec,mélange de 2 raisins différents cabernet sauvignon et merlot', '<p>C&#39;est un vin rouge rubis profond aux ar&ocirc;mes de cerise et de poivre qui offre une finale douce. Bouche : Il a des notes de chocolat noir, de cerise et de cassis en bouche et est cors&eacute; et riche. Des tanins fermes et une excellente acidit&eacute; lui conf&egrave;rent une longue finale.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000230', 0, 0, 1, NULL, NULL, '2023-12-08 11:45:29', '2024-02-05 06:59:50'),
(231, '657302b9ef39b', 'PRO000231', 0, 'Maipo Carmenere Cabernet Sauvignon 2018', '<p>The Carmenere/Cabernet Sauvignon was produced in the Valle Central of Chile, where exceptional soil and climate conditions have created a bright ruby red wine with red fruit aromas and delicate spicy notes. Soft, elegant and well-structured.</p>', 'vina maipo,a wine from chile,dry red wine,blend of carmener and cabernet sauvignon', 22, '', NULL, 33, 15, '', 'Maipo Carmenere Cabernet Sauvignon 2018', 'Vina Maipo,un vin du Chili,vin rouge sec,mélange de Carmener et de Cabernet Sauvignon', '<p>Le Carmen&egrave;re/Cabernet Sauvignon a &eacute;t&eacute; produit dans la Valle Central au Chili, o&ugrave; des conditions p&eacute;dologiques et climatiques exceptionnelles ont cr&eacute;&eacute; un vin rouge rubis vif avec des ar&ocirc;mes de fruits rouges et de d&eacute;licates notes &eacute;pic&eacute;es. Doux, &eacute;l&eacute;gant et bien structur&eacute;.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000231', 0, 0, 1, NULL, NULL, '2023-12-08 11:49:13', '2024-02-12 10:07:20'),
(232, '6573031607a48', 'PRO000232', 0, 'Vina Maipo Classic Series Sweet Red 2018', '<p>A young, bright and attractive wine that is fresh, sweet and persistent on the palate. Best served: 10-12&deg;C, even with ice. It is an ideal wine to accompany desserts and cakes.</p>\r\n\r\n<p>&nbsp;</p>', 'vina maipo with the classic series a sweet red wine', 22, '', NULL, 33, 15, '', 'Vina Maipo Classic Series Sweet Red 2018', 'vina maipo avec la série classique un vin rouge doux', '<p>Un vin jeune, lumineux et s&eacute;duisant, frais, doux et persistant en bouche. Meilleur servi : 10-12&deg;C, m&ecirc;me avec de la glace. C&#39;est un vin id&eacute;al pour accompagner les desserts et les g&acirc;teaux.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000232', 0, 0, 1, NULL, NULL, '2023-12-08 11:50:46', '2024-02-05 06:59:50'),
(233, '657303c95c024', 'PRO000233', 0, 'Wild Turkey 81', '<p>Wild Turkey 81 is a masterful blend composed primarily of five to eight year old whiskies, making it the longest-aged bourbon or Tennessee whiskey in its class. The result is a whiskey with a deep, rich amber colour, and a nose full of fruit, butterscotch, toffee and toasted oak.</p>', 'Wild Turkey 81 is a masterful blend composed primarily of five to eight year old whiskies', 37, '', NULL, 49, 81, '', 'Wild Turkey 81', 'Wild Turkey 81 est un assemblage magistral composé principalement de whiskies âgés de cinq à huit ans.', '<p>Wild Turkey 81 est un assemblage magistral compos&eacute; principalement de whiskies &acirc;g&eacute;s de cinq &agrave; huit ans, ce qui en fait le bourbon ou le whisky Tennessee le plus vieilli de sa cat&eacute;gorie. Le r&eacute;sultat est un whisky &agrave; la couleur ambr&eacute;e profonde et riche, et au nez plein de fruits, de caramel &eacute;cossais, de caramel anglais et de ch&ecirc;ne grill&eacute;.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000233', 0, 0, 1, NULL, NULL, '2023-12-08 11:53:45', '2024-05-08 09:48:54'),
(234, '65730427c59ee', 'PRO000234', 0, 'Wild Turkey 101', '<p>Wild Turkey Straight Kentucky 101 Bourbon Whiskey is a genuine super-premium bourbon carefully crafted in the heart of Kentucky. Classic caramel and vanilla, with notes of honey and oranges. The finish is very long, rich and full-bodied, powerful, yet soothing. A great full-flavoured bourbon whiskey.</p>', 'Wild Turkey 101 is the benchmark in bourbon, best enjoyed neat or on the rocks.', 37, '', NULL, 49, 81, '', 'Wild Turkey 101', 'Wild Turkey 101 est la référence en matière de bourbon, à déguster pur ou sur glace.', '<p>Le whisky Wild Turkey Straight Kentucky 101 Bourbon est un v&eacute;ritable bourbon de qualit&eacute; sup&eacute;rieure soigneusement &eacute;labor&eacute; au c&oelig;ur du Kentucky. Caramel classique et vanille, avec des notes de miel et d&#39;oranges. La finale est tr&egrave;s longue, riche et cors&eacute;e, puissante mais apaisante. Un excellent whisky bourbon plein de saveurs.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000234', 0, 0, 1, NULL, NULL, '2023-12-08 11:55:19', '2024-05-08 09:48:35'),
(235, '6573046d1508f', 'PRO000235', 0, 'Wild Turkey American Honey', '<p>Wild Turkey American Honey is an exceptionally smooth 71 proof (35.5% alcohol) liqueur blended with pure honey and real Wild Turkey Bourbon Whiskey. It&#39;s perfect straight out of the bottle, chilled in the freezer, or on the rocks.</p>', 'wild turkey from america, liqueur blended with pure honey and real Wild Turkey Bourbon Whiskey.', 37, '', NULL, 61, 81, '', 'Wild Turkey American Honey', 'dinde sauvage d\'Amérique, liqueur mélangée avec du miel pur et du vrai whisky Wild Turkey Bourbon.', '<p>Wild Turkey American Honey est une liqueur exceptionnellement douce &agrave; 71 degr&eacute;s (35,5 % d&#39;alcool) m&eacute;lang&eacute;e &agrave; du miel pur et du vrai whisky Wild Turkey Bourbon. Il est parfait directement sorti de la bouteille, r&eacute;frig&eacute;r&eacute; au cong&eacute;lateur ou sur glace.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000235', 0, 0, 1, NULL, NULL, '2023-12-08 11:56:29', '2024-06-05 14:07:54'),
(236, '6576aa596e5d2', 'PRO000236', 0, '7 Hills Natural Sweet Red 8%', '<p>A fragrant, ruby-red wine with soft rose petal perfume. Flavours of ripe plums, strawberries, and exotic spices are followed by a soft, lingering finish. Pairs well with light red meats and pasta or perfect with any dish, every day!</p>', 'A sweet red wine, blended from dry red wine and grape juice,A fragrant, ruby-red wine with soft rose petal perfume.', 22, '', NULL, 33, 82, '', '7 Hills Natural Sweet Red 8%', 'Un vin rouge doux, assemblage de vin rouge sec et de jus de raisin,Un vin rouge rubis parfumé au doux parfum de pétale de rose.', '<p>Un vin rouge rubis parfum&eacute; au doux parfum de p&eacute;tale de rose. Les saveurs de prunes m&ucirc;res, de fraises et d&#39;&eacute;pices exotiques sont suivies d&#39;une finale douce et persistante. Se marie bien avec les viandes rouges l&eacute;g&egrave;res et les p&acirc;tes ou parfait avec n&#39;importe quel plat, tous les jours !</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000236', 0, 0, 1, NULL, NULL, '2023-12-11 06:21:13', '2024-02-05 06:59:50'),
(237, '6576aaaeaea7c', 'PRO000237', 0, '7 Hills Natural Sweet White 8.5%', '<p>Youthful, fragrantly refreshing sweet wine with tropical fruit salad flavours. A fragrant, sunshine coloured wine with gentle honeysuckle perfume. Flavours of luscious apricots, nougat and rich tropical fruit salad is followed by a soft, lingering finish.</p>', 'Flavours of luscious apricots, nougat and rich tropical fruit salad is followed by a soft, lingering finish.', 22, '', NULL, 40, 82, '', '7 Hills Natural Sweet White 8.5%', 'Les saveurs d\'abricots succulents, de nougat et de riche salade de fruits tropicaux sont suivies d\'une finale douce et persistante.', '<p>Vin doux jeune et parfum&eacute; rafra&icirc;chissant aux ar&ocirc;mes de salade de fruits tropicaux. Un vin parfum&eacute; &agrave; la robe ensoleill&eacute;e, au doux parfum de ch&egrave;vrefeuille. Les saveurs d&#39;abricots succulents, de nougat et de riche salade de fruits tropicaux sont suivies d&#39;une finale douce et persistante.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000237', 0, 0, 1, NULL, NULL, '2023-12-11 06:22:38', '2024-02-05 06:59:50'),
(238, '6576ab1b03f5a', 'PRO000238', 0, '19 Crimes Cabernet Sauvignon 2020', '<p>A rich bright red to crimson color, this wine has an intense nose with lifted vanilla aromatics balanced with red currants, violets, and mulberry fruits. It is a wine that is firm and full on the palate with a subtle sweetness giving a rich mouth feel.</p>', 'It is a wine that is firm and full on the palate with a subtle sweetness giving a rich mouth feel.', 22, '', NULL, 33, 63, '', '19 Crimes Cabernet Sauvignon 2020', 'C\'est un vin ferme et ample en bouche avec une douceur subtile donnant une bouche riche.', '<p>D&#39;une riche couleur rouge vif &agrave; pourpre, ce vin a un nez intense avec des ar&ocirc;mes de vanille relev&eacute;s &eacute;quilibr&eacute;s par des groseilles rouges, des violettes et des fruits de m&ucirc;re. C&#39;est un vin ferme et ample en bouche avec une douceur subtile donnant une bouche riche.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000238', 0, 0, 1, NULL, NULL, '2023-12-11 06:24:27', '2024-02-05 06:59:50'),
(239, '6576ab798e84e', 'PRO000239', 0, '19 Crimes 2019 Red Wine', '<p>FLAVOUR, full and roundon the palate with a distinct sweetness giving a rich andround mouth feel. PAIRING, BBQ meats, pizza and pasta. CHEERS TO THE INFAMOUS, 19 Crimes wines are not just about the land in which the grapes are grown, it&#39;s about the history of the infamous people who founded the land.</p>', '19 Crimes, Red Wine is a full bodied blend with flavours of red currants, dark cherries and chocolate, finished nicely with a hint of vanilla.', 22, '', NULL, 33, 63, '', '19 Crimes 2019 Red Wine', '19 Crimes, Red Wine est un mélange corsé aux saveurs de groseille, de cerise noire et de chocolat, joliment terminé par une pointe de vanille.', '<p>SAVEUR, ample et ronde en bouche avec une douceur distincte donnant une bouche riche et ronde. ACCOMPAGNEMENT, viandes BBQ, pizza et p&acirc;tes. Bravo aux inf&acirc;mes, les vins 19 Crimes ne parlent pas seulement de la terre dans laquelle les raisins sont cultiv&eacute;s, mais aussi de l&#39;histoire des personnes inf&acirc;mes qui ont fond&eacute; la terre.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000239', 0, 0, 1, NULL, NULL, '2023-12-11 06:26:01', '2024-02-05 06:59:50'),
(240, '6576ac4f2af01', 'PRO000240', 0, '1949 Roodeberg Vintage 2017', '<p>KWV 1949 Roodeberg Red Blend 2017, WO Stellenbosch, 14.5% Abv. This wine shows a very attractive aromatic profile of ripe red and black berries, caramelised notes of pecan pie, black liquorice, kirsch liquor and br&ucirc;l&eacute;ed coffee beans. It&#39;s certainly very inviting and seductive and doesn&#39;t disappoint on the palate.</p>', 'This deep, ruby coloured, concentrated red blend shows prominent aromas of dark cherry, blackcurrant and vanilla.', 22, '', NULL, 33, 83, '', '1949 Roodeberg Vintage 2017', 'Cet assemblage rouge concentré, de couleur rubis profond, révèle des arômes dominants de cerise noire, de cassis et de vanille.', '<p>KWV 1949 Roodeberg Red Blend 2017, WO Stellenbosch, 14,5 % Abv. Ce vin pr&eacute;sente un profil aromatique tr&egrave;s attractif de petits fruits rouges et noirs m&ucirc;rs, des notes caram&eacute;lis&eacute;es de tarte aux noix de p&eacute;can, de r&eacute;glisse noire, de liqueur de kirsch et de grains de caf&eacute; br&ucirc;l&eacute;s. C&#39;est certainement tr&egrave;s invitant et s&eacute;duisant et ne d&eacute;&ccedil;oit pas en bouche.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000240', 0, 0, 1, NULL, NULL, '2023-12-11 06:29:35', '2024-02-05 06:59:50'),
(241, '6576ad0e164e4', 'PRO000241', 0, 'Allure Cabernet Sauvignon', '<p>Translucent red, unripe cherry and currant leaves on the nose. On the palate with fresh acidity, little fruit, rather hard on the finish, emphasized by unripe tannins.</p>', 'Instant pop of dense berry then cigar box like notes kick in. Cassis in spades and not bowled over with excessive tannins.', 22, '', NULL, 33, 84, '', 'Allure Cabernet Sauvignon', 'Des notes instantanées de baies denses, puis des notes de boîte à cigares entrent en jeu. Du cassis à la pelle et', '<p>Nez rouge translucide, feuilles de cerise non m&ucirc;res et de cassis. Bouche &agrave; l&#39;acidit&eacute; fra&icirc;che, peu de fruit, finale assez dure, soulign&eacute;e par des tanins pas m&ucirc;rs.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000241', 0, 0, 1, NULL, NULL, '2023-12-11 06:32:46', '2024-02-05 06:59:50');
INSERT INTO `product` (`id`, `uniqid`, `product_item_id`, `supplier_id`, `product_name`, `description`, `short_description`, `category_id`, `product_image`, `images`, `subcategory_id`, `brand_id`, `video`, `product_name_fr`, `short_description_fr`, `page_content_fr`, `product_qty`, `tech_data_sheet`, `retail_price`, `discount_price`, `is_admin_approve`, `most_view`, `is_product_bestseller`, `sku`, `average_rating`, `offer`, `status`, `in_store`, `in_online`, `created_at`, `updated_at`) VALUES
(242, '6576ad7925f06', 'PRO000242', 0, 'Allure Merlot Rose', '<p>Allure Merlot Ros&eacute; is a charming ros&eacute; wine from Italy, made from Merlot grapes. The fine pink color reflects the delicate taste of red berries with distinct shades of raspberry. An elegant and fruity wine that goes well with spicy dishes.</p>', 'Translucent red, unripe cherry and currant leaves on the nose. On the palate with fresh acidity, little fruit, rather hard on the finish.', 22, '', NULL, 46, 84, '', 'Allure Merlot Rose', 'Nez rouge translucide, feuilles de cerise non mûres et de cassis. En bouche avec une acidité fraîche, peu de fruit, finale assez dure.', '<p>Allure Merlot Ros&eacute; est un charmant vin ros&eacute; d&#39;Italie, &eacute;labor&eacute; &agrave; partir de raisins Merlot. La fine robe rose refl&egrave;te le go&ucirc;t d&eacute;licat des fruits rouges avec des nuances distinctes de framboise. Un vin &eacute;l&eacute;gant et fruit&eacute; qui s&#39;accorde bien avec les plats &eacute;pic&eacute;s.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000242', 0, 0, 1, NULL, NULL, '2023-12-11 06:34:33', '2024-02-05 06:59:50'),
(243, '6576ae9c87af7', 'PRO000243', 0, 'Avion Reposado', '<p>Avi&oacute;n Reposado is the result 100% blue weber agave hand-selected and hand-harvested after maturing for at least 5 years. It is then slow roasted for two days in brick ovens to perfect the caramelization and to bring out richer agave flavors.</p>', 'aged for six months in oak barrels, it has a roasted agave presence, notes of cherry, pear, and peach, flower hues of rose petals and tinges of herbs.', 21, '', NULL, 38, 85, '', 'Avion Reposado', 'vieilli pendant six mois en fûts de chêne, il présente une présence d\'agave grillée, des notes de cerise, de poire et de pêche, des teintes', '<p>Avi&oacute;n Reposado est le r&eacute;sultat 100 % d&#39;agave bleu weber s&eacute;lectionn&eacute; et r&eacute;colt&eacute; &agrave; la main apr&egrave;s une maturation d&#39;au moins 5 ans. Il est ensuite torr&eacute;fi&eacute; lentement pendant deux jours dans des fours en brique pour parfaire la caram&eacute;lisation et faire ressortir des saveurs d&#39;agave plus riches.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000243', 0, 0, 1, NULL, NULL, '2023-12-11 06:39:24', '2024-02-05 06:59:50'),
(244, '6576af4053d1e', 'PRO000244', 0, 'Ballantine\'s Finest', '<p>This blended scotch whisky is made from more than 50 single malts, particularly single malts from Miltonduff and Glenburgie as well as four single grain whiskies. In 1827, George Ballantine, a Scottish entrepreneur created Europe&#39;s best scotch whisky.</p>', 'Ballantine\'s Scotch Whisky has a soft and elegant nose of heather, honey and spice notes develop into balanced, subtle flavours.', 15, '', NULL, 48, 16, '', 'Ballantine\'s Finest', 'Le Scotch Whisky Ballantine\'s présente un nez doux et élégant de notes de bruyère, de miel et d\'épices se dévelo', '<p>Ce whisky &eacute;cossais m&eacute;lang&eacute; est compos&eacute; de plus de 50 single malts, notamment des single malts de Miltonduff et Glenburgie ainsi que de quatre whiskies single grain. En 1827, George Ballantine, un entrepreneur &eacute;cossais cr&eacute;a le meilleur scotch whisky d&#39;Europe.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000244', 0, 0, 1, NULL, NULL, '2023-12-11 06:42:08', '2024-05-30 11:53:20'),
(245, '6576b052edd6a', 'PRO000245', 0, 'Ballantine\'s Finest Blended Scotch', '<p>This blended scotch whisky is made from more than 50 single malts, particularly single malts from Miltonduff and Glenburgie as well as four single grain whiskies. In 1827, George Ballantine, a Scottish entrepreneur created Europe&#39;s best scotch whisky.</p>', 'Light gold. Nose: Soft, elegant, heather honey aromas with a hint of spice. Palate: A balance of subtle, sweet flavors like milk chocolate.', 15, '', NULL, 48, 16, '', 'Ballantine\'s Finest Blended Scotch', 'Or clair. Nez : Doux, élégant, des arômes de miel de bruyère avec une pointe d\'épices. Bouche : Un équilibre de saveurs', '<p>Ce whisky &eacute;cossais m&eacute;lang&eacute; est compos&eacute; de plus de 50 single malts, notamment des single malts de Miltonduff et Glenburgie ainsi que de quatre whiskies single grain. En 1827, George Ballantine, un entrepreneur &eacute;cossais cr&eacute;a le meilleur scotch whisky d&#39;Europe.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000245', 0, 0, 1, NULL, NULL, '2023-12-11 06:46:42', '2024-05-30 11:51:40'),
(246, '6576b10da9b5a', 'PRO000246', 0, 'Bombay Sapphire Gin 47%', '<p>Bombay Sapphire is a world famous gin known for its distinctive blue bottle. Every drop contains 10 hand-selected botanicals from exotic locations around the world. The most versatile gin for cocktail creativity. Perfectly balanced, bright and fresh.</p>', 'Ten all-natural, sustainably sourced exotic botanicals from the Cubeb Berries from Java to the spice of West African Grains of Paradise.', 21, '', NULL, 31, 86, '', 'Bombay Sapphire Gin 47%', 'Dix plantes exotiques entièrement naturelles et provenant de sources durables, des baies de cubèbe de Java', '<p>Bombay Sapphire est un gin de renomm&eacute;e mondiale connu pour sa bouteille bleue distinctive. Chaque goutte contient 10 plantes s&eacute;lectionn&eacute;es &agrave; la main provenant de lieux exotiques du monde entier. Le gin le plus polyvalent pour la cr&eacute;ativit&eacute; des cocktails. Parfaitement &eacute;quilibr&eacute;, lumineux et frais.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000246', 0, 0, 1, NULL, NULL, '2023-12-11 06:49:49', '2024-02-05 06:59:50'),
(247, '6576b18f97d14', 'PRO000247', 0, 'Bullet Vodka Mixed Drink', '<p>Bullet Vodka Mixed Drink 250ml; The Bullet Energy Drink with Vodka black 250ml. A Caffeine free energy drink that tastes exactly like Red Bull, but comes at a shade higher than half the price. Bullet Energy Drink gives you the burst of energy you need to kick-start your day.</p>', 'A Caffeine free energy drink that tastes exactly like Red Bull, but comes at a shade higher than half the price.', 21, '', NULL, 29, 87, '', 'Bullet Vodka Mixed Drink', 'Une boisson énergisante sans caféine qui a exactement le même goût que Red Bull, mais dont le prix est supérieur à la moitié du prix.', '<p>Boisson mixte Bullet Vodka 250 ml ; La boisson &eacute;nergisante Bullet avec Vodka noire 250ml. Une boisson &eacute;nergisante sans caf&eacute;ine qui a exactement le m&ecirc;me go&ucirc;t que Red Bull, mais dont le prix est sup&eacute;rieur &agrave; la moiti&eacute; du prix. Bullet Energy Drink vous donne l&#39;&eacute;nergie dont vous avez besoin pour bien d&eacute;marrer votre journ&eacute;e.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000247', 0, 0, 1, NULL, NULL, '2023-12-11 06:51:59', '2024-02-05 06:59:50'),
(248, '6576b2a68b75a', 'PRO000248', 0, 'Café De Paris Mango', '<p>Colour:delicate pale yellow Nose:very lively with fruit aromas Palate:nice freshness with mango notes. Food pairing: as an aperitif and with desserts.</p>', 'delicate pale yellow Nose:very lively with fruit aromas Palate:nice freshness with mango notes. Food pairing: as an aperitif and with desserts.', 22, '', NULL, 45, 88, '', 'Café De Paris Mango', 'délicat jaune pâle Nez : très vif avec des arômes de fruits Bouche : belle fraîcheur avec des notes de mangue. Accords culinaires', '<p>Couleur : jaune p&acirc;le d&eacute;licat Nez : tr&egrave;s vif avec des ar&ocirc;mes de fruits Bouche : belle fra&icirc;cheur avec des notes de mangue. Accords culinaires : &agrave; l&#39;ap&eacute;ritif et avec les desserts.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000248', 0, 0, 1, NULL, NULL, '2023-12-11 06:56:38', '2024-02-05 06:59:50'),
(249, '6576b3491a14f', 'PRO000249', 0, 'Campo Viejo Tempranillo', '<p>Nose is rich in aromas and pronounced in intensity. We are struck by the ripe red fruit, later we get the wood nuances with gently sweet notes of vanilla to finish with other sweet spices. On the palate it is perfumed, soft and fresh with a long finish that leaves memories of red fruit, vanilla and cocoa.</p>', 'ripe red fruit, later we get the wood nuances with gently sweet notes of vanilla to finish with other sweet spices.', 22, '', NULL, 33, 24, '', 'Campo Viejo Tempranillo', 'fruits rouges mûrs, on retrouve plus tard les nuances boisées avec des notes doucement sucrées de vanille pour finir avec d\'autres épices douces.', '<p>Le nez est riche en ar&ocirc;mes et prononc&eacute; en intensit&eacute;. On est frapp&eacute; par le fruit rouge m&ucirc;r, on retrouve plus tard les nuances bois&eacute;es avec des notes doucement sucr&eacute;es de vanille pour finir avec d&#39;autres &eacute;pices douces. En bouche, il est parfum&eacute;, doux et frais avec une longue finale qui laisse des souvenirs de fruits rouges, de vanille et de cacao.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000249', 0, 0, 1, NULL, NULL, '2023-12-11 06:59:21', '2024-02-05 06:59:50'),
(250, '6576b3d962cc4', 'PRO000250', 0, 'Chardolini Sparkling Perry', '<p>Chardolini is our premier Perry brand, available in both still and slightly sparkling formats. Made using the finest blend of pears to deliver a light, refreshingly fruity taste, guaranteed to add a touch of sparkle to any occasion.</p>', 'Made using the finest blend of pears to deliver a light, refreshingly fruity taste, guaranteed to add a touch of sparkle to any occasion.', 22, '', NULL, 40, 89, '', 'Chardolini Sparkling Perry', 'Fabriqué à partir du meilleur mélange de poires pour offrir un goût fruité léger et rafraîchissant, garanti pour ajouter une', '<p>Chardolini est notre premi&egrave;re marque Perry, disponible en format plat et l&eacute;g&egrave;rement p&eacute;tillant. Fabriqu&eacute; &agrave; partir du meilleur m&eacute;lange de poires pour offrir un go&ucirc;t l&eacute;ger et fruit&eacute; rafra&icirc;chissant, garanti pour ajouter une touche d&#39;&eacute;clat &agrave; toute occasion.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000250', 0, 0, 1, NULL, NULL, '2023-12-11 07:01:45', '2024-02-05 06:59:50'),
(251, '6576b47f09461', 'PRO000251', 0, 'Chivas Regal 12yr', '<p>A blend of the finest malt and grain whiskies, including Strathisla single malt and Strathclyde single grain are combined. Being matured for at least 12 years, this luxurious Speyside whisky delivers luxurious honey, vanilla and ripe apple notes. Over the years the classic taste has been maintained.</p>', 'Chivas Regal 12 Year Old Scotch Whisky is smooth, rich and generous. It\'s a blend of the finest malt and grain whiskies.', 15, '', NULL, 48, 27, '', 'Chivas Regal 12yr', 'Le whisky écossais Chivas Regal 12 ans d\'âge est doux, riche et généreux. C\'est un mélange des meilleurs whiskies de malt et de grain.', '<p>Un m&eacute;lange des meilleurs whiskies de malt et de grain, dont le single malt Strathisla et le single grain Strathclyde sont combin&eacute;s. Affin&eacute; pendant au moins 12 ans, ce luxueux whisky du Speyside offre de luxueuses notes de miel, de vanille et de pomme m&ucirc;re. Au fil des ann&eacute;es, le go&ucirc;t classique a &eacute;t&eacute; conserv&eacute;.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000251', 0, 0, 1, NULL, NULL, '2023-12-11 07:04:31', '2024-05-30 11:52:50'),
(252, '6576b8aaa5ff0', 'PRO000252', 0, 'Fantinel Prosecco Extra Dry', '<p>Fantinel Prosecco Extra Dry is an inviting wine, made from Glera grapes. This wine has a cork closure and is made with added suplhites but is suitable for vegetarian drinkers. Whilst famed as an ap&eacute;ritif, the soft fizz of Prosecco also partners light chicken dishes, delicate seafood and salads well.</p>', 'Attractive straw-yellow appearance with a fine, persistent bead. Delicate floral tones on the nose and a pleasurably soft, velvety mouthfeel.', 22, '', NULL, 36, 69, '', 'Fantinel Prosecco Extra Dry', 'Joli aspect jaune paille avec un cordon fin et persistant. Des tonalités florales délicates au nez et une bouche agréablement douce et veloutée.', '<p>Fantinel Prosecco Extra Dry est un vin invitant, issu de raisins Glera. Ce vin a un bouchon en li&egrave;ge et est &eacute;labor&eacute; avec des suplhites ajout&eacute;s mais convient aux buveurs v&eacute;g&eacute;tariens. Bien que c&eacute;l&egrave;bre &agrave; l&#39;ap&eacute;ritif, le doux p&eacute;tillant du Prosecco s&#39;associe &eacute;galement bien aux plats de poulet l&eacute;gers, aux fruits de mer d&eacute;licats et aux salades.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000252', 0, 0, 1, NULL, NULL, '2023-12-11 07:22:18', '2024-02-05 06:59:50'),
(253, '6576b93534c5b', 'PRO000253', 0, 'G.H.Mumm Cordon Rouge', '<p>ordon Rouge Brut is typically composed of 45% Pinot Noir, 30% Chardonnay and 25% Pinot Meunier. The dosage is 8 grams per liter and is typically aged 2 1/2 years or more on the lees. Mumm has begun using DIAM cork for half bottles of their Cordon Rouge.</p>', 'Blended from a minimum of 100 crus, Mumm Cordon Rouge expresses the rich diversity of Champagne’s terroirs, always in the fresh, vibrant style.', 23, '', NULL, 37, 33, '', 'G.H.Mumm Cordon Rouge', 'Assemblé à partir d\'un minimum de 100 crus, Mumm Cordon Rouge exprime la riche diversité des terroirs champenois,', '<p>ordon Rouge Brut est g&eacute;n&eacute;ralement compos&eacute; de 45 % de Pinot Noir, 30 % de Chardonnay et 25 % de Pinot Meunier. Le dosage est de 8 grammes par litre et est g&eacute;n&eacute;ralement vieilli 2 ans et demi ou plus sur lies. Mumm a commenc&eacute; &agrave; utiliser le li&egrave;ge DIAM pour les demi-bouteilles de son Cordon Rouge.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000253', 0, 0, 1, NULL, NULL, '2023-12-11 07:24:37', '2024-02-05 06:59:50'),
(254, '6576b9a7b364e', 'PRO000254', 0, 'Gato Negro Cabernet Sauvignon', '<p>Gato Negro Cabernet Sauvignon is a red wine, dark ruby-red color. Fresh and intense flavors and aromas with notes of strawberries and chocolate, and a hint of vanilla. Delicious mouthfeel, this medium-bodied wine is notable for its freshness and long-soft finish.</p>', 'Dark ruby in colour. The Gato Negro Cabernet Sauvignon 750ml is a full-bodied wine with aromas of red fruit, namely chassis, and cherries.', 22, '', NULL, 33, 90, '', 'Gato Negro Cabernet Sauvignon', 'Robe rubis foncé. Le Gato Negro Cabernet Sauvignon 750ml est un vin corsé aux arômes de fruits rouges, notamment de châssis, et de cerises.', '<p>Gato Negro Cabernet Sauvignon est un vin rouge de couleur rouge rubis fonc&eacute;. Saveurs et ar&ocirc;mes frais et intenses avec des notes de fraises et de chocolat, et une pointe de vanille. D&eacute;licieuse en bouche, ce vin moyennement cors&eacute; se distingue par sa fra&icirc;cheur et sa finale longue et douce.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000254', 0, 0, 1, NULL, NULL, '2023-12-11 07:26:31', '2024-02-05 06:59:50'),
(255, '6576ba0c64d44', 'PRO000255', 0, 'Giacondi Merlot Vino D\'Italia', '<p>This wine is vibrant ruby red in colour. We find aromas of black cherry and blackcurrant with savory oak complexity. On the palate it gives notes of ripe plum and cherry flavors are complimented by soft subtle tannins with sweet smokey oak notes.</p>', 'Italy is a big producer of merlot and this wine originates in the North East. It has soft cherry flavours accentuated by herbal notes.', 22, '', NULL, 33, 71, '', 'Giacondi Merlot Vino D\'Italia', 'L\'Italie est un grand producteur de merlot et ce vin est originaire du Nord-Est. Il présente des saveurs douces de', '<p>Ce vin pr&eacute;sente une robe rouge rubis vibrante. On retrouve des ar&ocirc;mes de cerise noire et de cassis avec une complexit&eacute; bois&eacute;e savoureuse. En bouche, il donne des notes de prune m&ucirc;re et de cerise, compl&eacute;t&eacute;es par des tanins doux et subtils avec de douces notes de ch&ecirc;ne fum&eacute;.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000255', 0, 0, 1, NULL, NULL, '2023-12-11 07:28:12', '2024-02-05 06:59:50'),
(256, '6576ba8745bdc', 'PRO000256', 0, 'Glenfiddich 12yrs', '<p>Glenfiddich 12 is part of the distillery&#39;s flagship collection, a great choice for seasoned sippers or those who are new to whisky, with lots of light and fruity flavours thanks to a high cut point. Aged for 12 years in American and European oak casks, it&#39;s also the world&#39;s most awarded single malt!</p>\r\n\r\n<p>&nbsp;</p>', 'Single malt Scotch Whisky with distinctive flavors of fresh, creamy pear and toasty oak flavors with a long, smooth, ripe finish.', 15, '', NULL, 35, 34, '', 'Glenfiddich 12yrs', 'Whisky écossais single malt aux saveurs distinctives de poire fraîche et crémeuse et de chêne grillé avec une finale longue, douce et mûre.', '<p>Glenfiddich 12 fait partie de la collection phare de la distillerie, un excellent choix pour les amateurs chevronn&eacute;s ou ceux qui d&eacute;butent dans le whisky, avec beaucoup de saveurs l&eacute;g&egrave;res et fruit&eacute;es gr&acirc;ce &agrave; un point de coupe &eacute;lev&eacute;. Vieilli 12 ans en f&ucirc;ts de ch&ecirc;ne am&eacute;ricain et europ&eacute;en, c&#39;est aussi le single malt le plus prim&eacute; au monde !</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000256', 0, 0, 2, NULL, NULL, '2023-12-11 07:30:15', '2024-05-15 15:10:21'),
(257, '6576bb182c9ea', 'PRO000257', 0, 'Glenfiddich 15 Yrs', '<p>Glenfiddich 15 Years Single Malt exemplifies a family&#39;s tradition of innovation. The whiskey is mellowed and aged in a unique Solera Vat, a massive oak tun inspired by the sherry bodegas of Spain and Portugal, after being aged in European oak sherry barrels and new oak barrels.</p>', 'It has using a technique pioneered by Malt Master and its warm, spicy flavours are transformed with the alchemy of the Solera Vat.', 15, '', NULL, 35, 34, '', 'Glenfiddich 15 Yrs', 'Il utilise une technique mise au point par Malt Master et ses saveurs chaudes et épicées sont transformées par l\'alchimie de la cuve Solera.', '<p>Glenfiddich 15 Years Single Malt illustre la tradition d&#39;innovation d&#39;une famille. Le whisky est adouci et vieilli dans une cuve Solera unique, un &eacute;norme f&ucirc;t en ch&ecirc;ne inspir&eacute; des bodegas de x&eacute;r&egrave;s d&#39;Espagne et du Portugal, apr&egrave;s avoir &eacute;t&eacute; vieilli dans des f&ucirc;ts de x&eacute;r&egrave;s en ch&ecirc;ne europ&eacute;en et des f&ucirc;ts de ch&ecirc;ne neufs.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000257', 0, 0, 2, NULL, NULL, '2023-12-11 07:32:40', '2024-05-15 15:10:28'),
(258, '6576bbc5f330e', 'PRO000258', 0, 'Havana Club S.De Maestros', '<p>Havana Club Selecci&oacute;n de Maestros is distinguished by a warm amber hue and a deep red glow. On the nose, toasted pecan and spice showcase the wood ageing. On the palate, a round mouth feel leads to a complex, flavourful, full-bodied palate of cocoa, coffee, sweet tobacco and brown spices.</p>', 'Havana Club Seleccion De Maestros Rum is a luxurious rum that captures the essence of Cuban craftsmanship.', 21, '', NULL, 34, 91, '', 'Havana Club S.De Maestros', 'Le rhum Havana Club Seleccion De Maestros est un rhum luxueux qui capture l\'essence de l\'artisanat cubain.', '<p>Havana Club Selecci&oacute;n de Maestros se distingue par une teinte ambr&eacute;e chaude et une lueur rouge profond. Au nez, des notes de noix de p&eacute;can grill&eacute;es et d&#39;&eacute;pices mettent en valeur le vieillissement sous bois. En bouche, une bouche ronde m&egrave;ne &agrave; une bouche complexe, savoureuse et cors&eacute;e de cacao, de caf&eacute;, de tabac doux et d&#39;&eacute;pices brunes.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000258', 0, 0, 1, NULL, NULL, '2023-12-11 07:35:33', '2024-02-05 06:59:50'),
(259, '6576bc237be77', 'PRO000259', 0, 'Havana Club Anejo 15yrs', '<p>A masterpiece of Cuban rum-making, Havana Club 15 Year Old is a bold, full-bodied rum with a rich, mahogany colour. The palate offers notes of dried fruits, prunes and raisins, alongside spicy oak and rich tobacco. The finish is full of complex vanilla, cocoa and coffee flavours that linger delightfully.</p>\r\n\r\n<p>&nbsp;</p>', 'Havana Club. Havana Club \'Gran Reserva\' 15 Years Old acquires its complexity of taste in an aging process of at least 15 years.', 21, '', NULL, 34, 91, '', 'Havana Club Anejo 15yrs', 'La Havane-Club. Havana Club \'Gran Reserva\' 15 ans acquiert sa complexité gustative au cours d\'un processus de vieillissement d\'au moins 15 ans.', '<p>Chef-d&#39;&oelig;uvre de la fabrication du rhum cubain, Havana Club 15 ans est un rhum audacieux et cors&eacute; avec une riche couleur acajou. La bouche offre des notes de fruits secs, de pruneaux et de raisins secs, ainsi que de ch&ecirc;ne &eacute;pic&eacute; et de tabac riche. La finale est pleine de saveurs complexes de vanille, de cacao et de caf&eacute; qui persistent d&eacute;licieusement.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000259', 0, 0, 1, NULL, NULL, '2023-12-11 07:37:07', '2024-02-05 06:59:50'),
(260, '6576bce994712', 'PRO000260', 0, 'Havana Club Anejo Rum Especial', '<p>Havana Club A&ntilde;ejo Especial is a double-aged amber rum. Incorporating vintages of up to five years, this rum, blended under the direction of the distillery&#39;s cellar master, also includes young rums, thus combining the characteristics of white and aged rums. Strength and lightness are thus found in the same blend.</p>', 'It is elaborated with rums aged in oak barrels and perfectly balanced by the Maestro Ronero, who selects each component for the final blending.', 21, '', NULL, 34, 91, '', 'Havana Club Anejo Rum Especial', 'Il est élaboré à partir de rhums vieillis en fûts de chêne et parfaitement équilibré par le Maestro Ronero, qui sélectionne chaq', '<p>Havana Club A&ntilde;ejo Especial est un rhum ambr&eacute; doublement vieilli. Incorporant des mill&eacute;simes allant jusqu&#39;&agrave; cinq ans, ce rhum, assembl&eacute; sous la direction du ma&icirc;tre de chai de la distillerie, comprend &eacute;galement des rhums jeunes, alliant ainsi les caract&eacute;ristiques des rhums blancs et vieux. Force et l&eacute;g&egrave;ret&eacute; se retrouvent ainsi dans un m&ecirc;me m&eacute;lange.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000260', 0, 0, 1, NULL, NULL, '2023-12-11 07:40:25', '2024-05-08 07:01:01'),
(261, '6576bdb7cc6c0', 'PRO000261', 0, 'Hennessy Cognac Xo', '<p>A blend of 100 eaux-de-vie, its deep amber color is a sign of its intensity. At once rich and robust, it constantly reveals layers of flavors with distinctive persistence on the palate. The original X.O Cognac is both elegant and complex, aged and blended to be bold, rich, and persistent.</p>', 'The blend contains a selection of spirits aged between 12 and 30 years in order to give unparalleled elegance, complexity and robustness.', 21, '', NULL, 43, 72, '', 'Hennessy Cognac Xo', 'L\'assemblage contient une sélection de spiritueux âgés entre 12 et 30 ans afin de donner une élégance, une complexité et une robustesse sans égal.', '<p>Assemblage de 100 eaux-de-vie, sa couleur ambr&eacute;e profonde est signe de son intensit&eacute;. &Agrave; la fois riche et charpent&eacute;, il r&eacute;v&egrave;le constamment des &eacute;tages de saveurs avec une persistance distinctive en bouche. Le Cognac X.O original est &agrave; la fois &eacute;l&eacute;gant et complexe, vieilli et assembl&eacute; pour &ecirc;tre audacieux, riche et persistant.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000261', 0, 0, 1, NULL, NULL, '2023-12-11 07:43:51', '2024-02-05 06:59:50'),
(262, '6576be1dad213', 'PRO000262', 0, 'Inverroche Classic', '<p>This gin is distilled with endemic plants from South Africa called fynbos, handpicked in the hills and limestone-rich cliffs. The nose feels a lovely balance of citrus fruit, juniper and orange blossom.</p>', 'Infused with fynbos from the limestone-rich soils of the low lands of the Cape Floral Kingdo', 21, '', NULL, 31, 40, '', 'Inverroche Classic', 'Infusé de fynbos provenant des sols riches en calcaire des basses terres du Cape Floral Kingdo', '<p>Ce gin est distill&eacute; avec des plantes end&eacute;miques d&#39;Afrique du Sud appel&eacute;es fynbos, cueillies &agrave; la main dans les collines et les falaises riches en calcaire. Le nez pr&eacute;sente un bel &eacute;quilibre d&#39;agrumes, de geni&egrave;vre et de fleur d&#39;oranger.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000262', 0, 0, 1, NULL, NULL, '2023-12-11 07:45:33', '2024-02-05 06:59:50'),
(263, '6576beffc2752', 'PRO000263', 0, 'Itnera Prosecco Brut', '<p>Produced by the MGM / Mondo del Vino juggernaut, this is quality prosecco at an excellent price point. It&#39;s fresh and fruity with soft peach and pear flavours on the palate. At 11%, it&#39;s slightly lower in alcohol and makes for a perfect aperitif or celebratory glass of bubbles.</p>', 'It\'s fresh and fruity with soft peach and pear flavours on the palate. At 11%, it\'s slightly lower in alcohol and makes for a perfect aperitif .', 22, '', NULL, 36, 92, '', 'Itnera Prosecco Brut', 'Il est frais et fruité avec de douces saveurs de pêche et de poire en bouche. À 11%, il est légèrement moins alcoolisé et', '<p>Produit par le mastodonte MGM / Mondo del Vino, c&#39;est un prosecco de qualit&eacute; &agrave; un excellent prix. Il est frais et fruit&eacute; avec de douces saveurs de p&ecirc;che et de poire en bouche. &Agrave; 11 %, il est l&eacute;g&egrave;rement moins alcoolis&eacute; et constitue un parfait ap&eacute;ritif ou un verre de bulles de f&ecirc;te.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000263', 0, 0, 1, NULL, NULL, '2023-12-11 07:49:19', '2024-02-05 06:59:50'),
(264, '6576c187373fa', 'PRO000264', 0, 'Jack Daniel\'s Whiskey', '<p>A warm amber colour with aromas of sweet vanilla, this is a smooth, full-bodied whiskey, with flavours of orange, brown sugar and spice, and a long rich finish. Jack Daniel registered his distillery in 1866, making it the oldest registered distillery in the United States.</p>\r\n\r\n<p>&nbsp;</p>', 'A warm amber colour with aromas of sweet vanilla, this is a smooth, full-bodied whiskey, with flavours of orange, brown sugar and spice.', 37, '', NULL, 61, 93, '', 'Jack Daniel\'s Whiskey', 'D\'une couleur ambrée chaude avec des arômes de vanille douce, c\'est un whisky doux et corsé, aux saveurs d\'orange, de cassonade et d\'épices.', '<p>Jack Daniel&#39;s Old No. 7 est un whisky du Tennessee haut de gamme. D&#39;une couleur ambr&eacute;e chaude avec des ar&ocirc;mes de vanille douce, c&#39;est un whisky doux et cors&eacute;, avec des saveurs d&#39;orange, de cassonade et d&#39;&eacute;pices, et une longue finale riche.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000264', 0, 0, 1, NULL, NULL, '2023-12-11 08:00:07', '2024-06-05 14:07:04'),
(265, '6576c24b9f5d4', 'PRO000265', 0, 'Jack Daniel\'s Honey', '<p>A blend of Jack Daniel&#39;s Tennessee Whiskey and a unique honey liqueur, for a taste that&#39;s one-of-a-kind and unmistakably Jack. With hints of honey and a finish that&#39;s naturally smooth, Jack Daniel&#39;s Tennessee Honey offers a taste of the unexpected.</p>\r\n\r\n<p>&nbsp;</p>', 'Jack Daniel\'s Tennessee Whiskey and a unique honey liqueur of our own making, for a taste that\'s one-of-a-kind and unmistakably Jack.', 37, '', NULL, 61, 93, '', 'Jack Daniel\'s Honey', 'Le whisky Tennessee Jack Daniel\'s et une liqueur de miel unique de notre propre fabrication, pour un goût unique et indéniablement Jack.', '<p>Un m&eacute;lange de Jack Daniel&#39;s Tennessee Whiskey et d&#39;une liqueur de miel unique, pour un go&ucirc;t unique et ind&eacute;niablement Jack. Avec des notes de miel et une finale naturellement douce, Jack Daniel&#39;s Tennessee Honey offre un avant-go&ucirc;t de l&#39;inattendu.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000265', 0, 0, 1, NULL, NULL, '2023-12-11 08:03:23', '2024-06-05 14:06:00'),
(266, '6576c2d6c6e31', 'PRO000266', 0, 'Jack Daniel\'s Whiskey', '<p>Iconic Tennessee whiskey from a distiller with over 140 years experience. Jack Daniels Tennessee Whiskey 350mL is one of the very few whiskies that is charcoal mellowed. Jack Daniel&#39;s has a smooth aroma and flavour of vanilla, toasted oak and caramel translates well to the palate.</p>', 'A warm amber colour with aromas of sweet vanilla, this is a smooth, full-bodied whiskey, with flavours of orange, brown sugar and spice.', 37, '', NULL, 61, 93, '', 'Jack Daniel\'s Whiskey', 'D\'une couleur ambrée chaude avec des arômes de vanille douce, c\'est un whisky doux et corsé, aux saveurs d\'orange, de cassonade et d\'épices.', '<p>Whisky embl&eacute;matique du Tennessee provenant d&#39;un distillateur avec plus de 140 ans d&#39;exp&eacute;rience. Jack Daniels Tennessee Whiskey 350 mL est l&#39;un des tr&egrave;s rares whiskies adoucis au charbon de bois. Jack Daniel&#39;s a un ar&ocirc;me doux et une saveur de vanille, de ch&ecirc;ne grill&eacute; et de caramel qui se traduisent bien au palais.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000266', 0, 0, 1, NULL, NULL, '2023-12-11 08:05:42', '2024-06-05 14:06:21'),
(267, '6576cecb01b8e', 'PRO000267', 0, 'Jack Daniel\'s Bourbon Whisky', '<p>It has the perfect blend of corn, rye and barley. Most importantly, this filtering process allows the whiskey to soak for about twelve days drop by drop through an approximately three meter thick layer of charcoal, which is produced on the premises of the distillery from sugar maple.special edition with a large 3 ltr bottle</p>', 'Jack Daniel\'s Old No. 7 is a premium Tennessee Whiskey. A warm amber colour with aromas of sweet vanilla, this is a smooth, full-bodied whiskey.', 37, '', NULL, 49, 93, '', 'Jack Daniel\'s Bourbon Whisky', 'Jack Daniel\'s Old No. 7 est un whisky du Tennessee haut de gamme. D\'une couleur ambrée chaude avec des arômes de vanille douce,', '<p>Il contient le m&eacute;lange parfait de ma&iuml;s, de seigle et d&rsquo;orge. Plus important encore, ce processus de filtration permet au whisky de tremper pendant environ douze jours goutte &agrave; goutte &agrave; travers une couche de charbon de bois d&#39;environ trois m&egrave;tres d&#39;&eacute;paisseur, produite dans les locaux de la distillerie &agrave; partir d&#39;&eacute;rable &agrave; sucre.&eacute;dition sp&eacute;ciale avec une grande bouteille de 3 litres</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000267', 0, 0, 1, NULL, NULL, '2023-12-11 08:56:43', '2024-05-08 07:06:44'),
(268, '6576cf9043cb7', 'PRO000268', 0, 'Jack Daniel\'s Gentlement Jack', '<p>Inspired by their founder and the original &#39;Gentleman Distiller&#39; Gentleman Jack goes through a second stage of charcoal mellowing to achieve incredible smoothness and a mellow, balanced flavour. Smooth and delicious, enjoy neat, over ice, or with your favourite mixer or cocktail.</p>', 'This super premium expression has a balanced flavour which is perfect for celebrating life’s extraordinary occasions.', 37, '', NULL, 61, 93, '', 'Jack Daniel\'s Gentlement Jack', 'Cette expression super premium a une saveur équilibrée, parfaite pour célébrer les occasions extraordinaires de la vie.', '<p>Inspir&eacute; par leur fondateur et le &laquo; Gentleman Distiller &raquo; original, Gentleman Jack passe par une deuxi&egrave;me &eacute;tape d&#39;adoucissement au charbon de bois pour obtenir une douceur incroyable et une saveur douce et &eacute;quilibr&eacute;e. Onctueux et d&eacute;licieux, &agrave; d&eacute;guster pur, sur glace ou avec votre mixeur ou cocktail pr&eacute;f&eacute;r&eacute;.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000268', 0, 0, 1, NULL, NULL, '2023-12-11 09:00:00', '2024-06-05 14:04:47'),
(269, '6576d0c0787a8', 'PRO000269', 0, 'Jack Daniel\'s Whisky Fire', '<p>Jack Daniel&#39;s Fire blends warm cinnamon liqueur with the bold character of Jack Daniel&#39;s Old No. 7 for a classic spirit with a surprisingly smooth finish. Made with real cinnamon. Jeff Arnett, Jack&#39;s Master Distiller, would describe it as a &ldquo;hot bakery cinnamon roll in a glass of Jack&rdquo;.</p>', 'It delivers the smooth character of Jack Daniel\'s Tennessee Whiskey with the fiery yet smooth finish of cinnamon.', 37, '', NULL, 61, 93, '', 'Jack Daniel\'s Whisky Fire', 'It delivers the smooth character of Jack Daniel\'s Tennessee Whiskey with the fiery yet smooth finish of cinnamon.', '<p>Jack Daniel&#39;s Fire m&eacute;lange la liqueur chaude de cannelle avec le caract&egrave;re audacieux du Jack Daniel&#39;s Old No. 7 pour un spiritueux classique avec une finale &eacute;tonnamment douce. Fabriqu&eacute; avec de la vraie cannelle. Jeff Arnett, le ma&icirc;tre distillateur de Jack, le d&eacute;crirait comme &laquo; un petit pain chaud &agrave; la cannelle dans un verre de Jack &raquo;.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000269', 0, 0, 1, NULL, NULL, '2023-12-11 09:05:04', '2024-06-05 14:03:53'),
(270, '6576d1ebee8a0', 'PRO000270', 0, 'Jack Daniel\'s Honey 35 %', '<p>It delivers the bold character of Jack Daniel&#39;s Tennessee Whiskey with the taste of rich honey and a nutty finish. Described by our Master Distiller as being &#39;like a slice of pecan pie in a glass of Jack&#39;, Jack Daniel&#39;s Tennessee Honey is best enjoyed on the rocks or in a variety of cocktails.&quot;</p>', 'Jack Daniel\'s Tennessee Whiskey and a unique honey liqueur of our own making, for a taste that\'s one-of-a-kind and unmistakably Jack.', 37, '', NULL, 61, 93, '', 'Jack Daniel\'s Honey 35 %', 'Le whisky Tennessee Jack Daniel\'s et une liqueur de miel unique de notre propre fabrication, pour un goût unique et indéniablement Jack.', '<p>Il offre le caract&egrave;re audacieux du Tennessee Whiskey Jack Daniel&#39;s avec un go&ucirc;t de miel riche et une finale de noisette. D&eacute;crit par notre ma&icirc;tre distillateur comme &eacute;tant &laquo; comme une tranche de tarte aux pacanes dans un verre de Jack &raquo;, le miel du Tennessee de Jack Daniel&#39;s se d&eacute;guste de pr&eacute;f&eacute;rence sur glace ou dans une vari&eacute;t&eacute; de cocktails. &raquo;</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000270', 0, 0, 1, NULL, NULL, '2023-12-11 09:10:03', '2024-06-05 14:03:15'),
(271, '6576d2c6e4405', 'PRO000271', 0, 'Jacob\'s Creek Classic Crisp Rose', '<p>jacobs Creek Classic Crisp Rose is a light-bodied, refreshing pink wine from Australia. It has a crisp and clean taste, with fruit flavours of red berries and citrus. This wine is typically dry, with a balanced acidity and a light to medium alcohol content, with an average ABV of 11%.</p>', 'Jacob’s Creek Classic range offers fresh, great tasting wines across a wide selection of popular varieties and blends.', 22, '', NULL, 46, 41, '', 'Jacob\'s Creek Classic Crisp Rose', 'La gamme Jacob\'s Creek Classic propose des vins frais et savoureux dans une large sélection de variétés et d\'assemblages populaires.', '<p>Jacobs Creek Classic Crisp Rose est un vin rose l&eacute;ger et rafra&icirc;chissant d&#39;Australie. Il a un go&ucirc;t vif et net, avec des saveurs fruit&eacute;es de fruits rouges et d&#39;agrumes. Ce vin est typiquement sec, avec une acidit&eacute; &eacute;quilibr&eacute;e et une teneur en alcool l&eacute;g&egrave;re &agrave; moyenne, avec un titre moyen de 11 %.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000271', 0, 0, 1, NULL, NULL, '2023-12-11 09:13:42', '2024-02-05 06:59:50'),
(272, '6576d3d911100', 'PRO000272', 0, 'Jacob\'s Creek Classic Merlot', '<p>Medium ruby red with purple hues. Fresh fruit aromas of ripe mulberry, cherry and spicy red currant, accompanied by subtle, well-integrated vanillin oak notes adding richness and complexity.</p>', 'Showcasing merlot\'s varietal purity with a soft, enjoyable finish. It has great lift with concentration of varietal spice and savory red fruits.', 22, '', NULL, 33, 41, '', 'Jacob\'s Creek Classic Merlot', 'Mettant en valeur la pureté variétale du merlot avec une finale douce et agréable. Il est très relevé et révèle une concentration d\'épices', '<p>Rouge rubis moyen aux reflets violets. Ar&ocirc;mes de fruits frais de m&ucirc;re m&ucirc;re, de cerise et de groseille &eacute;pic&eacute;e, accompagn&eacute;s de notes subtiles et bien int&eacute;gr&eacute;es de ch&ecirc;ne vanillin ajoutant richesse et complexit&eacute;.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000272', 0, 0, 1, NULL, NULL, '2023-12-11 09:18:17', '2024-02-05 06:59:50'),
(273, '6576d4c503ca7', 'PRO000273', 0, 'Jp Chenet Colombard Sauvignon 11%', '<p>Its rich flavour is reminiscent of soft fresh greenery and white colours, a range of fruit nuances and notes of lime. The taste is delicate and refreshing, with a good balance of fruit shades, amiable acidity and a faint trace of minerality.</p>', 'Intense aromas of lime and grapefruit. TASTE: Flavors of diluted honey, apple and grass notes. High acidity with a persistent aftertaste.', 22, '', NULL, 40, 43, '', 'Jp Chenet Colombard Sauvignon 11%', 'Arômes intenses de citron vert et de pamplemousse. GOÛT : Saveurs de miel dilué, de pomme et de notes d\'herbe. Acidité élevée', '<p>Sa saveur riche rappelle la verdure douce et fra&icirc;che et les couleurs blanches, une gamme de nuances fruit&eacute;es et des notes de citron vert. Le go&ucirc;t est d&eacute;licat et rafra&icirc;chissant, avec un bon &eacute;quilibre de nuances fruit&eacute;es, une acidit&eacute; agr&eacute;able et une l&eacute;g&egrave;re trace de min&eacute;ralit&eacute;.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000273', 0, 0, 1, NULL, NULL, '2023-12-11 09:22:13', '2024-02-05 06:59:50'),
(274, '6576d5714530b', 'PRO000274', 0, 'Jw Black Label 12yr', '<p>A smooth and complex character on the palate releasing intense notes of sweet vanilla that give way to notes of orange peel and aromas of spices and raisins. A lovely smooth and balanced finish, rich in smoke, peat and malt. Bottled at 40% ABV</p>', 'Johnnie Walker Black Label is an Iconic Blend, recognized as the benchmark for all other deluxe blends.', 15, '', NULL, 48, 13, '', 'Jw Black Label 12yr', 'Johnnie Walker Black Label est un mélange emblématique, reconnu comme la référence pour tous les autres mélanges de luxe.', '<p>Un caract&egrave;re doux et complexe en bouche lib&eacute;rant des notes intenses de vanille douce qui laissent place &agrave; des notes d&#39;&eacute;corce d&#39;orange et &agrave; des ar&ocirc;mes d&#39;&eacute;pices et de raisins secs. Une belle finale douce et &eacute;quilibr&eacute;e, riche en fum&eacute;e, tourbe et malt. Mis en bouteille &agrave; 40% ABV.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000274', 0, 0, 1, NULL, NULL, '2023-12-11 09:25:05', '2024-05-30 11:24:23'),
(275, '6576d5cdeec29', 'PRO000275', 0, 'Jw Red Label', '<p>This gift pack contains 1 x Johnnie Walker Red Label Blended Scotch Whisky 70cl and 1 x Johnnie Walker Black Label 20cl. Red Label crackles with sweet smoke and sparkles with cinnamon with honey cascading over fresh fruit. Black Label is loaded with layers of creamy toffee, rich, sweet fruit and spicy vanilla, all wrapped in sweet smoke.</p>', 'It\'s a blend that combines light whiskies from Scotland\'s East Coast and more peaty whiskies from the West, creating an extraordinary depth of flavor.', 15, '', NULL, 48, 13, '', 'Jw Red Label', 'Il s\'agit d\'un mélange qui associe des whiskies légers de la côte Est de l\'Écosse et des whiskies plus tourbés de l\'Ouest, créant une', '<p>Ce coffret cadeau contient 1 x Johnnie Walker Red Label Blended Scotch Whisky 70cl et 1 x Johnnie Walker Black Label 20cl. Red Label cr&eacute;pite de fum&eacute;e douce et scintille de cannelle et de miel en cascade sur des fruits frais. Black Label regorge de couches de caramel cr&eacute;meux, de fruits riches et sucr&eacute;s et de vanille &eacute;pic&eacute;e, le tout envelopp&eacute; dans une fum&eacute;e douce.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000275', 0, 0, 1, NULL, NULL, '2023-12-11 09:26:37', '2024-05-30 11:23:19'),
(276, '6576d6a35e112', 'PRO000276', 0, 'Jw Red Label', '<p>Johnnie Walker Red Label is crackling with spice and bursting with vibrant, smoky flavors. It&#39;s a blend that combines light whiskies from Scotland&#39;s East Coast and more peaty whiskies from the West, creating an extraordinary depth of flavor.</p>', 'It\'s a blend that combines light whiskies from Scotland\'s East Coast and more peaty whiskies from the West, creating an extraordinary depth of flavor.', 15, '', NULL, 48, 13, '', 'Jw Red Label', 'Il s\'agit d\'un mélange qui associe des whiskies légers de la côte Est de l\'Écosse et des whiskies plus tourbés de l\'Ouest, créant une', '<p>Le Johnnie Walker Red Label cr&eacute;pite d&#39;&eacute;pices et regorge de saveurs vibrantes et fum&eacute;es. Il s&#39;agit d&#39;un m&eacute;lange qui associe des whiskies l&eacute;gers de la c&ocirc;te Est de l&#39;&Eacute;cosse et des whiskies plus tourb&eacute;s de l&#39;Ouest, cr&eacute;ant une profondeur de saveur extraordinaire.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000276', 0, 0, 1, NULL, NULL, '2023-12-11 09:30:11', '2024-05-30 11:20:57'),
(277, '6576d797693a4', 'PRO000277', 0, 'Ketal One Vodka', '<p>Our 80 proof vodka is carefully crafted using exclusively 100% non-GMO European wheat for smoothness and neutrality. Distilled in copper pot stills, filtered over loose charcoal and stored in lined tanks, our vodka offers a crisp, unique flavor and strong finish.</p>', 'Distilled in copper pot stills, filtered over loose charcoal and stored in lined tanks, our vodka offers a crisp, unique flavor and strong finish.', 21, '', NULL, 29, 94, '', 'Ketal One Vodka', 'Distillée dans des alambics en cuivre, filtrée sur du charbon de bois libre et stockée dans des cuves doublées, notre vodka offre une saveur', '<p>Notre vodka &agrave; 80&deg; est soigneusement &eacute;labor&eacute;e &agrave; partir de bl&eacute; europ&eacute;en 100 % sans OGM pour plus de douceur et de neutralit&eacute;. Distill&eacute;e dans des alambics en cuivre, filtr&eacute;e sur du charbon de bois libre et stock&eacute;e dans des cuves doubl&eacute;es, notre vodka offre une saveur vive et unique et une finale forte.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000277', 0, 0, 1, NULL, NULL, '2023-12-11 09:34:15', '2024-02-05 06:59:50'),
(278, '6576d86d15745', 'PRO000278', 0, 'Knights Whisky', '<p>Knights is a blend of the finest malt and grain whiskies, matured in oak barrels to give it a full character with a slightly sweet palate made for your enjoyment. The nose is fruity and well-malted with some smoke and a touch of honey on the palate. Knights whisky is smokey with a touch of honey on the palate.</p>', 'The taste of Knights finest matured whisky is uncomplicated, sophisticated yet playful.', 15, '', NULL, 50, 95, '', 'Knights Whisky', 'Le goût du whisky vieilli le plus fin Knights est simple, sophistiqué mais ludique.', '<p>Knights est un m&eacute;lange des meilleurs whiskies de malt et de grain, vieilli en f&ucirc;ts de ch&ecirc;ne pour lui donner un caract&egrave;re plein avec une bouche l&eacute;g&egrave;rement sucr&eacute;e faite pour votre plaisir. Le nez est fruit&eacute; et bien malt&eacute; avec un peu de fum&eacute;e et une touche de miel en bouche. Le whisky Knights est fum&eacute; avec une touche de miel en bouche.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000278', 0, 0, 2, NULL, NULL, '2023-12-11 09:37:49', '2024-05-31 10:36:33'),
(279, '6576d968bc25e', 'PRO000279', 0, 'Lindeman\'s Bin 46 Sweet Red 2017', '<p>Lindeman&#39;s Bin 46 Sweet Red is light red in colour, features aromas of strawberry fruits, with a hint of musk, whilst the palate is fresh with berry fruit flavours wrapped up in a luscious sweet finish.</p>', 'light red in colour, features aromas of strawberry fruits, with a hint of musk, whilst the palate is fresh with berry fruit flavours.', 22, '', NULL, 33, 73, '', 'Lindeman\'s Bin 46 Sweet Red 2017', 'De couleur rouge clair, il présente des arômes de fraises, avec une pointe de musc, tandis que la bouche est fraîche avec des arômes de petits fruits.', '<p>Le Lindeman&#39;s Bin 46 Sweet Red est de couleur rouge clair, pr&eacute;sente des ar&ocirc;mes de fraises, avec une touche de musc, tandis que la bouche est fra&icirc;che avec des saveurs de petits fruits envelopp&eacute;es dans une finale sucr&eacute;e succulente.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000279', 0, 0, 1, NULL, NULL, '2023-12-11 09:42:00', '2024-02-12 10:05:34'),
(280, '6576da31691f0', 'PRO000280', 0, 'Lindeman\'s Winemakers  Soft & Fruity', '<p>This Spanish red wine comes from a blend of Tempranillo, Syrah and Garnacha. The result is a soft fruity medley of blackberry and cherry with hints of chocolate and a slightly spicy finish.</p>', 'Lindeman\'s Winemakers Release Red Wine 750ml Wine of Spain Soft & fruity This Spanish red wine comes from a blend of Tempranillo, Syrah and Garnacha.', 22, '', NULL, 33, 73, '', 'Lindeman\'s Winemakers  Soft & Fruity', 'Les vignerons de Lindeman lancent du vin rouge 750 ml Vin d\'Espagne Doux et fruité Ce vin rouge espagnol est issu d\'un assemblage', '<p>Ce vin rouge espagnol est issu d&#39;un assemblage de Tempranillo, Syrah et Garnacha. Le r&eacute;sultat est un m&eacute;lange fruit&eacute; doux de m&ucirc;re et de cerise avec des notes de chocolat et une finale l&eacute;g&egrave;rement &eacute;pic&eacute;e.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000280', 0, 0, 1, NULL, NULL, '2023-12-11 09:45:21', '2024-02-05 06:59:50'),
(281, '6576dd151a5f1', 'PRO000281', 0, 'Luc Belaire Rare Luxe', '<p>Indulge with true French Luxury. Belaire Rare Luxe is made in Burgundy, France, from exquisite French grapes, and blended with a special Chardonnay dosage. Belaire Luxe is an authentic French Blanc de Blancs made from grapes selected for their rich and delicate character.</p>', 'Luc Belaire Rare Luxe is a beautifully blended champagne that produces light, fruity notes of apricot, honeysuckle, and brioche.', 22, '', NULL, 45, 96, '', 'Luc Belaire Rare Luxe', 'Luc Belaire Rare Luxe est un champagne magnifiquement assemblé qui produit des notes légères et fruitées d\'abricot, de chèvrefeuille et de brioche.', '<p>Offrez-vous le vrai luxe &agrave; la fran&ccedil;aise. Belaire Rare Luxe est fabriqu&eacute; en Bourgogne, en France, &agrave; partir de raisins fran&ccedil;ais exquis et assembl&eacute; avec un dosage sp&eacute;cial de Chardonnay. Belaire Luxe est un authentique Blanc de Blancs fran&ccedil;ais issu de raisins s&eacute;lectionn&eacute;s pour leur caract&egrave;re riche et d&eacute;licat.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000281', 0, 0, 1, NULL, NULL, '2023-12-11 09:57:41', '2024-02-05 06:59:50'),
(282, '6576e490d033d', 'PRO000282', 0, 'Luc Belaire Brut Gold 12.5%', '<p>Luc Belaire Gold presents a very fine and balanced character with notes of stone fruit, ripe pear and brioche in the nose. On the palate, the tropical aroma of mango is connected with fresh chardonnay notes. The finish of this sparkling wine is dry and light.</p>', 'Balanced and elegant, the wine begins with aromas of stone fruits, ripe pear and brioche.', 22, '', NULL, 45, 96, '', 'Luc Belaire Brut Gold 12.5%', 'Equilibré et élégant, le vin débute sur des arômes de fruits à noyau, de poire mûre et de brioche.', '<p>Luc Belaire Gold pr&eacute;sente un caract&egrave;re tr&egrave;s fin et &eacute;quilibr&eacute; avec au nez des notes de fruits &agrave; noyau, de poire m&ucirc;re et de brioche. En bouche, l&#39;ar&ocirc;me tropical de la mangue s&#39;associe &agrave; des notes fra&icirc;ches de chardonnay. La finale de ce vin mousseux est s&egrave;che et l&eacute;g&egrave;re.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000282', 0, 0, 1, NULL, NULL, '2023-12-11 10:29:36', '2024-02-05 06:59:50'),
(283, '6576e5b11378f', 'PRO000283', 0, 'Malibu', '<p>Caribbean rum with natural coconut flavour. The taste of MALIBU is sunshine in a bottle - smooth, fresh coconut flavour with a sweet finish</p>', 'It is a liqueur blended with the finest Caribbean rums and has a distinct coconut flavour.', 21, '', NULL, 34, 97, '', 'Malibu', 'C\'est une liqueur mélangée avec les meilleurs rhums des Caraïbes et qui a une saveur distincte de noix de coco.', '<p>Rhum des Cara&iuml;bes &agrave; l&#39;ar&ocirc;me naturel de noix de coco. Le go&ucirc;t de MALIBU est celui du soleil dans une bouteille : saveur de noix de coco douce et fra&icirc;che avec une finale sucr&eacute;e.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000283', 0, 0, 1, NULL, NULL, '2023-12-11 10:34:25', '2024-05-08 07:26:48'),
(284, '6576e67de4ab6', 'PRO000284', 0, 'Martell Cognac VSOP', '<p>Martell VSOP is a blend of eaux-de-vie, the youngest of which has aged for at least 4 years. This cognac offers a perfect balance between the lusciously fine, fruity notes and the subtle woody overtones. Elegant and harmonious, Martell VSOP is an authentic expression of the Martell style.</p>', 'Its time spent ageing in a barrel infuses it with complex aromas along with notes of caramelised dried fruits and prunes.', 21, '', NULL, 43, 46, '', 'Martell Cognac VSOP', 'Son vieillissement en barrique lui confère des arômes complexes accompagnés de notes de fruits secs caramélisés et de pruneaux.', '<p>Martell VSOP est un assemblage d&#39;eaux-de-vie dont la plus jeune a vieilli au moins 4 ans. Ce cognac offre un &eacute;quilibre parfait entre les notes fruit&eacute;es d&eacute;licieusement fines et les subtiles notes bois&eacute;es. &Eacute;l&eacute;gant et harmonieux, Martell VSOP est une expression authentique du style Martell.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000284', 0, 0, 1, NULL, NULL, '2023-12-11 10:37:49', '2024-05-08 07:27:03');
INSERT INTO `product` (`id`, `uniqid`, `product_item_id`, `supplier_id`, `product_name`, `description`, `short_description`, `category_id`, `product_image`, `images`, `subcategory_id`, `brand_id`, `video`, `product_name_fr`, `short_description_fr`, `page_content_fr`, `product_qty`, `tech_data_sheet`, `retail_price`, `discount_price`, `is_admin_approve`, `most_view`, `is_product_bestseller`, `sku`, `average_rating`, `offer`, `status`, `in_store`, `in_online`, `created_at`, `updated_at`) VALUES
(285, '6576e71441296', 'PRO000285', 0, 'Martell Vs Single Distillery', '<p>A nice blend, sweet and fruity. Bright and golden in color, Martell VS Single Distillery reveals pleasing notes of plum, apricot and candied lemon on the nose. Its rich fruit flavors on the palate and its generosity on the palate make it a great cognac to enjoy in long drinks or cocktails.</p>', 'Martell VS has a design that is easily recognizable, reflecting the cognac\'s distinctive taste. Rich, clear gold liquid with intense aromas of plum.', 21, '', NULL, 43, 46, '', 'Martell Vs Single Distillery', 'Martell VS a un design facilement reconnaissable, reflétant le goût distinctif du cognac. Liquide doré riche et clair aux arômes intenses de prune.', '<p>Un joli m&eacute;lange, doux et fruit&eacute;. De couleur vive et dor&eacute;e, Martell VS Single Distillery r&eacute;v&egrave;le au nez d&#39;agr&eacute;ables notes de prune, d&#39;abricot et de citron confit. Ses riches ar&ocirc;mes de fruits en bouche et sa g&eacute;n&eacute;rosit&eacute; en bouche en font un excellent cognac &agrave; d&eacute;guster en longdrinks ou en cocktails.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000285', 0, 0, 1, NULL, NULL, '2023-12-11 10:40:20', '2024-02-05 06:59:50'),
(286, '6576e779a16bd', 'PRO000286', 0, 'Moet & Chandon Ice Imperial Rose', '<p>Moet &amp; Chandon Ice Imperial Rose has a bright pink color with golden reflections. Its vibrant and fruity aroma has mainly red berries and cherries (cherry Morello and two types of cranberry), with nuances of juicy summer fruits (such as fig or nectarine), with an appetizing note of grenadine.</p>', 'Moet Ice Imperial Rose, is the first and only rose champagne especially created to be enjoyed on ice.', 23, '', NULL, 37, 75, '', 'Moet & Chandon Ice Imperial Rose', 'Moet Ice Imperial Rose, est le premier et le seul champagne rosé spécialement créé pour être dégusté sur glace.', '<p>Moet &amp; Chandon Ice Imperial Rose a une couleur rose vif aux reflets dor&eacute;s. Son ar&ocirc;me vibrant et fruit&eacute; pr&eacute;sente principalement des fruits rouges et des cerises (griotte et deux types de canneberge), avec des nuances de fruits d&#39;&eacute;t&eacute; juteux (comme la figue ou la nectarine), avec une app&eacute;tissante note de grenadine.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000286', 0, 0, 1, NULL, NULL, '2023-12-11 10:42:01', '2024-02-05 06:59:50'),
(287, '6576e850ad1c9', 'PRO000287', 0, 'Nederberg Baronne', '<p>Nederburg Baronne is one of South Africa&#39;s most popular wines. A rich, medium bodied wine with an aroma of cherry, blackcurrant and plum, oak, and a hint of dark chocolate. A blend of Cabinet Sauvignon and Shiraz.</p>', 'A rich, medium bodied wine with an aroma of cherry, blackcurrant and plum, oak, and a hint of dark chocolate. A blend of Cabinet Sauvignon and Shiraz.', 22, '', NULL, 33, 49, '', 'Nederberg Baronne', 'Un vin riche et moyennement corsé avec un arôme de cerise, de cassis et de prune, de chêne et une touche de chocolat noir. Un assemblage', '<p>Nederburg Baronne est l&#39;un des vins les plus populaires d&#39;Afrique du Sud. Un vin riche et moyennement cors&eacute; avec un ar&ocirc;me de cerise, de cassis et de prune, de ch&ecirc;ne et une touche de chocolat noir. Un assemblage de Cabinet Sauvignon et Shiraz.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000287', 0, 0, 1, NULL, NULL, '2023-12-11 10:45:36', '2024-02-05 06:59:50'),
(288, '6576e96a2e2b2', 'PRO000288', 0, 'Neft Vodka White', '<p>Meticulously distilled in Austria using only artesian spring water from the Alps and old-world non-GMO rye grains, NEFT Vodka lets the quality of its ingredients shine with no extra flavors or additives.</p>', 'Great-tasting, smooth, top shelf quality rye vodka, distilled in small batches. It is vodka worth sipping, no dressing up or watering down required.', 21, '', NULL, 29, 98, '', 'Neft Vodka White', 'Vodka de seigle savoureuse, douce et de qualité supérieure, distillée en petits lots. C\'est une vodka qui vaut la peine d\'être sirotée,', '<p>M&eacute;ticuleusement distill&eacute;e en Autriche en utilisant uniquement de l&#39;eau de source art&eacute;sienne des Alpes et des grains de seigle du vieux monde sans OGM, la vodka NEFT laisse briller la qualit&eacute; de ses ingr&eacute;dients sans ar&ocirc;mes ni additifs suppl&eacute;mentaires.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000288', 0, 0, 1, NULL, NULL, '2023-12-11 10:50:18', '2024-02-05 06:59:50'),
(289, '6576ea6794378', 'PRO000289', 0, 'Old Monk Rum  42.8%', '<p>Old Monk Rum is quality dark rum made by traditional method, matured in oak barrels for a minimum 7 years. This organic beverage contains 42.8% alcohol. It has a smooth creamy consistency. It&#39;s taste has notes of caramel, chocolate with a hint of vanilla flavor creating a truly pleasant harmony.</p>\r\n\r\n<p>&nbsp;</p>', 'A velvet smooth dark rum with a hint of vanilla, it has an alcohol content of 42.8%.', 21, '', NULL, 34, 99, '', 'Old Monk Rum  42.8%', 'Un rhum brun onctueux et velouté avec une pointe de vanille, il titre 42,8 % d\'alcool.', '<p>Le rhum Old Monk est un rhum brun de qualit&eacute; &eacute;labor&eacute; selon une m&eacute;thode traditionnelle, vieilli en f&ucirc;ts de ch&ecirc;ne pendant au moins 7 ans. Cette boisson biologique contient 42,8% d&#39;alcool. Il a une consistance onctueuse et cr&eacute;meuse. Son go&ucirc;t pr&eacute;sente des notes de caramel, de chocolat avec une pointe de vanille cr&eacute;ant une harmonie vraiment agr&eacute;able.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000289', 0, 0, 1, NULL, NULL, '2023-12-11 10:54:31', '2024-02-05 06:59:50'),
(290, '6576ead6ae5ab', 'PRO000290', 0, 'Old Monk Rum  42.8%', '<p>Old Monk Rum is quality dark rum made by traditional method, matured in oak barrels for a minimum 7 years. This organic beverage contains 42.8% alcohol. It has a smooth creamy consistency. It&#39;s taste has notes of caramel, chocolate with a hint of vanilla flavor creating a truly pleasant harmony.</p>', 'A velvet smooth dark rum with a hint of vanilla, it has an alcohol content of 42.8%.', 21, '', NULL, 34, 99, '', 'Old Monk Rum  42.8%', 'Un rhum brun onctueux et velouté avec une pointe de vanille, il titre 42,8 % d\'alcool.', '<p>Le rhum Old Monk est un rhum brun de qualit&eacute; &eacute;labor&eacute; selon une m&eacute;thode traditionnelle, vieilli en f&ucirc;ts de ch&ecirc;ne pendant au moins 7 ans. Cette boisson biologique contient 42,8% d&#39;alcool. Il a une consistance onctueuse et cr&eacute;meuse. Son go&ucirc;t pr&eacute;sente des notes de caramel, de chocolat avec une pointe de vanille cr&eacute;ant une harmonie vraiment agr&eacute;able.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000290', 0, 0, 1, NULL, NULL, '2023-12-11 10:56:22', '2024-02-05 06:59:50'),
(291, '6576ec1f379a2', 'PRO000291', 0, 'Pouilly Fume Les Chaumiennes 2020', '<p>Full-bodied, but delicate aroma of the wine reveals notes of white flowers, apricots and citrus fruits, especially grapefruit.The taste of wine is soft, delicate, with notes of fruit, flowers and herbs, long refreshing finish.</p>', 'The taste of wine is soft, delicate, with notes of fruit, flowers and herbs, long refreshing finish.', 22, '', NULL, 40, 100, '', 'Pouilly Fume Les Chaumiennes 2020', 'Le goût du vin est doux, délicat, avec des notes de fruits, de fleurs et d\'herbes, longue finale rafraîchissante.', '<p>L&#39;ar&ocirc;me cors&eacute; mais d&eacute;licat du vin r&eacute;v&egrave;le des notes de fleurs blanches, d&#39;abricots et d&#39;agrumes, notamment de pamplemousse. Le go&ucirc;t du vin est doux, d&eacute;licat, avec des notes de fruits, de fleurs et d&#39;herbes, longue finale rafra&icirc;chissante.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000291', 0, 0, 1, NULL, NULL, '2023-12-11 11:01:51', '2024-02-05 06:59:50'),
(292, '6576ece4aad33', 'PRO000292', 0, 'Remy Martin VSOP', '<p>R&eacute;my Martin VSOP is a cognac that has been produced by R&eacute;my Martin since 1724. The name &quot;VSOP&quot; stands for &quot;Very Superior Old Pale&quot;. R&eacute;my Martin VSOP is made from a blend of Grande and Petite Champagne cognacs and is aged for a minimum of four years in French oak barrels.</p>', 'A smooth, fruity VSOP Cognac from Remy Martin, with aromas of vanilla, toasted oak, apricot, baked apple and white flowers.', 21, '', NULL, 43, 101, '', 'Remy Martin VSOP', 'Un Cognac VSOP doux et fruité de Rémy Martin, aux arômes de vanille, de chêne grillé, d\'abricot, de pomme au four et de fleurs blanches.', '<p>R&eacute;my Martin VSOP est un cognac produit par R&eacute;my Martin depuis 1724. Le nom &laquo; VSOP &raquo; signifie &laquo; Very Superior Old Pale &raquo;. R&eacute;my Martin VSOP est issu d&#39;un assemblage de cognacs Grande et Petite Champagne et est vieilli pendant au moins quatre ans en f&ucirc;ts de ch&ecirc;ne fran&ccedil;ais.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000292', 0, 0, 1, NULL, NULL, '2023-12-11 11:05:08', '2024-05-08 07:29:31'),
(293, '6576ed46ccb7a', 'PRO000293', 0, 'Remy Martin VSOP', '<p>R&eacute;my Martin VSOP is a cognac that has been produced by R&eacute;my Martin since 1724. The name &quot;VSOP&quot; stands for &quot;Very Superior Old Pale&quot;. R&eacute;my Martin VSOP is made from a blend of Grande and Petite Champagne cognacs and is aged for a minimum of four years in French oak barrels.</p>', 'A smooth, fruity VSOP Cognac from Remy Martin, with aromas of vanilla, toasted oak, apricot, baked apple and white flowers.', 21, '', NULL, 43, 101, '', 'Remy Martin VSOP', 'Un Cognac VSOP doux et fruité de Rémy Martin, aux arômes de vanille, de chêne grillé, d\'abricot, de pomme au four et de fleurs blanches.', '<p>R&eacute;my Martin VSOP est un cognac produit par R&eacute;my Martin depuis 1724. Le nom &laquo; VSOP &raquo; signifie &laquo; Very Superior Old Pale &raquo;. R&eacute;my Martin VSOP est issu d&#39;un assemblage de cognacs Grande et Petite Champagne et est vieilli pendant au moins quatre ans en f&ucirc;ts de ch&ecirc;ne fran&ccedil;ais.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000293', 0, 0, 1, NULL, NULL, '2023-12-11 11:06:46', '2024-02-05 06:59:50'),
(294, '6576edf42f991', 'PRO000294', 0, 'Remy Martin Xo', '<p>R&eacute;my Martin XO is the signature of our Cellar Master who with his expertise blends hundreds of eaux-de-vie. His art of blending allows us to express the full aromatic complexity of this XO Cognac Fine Champagne. R&eacute;my Martin XO is a fine champagne cognac that has been aged for at least ten years. It is produced by R&eacute;my Martin, a French company that has been making cognac since 1724. R&eacute;my Martin XO is a blend of several different types of cognacs, each of which has been aged for a minimum of ten years. The result is a complex and refined Cognac.Remy Martin XO is a blend of 85% Grande Champagne and 15% Petite Champagne cognac</p>', 'Rémy Martin XO is made with a blend of Ugni Blanc, Folle Blanche, and Colombard grapes. The cognac is then aged in oak barrels for at least ten years.', 21, '', NULL, 43, 101, '', 'Remy Martin Xo', 'Rémy Martin XO est issu d\'un assemblage de raisins Ugni Blanc, Folle Blanche et Colombard. Le cognac est ensuite vieilli en fûts de ch', '<p>R&eacute;my Martin XO est la signature de notre Ma&icirc;tre de Chai qui, avec son savoir-faire, assemble des centaines d&#39;eaux-de-vie. Son art de l&#39;assemblage permet d&#39;exprimer toute la complexit&eacute; aromatique de ce Cognac Fine Champagne XO. R&eacute;my Martin XO est un cognac de fine champagne vieilli au moins dix ans. Il est produit par R&eacute;my Martin, une entreprise fran&ccedil;aise qui produit du cognac depuis 1724. R&eacute;my Martin XO est un assemblage de plusieurs types de cognacs diff&eacute;rents, chacun ayant vieilli au moins dix ans. Le r&eacute;sultat est un Cognac complexe et raffin&eacute;. R&eacute;my Martin XO est un assemblage de 85% de Grande Champagne et 15% de Cognac de Petite Champagne.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000294', 0, 0, 1, NULL, NULL, '2023-12-11 11:09:40', '2024-05-14 13:14:48'),
(295, '6576f6c8064df', 'PRO000295', 0, 'Sparkwine Jp Chenet Pink Ice Edition 11%', '<p>An strong aroma of red fruit such as strawberries, cherries, and raspberries leads to a creamy and smooth tongue, extremely enjoyable and well balanced. The JP Chenet Ice Edition Rose is a semi-dry sparkling wine with a fruity fragrance that is both pleasant and light.</p>', 'Very clear, salmon and brilliant rose. Very meaning nose revealing aromas of small fresh red berries and strawberries.', 22, '', NULL, 45, 102, '', 'Sparkwine Jp Chenet Pink Ice Edition 11%', 'Très clair, saumoné et rose brillant. Nez très expressif révélant des arômes de petits fruits rouges frais et de fraises.', '<p>Un fort ar&ocirc;me de fruits rouges comme les fraises, les cerises et les framboises conduit &agrave; une langue cr&eacute;meuse et onctueuse, extr&ecirc;mement agr&eacute;able et bien &eacute;quilibr&eacute;e. Le JP Chenet Ice Edition Rose est un vin mousseux demi-sec au parfum fruit&eacute; &agrave; la fois agr&eacute;able et l&eacute;ger.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000295', 0, 0, 1, NULL, NULL, '2023-12-11 11:47:20', '2024-02-05 06:59:37'),
(296, '6576f84967ff1', 'PRO000296', 0, 'ST-Remy Xo Extra Old French Brandy', '<p>St-Remy XO is a brandy of character with complex aromas and a robust taste. It is recognized for its elegance, smoothness and the way it lingers on the palate. Enriched by a multitude of flavors that make it irresistible to the connoisseur. It can be enjoyed as an aperitif.</p>\r\n\r\n<p>&nbsp;</p>', 'a brandy of character with complex aromas and a robust taste.', 21, '', NULL, 42, 103, '', 'ST-Remy Xo Extra Old French Brandy', 'une eau-de-vie de caractère aux arômes complexes et au goût charpenté.', '<p>St-R&eacute;my XO est une eau-de-vie de caract&egrave;re aux ar&ocirc;mes complexes et au go&ucirc;t charpent&eacute;. Il est reconnu pour son &eacute;l&eacute;gance, sa douceur et sa longueur en bouche. Enrichi d&#39;une multitude de saveurs qui le rendent irr&eacute;sistible pour le connaisseur. Il peut &ecirc;tre d&eacute;gust&eacute; &agrave; l&#39;ap&eacute;ritif.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000296', 0, 0, 1, NULL, NULL, '2023-12-11 11:53:45', '2024-05-08 07:31:31'),
(297, '6576f89de4ae0', 'PRO000297', 0, 'ST-Remy VSOP 40%', '<p>Appearance: Amber-yellow in colour with golden highlights. Nose: A wonderful aromatic richness with fruity cherry, gooseberry &amp; wild strawberry flavours. Floral aromas blend subtly with the woody &amp; vanilla tones of oak. The overall effect is pleasing harmonious &amp; smooth.</p>', 'Created in 1886, St-Rémy is the world’s number-one French brandy. St-Rémy is bottled in the Loire Valley and shipped around the world!', 21, '', NULL, 43, 103, '', 'ST-Remy VSOP 40%', 'Créée en 1886, St-Rémy est le premier brandy français au monde. St-Rémy est mis en bouteille dans le Val de Loire et expédié dans le monde entier !', '<p>A l&#39;oeil : Robe jaune ambr&eacute;e aux reflets dor&eacute;s. Nez : Une belle richesse aromatique avec des ar&ocirc;mes fruit&eacute;s de cerise, de groseille et de fraise des bois. Les ar&ocirc;mes floraux se m&ecirc;lent subtilement aux tonalit&eacute;s bois&eacute;es et vanill&eacute;es du ch&ecirc;ne. L&#39;effet global est agr&eacute;able, harmonieux et doux.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000297', 0, 0, 1, NULL, NULL, '2023-12-11 11:55:09', '2024-02-05 06:59:37'),
(298, '6576f942b6a3b', 'PRO000298', 0, 'Tanqueray London Dry Gin 47.3%', '<p>Tanqueray London Dry Gin, created in 1830 by Charles Tanqueray, is still made according to the same classic and timeless recipe. Tanqueray London Dry is distilled four times to ensure perfect softness and allow the four classic gin herbs to shine.</p>', 'It is made with refreshing juniper, peppery coriander, aromatic angelica and sweet liquorice.', 21, '', NULL, 31, 58, '', 'Tanqueray London Dry Gin 47.3%', 'Il est composé de genièvre rafraîchissant, de coriandre poivrée, d\'angélique aromatique et de réglisse douce.', '<p>Tanqueray London Dry Gin, cr&eacute;&eacute; en 1830 par Charles Tanqueray, est toujours &eacute;labor&eacute; selon la m&ecirc;me recette classique et intemporelle. Tanqueray London Dry est distill&eacute; quatre fois pour assurer une douceur parfaite et permettre aux quatre herbes classiques du gin de briller.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000298', 0, 0, 1, NULL, NULL, '2023-12-11 11:57:54', '2024-02-05 06:59:37'),
(299, '6576fa156dee0', 'PRO000299', 0, 'Tequila Jose Cuervo Gold  40%', '<p>Jose Cuervo&reg; Gold is a joven tequila made from a blend of reposado (aged) and younger tequilas. Medium gold colour with aromas of freshly ground pepper, spice and orange. Flavours of black pepper and caramel, notes of toffee and vanilla on the finish.</p>', '40% Abv 80 Proof Tasting Notes: Color: Light Gold Hue Aroma: Sweet With Pleasant Agave Notes. Flavor:', 21, '', NULL, 38, 104, '', 'Tequila Jose Cuervo Gold  40%', '40 % Abv 80 Proof Notes de dégustation : Couleur : Teinte or clair Arôme : Doux avec des notes d\'agave agréables. Saveur:', '<p>Jose Cuervo&reg; Gold est une tequila jeune fabriqu&eacute;e &agrave; partir d&#39;un m&eacute;lange de tequilas reposado (vieillies) et plus jeunes. Robe or moyen avec des ar&ocirc;mes de poivre fra&icirc;chement moulu, d&#39;&eacute;pices et d&#39;orange. Saveurs de poivre noir et de caramel, notes de caramel anglais et de vanille en finale.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000299', 0, 0, 1, NULL, NULL, '2023-12-11 12:01:25', '2024-05-08 07:32:39'),
(300, '6577069a32d1b', 'PRO000300', 0, 'Tequila Jose Cuervo Silver 40%', '<p>Its aroma is fresh and clean with hints of agave. (40% ABV - 80 proof). On the palate, Especial Silver is equally crisp and clean, with subtle blue agave notes and a warm and smooth finish. No wonder Especial Silver is one of the fastest growing tequilas in America.</p>', 'Jose Cuervo Especial Silver is a crisp and smooth unaged tequila, carefully crafted by the master distillers at La Rojeña.', 21, '', NULL, 38, 104, '', 'Tequila Jose Cuervo Silver 40%', 'Jose Cuervo Especial Silver est une tequila non vieillie croustillante et onctueuse, soigneusement élaborée par les maîtres', '<p>Son ar&ocirc;me est frais et net avec des notes d&#39;agave. (40% ABV - preuve 80). En bouche, Especial Silver est tout aussi vif et net, avec de subtiles notes d&#39;agave bleu et une finale chaleureuse et douce. Il n&rsquo;est pas &eacute;tonnant qu&rsquo;Especial Silver soit l&rsquo;une des tequilas &agrave; la croissance la plus rapide en Am&eacute;rique.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000300', 0, 0, 1, NULL, NULL, '2023-12-11 12:54:50', '2024-05-08 07:32:52'),
(301, '6577076c5e243', 'PRO000301', 0, 'The Macallan 15yr Double Cask 43%', '<p>It has aged in two types of oak: specially selected handcrafted American oak barrels seasoned with dry Sherry Oloroso and European oak barrels. It reveals subtle notes of citrus, vanilla, spices and butterscotch giving this expression a soft and warm character.</p>', 'Double Cask 15 Years Old using a regal colour palette, exuding the rich opulence of smooth butterscotch and sweet spice.', 15, '', NULL, 35, 60, '', 'The Macallan 15yr Double Cask 43%', 'Double Cask 15 ans utilisant une palette de couleurs royales, exsudant la riche opulence du caramel au beurre doux et des épices douces.', '<p>Il a vieilli dans deux types de ch&ecirc;nes : des f&ucirc;ts de ch&ecirc;ne am&eacute;ricain artisanaux sp&eacute;cialement s&eacute;lectionn&eacute;s, assaisonn&eacute;s avec du Sherry Oloroso sec et des f&ucirc;ts de ch&ecirc;ne europ&eacute;en. Il r&eacute;v&egrave;le de subtiles notes d&#39;agrumes, de vanille, d&#39;&eacute;pices et de caramel au beurre donnant &agrave; cette expression un caract&egrave;re doux et chaleureux.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000301', 0, 0, 1, NULL, NULL, '2023-12-11 12:58:20', '2024-06-11 09:06:50'),
(302, '6577087392a8d', 'PRO000302', 0, 'The Macallan 18yr Double Cask 43%', '<p>Macallan 18 Year Old Double Cask 2022 Release 43% - Made by blending 18-year-old whisky from European and American oak casks, both of which are seasoned with sherry, this is a warming, sweet single malt and the pinnacle of Macallan&#39;s Double Cask range. Cask No.</p>', 'Sherry seasoned American oak adds delicate vanilla to the subtle spice of European oak, delivering a whisky with a sweeter, warmer taste and character', 15, '', NULL, 35, 60, '', 'The Macallan 18yr Double Cask 43%', 'Le chêne américain assaisonné au sherry ajoute une vanille délicate aux épices subtiles du chêne européen, offrant ainsi un whisky', '<p>Macallan 18 ans Double Cask 2022 version 43 % - Fabriqu&eacute; en m&eacute;langeant du whisky de 18 ans d&#39;&acirc;ge &agrave; partir de f&ucirc;ts de ch&ecirc;ne europ&eacute;en et am&eacute;ricain, tous deux assaisonn&eacute;s avec du sherry, il s&#39;agit d&#39;un single malt chaleureux et doux et le summum du Double Cask de Macallan. gamme. Num&eacute;ro de f&ucirc;t</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000302', 0, 1, 2, NULL, NULL, '2023-12-11 13:02:43', '2024-05-15 12:09:06'),
(303, '6577092b86e9b', 'PRO000303', 0, 'Veuve Clicquot Brut Rich', '<p>The Rich blend is comprised of Pinot Noir (45%), the main pillar of Veuve Clicquot&#39;s winemaking, which gives the champagne its fundamental structure. The large part of Meunier (40%) provides roundness to the blend and Chardonnay (15%) completes it with extra freshness.</p>\r\n\r\n<p>&nbsp;</p>', 'Veuve Clicquot Brut Rich satisfies with delicious fruit flavors. It is a sparkling wine blend handcrafted for discerning palates.', 23, '', NULL, 37, 105, '', 'Veuve Clicquot Brut Rich', 'Veuve Clicquot Brut Rich satisfait avec de délicieuses saveurs de fruits. Il s\'agit d\'un assemblage de vins mousseux élaboré à la main pour', '<p>L&#39;assemblage Riche est compos&eacute; de Pinot Noir (45%), principal pilier de la vinification de Veuve Clicquot, qui donne au champagne sa structure fondamentale. La grande partie du Meunier (40%) apporte de la rondeur &agrave; l&#39;assemblage et le Chardonnay (15%) le compl&egrave;te avec un suppl&eacute;ment de fra&icirc;cheur.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000303', 0, 0, 1, NULL, NULL, '2023-12-11 13:05:47', '2024-02-05 06:59:37'),
(304, '657709aa48ee7', 'PRO000304', 0, 'Veuve Clicquot Rose', '<p>Veuve Clicquot Ros&eacute; ensures the consistency of the House style: an intense and elegant champagne with a delightfully luscious, fruit-based charm. The coppery champagne, the burst of red fruit aromas&hellip;to achieve it, the blend is an essential element, a creative act.</p>', 'Its nose is intense and elegant. Notes of raspberry, wild starwberry and cherry predominate, followed by a touch of dried fruits and pastry.', 23, '', NULL, 37, 105, '', 'Veuve Clicquot Rose', 'Son nez est intense et élégant. Des notes de framboise, de myrtille sauvage et de cerise prédominent, suivies d\'une touche d', '<p>Veuve Clicquot Ros&eacute; assure la coh&eacute;rence du style de la Maison : un champagne intense et &eacute;l&eacute;gant au charme fruit&eacute; d&eacute;licieusement gourmand. Le champagne cuivr&eacute;, l&#39;&eacute;clatement des ar&ocirc;mes de fruits rouges&hellip; pour y parvenir, l&#39;assemblage est un &eacute;l&eacute;ment essentiel, un acte cr&eacute;atif.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000304', 0, 0, 1, NULL, NULL, '2023-12-11 13:07:54', '2024-02-05 06:59:37'),
(305, '65802ebcce29c', 'PRO000305', 0, 'Test 18/12/2023', '<p>-</p>', '-', 11, '', NULL, 32, 82, '', 'Test 18/12/2023', '-', '<p>-</p>', NULL, NULL, 0, NULL, 0, NULL, 1, 'LQ000305', 0, 1, 2, NULL, NULL, '2023-12-18 11:36:28', '2024-02-08 12:51:22'),
(306, '658678874349b', 'PRO000306', 0, '4Th Street Sweet Rose', '<p>The 4th Street Sweet Ros&eacute; has a delightful strawberry pink colour. The wine has fascinating aromas of strawberries with is followed by luscious berry flavours on the palate. Best paired with fresh fruit platters made with watermelon, strawberries, and blackberries. Also pairs with sushi and seafood dishes.</p>\r\n\r\n<p>&nbsp;</p>', '4th Street sweet rose is a South African wine classified as South African wines or rose wine. It has 7% ABV. It is offered in 750 ml, 1.5 litres.', 22, '', NULL, 46, 106, '', '4Th Street Sweet Rose', 'Le rose doux 4th Street est un vin sud-africain classé parmi les vins sud-africains ou vin rosé. Il contient 7 % d\'alcoolémie. Il est proposé en', '<p>Le 4th Street Sweet Ros&eacute; a une d&eacute;licieuse couleur rose fraise. Le vin pr&eacute;sente des ar&ocirc;mes fascinants de fraises suivis de succulentes saveurs de baies en bouche. Id&eacute;al avec des plateaux de fruits frais &agrave; base de past&egrave;que, de fraises et de m&ucirc;res. Se marie &eacute;galement avec les sushis et les plats de fruits de mer.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000306', 0, 0, 1, NULL, NULL, '2023-12-23 06:04:55', '2024-02-05 06:59:37'),
(307, '6586792cdddf5', 'PRO000307', 0, 'Allure Pinot Grigio', '<p>The little luxury that doesn&#39;t need a reason. But it brings a lot of enjoyment, fun and a great performance. The Pinot Grigio has developed into a trend grape variety in recent years. White, semi-dry Italian wine captivates with the scent of golden apples, juicy pears and ripe quince.</p>', 'White, semi-dry Italian wine captivates with the scent of golden apples, juicy pears and ripe quince. The taste is refreshing, slightly fruity.', 22, '', NULL, 40, 84, '', 'Allure Pinot Grigio', 'Le vin italien blanc demi-sec séduit par son parfum de pommes dorées, de poires juteuses et de coings mûrs. Le goût est rafraîchissant', '<p>Le petit luxe qui n&#39;a pas besoin de raison. Mais cela apporte beaucoup de plaisir, de plaisir et une belle performance. Le Pinot Grigio est devenu un c&eacute;page tendance ces derni&egrave;res ann&eacute;es. Le vin italien blanc demi-sec s&eacute;duit par son parfum de pommes dor&eacute;es, de poires juteuses et de coings m&ucirc;rs.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000307', 0, 0, 1, NULL, NULL, '2023-12-23 06:07:40', '2024-02-05 06:59:37'),
(308, '658679dbac36e', 'PRO000308', 0, 'Amani Bay Paradise Sweet White', '<p>This Amani Bay is a sweet white with a soft and fruity white blend. The wine has a light pale yellow colour with a faint greenish tinge. Nose: is a flinty tropical fruit expression. Palate: expresses a crisp and fruity white wine blend with great tropical flavours.</p>\r\n\r\n<p>&nbsp;</p>', 'sweet white with a soft and fruity white blend. The wine has a light pale yellow colour with a faint greenish tinge.', 22, '', NULL, 40, 107, '', 'Amani Bay Paradise Sweet White', 'blanc doux avec un mélange blanc doux et fruité. Le vin a une couleur jaune pâle clair avec une légère teinte verdâtre.', '<p>Cet Amani Bay est un blanc doux avec un m&eacute;lange blanc doux et fruit&eacute;. Le vin a une couleur jaune p&acirc;le clair avec une l&eacute;g&egrave;re teinte verd&acirc;tre. Nez : c&#39;est une expression de fruits tropicaux &agrave; silex. Bouche : exprime un assemblage de vins blancs vifs et fruit&eacute;s aux belles saveurs tropicales.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000308', 0, 0, 1, NULL, NULL, '2023-12-23 06:10:35', '2024-02-05 06:59:37'),
(309, '65867a6f9b94a', 'PRO000309', 0, 'Amani Bay Smooth Red', '<p>Amani Bay Smooth Red shows a charming cherry red fruit expression. On the nose is an enticing toast impression combined with fresh lime and a satisfying liquorice expression. The palate entrance expresses a delicate tannin structure with an excellent fusion of coffee, chocolate and a sweet ripe black fruit. The wine has a perfectly balanced palate with the oak component adding to the complexity.&nbsp; Best served with curry dishes, beef and lamb roast.</p>', 'Amani Bay Smooth Red is a South African wine classified as red wine. It has 12% ABV (alcohol by volume).', 22, '', NULL, 33, 107, '', 'Amani Bay Smooth Red', 'Amani Bay Smooth Red est un vin sud-africain classé comme vin rouge. Il contient 12 % ABV (alcool en volume).', '<p>Amani Bay Smooth Red montre une charmante expression de fruits rouge cerise. Au nez, une s&eacute;duisante impression de pain grill&eacute; associ&eacute;e &agrave; du citron vert frais et une expression de r&eacute;glisse satisfaisante. L&#39;entr&eacute;e en bouche exprime une structure tannique d&eacute;licate avec une excellente fusion de caf&eacute;, de chocolat et d&#39;un fruit noir m&ucirc;r et sucr&eacute;. Le vin a une bouche parfaitement &eacute;quilibr&eacute;e avec la composante bois&eacute;e ajoutant &agrave; la complexit&eacute;. Meilleur servi avec des plats de curry, du b&oelig;uf et du r&ocirc;ti d&#39;agneau.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000309', 0, 0, 1, NULL, NULL, '2023-12-23 06:13:03', '2024-02-05 06:59:37'),
(310, '65867b1b154c9', 'PRO000310', 0, 'Amani Bay Fresh White', '<p>The Amani Bay Fresh White is the perfect wine to pair with special occasions shared with friends and loved ones. This blend has a vibrant light green color. The nose is clean with a full ripe expression of tropical citrus fruits. A well-balanced harmonious blend gently lingers on the palate.</p>', 'Amani Bay Fresh White is a South African wine classified as white wine. It contains 12.5% ABV (alcohol by volume).', 22, '', NULL, 40, 107, '', 'Amani Bay Fresh White', 'Amani Bay Fresh White est un vin sud-africain classé comme vin blanc. Il contient 12,5% ABV (alcool en volume).', '<p>L&#39;Amani Bay Fresh White est le vin parfait pour accompagner des occasions sp&eacute;ciales partag&eacute;es avec des amis et des proches. Ce m&eacute;lange a une couleur vert clair vibrante. Le nez est net avec une expression pleine et m&ucirc;re d&#39;agrumes tropicaux. Un m&eacute;lange harmonieux et &eacute;quilibr&eacute; persiste doucement en bouche.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000310', 0, 0, 1, NULL, NULL, '2023-12-23 06:15:55', '2024-02-05 06:59:37'),
(311, '65867bfb7f05a', 'PRO000311', 0, 'Amani Bay Sweet Red', '<p>Amani Bay Sweet Red is a popular South African Red Sweet still wine mostly taken during special occasions. Amani Bay Sweet Red contains 9% alcohol. If within CBD, orders will be delivered within 20min or less.</p>', 'Soft and smooth from the combination of ingredients such as barley. and carefully selected high-quality hops', 22, '', NULL, 33, 107, '', 'Amani Bay Sweet Red', 'Doux et onctueux grâce à la combinaison d\'ingrédients tels que l\'orge. et des houblons de haute qualité soigneusement sélectionnés', '<p>Amani Bay Sweet Red est un vin tranquille rouge doux sud-africain populaire, principalement consomm&eacute; lors d&#39;occasions sp&eacute;ciales. Amani Bay Sweet Red contient 9 % d&#39;alcool. Si vous &ecirc;tes dans le CBD, les commandes seront livr&eacute;es dans un d&eacute;lai de 20 minutes ou moins.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000311', 0, 0, 1, NULL, NULL, '2023-12-23 06:19:39', '2024-02-05 06:59:37'),
(312, '65867c83c4e1b', 'PRO000312', 0, 'Amarula', '<p>Amarula original is fresh, smooth and well-rounded cream liqueur. It has a creamy consistency, with subtle tastes of exotic Marula fruit, followed by tones of vanilla, caramel and nuts.</p>', 'It has a creamy consistency, with subtle tastes of exotic Marula fruit, followed by tones of vanilla, caramel and nuts.', 21, '', NULL, 30, 108, '', 'Amarula', 'Il a une consistance crémeuse, avec des goûts subtils de fruits exotiques Marula , suivis de tons de vanille, de caramel et de noix.', '<p>Amarula original est une liqueur de cr&egrave;me fra&icirc;che, onctueuse et ronde. Il a une consistance cr&eacute;meuse, avec des go&ucirc;ts subtils de fruits exotiques de Marula, suivis de notes de vanille, de caramel et de noix.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000312', 0, 0, 1, NULL, NULL, '2023-12-23 06:21:55', '2024-05-08 07:35:40'),
(313, '65867cd001679', 'PRO000313', 0, 'Amarula', '<p>The spirit is aged for three years, then blended with cream. Amarula has hints of chocolate, vanilla, mango and caramel. The Marula Spirit sprouts from the delicious Marula fruit of the sub-equatorial Africa.</p>', 'Rich and creamy with a generous caramel backdrop supported by notes of chocolate, baked banana, nutmeg, and hints of cinnamon', 21, '', NULL, 30, 108, '', 'Amarula', 'Riche et crémeux avec un fond de caramel généreux soutenu par des notes de chocolat, de banane cuite, de muscade et des notes de cannelle', '<p>Le spiritueux est vieilli trois ans, puis assembl&eacute; &agrave; de la cr&egrave;me. Amarula a des notes de chocolat, de vanille, de mangue et de caramel. Le Marula Spirit est issu du d&eacute;licieux fruit Marula de l&#39;Afrique sub-&eacute;quatoriale.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000313', 0, 0, 1, NULL, NULL, '2023-12-23 06:23:12', '2024-02-05 06:59:37'),
(314, '65867deaf08dc', 'PRO000314', 0, 'Armand De Brignac Ace Spades BrutRose', '<p>Its bouquet is rich and pure with red fruits up front and delicately smoky grilled notes behind. The Champagne is fresh and full-bodied on the palate with aromas of fresh strawberries and blackcurrant and Armand de Brignac&#39;s characteristic long, silky finish.</p>\r\n\r\n<p>&nbsp;</p>', 'Armand de Brignac Brut Rosé champagne is a beautiful salmon-hued wine produced in the traditional, old-world style, from grape to glass.', 23, '', NULL, 37, 109, '', 'Armand De Brignac Ace Spades BrutRose', 'Le champagne Armand de Brignac Brut Rosé est un beau vin aux teintes saumonées produit dans le style traditionnel d\'antan, du raisin au verre.', '<p>Son bouquet est riche et pur avec des fruits rouges en t&ecirc;te et des notes grill&eacute;es d&eacute;licatement fum&eacute;es. Le Champagne est frais et cors&eacute; en bouche avec des ar&ocirc;mes de fraises fra&icirc;ches et de cassis et une finale longue et soyeuse caract&eacute;ristique d&#39;Armand de Brignac.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000314', 0, 0, 1, NULL, NULL, '2023-12-23 06:27:54', '2024-02-05 06:59:37'),
(315, '65867fcf1af04', 'PRO000315', 0, 'Armand De Brignac Ace  Spades BrutGold', '<p>Marvelously complex and full-bodied, its bouquet is both fresh and lively, with light floral notes. On the palate, our Brut Gold has a sumptuous, racy fruit character perfectly integrated with the wine&#39;s subtle brioche accents.</p>', 'Armand De Brignac Ace Of Spades Brut Gold is a complex Champagne is composed of a third of Chardonnay, a third of Pinot Meunier..', 23, '', NULL, 37, 109, '', 'Armand De Brignac Ace  Spades BrutGold', 'Armand De Brignac Ace Of Spades Brut Gold est un Champagne complexe composé d\'un tiers de Chardonnay, d\'un tiers de Pinot Meunier.', '<p>Merveilleusement complexe et cors&eacute;, son bouquet est &agrave; la fois frais et vif, avec de l&eacute;g&egrave;res notes florales. En bouche, notre Brut Gold pr&eacute;sente un caract&egrave;re fruit&eacute; somptueux et rac&eacute; parfaitement int&eacute;gr&eacute; aux subtils accents brioch&eacute;s du vin.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000315', 0, 0, 1, NULL, NULL, '2023-12-23 06:35:59', '2024-02-05 06:59:37'),
(316, '658681290197c', 'PRO000316', 0, 'Bacardi Carta Oro Superior Gold Rum', '<p>A distinctive golden rum with a smooth taste and subtle mellow characteristics which is extended ageing process by the infusion of subtle nut, wood and dried fruit flavours.</p>', 'BACARDÍ Gold Rum is hand blended, charcoal filtered and aged for two years in American white oak barrels.', 21, '', NULL, 34, 110, '', 'Bacardi Carta Oro Superior Gold Rum', 'Le rhum BACARDÍ Gold est mélangé à la main, filtré au charbon de bois et vieilli pendant deux ans en fûts de chêne blanc américain.', '<p>Un rhum dor&eacute; distinctif avec un go&ucirc;t doux et des caract&eacute;ristiques subtiles et moelleuses dont le processus de vieillissement est prolong&eacute; par l&#39;infusion d&#39;ar&ocirc;mes subtils de noix, de bois et de fruits secs.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000316', 0, 0, 1, NULL, NULL, '2023-12-23 06:41:45', '2024-05-08 07:37:23'),
(317, '658681a0f3474', 'PRO000317', 0, 'Bacardi Carta Negra Black Rum 40%', '<p>Bacardi Carta Negra Rum is a medium bodied dark rum, packed with smoky wood flavours, sweet molasses, tropical fruits and a buttery finish. On the light side of traditional dark rums, retaining the perfect balance despite its robust flavours.</p>', 'It is mellowed in heavily charred barrels which delivers a strong presence of vanilla, caramel, liquorice and molasses.', 21, '', NULL, 34, 110, '', 'Bacardi Carta Negra Black Rum 40%', 'Il est adouci dans des fûts fortement carbonisés qui délivrent une forte présence de vanille, de caramel, de réglisse et de mélasse.', '<p>Le rhum Bacardi Carta Negra est un rhum brun moyennement cors&eacute;, rempli de saveurs de bois fum&eacute;, de m&eacute;lasse sucr&eacute;e, de fruits tropicaux et d&#39;une finale beurr&eacute;e. Du c&ocirc;t&eacute; l&eacute;ger des rhums ambr&eacute;s traditionnels, conservant l&#39;&eacute;quilibre parfait malgr&eacute; ses ar&ocirc;mes charpent&eacute;s.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000317', 0, 0, 1, NULL, NULL, '2023-12-23 06:43:44', '2024-05-08 07:37:37'),
(318, '658682079f1f8', 'PRO000318', 0, 'Bacardi Carta Blanca Superior White Rum', '<p>Mild, soft, aromatic and delicate. Candied fruit, crystallised fruit, impressions of vanilla and apricot, sweet, creamy almond/marzipan flavours (almond croissant), Sweet fruity overtones, smooth and light. Finish: Dry, crisp and very clean finish, slightly sweet.</p>', 'Bacardi Carta Blanca is a light tasting and aromatic white Rum with delicate floral and fruity notes, ideal for mixing.', 21, '', NULL, 34, 110, '', 'Bacardi Carta Blanca Superior White Rum', 'Bacardi Carta Blanca est un rhum blanc au goût léger et aromatique aux délicates notes florales et fruitées, idéal pour les mélanges.', '<p>Doux, doux, aromatique et d&eacute;licat. Fruits confits, fruits confits, impressions de vanille et d&#39;abricot, saveurs douces et cr&eacute;meuses d&#39;amande/p&acirc;te d&#39;amande (croissant aux amandes), notes fruit&eacute;es douces, douces et l&eacute;g&egrave;res. Finale : Finale s&egrave;che, vive et tr&egrave;s propre, l&eacute;g&egrave;rement sucr&eacute;e.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000318', 0, 0, 1, NULL, NULL, '2023-12-23 06:45:27', '2024-05-08 07:37:52'),
(319, '658682c430684', 'PRO000319', 0, 'Baron Philippe De Rothschild Cabernet', '<p>Deep purple; intense cassis aroma &amp; flavour with herbal notes; medium-full bodied with firm tannins and raspberry notes in the finish. A classified First Growth, Ch&acirc;teau Mouton Rothschild spans 90 hectares (222 acres) of vines at Pauillac, in the M&eacute;doc.</p>\r\n\r\n<p>&nbsp;</p>', 'Deep purple; intense cassis aroma & flavour with herbal notes; medium-full bodied with firm tannins and raspberry notes in the finish.', 22, '', NULL, 33, 111, '', 'Baron Philippe De Rothschild Cabernet', 'Violet foncé; arôme et saveur intenses de cassis avec des notes herbacées; mi-corsé avec des tanins fermes et des notes de framboise en finale.', '<p>Violet fonc&eacute;; ar&ocirc;me et saveur intenses de cassis avec des notes herbac&eacute;es; mi-cors&eacute; avec des tanins fermes et des notes de framboise en finale. Class&eacute; Premier Cru, le Ch&acirc;teau Mouton Rothschild s&#39;&eacute;tend sur 90 hectares de vignes &agrave; Pauillac, dans le M&eacute;doc.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000319', 0, 0, 1, NULL, NULL, '2023-12-23 06:48:36', '2024-02-05 06:59:37'),
(320, '65868333b955a', 'PRO000320', 0, 'Barone Romero Spanish Red Wine 10.5 %', '<p>Baron Romero is an awesome wine blended from Spain. ... Baron Romero is a Spanish wine which comes in red and white with a sweet and berry and cherry mixed together with loamy soil note, subtle spicy and a composed oak finish.</p>', 'Baron Romero Spanish Red Wine is a rich and flavorful wine made from carefully selected Tempranillo grapes grown in the La Rioja region of Spain.', 22, '', NULL, 33, 112, '', 'Barone Romero Spanish Red Wine 10.5 %', 'Le vin rouge espagnol Baron Romero est un vin riche et savoureux élaboré à partir de raisins Tempranillo soigneusement sélectionnés et cultivés', '<p>Baron Romero est un superbe vin d&#39;Espagne. ... Baron Romero est un vin espagnol qui se d&eacute;cline en rouge et blanc avec une note sucr&eacute;e de baies et de cerises m&eacute;lang&eacute;es &agrave; une note de sol limoneux, d&#39;&eacute;pices subtiles et une finale de ch&ecirc;ne compos&eacute;e.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000320', 0, 0, 1, NULL, NULL, '2023-12-23 06:50:27', '2024-02-12 10:03:37'),
(321, '6586862a75a03', 'PRO000321', 0, 'Beer Faxe', '<p>The golden color and the rich, creamy foam promise an unforgettable experience from the first sip. Aroma: Fresh and clean, with notes of malt and a light hop aroma. Taste: Well-balanced, medium-bodied with a mild malty sweetness and a discreet bitter finish.</p>\r\n\r\n<p>&nbsp;</p>', 'There is a slight sweetness to this FAXE beer resulting in a balanced beer with a vinous taste.', 11, '', NULL, 32, 20, '', 'Beer Faxe', 'Il y a une légère douceur dans cette bière FAXE résultant en une bière équilibrée au goût vineux.', '<p>La couleur dor&eacute;e et la mousse riche et cr&eacute;meuse promettent une exp&eacute;rience inoubliable d&egrave;s la premi&egrave;re gorg&eacute;e. Ar&ocirc;me : Frais et propre, avec des notes de malt et un l&eacute;ger ar&ocirc;me de houblon. Go&ucirc;t : Bien &eacute;quilibr&eacute;, moyennement cors&eacute; avec une l&eacute;g&egrave;re douceur malt&eacute;e et une finale am&egrave;re discr&egrave;te.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000321', 3, 0, 1, NULL, NULL, '2023-12-23 07:03:06', '2024-06-06 16:28:39'),
(322, '6586885d00280', 'PRO000322', 0, 'Bottega Gold Prosecco', '<p>Smell: Typical, characteristic and refined with fruity notes (especially green apple, pear, citrus), floral (white flowers, acacia, wisteria and lily of the valley) and closing with sage and spices. Taste: Soft, harmonious and elegant, with a slim body and a present and well-balanced acidity.</p>', 'Typical, characteristic and refined with fruity notes (in particular green apple, pear, citrus), floral and to finish with sage and spicy.', 22, '', NULL, 36, 113, '', 'Bottega Gold Prosecco', 'Typique, caractéristique et raffiné avec des notes fruitées (notamment pomme verte, poire, agrumes), florales et pour finir sur', '<p>Odeur : Typique, caract&eacute;ristique et raffin&eacute;e avec des notes fruit&eacute;es (notamment pomme verte, poire, agrumes), florales (fleurs blanches, acacia, glycine et muguet) et se terminant par de la sauge et des &eacute;pices. Go&ucirc;t : Doux, harmonieux et &eacute;l&eacute;gant, avec un corps &eacute;lanc&eacute; et une acidit&eacute; pr&eacute;sente et bien &eacute;quilibr&eacute;e.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000322', 0, 0, 1, NULL, NULL, '2023-12-23 07:12:29', '2024-02-05 06:59:37'),
(323, '6586890fa28ea', 'PRO000323', 0, 'Bottega Rose Gold', '<p>Bottega Rose Gold is a 100% Pinot Noir Prosecco from Lombardy in Italy. The cool climate and hilly terrain makes the ideal place for sparkling wine production. Intense, elegant, complex, characterized by floral and fruity notes, mainly mixed berries, currants and wild strawberries.</p>', 'Color and Appearance: Brilliant, pale pink colour, fine and persistent perlage. Smell: Intense, complex, elegant, characterized by floral scents.', 22, '', NULL, 45, 113, '', 'Bottega Rose Gold', 'Couleur et Aspect : Robe brillante, rose pâle, perlage fin et persistant. Odeur : Intense, complexe, élégante, caractérisée par des senteurs florales.', '<p>Bottega Rose Gold est un Prosecco 100 % Pinot Noir de Lombardie en Italie. Le climat frais et le terrain vallonn&eacute; en font un endroit id&eacute;al pour la production de vins mousseux. Intense, &eacute;l&eacute;gant, complexe, caract&eacute;ris&eacute; par des notes florales et fruit&eacute;es, principalement des baies m&eacute;lang&eacute;es, des groseilles et des fraises des bois.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000323', 0, 0, 1, NULL, NULL, '2023-12-23 07:15:27', '2024-02-05 06:59:37'),
(324, '65868a5e9d2ab', 'PRO000324', 0, 'Bottega Sambuca', '<p>Made with star anise, this sambuca is rich in fragrant compounds making this liquor sweet and intense with an unique taste for the most demanding. A dense, velvety liqueur with great character and a very refined bouquet. Perfect after meals, it can be served neat, chilled, or added to an espresso.</p>', 'Typical white sambucas are dominated by the harsh flavour of star anise. Opal Bianca Sambuca is known for its round flavour and sweet texture.', 21, '', NULL, 30, 113, '', 'Bottega Sambuca', 'Les sambucas blanches typiques sont dominées par la saveur âpre de l\'anis étoilé. L\'Opale Bianca Sambuca est connue pour', '<p>Fabriqu&eacute;e &agrave; base d&#39;anis &eacute;toil&eacute;, cette sambuca est riche en compos&eacute;s parfum&eacute;s rendant cette liqueur douce et intense au go&ucirc;t unique pour les plus exigeants. Une liqueur dense et velout&eacute;e avec beaucoup de caract&egrave;re et un bouquet tr&egrave;s raffin&eacute;. Parfait apr&egrave;s les repas, il peut &ecirc;tre servi pur, frais ou ajout&eacute; &agrave; un expresso.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000324', 0, 0, 1, NULL, NULL, '2023-12-23 07:21:02', '2024-02-05 06:59:37'),
(325, '65868bdfe0049', 'PRO000325', 0, 'Bottega White Gold', '<p>Bottega White Gold is a Venezia DOC wine obtained from the vinification of Glera, Chardonnay and Pinot grapes. With its great character, this Brut sparkling wine is fresh and elegant, representing an expression of the territory where grapes are grown, among the provinces of Treviso and Venice.</p>', 'a Venezia DOC wine obtained from the vinification of Glera, Chardonnay and Pinot grapes.', 22, '', NULL, 45, 113, '', 'Bottega White Gold', 'un vin Venezia DOC obtenu à partir de la vinification des raisins Glera, Chardonnay et Pinot.', '<p>Bottega White Gold est un vin Venezia DOC obtenu &agrave; partir de la vinification des raisins Glera, Chardonnay et Pinot. Avec son grand caract&egrave;re, ce vin mousseux Brut est frais et &eacute;l&eacute;gant, repr&eacute;sentant une expression du territoire o&ugrave; sont cultiv&eacute;s les raisins, entre les provinces de Tr&eacute;vise et de Venise.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000325', 0, 0, 1, NULL, NULL, '2023-12-23 07:27:27', '2024-02-05 06:59:37'),
(326, '65868cccaf9ac', 'PRO000326', 0, 'Bottega Limoncino De Grappa', '<p>Limoncino Bottega is a &ldquo;limoncello&rdquo;, traditional Italian liqueur, dating back to the end of the nineteenth century. It is produced from an infusion of &ldquo;Femminello&rdquo; lemon peel. This cultivar which is widespread in Italy and characterised by a peel with a thin grain and high quality essential oils. This variety of lemon is called &ldquo;Femminello&rdquo; because of the fertility of the plant.</p>\r\n\r\n<p>&nbsp;</p>', 'Produced from fragrantly perfumed rinds of fresh Sicilian lemons, infused in alcohol, leading to an extraction of essential oils.', 21, '', NULL, 30, 113, '', 'Bottega Limoncino De Grappa', 'Produit à partir d\'écorces de citrons siciliens frais, infusées dans de l\'alcool, conduisant à une extraction d\'huiles essentielles.', '<p>Le Limoncino Bottega est un &laquo; limoncello &raquo;, liqueur italienne traditionnelle, datant de la fin du XIXe si&egrave;cle. Il est &eacute;labor&eacute; &agrave; partir d&#39;une infusion d&#39;&eacute;corces de citron &laquo; Femminello &raquo;. Ce cultivar r&eacute;pandu en Italie et caract&eacute;ris&eacute; par une peau au grain fin et des huiles essentielles de haute qualit&eacute;. Cette vari&eacute;t&eacute; de citron est appel&eacute;e &laquo; Femminello &raquo; en raison de la fertilit&eacute; de la plante.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000326', 0, 0, 1, NULL, NULL, '2023-12-23 07:31:24', '2024-02-05 06:59:37'),
(327, '65868d8751153', 'PRO000327', 0, 'Bottega Poeti Prosecco Extraa Dry', '<p>Delicate and fresh wine, with a clear and balanced taste; round and smooth on the palate Soft, captivating and balanced, with a pleasant blend of acidity and sugar, an agreeable sapidity and a typical aromaticity with delicate fruity and floral notes.</p>', 'with a pleasant blend of acidity and sugar, an agreeable sapidity and a typical aromaticity with delicate fruity and floral notes.', 22, '', NULL, 36, 113, '', 'Bottega Poeti Prosecco Extraa Dry', 'avec un agréable mélange d\'acidité et de sucre, une sapidité agréable et une spice typique avec de délicates notes fruitées et florales.', '<p>Vin d&eacute;licat et frais, au go&ucirc;t clair et &eacute;quilibr&eacute; ; Bouche ronde et onctueuse. Doux, captivant et &eacute;quilibr&eacute;, avec un agr&eacute;able m&eacute;lange d&#39;acidit&eacute; et de sucre, une sapidit&eacute; agr&eacute;able et une spice typique avec de d&eacute;licates notes fruit&eacute;es et florales.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000327', 0, 0, 1, NULL, NULL, '2023-12-23 07:34:31', '2024-02-05 06:59:37');
INSERT INTO `product` (`id`, `uniqid`, `product_item_id`, `supplier_id`, `product_name`, `description`, `short_description`, `category_id`, `product_image`, `images`, `subcategory_id`, `brand_id`, `video`, `product_name_fr`, `short_description_fr`, `page_content_fr`, `product_qty`, `tech_data_sheet`, `retail_price`, `discount_price`, `is_admin_approve`, `most_view`, `is_product_bestseller`, `sku`, `average_rating`, `offer`, `status`, `in_store`, `in_online`, `created_at`, `updated_at`) VALUES
(328, '65868ec8c88b9', 'PRO000328', 0, 'Café De Paris Peach', '<p>Cafe de Paris Peach Caffe de Paris Peach Caffe de Paris 25.4 fl oz (750 ml) with a rich flavor of ripe peach and just a mild mouth. This sparkling wine has a refreshing taste that brings out the pupil and sexiness. The gentle repelling foam will quickly hydrate your throat.</p>\r\n\r\n<p>&nbsp;</p>', 'Peach flavoured Cafe de Paris is a cocktail based on Sparkling Wine.', 22, '', NULL, 45, 88, '', 'Café De Paris Peach', 'Le Café de Paris aromatisé à la Pêche est un cocktail à base de Vin Pétillant.', '<p>Caf&eacute; de Paris Peach Caffe de Paris Peach Caffe de Paris 25,4 fl oz (750 ml) avec une riche saveur de p&ecirc;che m&ucirc;re et juste une bouche douce. Ce vin mousseux a un go&ucirc;t rafra&icirc;chissant qui fait ressortir la pupille et le c&ocirc;t&eacute; sexy. La mousse douce et r&eacute;pulsive hydratera rapidement votre gorge.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000328', 0, 0, 1, NULL, NULL, '2023-12-23 07:39:52', '2024-02-05 06:59:37'),
(329, '65868fc982cff', 'PRO000329', 0, 'Camus Intensely Aromatic VSOP', '<p>CAMUS VSOP is an intensely aromatic cognac, whose floral and fruity profile with notes of oak, spice and vanilla derive from a careful selection of the eaux-de-vie reflecting the quintessential flavours of the Terroir, some of which coming from the renowned Cru of Borderies.</p>', 'CAMUS VSOP is a cognac with an intense aroma, whose floral and fruity bouquet with spicy oak and vanilla notes.', 21, '', NULL, 43, 114, '', 'Camus Intensely Aromatic VSOP', 'CAMUS VSOP est un cognac à l\'arôme intense, dont le bouquet floral et fruité aux notes épicées de chêne et de vanille.', '<p>CAMUS VSOP est un cognac intens&eacute;ment aromatique, dont le profil floral et fruit&eacute; aux notes de ch&ecirc;ne, d&#39;&eacute;pices et de vanille r&eacute;sulte d&#39;une s&eacute;lection rigoureuse des eaux-de-vie refl&eacute;tant les saveurs par excellence du Terroir, dont certaines proviennent du c&eacute;l&egrave;bre Cru de Borderies.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000329', 0, 0, 1, NULL, NULL, '2023-12-23 07:44:09', '2024-05-08 07:40:20'),
(330, '658690b84de3f', 'PRO000330', 0, 'Camus XO', '<p>On the nose the CAMUS XO cognac contains savoury aromas of bitter apricot and oranges, as well as notes of exotic fruit and a dash of deep cacao. On the palate, it is first silky with a honey-like texture and an intense florality, a direct result of the Instensity process.</p>\r\n\r\n<p>&nbsp;</p>', 'The XO with the best balance between fruity notes and wood components in the category.', 21, '', NULL, 43, 114, '', 'Camus XO', 'Le XO avec le meilleur équilibre entre notes fruitées et composants boisés de la catégorie.', '<p>Au nez, le cognac CAMUS XO pr&eacute;sente des ar&ocirc;mes savoureux d&#39;abricot amer et d&#39;orange, ainsi que des notes de fruits exotiques et une touche de cacao profond. En bouche, il est d&#39;abord soyeux avec une texture mielleuse et une floralit&eacute; intense, r&eacute;sultat direct du processus Intensit&eacute;.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000330', 0, 0, 1, NULL, NULL, '2023-12-23 07:48:08', '2024-02-05 06:59:37'),
(331, '65869177dc554', 'PRO000331', 0, 'Cheval Noir Saint Emilion 2017', '<p>This elegant red wine with balanced aromas of red fruits and harmonious notes of spices comes from one of the oldest vineyards of the Bordeaux region.</p>\r\n\r\n<p>&nbsp;</p>', 'This elegant red wine with balanced aromas of red fruits and harmonious notes of spices comes from one of the oldest vineyards of the Bordeaux region.', 22, '', NULL, 33, 115, '', 'Cheval Noir Saint Emilion 2017', 'Ce vin rouge élégant aux arômes équilibrés de fruits rouges et aux notes harmonieuses d\'épices est issu d\'un des plus anciens vignoble', '<p>Ce vin rouge &eacute;l&eacute;gant aux ar&ocirc;mes &eacute;quilibr&eacute;s de fruits rouges et aux notes harmonieuses d&#39;&eacute;pices est issu d&#39;un des plus anciens vignobles de la r&eacute;gion bordelaise.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000331', 0, 0, 1, NULL, NULL, '2023-12-23 07:51:19', '2024-02-12 10:00:45'),
(332, '6586abddeff65', 'PRO000332', 0, 'Chivas Regal 12yr With 2 Glass', '<p>A blend of the finest malt and grain whiskies, including Strathisla single malt and Strathclyde single grain are combined. Being matured for at least 12 years, this luxurious Speyside whisky delivers luxurious honey, vanilla and ripe apple notes. Over the years the classic taste has been maintained.</p>', 'Chivas Regal 12 years with 2 Rock glass. Chivas is a blend of many different malt and grain Scotch whiskies, matured for at least 12 years.', 15, '', NULL, 48, 27, '', 'Chivas Regal 12yr With 2 Glass', 'Chivas Regal 12 ans avec 2 verres Rock. Chivas est un mélange de nombreux whiskies écossais de malt et de grains différents, vieillis pendant au', '<p>Un m&eacute;lange des meilleurs whiskies de malt et de grain, dont le single malt Strathisla et le single grain Strathclyde sont combin&eacute;s. Affin&eacute; pendant au moins 12 ans, ce luxueux whisky du Speyside offre de luxueuses notes de miel, de vanille et de pomme m&ucirc;re. Au fil des ann&eacute;es, le go&ucirc;t classique a &eacute;t&eacute; conserv&eacute;.</p>', NULL, NULL, 0, NULL, 0, NULL, 1, 'LQ000332', 0, 1, 1, NULL, NULL, '2023-12-23 09:43:57', '2024-05-30 11:51:59'),
(333, '6586ad34eb501', 'PRO000333', 0, 'Chivas Regal 12yr', '<p>A blend of the finest malt and grain whiskies, including Strathisla single malt and Strathclyde single grain are combined. Being matured for at least 12 years, this luxurious Speyside whisky delivers luxurious honey, vanilla and ripe apple notes. Over the years the classic taste has been maintained.</p>', 'It\'s a blend of the finest malt and grain whiskies matured for at least 12 years. It has infusion of wild herbs, heather, honey and orchard fruits.', 15, '', NULL, 48, 27, '', 'Chivas Regal 12yr', 'Il s\'agit d\'un mélange des meilleurs whiskies de malt et de grain vieillis pendant au moins 12 ans. Il contient une infusion d\'herbes sauvages,', '<p>Un m&eacute;lange des meilleurs whiskies de malt et de grain, dont le single malt Strathisla et le single grain Strathclyde sont combin&eacute;s. Affin&eacute; pendant au moins 12 ans, ce luxueux whisky du Speyside offre de luxueuses notes de miel, de vanille et de pomme m&ucirc;re. Au fil des ann&eacute;es, le go&ucirc;t classique a &eacute;t&eacute; conserv&eacute;.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000333', 0, 0, 1, NULL, NULL, '2023-12-23 09:49:40', '2024-05-30 11:50:51'),
(334, '6586ade71855c', 'PRO000334', 0, 'Chivas Regal 13yr Extra', '<p>Chivas Regal Extra is a Blended Scotch whisky that is selectively matured in Olorosso sherry casks for deeper aromas, fruitiness and sweetness. Bottled at the standard 40% ABV. Dark amber. Sweet fruits of pear and melon, creamy toffee, milk chocolate, cinnamon and a hint of ginger.</p>', 'Chivas Regal Extra is a Blended Scotch whisky that is selectively matured in Olorosso sherry casks for deeper aromas, fruitiness and sweetness.', 15, '', NULL, 48, 27, '', 'Chivas Regal 13yr Extra', 'Chivas Regal Extra est un whisky écossais mélangé qui est vieilli de manière sélective dans des fûts de sherry Olorosso pour des arômes plus', '<p>Chivas Regal Extra est&nbsp;un whisky &eacute;cossais m&eacute;lang&eacute; qui est vieilli de mani&egrave;re s&eacute;lective dans des f&ucirc;ts de sherry Olorosso pour des ar&ocirc;mes plus profonds, un fruit&eacute; et une douceur. Mis en bouteille &agrave; la norme 40% ABV. Ambre fonc&eacute;. Fruits sucr&eacute;s de poire et de melon, caramel cr&eacute;meux, chocolat au lait, cannelle et un soup&ccedil;on de gingembre.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000334', 0, 0, 1, NULL, NULL, '2023-12-23 09:52:39', '2024-05-30 11:49:10'),
(335, '6586aee9d3614', 'PRO000335', 0, 'Clan Macgregor Scotch Whisky', '<p>Plenty of dark sugar, toasted nuts and a subtle grassy note on the nose, followed by dried fruit, white pepper and chewy toffee on the palate.</p>', '40% vol. The Clan MacGregor contains fifteen excellent malt whiskies that were blended with the finest grain whiskies.', 15, '', NULL, 48, 116, '', 'Clan Macgregor Scotch Whisky', '40% vol. Le Clan MacGregor contient quinze excellents whiskies de malt assemblés avec les meilleurs whiskies de grain.', '<p>Beaucoup de sucre noir, de noix grill&eacute;es et une subtile note herbac&eacute;e au nez, suivie de fruits secs, de poivre blanc et de caramel mou en bouche.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000335', 0, 0, 1, NULL, NULL, '2023-12-23 09:56:57', '2024-05-31 10:31:53'),
(336, '6586afe43554b', 'PRO000336', 0, 'Cognac D`Usse VSOP 40%', '<p>On the nose, D&#39;Usse VSOP Cognac reveals a powerful bouquet, rich in woody notes that are layered with touches of cinnamon and floral notes. Distinctively and unexpectedly smooth, with each taste, you savor hints of spices, almond and cinnamon. Subtle accents of honey and dried fruits are the finale.</p>', 'Naturally aged at least four and a half years in the cellars of France’s Chateau de Cognac, D’USSE VSOP Cognac emerges as a bold.', 21, '', NULL, 43, 117, '', 'Cognac D`Usse VSOP 40%', 'Naturellement vieilli au moins quatre ans et demi dans les caves du Château de Cognac en France, le Cognac D\'USSE VSOP apparaît comme un audacieux.', '<p>Au nez, le Cognac D&#39;Usse VSOP r&eacute;v&egrave;le un bouquet puissant, riche en notes bois&eacute;es qui se superposent &agrave; des touches de cannelle et des notes florales. D&#39;une douceur distinctive et inattendue, &agrave; chaque go&ucirc;t, vous savourez des notes d&#39;&eacute;pices, d&#39;amande et de cannelle. De subtils accents de miel et de fruits secs concluent le tout.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000336', 0, 0, 1, NULL, NULL, '2023-12-23 10:01:08', '2024-02-05 06:59:37'),
(337, '6586b09dce4f3', 'PRO000337', 0, 'Corona Extra Beer', '<p>Premium beer imported from Mexico, amber. Unique refreshing taste,Soft and smooth from the combination of ingredients such as barley. and carefully selected high-quality hops</p>', 'It is a 4.5º alcohol Pilsner-type beer that is currently sold in more than 180 countries on five continents.', 11, '', NULL, 32, 118, '', 'Corona Extra Beer', 'Il s\'agit d\'une bière de type Pilsner titrant 4,5º d\'alcool et actuellement vendue dans plus de 180 pays sur cinq continents.', '<p>Bi&egrave;re premium import&eacute;e du Mexique, ambr&eacute;e. Go&ucirc;t rafra&icirc;chissant unique, doux et onctueux gr&acirc;ce &agrave; la combinaison d&#39;ingr&eacute;dients tels que l&#39;orge. et des houblons de haute qualit&eacute; soigneusement s&eacute;lectionn&eacute;s</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000337', 0, 0, 1, NULL, NULL, '2023-12-23 10:04:13', '2024-02-12 11:35:56'),
(338, '6586b1a12de8c', 'PRO000338', 0, 'Dom Perignon Rose Vintage 2008 Champagne', '<p>Full-bodied and layered with an incredible, three-dimensional element to the wine. This is so transparent and dynamic with dark fruit, yet it remains vivid and bright. Refined and precise, it goes on and on. Really savory, fresh and incredibly pinot-noir-like.</p>', 'This shows incredible depth of fruit with strawberry, cherry and phenolics. Full-bodied and layered with an incredible, three-dimensional element.', 23, '', NULL, 37, 31, '', 'Dom Perignon Rose Vintage 2008 Champagne', 'Cela montre une incroyable profondeur de fruit avec des notes de fraise, de cerise et de phénols. Corsé et étagé avec un élément', '<p>Cors&eacute; et &eacute;tag&eacute; avec un &eacute;l&eacute;ment tridimensionnel incroyable dans le vin. C&#39;est si transparent et dynamique avec des fruits noirs, mais il reste vif et lumineux. Raffin&eacute; et pr&eacute;cis, il continue encore et encore. Vraiment savoureux, frais et incroyablement proche du pinot noir.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000338', 0, 0, 1, NULL, NULL, '2023-12-23 10:08:33', '2024-02-05 06:59:37'),
(339, '6586b2e02073d', 'PRO000339', 0, 'Don Simon Orange', '<p>Orange juice with pulp 100% not from concentrate DON SIMON 1l. Orange juice made from the best oranges in Valencia. A juice with pulp and 100% natural flavour, rich in vitamin C. Enjoy this delicious Premium juice from Don Sim&oacute;n.</p>', 'Orange juice made from the best oranges in Valencia. A juice with pulp and 100% natural flavour, rich in vitamin C.', 25, '', NULL, 55, 119, '', 'Don Simon Orange', 'Jus d\'orange élaboré à partir des meilleures oranges de Valence. Un jus à la pulpe et à l\'arôme 100% naturel, riche en vitamine C.', '<p>Jus d&#39;orange avec pulpe 100% non concentr&eacute; DON SIMON 1l. Jus d&#39;orange &eacute;labor&eacute; &agrave; partir des meilleures oranges de Valence. Un jus avec de la pulpe et un ar&ocirc;me 100% naturel, riche en vitamine C. Savourez ce d&eacute;licieux jus Premium de Don Sim&oacute;n.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000339', 0, 0, 2, NULL, NULL, '2023-12-23 10:13:52', '2024-06-06 15:38:21'),
(340, '6586b41847d33', 'PRO000340', 0, 'Drostdy-Hof Sweet Red 8%', '<p>Bright ruby colour. Bouquet: Light and fruity. Palate: Soft and refreshing with a clean, sweet finish. This wine can be served chilled as an aperitif.</p>', 'Drostdy Hof Sweet Red is a full-bodied and fruity ruby red South African wine with cherry and plum flavours with a naturally sweet finish.', 22, '', NULL, 33, 120, '', 'Drostdy-Hof Sweet Red 8%', 'Drostdy Hof Sweet Red est un vin sud-africain rouge rubis corsé et fruité aux saveurs de cerise et de prune avec une finale naturellement douce.', '<p>Robe rubis brillante. Bouquet : L&eacute;ger et fruit&eacute;. Bouche : Douce et rafra&icirc;chissante avec une finale nette et sucr&eacute;e. Ce vin peut &ecirc;tre servi frais &agrave; l&#39;ap&eacute;ritif.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000340', 0, 0, 1, NULL, NULL, '2023-12-23 10:19:04', '2024-02-12 10:02:41'),
(341, '6586b54f9a3e3', 'PRO000341', 0, 'Energy Drink Powermalt', '<p>Power Malt is specifically developed to enhance performance, and it has a higher malt content than its competitors. Malt is barley which is steeped and allowed to sprout and thereby creating carbohydrates. Power Malt brews use four different barley malts &ndash; with our caramel malt providing a deep, rich creamy flavor.</p>', 'Product InformationPowermaltDescriptionPowermalt is a malt-based energy drink. It is formulated with malt extrac.', 25, '', NULL, 56, 121, '', 'Energy Drink Powermalt', 'Informations sur le produitPowermaltDescriptionPowermalt est une boisson énergisante à base de malt. Il est formulé avec de l\'extrait de malt.', '<p>Power Malt est sp&eacute;cifiquement d&eacute;velopp&eacute; pour am&eacute;liorer les performances et sa teneur en malt est plus &eacute;lev&eacute;e que ses concurrents. Le malt est de l&#39;orge qui est tremp&eacute;e et laiss&eacute;e germer, cr&eacute;ant ainsi des glucides. Les bi&egrave;res Power Malt utilisent quatre malts d&#39;orge diff&eacute;rents &ndash; notre malt caramel offrant une saveur cr&eacute;meuse profonde et riche.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000341', 0, 0, 2, NULL, NULL, '2023-12-23 10:24:15', '2024-06-06 15:26:06'),
(342, '6586b61a1cdc7', 'PRO000342', 0, 'Energy Drink Supermalt', '<p>Supermalt is a non-alcoholic, caffeine-free malt drink that was originally developed for the Nigerian Army in 1972. It has a high content of B vitamins, minerals and nutrients, and carbohydrates. It is dark brown in colour and has a sweet flavour.</p>\r\n\r\n<p>&nbsp;</p>', 'Supermalt Original drink is one of the most popular non-alcoholic malt drinks that\'s rich in B-vitamins.', 25, '', NULL, 56, 121, '', 'Energy Drink Supermalt', 'La boisson Supermalt Original est l\'une des boissons maltées non alcoolisées les plus populaires, riche en vitamines B.', '<p>Le Supermalt est une boisson malt&eacute;e sans alcool et sans caf&eacute;ine qui a &eacute;t&eacute; initialement d&eacute;velopp&eacute;e pour l&#39;arm&eacute;e nig&eacute;riane en 1972. Elle a une teneur &eacute;lev&eacute;e en vitamines B, en min&eacute;raux, en nutriments et en glucides. Il est de couleur brun fonc&eacute; et a une saveur sucr&eacute;e.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000342', 0, 0, 2, NULL, NULL, '2023-12-23 10:27:38', '2024-06-06 15:26:06'),
(343, '6586b6b8c0513', 'PRO000343', 0, 'Fairview La Capra Merlot', '<p>The La Capra Merlot is the easy going, smooth jazz singer of wines. Bringing soft, ripe redcurrant fruits aromas and a smooth and integrated plum palate to the fore.</p>', 'This is the easy going, smooth jazz singer of wines. Bringing soft, ripe redcurrant fruits aromas and a smooth and integrated plum palate to the fore.', 22, '', NULL, 33, 122, '', 'Fairview La Capra Merlot', 'C\'est le chanteur de vins facile à vivre et doux. Mettant en avant des arômes de fruits rouges doux et mûrs et une bouche de prune douce et intégrée.', '<p>Le Merlot La Capra est le chanteur de vins facile &agrave; vivre et doux. Mettant en avant des ar&ocirc;mes de fruits rouges doux et m&ucirc;rs et une bouche de prune douce et int&eacute;gr&eacute;e.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000343', 0, 0, 1, NULL, NULL, '2023-12-23 10:30:16', '2024-02-12 10:01:55'),
(344, '6586b85fba94c', 'PRO000344', 0, 'Franschhoek Cellar Cabernet 2018', '<p>Deep crimson with intense blackcurrants and violets on the nose, there are also notes of currant and mulberry fruit along with attractive savoury oak spice. The palate is smooth with good weight and balance, this really is a great example of a new world Cab.</p>', 'Deep crimson with intense blackcurrants and violets on the nose, there are also notes of currant and mulberry fruit.', 22, '', NULL, 33, 123, '', 'Franschhoek Cellar Cabernet 2018', 'Pourpre profond avec des notes intenses de cassis et de violette au nez, on retrouve également des notes de groseille et de mûre.', '<p>Au nez, un pourpre profond avec des cassis et des violettes intenses, il y a aussi des notes de groseille et de m&ucirc;re ainsi que de jolies notes &eacute;pic&eacute;es de ch&ecirc;ne. La bouche est douce avec un bon poids et un bon &eacute;quilibre, c&#39;est vraiment un excellent exemple d&#39;un Cab du nouveau monde.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000344', 0, 0, 1, NULL, NULL, '2023-12-23 10:37:19', '2024-02-05 06:59:37'),
(345, '6586bb706bb22', 'PRO000345', 0, 'Freixenet Cardon Negro Brut Cava', '<p>Cordon Negro Brut is a crisp, clean and well-balanced &#39;cava&#39; sparkling wine. The fresh palate of apple, ripe pear and bright citrus flavors combine with a long finish and an exciting touch of ginger.</p>\r\n\r\n<p>&nbsp;</p>', 'Description. Freixenet Cordon Negro Brut Cava Sparkling Wine is crisp and well-balanced, perfect as a palate cleanser.', 22, '', NULL, 45, 124, '', 'Freixenet Cardon Negro Brut Cava', 'Description. Le vin mousseux Freixenet Cordon Negro Brut Cava est vif et bien équilibré, parfait pour nettoyer le palais.', '<p>Cordon Negro Brut est un vin mousseux &laquo; cava &raquo; vif, propre et bien &eacute;quilibr&eacute;. La bouche fra&icirc;che de pomme, de poire m&ucirc;re et de vives saveurs d&#39;agrumes se combinent &agrave; une longue finale et une touche excitante de gingembre.</p>', NULL, NULL, 0, NULL, 0, NULL, 1, 'LQ000345', 0, 1, 1, NULL, NULL, '2023-12-23 10:50:24', '2024-02-05 06:59:37'),
(346, '6586bbb7e353a', 'PRO000346', 0, 'Freixenet Italian Sparkling Rose', '<p>With delicate pink hues, Freixenet Italian Ros&eacute; is light and effervescent. Enjoy notes of fresh red berries and underlying hints of white flowers and apples.</p>', 'Light and effervescent, Freixenet Italian Rosé offers delightful red berries notes over a delicate base of white flowers and apples.', 22, '', NULL, 45, 124, '', 'Freixenet Italian Sparkling Rose', 'Léger et effervescent, le Freixenet Italian Rosé offre de délicieuses notes de fruits rouges sur un fond délicat de fleurs blanches et de pommes.', '<p>Avec de d&eacute;licates teintes roses, le Freixenet Italian Ros&eacute; est l&eacute;ger et effervescent. Profitez de notes de fruits rouges frais et de notes sous-jacentes de fleurs blanches et de pommes.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000346', 0, 0, 1, NULL, NULL, '2023-12-23 10:51:35', '2024-02-05 06:59:37'),
(347, '6586bc3cdd7eb', 'PRO000347', 0, 'Freixenet Mia Moscato Spk Rose', '<p>Mia Moscato Rose is a beautiful, blush sparkler with a pale pink color and elegant bubbles. On the nose, it delivers a charming floral and tropical aroma. The delicious flavor is balanced by a fresh, natural sweetness and a delicate finish.</p>', 'Mia Moscato Rosé is a beautiful, blush sparkler with a pale pink color and elegant bubbles. It delivers a charming floral and tropical aroma.', 22, '', NULL, 45, 124, '', 'Freixenet Mia Moscato Spk Rose', 'Mia Moscato Rosé est un magnifique mousseux blush avec une couleur rose pâle et des bulles élégantes. Il délivre un charmant arôme floral et tropical.', '<p>Mia Moscato Rose est un magnifique blush scintillant avec une couleur rose p&acirc;le et des bulles &eacute;l&eacute;gantes. Au nez, il d&eacute;livre un charmant ar&ocirc;me floral et tropical. La saveur d&eacute;licieuse est &eacute;quilibr&eacute;e par une douceur fra&icirc;che et naturelle et une finale d&eacute;licate.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000347', 0, 0, 1, NULL, NULL, '2023-12-23 10:53:48', '2024-02-05 06:59:37'),
(348, '6586bcde3037d', 'PRO000348', 0, 'Freixenet Mia Moscato Spk White', '<p>Mia Sparkling Moscato combines freshness and body to produce an inviting and elegant wine. It has a delightful fruity aroma with hints of floral notes. The balance of sweetness and acidity creates a delicious, bubbly finish.</p>\r\n\r\n<p>&nbsp;</p>', 'On the nose it shows powerful and intense aromas, a background of white flowers, peach, ripe apricot and orange blossom.', 22, '', NULL, 45, 124, '', 'Freixenet Mia Moscato Spk White', 'Au nez, il présente des arômes puissants et intenses, sur un fond de fleurs blanches, de pêche, d\'abricot mûr et de fleur d\'oranger.', '<p>Mia Sparkling Moscato associe fra&icirc;cheur et corps pour produire un vin invitant et &eacute;l&eacute;gant. Il pr&eacute;sente un d&eacute;licieux ar&ocirc;me fruit&eacute; avec des notes florales. L&#39;&eacute;quilibre entre douceur et acidit&eacute; cr&eacute;e une finale d&eacute;licieuse et p&eacute;tillante.</p>', NULL, NULL, 0, NULL, 0, NULL, 1, 'LQ000348', 0, 0, 1, NULL, NULL, '2023-12-23 10:56:30', '2024-02-05 06:59:37'),
(349, '6586bd946236e', 'PRO000349', 0, 'Frontera Carbernet Sauvignon Chile 2018', '<p>Bright and intense ruby red, with violet reflections. The nose delivers fresh red fruits, together notes of coffee and chocolate. Harmonic tannins, medium-bodied. This wine is best served with red meats, cheese, spicy stews, and pasta with spicy sauces.</p>', 'Appealing ruby-red wine with a fruity aroma and notes of chocolate, red plums and vanilla.', 22, '', NULL, 33, 125, '', 'Frontera Carbernet Sauvignon Chile 2018', 'Vin rouge rubis attrayant avec un arôme fruité et des notes de chocolat, de prune rouge et de vanille.', '<p>Rouge rubis brillant et intense, aux reflets violets. Le nez d&eacute;livre des fruits rouges frais, accompagn&eacute;s de notes de caf&eacute; et de chocolat. Tanins harmonieux, moyennement cors&eacute;s. Ce vin s&#39;accorde parfaitement avec les viandes rouges, les fromages, les rago&ucirc;ts &eacute;pic&eacute;s et les p&acirc;tes aux sauces &eacute;pic&eacute;es.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000349', 0, 0, 1, NULL, NULL, '2023-12-23 10:59:32', '2024-02-12 09:59:13'),
(350, '6586be20c0a03', 'PRO000350', 0, 'Ginger Beer Grace', '<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" style=\"border-collapse:\r\n collapse;width:176pt\" width=\"235\">\r\n	<tbody>\r\n		<tr height=\"20\" style=\"height:15.05pt\">\r\n			<td class=\"xl65\" height=\"20\" style=\"height:15.05pt;width:176pt\" width=\"235\">Deliciously fiery, non-alcoholic soft drink. A fresh, zesty flavour which refreshes and revitalizes! Deliciously fiery, non-alcoholic soft drink. A fresh, zesty flavour which refreshes and revitalizes!</td>\r\n		</tr>\r\n		<tr>\r\n			<td class=\"xl65\" height=\"20\" style=\"height:15.05pt;width:176pt\" width=\"235\">&nbsp;</td>\r\n		</tr>\r\n	</tbody>\r\n</table>', 'Deliciously fiery, non-alcoholic soft drink. A fresh, zesty flavour which refreshes and revitalizes!', 11, '', NULL, 32, 126, '', 'Ginger Beer Grace', 'Boisson gazeuse sans alcool délicieusement ardente. Une saveur fraîche et piquante qui rafraîchit et revitalise !', '<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" style=\"width:281px;\" width=\"281\">\r\n	<tbody>\r\n		<tr height=\"20\">\r\n			<td align=\"left\" height=\"20\" style=\"height:20px;width:281px;\"><img alt=\"Community-verified icon,Community-verified icon,Community-verified icon,Community-verified icon,Community-verified icon,Community-verified icon,Community-verified icon,Community-verified icon,Community-verified icon,Community-verified icon\" height=\"16\" src=\"file:///C:/Users/Ali/AppData/Local/Temp/msohtmlclip1/01/clip_image002.png\" width=\"16\" />\r\n			<table cellpadding=\"0\" cellspacing=\"0\">\r\n				<tbody>\r\n					<tr>\r\n						<td height=\"20\" style=\"height:20px;width:281px;\">Boisson gazeuse sans alcool d&eacute;licieusement ardente. Une saveur fra&icirc;che et piquante qui rafra&icirc;chit et revitalise ! Boisson gazeuse sans alcool d&eacute;licieusement ardente. Une saveur fra&icirc;che et piquante qui rafra&icirc;chit et revitalise !</td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000350', 2.5, NULL, 2, NULL, NULL, '2023-12-23 11:01:52', '2024-02-09 07:52:32'),
(351, '6586cb9f479a1', 'PRO000351', 0, 'Glenfiddich Select Cask', '<p>The Glenfiddich Select Cask - 1 Litre is a refreshingly fragrant and floral single malt from one of the world&#39;s most well-known distilleries. Known for its summer blossom notes and traces of decadent vanilla toffee, this subtly oaky whisky is a joy to sip.</p>', 'a refreshingly fragrant and floral single malt from one of the world\'s most well-known distilleries blossom notes.', 15, '', NULL, 35, 34, '', 'Glenfiddich Select Cask', 'un single malt rafraîchissant, parfumé et floral, issu des notes florales de l\'une des distilleries les plus connues au monde.', '<p>Le Glenfiddich Select Cask - 1 Litre est un single malt rafra&icirc;chissant, parfum&eacute; et floral provenant de l&#39;une des distilleries les plus connues au monde. Connu pour ses notes de fleurs d&#39;&eacute;t&eacute; et ses traces de caramel vanill&eacute; d&eacute;cadent, ce whisky subtilement bois&eacute; est un plaisir &agrave; siroter.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000351', 0, 0, 2, NULL, NULL, '2023-12-23 11:59:27', '2024-05-15 14:33:07'),
(352, '6586cc88ca879', 'PRO000352', 0, 'Grants Triple Wood Stand Fast', '<p>William Grant&#39;s Grant&#39;s Triple Wood Stand Fast Blended Scotch Whisky 43% 1L. Consist: Nose: Smooth and sweet with elegant layers of honeycomb and spice. Taste: Notes of dried fruits and oak playfully combine with vanilla and cinnamon.</p>', 'William Grant\'s Grant\'s Triple Wood Stand Fast Blended Scotch Whisky 43% 1L. Consist: Nose: Smooth and sweet with honeycomb and spice.', 15, '', NULL, 35, 127, '', 'Grants Triple Wood Stand Fast', 'William Grant\'s Grant\'s Triple Wood Stand Fast Blended Scotch Whisky 43% 1L. Composition : Nez : Doux et sucré avec du nid d\'abeille', '<p>William Grant&#39;s Grant&#39;s Triple Wood Stand Fast Blended Scotch Whisky 43% 1L. Composition : Nez : Doux et sucr&eacute; avec d&#39;&eacute;l&eacute;gantes couches de nid d&#39;abeille et d&#39;&eacute;pices. Go&ucirc;t : Des notes de fruits secs et de ch&ecirc;ne se combinent de mani&egrave;re ludique avec la vanille et la cannelle.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000352', 0, 0, 0, NULL, NULL, '2023-12-23 12:03:20', '2024-05-16 09:16:53'),
(353, '6586cd4f4154d', 'PRO000353', 0, 'Grants Rum Cask Finish', '<p>Blender master Brian Kinsman has combined real traditional Scotch whiskey with an exotic Caribbean flavor. The whiskey first matures for a long time in oak barrels, later it is transferred to oak barrels along the Caribbean rum, giving it a smooth, rich and sweet taste.</p>', 'After many years ageing in oak barrels, the whisky is further matured in Caribbean rum casks for a smooth, rich and sweet taste.', 15, '', NULL, 48, 127, '', 'Grants Rum Cask Finish', 'Après de nombreuses années de vieillissement en fûts de chêne, le whisky est ensuite vieilli dans des fûts de rhum des Caraïbes pour', '<p>Le ma&icirc;tre m&eacute;langeur Brian Kinsman a combin&eacute; un v&eacute;ritable whisky &eacute;cossais traditionnel avec une saveur exotique des Cara&iuml;bes. Le whisky m&ucirc;rit d&#39;abord longtemps en f&ucirc;ts de ch&ecirc;ne, puis il est transf&eacute;r&eacute; dans des f&ucirc;ts de ch&ecirc;ne avec le rhum des Cara&iuml;bes, lui conf&eacute;rant un go&ucirc;t doux, riche et sucr&eacute;.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000353', 0, 0, 1, NULL, NULL, '2023-12-23 12:06:39', '2024-05-17 10:28:15'),
(354, '6586ce5d5d2de', 'PRO000354', 0, 'Grey Goose Vodka', '<p>Grey Goose Vodka is crafted in France&#39;s legendary Cognac region. Using wheat and artesian spring water creating clear, fresh and elegant aromas that produce a soft, gentle and full-balanced flavor.</p>', 'Grey Goose Vodka is crafted in France\'s legendary Cognac region. Using wheat and artesian spring water creating clear, fresh and elegant aromas.', 21, '', NULL, 29, 37, '', 'Grey Goose Vodka', 'La vodka Grey Goose est fabriquée dans la légendaire région française du Cognac. Utilisation de blé et d\'eau de source artésienne créant des arômes', '<p>La vodka Grey Goose est fabriqu&eacute;e dans la l&eacute;gendaire r&eacute;gion fran&ccedil;aise du Cognac. Utilisation de bl&eacute; et d&#39;eau de source art&eacute;sienne cr&eacute;ant des ar&ocirc;mes clairs, frais et &eacute;l&eacute;gants qui produisent une saveur douce, douce et &eacute;quilibr&eacute;e.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000354', 0, 0, 1, NULL, NULL, '2023-12-23 12:11:09', '2024-05-08 07:47:26'),
(355, '6586daa01fb64', 'PRO000355', 0, 'Havana Club Anejo 3 Anos', '<p>Havana Club 3 A&ntilde;os has a pale, golden straw colour that reveals its age: every single drop has aged for a minimum of three years. The nose is a full bouquet of smooth aromas, with hints of oak, molasses and sugar cane.</p>', 'made up of many different rums aged in white oak barrels selected by Maestro Ronero.', 21, '', NULL, 34, 91, '', 'Havana Club Anejo 3 Anos', 'composé de nombreux rhums différents vieillis en fûts de chêne blanc sélectionnés par Maestro Ronero.', '<p>Havana Club 3 A&ntilde;os a une couleur paille p&acirc;le et dor&eacute;e qui r&eacute;v&egrave;le son &acirc;ge : chaque goutte a vieilli pendant au moins trois ans. Le nez est un bouquet complet d&#39;ar&ocirc;mes doux, avec des notes de ch&ecirc;ne, de m&eacute;lasse et de canne &agrave; sucre.</p>', NULL, NULL, 0, NULL, 0, NULL, 1, 'LQ000355', 0, 1, 1, NULL, NULL, '2023-12-23 13:03:28', '2024-05-08 07:47:50'),
(356, '6586dbf8841d6', 'PRO000356', 0, 'Heart Beats Sweet Wine Red', '<p>Fragrance: fruity, with ripe strawberries and raspberries. Flavor: full-bodied, Jamy and softly sweet. Suits desserts.</p>', 'Heart Beats Sweet Cabernet Sauvignon ... Fruity with notes of ripen strawberries and raspberries. Full-bodied, jammy and softly sweet', 22, '', NULL, 33, 128, '', 'Heart Beats Sweet Wine Red', 'Heart Beats Sweet Cabernet Sauvignon... Fruité avec des notes de fraises mûres et de framboises. Corsé, confituré et légèrement sucré', '<p>Parfum : fruit&eacute;, avec des fraises et des framboises m&ucirc;res. Saveur : cors&eacute;e, confitur&eacute;e et l&eacute;g&egrave;rement sucr&eacute;e. Convient aux desserts.</p>', NULL, NULL, 0, NULL, 0, NULL, 1, 'LQ000356', 0, 1, 1, NULL, NULL, '2023-12-23 13:09:12', '2024-02-05 06:59:37'),
(357, '6586dcbe8104e', 'PRO000357', 0, 'Heart Beats White Wine Medium Sweet', '<p>Wine sowing an intense nose of apples, creamy honey with peach and citrus flavours. It is a soft wine with fresh finish.</p>', 'Fruity with notes of ripen strawberries and raspberries. Full-bodied, jammy and softly sweet', 22, '', NULL, 40, 128, '', 'Heart Beats White Wine Medium Sweet', 'Fruité avec des notes de fraises et de framboises mûres. Corsé, confituré et légèrement sucré', '<p>Vin semant un nez intense de pommes, de miel cr&eacute;meux aux ar&ocirc;mes de p&ecirc;che et d&#39;agrumes. C&#39;est un vin doux avec une finale fra&icirc;che.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000357', 0, 0, 1, NULL, NULL, '2023-12-23 13:12:30', '2024-02-05 06:59:37'),
(358, '6586ddef8dce1', 'PRO000358', 0, 'Hendrik\'s Gin 41.4%', '<p>Hendrick&#39;s Gin is a super-premium gin produced by William Grant &amp; Sons at the Girvan distillery, Scotland, and launched in 1999. In addition to the traditional juniper infusion, Hendrick&#39;s uses Bulgarian rose and cucumber to add flavour. Hendrick&#39;s gin is bottled in a dark brown, apothecary-style bottle.</p>', 'a super-premium gin produced by William Grant & Sons at the Girvan distillery, Scotland, and launched in 1999.', 21, '', NULL, 31, 129, '', 'Hendrik\'s Gin 41.4%', 'un gin super premium produit par William Grant & Sons à la distillerie Girvan, en Écosse, et lancé en 1999.', '<p>Hendrick&#39;s Gin est un gin super premium produit par William Grant &amp; Sons &agrave; la distillerie Girvan, en &Eacute;cosse, et lanc&eacute; en 1999. En plus de l&#39;infusion traditionnelle de geni&egrave;vre, Hendrick&#39;s utilise de la rose bulgare et du concombre pour ajouter de la saveur. Le gin Hendrick&#39;s est mis en bouteille dans une bouteille brun fonc&eacute; de style apothicaire.</p>', NULL, NULL, 0, NULL, 0, NULL, 1, 'LQ000358', 0, 1, 1, NULL, NULL, '2023-12-23 13:17:35', '2024-02-05 06:59:37'),
(359, '6586de91e56d6', 'PRO000359', 0, 'Hendrik\'s Midsummer Gin 43.4%', '<p>Inspired by the glory of a midsummer day, this limited edition release from the Hendrick&#39;s Gin range boasts heavy floral influence &ndash; orange blossom, iris and cut grass abound! This comes alongside classic Hendrick&#39;s elements, including refreshing juniper, rose petal and chamomile.</p>', 'Using a secret selection of flowers, Hendrick\'s have created a gin with an intensely floral bouquet that blossoms on the palate.', 21, '', NULL, 31, 129, '', 'Hendrik\'s Midsummer Gin 43.4%', 'À partir d\'une sélection secrète de fleurs, Hendrick\'s a créé un gin au bouquet intensément floral qui s\'épanouit en bouche.', '<p>Inspir&eacute;e par la gloire d&#39;une journ&eacute;e d&#39;&eacute;t&eacute;, cette &eacute;dition limit&eacute;e de la gamme Hendrick&#39;s Gin poss&egrave;de une forte influence florale : la fleur d&#39;oranger, l&#39;iris et l&#39;herbe coup&eacute;e abondent ! Cela s&#39;accompagne d&#39;&eacute;l&eacute;ments classiques de Hendrick, notamment du gen&eacute;vrier rafra&icirc;chissant, des p&eacute;tales de rose et de la camomille.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000359', 0, 0, 1, NULL, NULL, '2023-12-23 13:20:17', '2024-02-05 06:59:37'),
(360, '6586e02a2dedf', 'PRO000360', 0, 'Jelzin Vodka 37.5%', '<p>The Boris Jelzin Vodka is a classic mixing Vodka and is ideal for a wide range of interesting drinks and cocktails. It&#39;s very clear aroma with hints of herbs and citrus never distorts the flavor of other ingredients.</p>', 'French Vodka for Joe Collins or other long pours. Good quality affordable Vodka for mixing and long drinks keep it in the freezer.', 21, '', NULL, 29, 130, '', 'Jelzin Vodka 37.5%', 'Vodka française pour Joe Collins ou autres longues coulées. Vodka abordable de bonne qualité pour mélanger et longdrinks à conserver', '<p>La vodka Boris Jelzin est une vodka de m&eacute;lange classique et est id&eacute;ale pour une large gamme de boissons et de cocktails int&eacute;ressants. Son ar&ocirc;me tr&egrave;s clair avec des notes d&#39;herbes et d&#39;agrumes ne d&eacute;nature jamais la saveur des autres ingr&eacute;dients.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000360', 0, 0, 1, NULL, NULL, '2023-12-23 13:27:06', '2024-05-08 07:48:56'),
(361, '6586e1568ed47', 'PRO000361', 0, 'John\'s Grenadine Syrup', '<p>Sweet, slightly tart taste.Red berries with a touch of vanilla.Brilliant red with orangey glints</p>', 'Pure sugar syrup with natural ingredients and flavourings. Alcohol-free, suitable for vegan and vegetarian diets.', 25, '', NULL, 47, 131, '', 'John\'s Grenadine Syrup', 'Sirop de sucre pur avec des ingrédients et des arômes naturels. Sans alcool, adapté aux régimes végétaliens et végétariens.', '<p>Go&ucirc;t sucr&eacute; et l&eacute;g&egrave;rement acidul&eacute;. Fruits rouges avec une touche de vanille. Rouge brillant aux reflets orang&eacute;s.</p>', NULL, NULL, 0, NULL, 0, NULL, 1, 'LQ000361', 0, 0, 1, NULL, NULL, '2023-12-23 13:32:06', '2024-02-05 06:59:37'),
(362, '658d1ed4d519b', 'PRO000362', 0, 'Jp Chenet Cab Syrah Red Med Poc 13%', '<p>This blend of 60% Cabernet and 40% Syrah is an exquisite, fruit-forward wine with rich berry aromas and an appealing spiciness to complement the vivid raspberry and blackberry flavors. Aromas of blackcurrant, cherry, leather, and jam, as well as hints of strawberry and some raisins, are fruity and well structured, with a touch of liquorice and peppery notes, and tastes of blackcurrant, cherry, leather, and jam, along with hints of strawberry and some raisins.</p>', 'Aromas of cherry and blackcurrant, a touch of liquorice and peppery notes,Ruby red, strong and clear,For a meal.', 22, '', NULL, 45, 43, '', 'Jp Chenet Cab Syrah Red Med Poc 13%', 'Arômes de cerise et de cassis, une touche de réglisse et des notes poivrées,Rouge rubis, fort et clair,Pour un repas.', '<p>Cet assemblage de 60 % de cabernet et 40 % de syrah est un vin exquis et fruit&eacute; avec de riches ar&ocirc;mes de baies et un piquant attrayant qui compl&egrave;te les saveurs vives de framboise et de m&ucirc;re. Les ar&ocirc;mes de cassis, de cerise, de cuir et de confiture, ainsi que des notes de fraise et quelques raisins secs, sont fruit&eacute;s et bien structur&eacute;s, avec une touche de r&eacute;glisse et des notes poivr&eacute;es, et des go&ucirc;ts de cassis, de cerise, de cuir et de confiture, accompagn&eacute;s de des notes de fraise et quelques raisins secs.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000362', 0, 0, 1, NULL, NULL, '2023-12-28 07:08:04', '2024-02-05 06:59:37'),
(363, '658d1f67c72d2', 'PRO000363', 0, 'Jp Chenet Cab Syrah Red Poc 12.5%', '<p>Aromas of cherry and blackcurrant, a touch of liquorice and peppery notes,Ruby red, strong and clear,For a meal with friends, with good meat or cheeses</p>', 'A perfect balance, an intensely fruity wine with a silky body', 22, '', NULL, 45, 43, '', 'Jp Chenet Cab Syrah Red Poc 12.5%', 'Un équilibre parfait, un vin intensément fruité au corps soyeux', '<p>Ar&ocirc;mes de cerise et de cassis, une touche de r&eacute;glisse et des notes poivr&eacute;es,Rouge rubis, fort et clair,Pour un repas entre amis, avec de bonnes viandes ou fromages</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000363', 0, 0, 1, NULL, NULL, '2023-12-28 07:10:31', '2024-02-05 06:59:37'),
(364, '658d2044c43fc', 'PRO000364', 0, 'KWV Cathedrale Cellar Cabernet Sauvignon', '<p>This layered Cabernet Sauvignon shows upfront aromas of mulberry, plums and cigar box with hints of raspberries and dried herbs. The palate is rich and juicy with a bright acidity, bold tannin structure and an enduring finish.</p>', 'These bold wines incorporate rich black fruit flavours and spice in a densely structured profile with firm tannins.', 22, '', NULL, 33, 44, '', 'KWV Cathedrale Cellar Cabernet Sauvignon', 'Ces vins audacieux intègrent de riches saveurs de fruits noirs et d\'épices dans un profil densément structuré avec des tanins fermes.', '<p>Ce cabernet sauvignon &eacute;tag&eacute; pr&eacute;sente des ar&ocirc;mes directs de m&ucirc;re, de prune et de bo&icirc;te &agrave; cigares avec des notes de framboise et d&#39;herbes s&eacute;ch&eacute;es. La bouche est riche et juteuse avec une acidit&eacute; vive, une structure tannique audacieuse et une finale persistante.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000364', 0, 0, 1, NULL, NULL, '2023-12-28 07:14:12', '2024-02-05 06:59:37'),
(365, '658d20e4e69c4', 'PRO000365', 0, 'Martell Vs Single Distillery', '<p>A nice blend, sweet and fruity. Bright and golden in color, Martell VS Single Distillery reveals pleasing notes of plum, apricot and candied lemon on the nose. Its rich fruit flavors on the palate and its generosity on the palate make it a great cognac to enjoy in long drinks or cocktails.</p>', 'It is easily recognizable, reflecting the cognac\'s distinctive taste. Rich, clear gold liquid with intense aromas of plum, apricot, and candies lemon.', 21, '', NULL, 43, 46, '', 'Martell Vs Single Distillery', 'Il est facilement reconnaissable et reflète le goût distinctif du cognac. Liquide doré riche et clair aux arômes intenses de prune, d\'abrico', '<p>Un joli m&eacute;lange, doux et fruit&eacute;. De couleur vive et dor&eacute;e, Martell VS Single Distillery r&eacute;v&egrave;le au nez d&#39;agr&eacute;ables notes de prune, d&#39;abricot et de citron confit. Ses riches ar&ocirc;mes de fruits en bouche et sa g&eacute;n&eacute;rosit&eacute; en bouche en font un excellent cognac &agrave; d&eacute;guster en longdrinks ou en cocktails.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000365', 0, 0, 1, NULL, NULL, '2023-12-28 07:16:52', '2024-02-05 06:59:37'),
(366, '658d22b551872', 'PRO000366', 0, 'Mouton Cadet Blanc', '<p>The nose is elegant and fresh, expressing citrus and tropical Sauvignon freshness and rich Semillon fruit. Soft pear, grass and citrus flavors dominate the palate with light mineral flavor and a vibrant, refreshing finish. Since 1930,&nbsp;Mouton Cadet&nbsp;has been renowned for its exacting standards and audacity.</p>\r\n\r\n<p>&nbsp;</p>', 'Glittering pale straw yellow. The nose displays perfect balance between fresh fruit and acidulated notes such as lemon.', 22, '', NULL, 40, 132, '', 'Mouton Cadet Blanc', 'Jaune paille pâle scintillant. Le nez affiche un équilibre parfait entre les fruits frais et des notes acidulées comme le citron.', '<p>Le nez est &eacute;l&eacute;gant et frais, exprimant la fra&icirc;cheur des agrumes et du Sauvignon tropical et la richesse du fruit du S&eacute;millon. Des saveurs douces de poire, d&#39;herbe et d&#39;agrumes dominent le palais avec une l&eacute;g&egrave;re saveur min&eacute;rale et une finale vibrante et rafra&icirc;chissante. Depuis 1930, Mouton Cadet est r&eacute;put&eacute; pour son exigence et son audace.</p>', NULL, NULL, 0, NULL, 0, NULL, 1, 'LQ000366', 0, 0, 1, NULL, NULL, '2023-12-28 07:24:37', '2024-02-05 06:59:37'),
(367, '658d25ab21948', 'PRO000367', 0, 'Mouton Cadet Sauvignon Blanc', '<p>The nose opens on zesty fruit aromas such as lemon and grapefruit, then goes on with airing to reveal fresh notes of broom balanced by aromas of ripe yellow fruit such as peach and apricot. The fresh and elegant attack leads into a mid-palate on very fresh citrus fruit flavours, while hints of broom lift the finish.</p>\r\n\r\n<p>&nbsp;</p>', 'The nose opens on citrus notes combined with the elegant white fruit aromas typical of Semillon', 22, '', NULL, 40, 132, '', 'Mouton Cadet Sauvignon Blanc', 'Le nez s\'ouvre sur des notes d\'agrumes associées aux élégants arômes de fruits blancs typiques du Sémillon.', '<p>Le nez s&#39;ouvre sur des ar&ocirc;mes de fruits piquants comme le citron et le pamplemousse, puis se poursuit &agrave; l&#39;a&eacute;ration pour r&eacute;v&eacute;ler des notes fra&icirc;ches de gen&ecirc;t &eacute;quilibr&eacute;es par des ar&ocirc;mes de fruits jaunes m&ucirc;rs comme la p&ecirc;che et l&#39;abricot. L&#39;attaque fra&icirc;che et &eacute;l&eacute;gante m&egrave;ne &agrave; un milieu de bouche sur des ar&ocirc;mes d&#39;agrumes tr&egrave;s frais, tandis que des notes de gen&ecirc;t rel&egrave;vent la finale.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000367', 0, 0, 1, NULL, NULL, '2023-12-28 07:37:15', '2024-02-05 06:59:37'),
(368, '658d26d7512fa', 'PRO000368', 0, 'Namaqua Natural Sweet Red', '<p>This wine has a healthy ruby colour with a smoky strawberry nose. Sweet, but a firm structure from touch tannin courtesy of Merlot, Pinotage and Ruby Cabernet.</p>', 'It has a healthy ruby colour with a smoky strawberry nose. Sweet, but a firm structure from touch tannin courtesy of Merlot, Pinotage.', 22, '', NULL, 33, 133, '', 'Namaqua Natural Sweet Red', 'Il présente une robe rubis saine avec un nez de fraise fumée. Doux, mais une structure ferme grâce aux tanins tactiles gracieuseté du', '<p>Ce vin pr&eacute;sente une robe rubis saine avec un nez de fraise fum&eacute;e. Doux, mais une structure ferme gr&acirc;ce aux tanins tactiles gracieuset&eacute; du Merlot, du Pinotage et du Ruby Cabernet.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000368', 0, 0, 1, NULL, NULL, '2023-12-28 07:42:15', '2024-05-08 09:12:57'),
(369, '658d2769c5dd8', 'PRO000369', 0, 'Namaqua Natural Sweet White', '<p>An easy-sipping wine full of flavours of juicy peach and ripe apricots. A natural sweet wine with a tropical, almost muscat after taste. Suggested pairings: Enjoy with mild cheeses, fresh fruit or spicy Asian dishes. It&#39;s also terrific with desserts.</p>', 'A natural sweet wine with a tropical, almost muscat after taste. Suggested pairings: Enjoy with mild cheeses, fresh fruit or spicy Asian dishes.', 22, '', NULL, 40, 133, '', 'Namaqua Natural Sweet White', 'Un vin doux naturel avec un arrière-goût tropical presque muscaté. Accords suggérés : À déguster avec des fromages doux, des fruits frais', '<p>Un vin facile &agrave; siroter, plein de saveurs de p&ecirc;che juteuse et d&#39;abricots m&ucirc;rs. Un vin doux naturel avec un arri&egrave;re-go&ucirc;t tropical, presque muscat&eacute;. Accords sugg&eacute;r&eacute;s : &Agrave; d&eacute;guster avec des fromages doux, des fruits frais ou des plats asiatiques &eacute;pic&eacute;s. C&#39;est aussi g&eacute;nial avec les desserts.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000369', 0, 0, 1, NULL, NULL, '2023-12-28 07:44:41', '2024-02-05 06:59:37'),
(370, '658d28173b279', 'PRO000370', 0, 'Nederburg Winemaster Shiraz', '<p>Full-bodied &amp; Smooth. Characteristics: Smoky, plum, berry, leather and spice aromas; medium-to-full bodied with rich dark berry flavours and a long finish. Suggested Pairings: This dark ruby-coloured wine is delicious with Mediterranean meat dishes and roasts.</p>', 'Dark ruby colour with an aroma of spicy bacon and dark berries complimented by white pepper notes. A rich, full - bodied wine with ripe plum flavours.', 22, '', NULL, 33, 49, '', 'Nederburg Winemaster Shiraz', 'Robe rubis foncé avec un arôme de bacon épicé et de baies noires complété par des notes de poivre blanc. Un vin riche et corsé aux', '<p>Cors&eacute; et doux. Caract&eacute;ristiques : Ar&ocirc;mes fum&eacute;s, de prune, de baies, de cuir et d&#39;&eacute;pices ; mi-cors&eacute; &agrave; cors&eacute; avec de riches saveurs de petits fruits noirs et une longue finale. Accords sugg&eacute;r&eacute;s : Ce vin &agrave; la robe rubis fonc&eacute; est d&eacute;licieux avec les plats de viande et les r&ocirc;tis m&eacute;diterran&eacute;ens.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000370', 0, 0, 1, NULL, NULL, '2023-12-28 07:47:35', '2024-02-12 09:57:00'),
(371, '658d291c8ee9c', 'PRO000371', 0, 'Pearly Bay Cape Sweet Rose', '<p>An easy drinking sweet ros&eacute; with hints of strawberry, floral aromas and spice. This wine can be enjoyed on its own, with alfresco meals, fruit salads and various desserts. It will show best when the wine is well chilled.</p>', 'sweet rosé with hints of strawberry, floral aromas and spice.', 22, '', NULL, 46, 134, '', 'Pearly Bay Cape Sweet Rose', 'rosé doux avec des notes de fraise, des arômes floraux et d\'épices.', '<p>Un ros&eacute; doux et facile &agrave; boire avec des notes de fraise, des ar&ocirc;mes floraux et d&#39;&eacute;pices. Ce vin peut &ecirc;tre d&eacute;gust&eacute; seul, avec des repas en plein air, des salades de fruits et divers desserts. Il se r&eacute;v&eacute;lera mieux lorsque le vin sera bien frais.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000371', 0, 0, 1, NULL, NULL, '2023-12-28 07:51:56', '2024-02-05 06:59:37'),
(372, '658d29cf10f97', 'PRO000372', 0, 'Pearly Bay Natural Sweet White', '<p>Pearly Bay Sweet White is an easy-drinking sweet, fruity white wine. The wine has lush juicy peach and ripe apricots with undertones of floral blossoms.</p>', 'Pearly Bay Sweet White is an easy-drinking sweet, fruity white wine. The wine has lush juicy peach and ripe apricots..', 22, '', NULL, 40, 134, '', 'Pearly Bay Natural Sweet White', 'Pearly Bay Sweet White est un vin blanc doux et fruité facile à boire. Le vin présente des pêches juteuses et luxuriantes et des abricots mûrs.', '<p>Pearly Bay Sweet White est un vin blanc doux et fruit&eacute; facile &agrave; boire. Le vin pr&eacute;sente des notes de p&ecirc;che juteuse et d&#39;abricots m&ucirc;rs avec des nuances de fleurs florales.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000372', 0, 0, 1, NULL, NULL, '2023-12-28 07:54:55', '2024-02-05 06:59:37');
INSERT INTO `product` (`id`, `uniqid`, `product_item_id`, `supplier_id`, `product_name`, `description`, `short_description`, `category_id`, `product_image`, `images`, `subcategory_id`, `brand_id`, `video`, `product_name_fr`, `short_description_fr`, `page_content_fr`, `product_qty`, `tech_data_sheet`, `retail_price`, `discount_price`, `is_admin_approve`, `most_view`, `is_product_bestseller`, `sku`, `average_rating`, `offer`, `status`, `in_store`, `in_online`, `created_at`, `updated_at`) VALUES
(373, '658d2aca6a1de', 'PRO000373', 0, 'Plaisir De Merle Cabernet Sauvignon 2017', '<p>Dark red colour, aromatic red berries, mulberry and plums, cedar and subtle vanilla oak aromas. Rich in flavour, aromas of cassis, red and black cherries, with hints of oak, spice, vanilla and cedar. Velvety and firm tannins on the finish.</p>', 'Rich in flavour, aromas of cassis, red and black cherries, with hints of oak, spice, vanilla and cedar. Velvety and firm tannins on the finish.', 22, '', NULL, 33, 135, '', 'Plaisir De Merle Cabernet Sauvignon 2017', 'Riche en saveur, arômes de cassis, de cerises rouges et noires, avec des notes de chêne, d\'épices, de vanille et de cèdre. Tanins veloutés et', '<p>Robe rouge fonc&eacute;, ar&ocirc;mes aromatiques de petits fruits rouges, de m&ucirc;re et de prune, de c&egrave;dre et de subtils ar&ocirc;mes de ch&ecirc;ne vanill&eacute;. Riche en saveur, ar&ocirc;mes de cassis, de cerises rouges et noires, avec des notes de ch&ecirc;ne, d&#39;&eacute;pices, de vanille et de c&egrave;dre. Tanins velout&eacute;s et fermes en finale.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000373', 0, 0, 1, NULL, NULL, '2023-12-28 07:59:06', '2024-02-05 06:59:37'),
(374, '658d2b7e575dd', 'PRO000374', 0, 'Porto Monteiro Ruby', '<p>The wine has a velvety, deep ruby ​​color. The wine has a rich, well-balanced taste with notes of red berries and spicy flavor. Intense, clean aroma of the wine is filled with delicate fruit and berry shades and nuances of licorice. The wine used to accompany desserts, pastries or as an aperitif.</p>', 'The wine has a rich, well-balanced taste with notes of red berries and spicy flavor.', 22, '', NULL, 33, 136, '', 'Porto Monteiro Ruby', 'Le vin a un goût riche et équilibré avec des notes de fruits rouges et une saveur épicée.', '<p>Le vin pr&eacute;sente une robe rubis velout&eacute;e et profonde. Le vin a un go&ucirc;t riche et &eacute;quilibr&eacute; avec des notes de fruits rouges et une saveur &eacute;pic&eacute;e. L&#39;ar&ocirc;me intense et propre du vin est rempli de nuances d&eacute;licates de fruits et de baies et de nuances de r&eacute;glisse. Le vin s&#39;utilise pour accompagner les desserts, les p&acirc;tisseries ou &agrave; l&#39;ap&eacute;ritif.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000374', 0, 0, 1, NULL, NULL, '2023-12-28 08:02:06', '2024-02-05 06:59:37'),
(375, '658d368c91775', 'PRO000375', 0, 'Puschkin Vodka', '<p>Puschkin Vodka is meticulously crafted using the finest ingredients, resulting in a smooth and velvety texture that glides effortlessly over the palate. Its distinct character and exceptional quality make it a favorite among vodka enthusiasts and connoisseurs alike.</p>', 'With its 1000ml volume, this bottle ensures you have an ample supply of Puschkin Vodka to enjoy at your leisure.', 21, '', NULL, 29, 137, '', 'Puschkin Vodka', 'Avec son volume de 1 000 ml, cette bouteille vous assure de disposer d\'une quantité suffisante de vodka Puschkin à déguster à votre guise.', '<p>La vodka Puschkin est m&eacute;ticuleusement &eacute;labor&eacute;e &agrave; partir des meilleurs ingr&eacute;dients, ce qui donne une texture douce et velout&eacute;e qui glisse sans effort sur le palais. Son caract&egrave;re distinct et sa qualit&eacute; exceptionnelle en font un favori des amateurs et des connaisseurs de vodka.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000375', 0, 0, 1, NULL, NULL, '2023-12-28 08:49:16', '2024-05-08 09:19:19'),
(376, '658d379d7d4d1', 'PRO000376', 0, 'Ruskov Imported Vodka', '<p>Ruskov Vodka is made from sugar beet, which gives it a really unique taste. Made in France, this is a great value for money vodka which makes it perfect for mixing with cranberry juice or shaken up in your favourite vodka cocktail.</p>', 'Ruskov Vodka is made from sugar beet, which gives it a really unique taste.', 21, '', NULL, 29, 138, '', 'Ruskov Imported Vodka', 'La vodka Ruskov est fabriquée à partir de betterave sucrière, ce qui lui donne un goût vraiment unique.', '<p>La vodka Ruskov est fabriqu&eacute;e &agrave; partir de betterave sucri&egrave;re, ce qui lui donne un go&ucirc;t vraiment unique. Fabriqu&eacute;e en France, c&#39;est une vodka d&#39;un excellent rapport qualit&eacute;-prix qui la rend parfaite &agrave; m&eacute;langer avec du jus de canneberge ou &agrave; shaker dans votre cocktail de vodka pr&eacute;f&eacute;r&eacute;.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000376', 0, 0, 1, NULL, NULL, '2023-12-28 08:53:49', '2024-02-05 06:59:37'),
(377, '658d3890cd5e2', 'PRO000377', 0, 'Ruskov Imported Vodka', '<p>Ruskov Vodka is no ordinary Vodka. Made from sugar beet, Ruskov has a unique taste that is great for mixing or as the perfect base to many cocktails, including the famous Cosmopolitan.</p>', 'Made from sugar beet, Ruskov has a unique taste that is great for mixing or as the perfect base to many cocktails, including the famous Cosmopolitan.', 21, '', NULL, 29, 138, '', 'Ruskov Imported Vodka', 'Fabriqué à partir de betterave sucrière, le Ruskov a un goût unique qui est idéal pour mélanger ou comme base parfaite pour de nombreux cocktails', '<p>La vodka Ruskov n&#39;est pas une vodka ordinaire. Fabriqu&eacute; &agrave; partir de betterave sucri&egrave;re, le Ruskov a un go&ucirc;t unique qui est id&eacute;al pour m&eacute;langer ou comme base parfaite pour de nombreux cocktails, dont le c&eacute;l&egrave;bre Cosmopolitan.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000377', 0, 0, 1, NULL, NULL, '2023-12-28 08:57:52', '2024-05-08 09:19:54'),
(378, '658d398e6ec6c', 'PRO000378', 0, 'Saint James 45%', '<p>Its pretty amber colour offers a round, fruity and flowery nose with pleasant woody and spicy notes. Its round and harmonious palate offers a nice presence and a long persistence thanks to pleasant woody notes.</p>', 'It\'s quite sweet and a little flowery. Very nutty with lots of peanut, walnut and praline bursting out from under the grassier, floral notes.', 21, '', NULL, 34, 139, '', 'Saint James 45%', 'C\'est assez sucré et un peu fleuri. Très noix avec beaucoup de cacahuète, de noix et de pralin qui jaillissent sous les notes florales plus herbacées.', '<p>Sa jolie robe ambr&eacute;e offre un nez rond, fruit&eacute; et fleuri avec d&#39;agr&eacute;ables notes bois&eacute;es et &eacute;pic&eacute;es. Sa bouche ronde et harmonieuse offre une belle pr&eacute;sence et une longue persistance gr&acirc;ce &agrave; d&#39;agr&eacute;ables notes bois&eacute;es.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000378', 0, 0, 1, NULL, NULL, '2023-12-28 09:02:06', '2024-05-08 09:20:45'),
(379, '658d6693080e1', 'PRO000379', 0, 'San Simon Monastrell Jumila', '<p>This wine has a ruby red with crimson tones, medium coat color, limpid and bright. Its aroma is fresh and fruity, keeping all the qualities of the Monastrell variety. On the mouth is tasty and easy to drink. Colour | Red mixed with Dark Berries.</p>\r\n\r\n<p>&nbsp;</p>', 'Bright cherry red color, which denotes the youth of the base wine.', 22, '', NULL, 33, 140, '', 'San Simon Monastrell Jumila', 'Couleur rouge cerise brillante, qui dénote la jeunesse du vin de base.', '<p>Ce vin pr&eacute;sente une robe rouge rubis aux reflets pourpres, de robe moyenne, limpide et brillante. Son ar&ocirc;me est frais et fruit&eacute;, conservant toutes les qualit&eacute;s de la vari&eacute;t&eacute; Monastrell. La bouche est savoureuse et facile &agrave; boire. Couleur | Rouge m&eacute;lang&eacute; &agrave; des baies noires.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000379', 0, 0, 1, NULL, NULL, '2023-12-28 12:14:11', '2024-02-05 06:59:37'),
(380, '658d6a8df1f06', 'PRO000380', 0, 'Scavi & Ray Al Chocolata', '<p>With an alcohol content of 10 % ABV, the speciality wine is characterised by its crimson colour with violet hues and a sweet taste. It carries an intense aroma of dark ripe fruits with soft vanilla pods and is pleasantly creamy when poured. Then you get an aroma of fine chocolate, delicate cherry and light plum.</p>', 'With an alcohol content of 10 % ABV, the speciality wine is characterised by its crimson colour with violet hues and a sweet taste.', 22, '', NULL, 33, 55, '', 'Scavi & Ray Al Chocolata', 'Avec une teneur en alcool de 10% ABV, le vin de spécialité se caractérise par sa couleur pourpre aux reflets violets et son goût sucré.', '<p>Avec une teneur en alcool de 10 % ABV, ce vin de sp&eacute;cialit&eacute; se caract&eacute;rise par sa couleur pourpre aux reflets violets et son go&ucirc;t sucr&eacute;. Il d&eacute;gage un ar&ocirc;me intense de fruits noirs m&ucirc;rs avec des gousses de vanille douces et est agr&eacute;ablement cr&eacute;meux lorsqu&#39;on le verse. Ensuite, vous obtenez un ar&ocirc;me de chocolat fin, de cerise d&eacute;licate et de prune l&eacute;g&egrave;re.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000380', 0, 0, 1, NULL, NULL, '2023-12-28 12:31:09', '2024-02-05 06:59:37'),
(381, '658d6b8322fa9', 'PRO000381', 0, 'Scavi & Ray Moscato Spumante', '<p>The SCAVI &amp; RAY MOSCATO SPUMANTE is not only about the glamorous, stylish packaging it comes in, but also about the refreshing, tingling taste. For the perfect serve, enjoy chilled on the rocks out of a wine glass with a lemon zest garnish so that the intense muscat aromas and its fine, light sweetness can unfold.</p>', 'The classic drink, made from white muscat grapes, is back in trend and has become a must-have drink at hip parties across New York.', 22, '', NULL, 45, 55, '', 'Scavi & Ray Moscato Spumante', 'La boisson classique, à base de raisins muscat blanc, revient à la mode et est devenue une boisson incontournable des soirées branchées de New York.', '<p>Le SCAVI &amp; RAY MOSCATO SPUMANTE ne se r&eacute;sume pas seulement &agrave; son emballage glamour et &eacute;l&eacute;gant, mais aussi &agrave; son go&ucirc;t rafra&icirc;chissant et piquant. Pour un service parfait, d&eacute;gustez-le frais sur glace dans un verre &agrave; vin garni de zeste de citron pour que les ar&ocirc;mes intenses de muscat et sa douceur fine et l&eacute;g&egrave;re se d&eacute;ploient.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000381', 0, 0, 1, NULL, NULL, '2023-12-28 12:35:15', '2024-02-12 10:15:02'),
(382, '658d6cdc30dc0', 'PRO000382', 0, 'Sheridan\'s Coffee Liqueur', '<p>Sheridan&#39;s is an innovative combination of dark coffee chocolate liqueur and a smooth vanilla cream liqueur. Its unique pack consists of two bottles, one with coffee and whisky flavoured liqueur and the other white chocolate flavoured liqueur.</p>', 'The aroma of this is full of coffee, vanilla, cream and chocolate, and just a hint of whiskey. The flavour has an intense coffee taste.', 21, '', NULL, 30, 141, '', 'Sheridan\'s Coffee Liqueur', 'L\'arôme est plein de café, de vanille, de crème et de chocolat, avec juste un soupçon de whisky. La saveur a un goût de café intense.', '<p>Sheridan&#39;s est une combinaison innovante de liqueur de chocolat au caf&eacute; noir et d&#39;une onctueuse liqueur de cr&egrave;me &agrave; la vanille. Son pack unique se compose de deux bouteilles, l&#39;une avec une liqueur aromatis&eacute;e au caf&eacute; et au whisky et l&#39;autre avec une liqueur aromatis&eacute;e au chocolat blanc.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000382', 0, 0, 1, NULL, NULL, '2023-12-28 12:41:00', '2024-05-08 09:27:17'),
(383, '658d6e5641a92', 'PRO000383', 0, 'Sheridan\'s Coffee Liqueur', '<p>It is uniquely bottled, consisting of two separate sections, separated by glass, but fused together. One section is filled with a black liqueur, consisting of coffee and whiskey flavors, while the other is filled with a white liqueur of milk white chocolate.</p>', 'Sheridan\'s Coffee Layered Liqueur boasts two vessels inside the bottle. One side is \'white chocolatiness\', the other, sweet coffee.', 21, '', NULL, 30, 141, '', 'Sheridan\'s Coffee Liqueur', 'La liqueur en couches de café Sheridan\'s possède deux récipients à l\'intérieur de la bouteille. Un côté est « chocolaté blanc », l\'autre', '<p>Il s&#39;agit d&#39;une bouteille unique, compos&eacute;e de deux sections distinctes, s&eacute;par&eacute;es par du verre, mais fusionn&eacute;es. Une section est remplie d&#39;une liqueur noire compos&eacute;e d&#39;ar&ocirc;mes de caf&eacute; et de whisky, tandis que l&#39;autre est remplie d&#39;une liqueur blanche de chocolat blanc au lait.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000383', 0, 0, 1, NULL, NULL, '2023-12-28 12:47:18', '2024-02-05 06:59:37'),
(384, '658d79efd4a13', 'PRO000384', 0, 'Sparkwine Jaume Serra Cava Rose', '<p>Jaume Serra Rose Bouquet Cava Brut has a dry taste with lemon and lime mix and aromas of apples. The pleasant mousse fills the whole mouth. Cava has, like champagne, fermented a second time in a bottle, which gives a complexity and wonderful tones of toast in both nose and mouth.</p>', 'It is made from the grapes and pinot noir and here it is raspberries and pomegranate that dominate aroma and taste, as well as hints of strawberries.', 22, '', NULL, 45, 142, '', 'Sparkwine Jaume Serra Cava Rose', 'Il est élaboré à partir de raisins et de pinot noir et ici ce sont les framboises et la grenade qui dominent l\'arôme et le goût, ainsi que des', '<p>Jaume Serra Rose Bouquet Cava Brut a un go&ucirc;t sec avec un m&eacute;lange de citron et de citron vert et des ar&ocirc;mes de pommes. La mousse agr&eacute;able remplit toute la bouche. Le cava a, comme le champagne, ferment&eacute; une seconde fois en bouteille, ce qui lui conf&egrave;re une complexit&eacute; et de merveilleuses tonalit&eacute;s grill&eacute;es au nez comme en bouche.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000384', 0, 0, 1, NULL, NULL, '2023-12-28 13:36:47', '2024-02-05 06:59:37'),
(385, '658d7a574fbd7', 'PRO000385', 0, 'Sparkwine Jaume Serra Cava Brut', '<p>Sweetness varies from very dry to medium-sweet. Their rich fruitiness is typically balanced with a crisp acidity. Ideal for toasts, socialising and buffets, or to accompany shellfish, fish and vegetable dishes.</p>', 'Jaume Serra Rose Bouquet Cava Brut has a dry taste with lemon and lime mix and aromas of apples. The pleasant mousse fills the whole mouth.', 22, '', NULL, 45, 142, '', 'Sparkwine Jaume Serra Cava Brut', 'Jaume Serra Rose Bouquet Cava Brut a un goût sec avec un mélange de citron et de citron vert et des arômes de pommes. L\'agréable mousse', '<p>La douceur varie de tr&egrave;s s&egrave;che &agrave; moyennement douce. Leur riche fruit&eacute; est g&eacute;n&eacute;ralement &eacute;quilibr&eacute; avec une acidit&eacute; vive. Id&eacute;al pour les toasts, les convivialit&eacute;s et les buffets, ou pour accompagner des plats de crustac&eacute;s, de poissons et de l&eacute;gumes.</p>', NULL, NULL, 0, NULL, 0, NULL, 1, 'LQ000385', 0, 1, 1, NULL, NULL, '2023-12-28 13:38:31', '2024-02-05 06:59:37'),
(386, '658d7c7670619', 'PRO000386', 0, 'Tall Horse Chardonnay', '<p>Brilliant gold with broad tropical fruit top notes revealing a deliciously rich palate packed with forward ripe fruit flavours, layered with spicy vanilla and a fresh citrus finish. A wonderfully expressive wine to drink immediatelly or within 2 years of vintage.</p>', 'Brilliant gold with broad tropical fruit top notes revealing a deliciously rich palate packed with forward ripe fruit flavours, and spicy vanilla.', 22, '', NULL, 40, 57, '', 'Tall Horse Chardonnay', 'Robe dorée brillante avec de larges notes de tête de fruits tropicaux révélant une bouche délicieusement riche remplie de saveurs de fruits', '<p>Un vin dor&eacute; brillant avec de larges notes de t&ecirc;te de fruits tropicaux r&eacute;v&eacute;lant une bouche d&eacute;licieusement riche remplie de saveurs de fruits m&ucirc;rs, recouvertes de vanille &eacute;pic&eacute;e et d&#39;une finale d&#39;agrumes frais. Un vin merveilleusement expressif &agrave; boire imm&eacute;diatement ou dans les 2 ans suivant le mill&eacute;sime.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000386', 0, 1, 1, NULL, NULL, '2023-12-28 13:47:34', '2024-02-05 06:59:37'),
(387, '658d7d1d9a4be', 'PRO000387', 0, 'Tall Horse Cabernet Sauvignon 2020', '<p>Dense ruby with a bright strawberry rim bursting with sumptuous blue and blackberry aromas and flavours integrated with peppery high notes that end gently with succulent fruit intrigue. Smooth and fruity for easy enjoyment immediately or within 3 years of vintage.</p>', 'Dense ruby with a bright strawberry rim bursting with sumptuous blue and blackberry aromas and flavours integrated with peppery high notes.', 22, '', NULL, 33, 57, '', 'Tall Horse Cabernet Sauvignon 2020', 'Rubis dense avec un bord de fraise brillant regorgeant de somptueux arômes et saveurs de bleu et de mûre intégrés à des notes élevées poivrées.', '<p>Rubis dense avec un bord de fraise brillant d&eacute;bordant de somptueux ar&ocirc;mes et saveurs de bleu et de m&ucirc;re int&eacute;gr&eacute;s &agrave; des notes &eacute;lev&eacute;es poivr&eacute;es qui se terminent doucement par une intrigue fruit&eacute;e succulente. Doux et fruit&eacute; pour une d&eacute;gustation facile imm&eacute;diatement ou dans les 3 ans suivant le mill&eacute;sime.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000387', 0, 0, 1, NULL, NULL, '2023-12-28 13:50:21', '2024-02-05 06:59:37'),
(388, '658d7e22dc1ba', 'PRO000388', 0, 'Tall Horse Sauvignon Blanc', '<p>An engaging perfumed nose with expressive grassy tropical fruit aromas and deliciously well rounded green pineapple, gooseberry and citrus flavours with a zesty fresh finish.</p>', 'It is an engaging perfumed nose wine with expressive grassy tropical fruit aromas and deliciously well-rounded green pineapple, gooseberry.', 22, '', NULL, 40, 57, '', 'Tall Horse Sauvignon Blanc', 'C\'est un vin au nez parfumé et engageant avec des arômes expressifs de fruits tropicaux herbacés et des saveurs délicieusement rondes d\'anana', '<p>Un nez parfum&eacute; engageant avec des ar&ocirc;mes expressifs de fruits tropicaux herbac&eacute;s et des saveurs d&eacute;licieusement rondes d&#39;ananas vert, de groseille et d&#39;agrumes avec une finale fra&icirc;che et piquante.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000388', 0, 1, 1, NULL, NULL, '2023-12-28 13:54:42', '2024-02-05 06:59:37'),
(389, '658d7ed50af8d', 'PRO000389', 0, 'Tequila Agavita Gold  38%', '<p>Agavita Gold Tequila is a premium Mexican spirit that is made from the finest blue agave plants, grown in the Jalisco region of Mexico. The tequila is aged for several months in oak barrels, which gives it its rich, golden colour and a smooth, full-bodied flavour with notes of vanilla and caramel.</p>', 'a premium Mexican spirit that is made from the finest blue agave plants, grown in the Jalisco region of Mexico.', 21, '', NULL, 38, 143, '', 'Tequila Agavita Gold  38%', 'un spiritueux mexicain haut de gamme fabriqué à partir des meilleures plantes d\'agave bleue, cultivées dans la région de Jalisco au Mexique.', '<p>Agavita Gold Tequila est un spiritueux mexicain haut de gamme fabriqu&eacute; &agrave; partir des meilleures plantes d&#39;agave bleue, cultiv&eacute;es dans la r&eacute;gion de Jalisco au Mexique. La tequila est vieillie plusieurs mois en f&ucirc;ts de ch&ecirc;ne, ce qui lui conf&egrave;re sa couleur riche et dor&eacute;e et une saveur douce et cors&eacute;e aux notes de vanille et de caramel.</p>', NULL, NULL, 0, NULL, 0, NULL, 1, 'LQ000389', 0, 0, 1, NULL, NULL, '2023-12-28 13:57:41', '2024-02-05 06:59:37'),
(390, '658d800829d56', 'PRO000390', 0, 'Toki Suntory Whisky', '<p>Toki is a blended whisky from Suntory&#39;s three distilleries: Yamazaki, Hakushu and Chita. This is a round and sweet blend with a refreshing citrus character and a spicy finish. &#39;Toki&#39; means &#39;time&#39; in Japanese.</p>', 'Clear gold in colour. On the nose is basil, green apple, and honey. The palate hints of flavours of grapefruit, green grapes, peppermint, and thyme.', 15, '', NULL, 57, 144, '', 'Toki Suntory Whisky', 'De couleur or clair. Au nez, on retrouve le basilic, la pomme verte et le miel. La bouche évoque des saveurs de pamplemousse, de raisin vert', '<p>Toki est un whisky d&#39;assemblage issu des trois distilleries de Suntory : Yamazaki, Hakushu et Chita. Il s&#39;agit d&#39;un m&eacute;lange rond et sucr&eacute; avec un caract&egrave;re d&#39;agrumes rafra&icirc;chissant et une finale &eacute;pic&eacute;e. &laquo; Toki &raquo; signifie &laquo; temps &raquo; en japonais.</p>', NULL, NULL, 0, NULL, 0, NULL, 1, 'LQ000390', 0, 1, 1, NULL, NULL, '2023-12-28 14:02:48', '2024-02-12 13:15:11'),
(391, '658d82644b43b', 'PRO000391', 0, 'Veuve Du Vernay Brut Rose Classic', '<p>Veuve du Vernay Brut Rose a sparkling wine with aromas of berries, subtle and delicate, it brings festivity and glamour to you table with its nice pink color. Fresh and fruity to the nose complemented by smooth, velvety bubbles and raspberry and red fruit flavours on the palate.</p>\r\n\r\n<p>&nbsp;</p>', 'Charming and bubbly, I flaunt a beautiful bright pink color and a subtle scent of small red berries (blackcurrant, redcurrant).', 22, '', NULL, 45, 80, '', 'Veuve Du Vernay Brut Rose Classic', 'Charmante et pétillante, j\'affiche une belle robe rose vif et un subtil parfum de petits fruits rouges (cassis, groseille).', '<p>Veuve du Vernay Brut Rose un vin effervescent aux ar&ocirc;mes de petits fruits, subtil et d&eacute;licat, il apporte de la f&ecirc;te et du glamour &agrave; votre table avec sa jolie couleur rose. Le nez frais et fruit&eacute; est compl&eacute;t&eacute; par des bulles douces et velout&eacute;es et des saveurs de framboise et de fruits rouges en bouche.</p>', NULL, NULL, 0, NULL, 0, NULL, 1, 'LQ000391', 0, 1, 1, NULL, NULL, '2023-12-28 14:12:52', '2024-02-05 06:59:37'),
(392, '658d82d3b4701', 'PRO000392', 0, 'Vodka Classis Jelzin Curaant 37.5%', '<p>it is a fresh Vodka with the aroma of blackcurrant. Whether mixed with juice or pure on ice, this special Vodka will refresh your senses and convince with its special clarity.</p>', 'As the name of this Boris Jelzin Vodka Currant suggests, it is a fresh Vodka with the aroma of blackcurrant.', 21, '', NULL, 29, 130, '', 'Vodka Classis Jelzin Curaant 37.5%', 'Comme le nom de cette Boris Jelzin Vodka Currant l\'indique, il s\'agit d\'une Vodka fraîche à l\'arôme de cassis.', '<p>c&#39;est une Vodka fra&icirc;che &agrave; l&#39;ar&ocirc;me de cassis. Qu&#39;elle soit m&eacute;lang&eacute;e &agrave; du jus ou pure sur glace, cette Vodka sp&eacute;ciale rafra&icirc;chira vos sens et convaincra par sa clart&eacute; particuli&egrave;re.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000392', 0, 1, 1, NULL, NULL, '2023-12-28 14:14:43', '2024-02-05 06:59:37'),
(393, '658d858fba57e', 'PRO000393', 0, 'Wolf Blass Black Label 40Th Vintage', '<p>A distinctive and characteristic Black Label nose defined by layers of fragrant dark berries and blackcurrant, backed up with deep notes of espresso coffee, panforte and smoky, toasted nut barrel ferment characters. Hints of Langhorne Creek mint are evident without being dominant.</p>', 'Full-bodied Cabernet Sauvignon Shiraz Malbec in 1 glass bottle. 14.5% alc. / vol. Rich, generous and complex, with dark plum.', 22, '', NULL, 33, 145, '', 'Wolf Blass Black Label 40Th Vintage', 'Cabernet Sauvignon Shiraz Malbec corsé dans 1 bouteille en verre. 14,5% alc. / vol. Riche, généreux et complexe, avec des notes de prune noire.', '<p>Un nez distinctif et caract&eacute;ristique de Black Label d&eacute;fini par des couches de baies noires parfum&eacute;es et de cassis, soutenu par des notes profondes de caf&eacute; expresso, de panforte et des caract&egrave;res de fermentation en f&ucirc;t de noix grill&eacute;es et fum&eacute;s. Des notes de menthe Langhorne Creek sont &eacute;videntes sans &ecirc;tre dominantes.</p>', NULL, NULL, 0, NULL, 0, NULL, 1, 'LQ000393', 0, 1, 1, NULL, NULL, '2023-12-28 14:26:23', '2024-05-06 10:28:59'),
(394, '65a79c4de848f', 'PRO000394', 0, 'Ginger Beer Grace', '<p>Deliciously fiery, non-alcoholic soft drink. A fresh, zesty flavour which refreshes and revitalizes! Deliciously fiery, non-alcoholic soft drink. A fresh, zesty flavour which refreshes and revitalizes!</p>', 'Deliciously fiery, non-alcoholic soft drink. A fresh, zesty flavour which refreshes and revitalizes!', 11, '', NULL, 32, 126, '', 'Ginger Beer Grace', 'Boisson gazeuse sans alcool délicieusement ardente. Une saveur fraîche et piquante qui rafraîchit et revitalise !', '<p>Boisson gazeuse sans alcool d&eacute;licieusement ardente. Une saveur fra&icirc;che et piquante qui rafra&icirc;chit et revitalise ! Boisson gazeuse sans alcool d&eacute;licieusement ardente. Une saveur fra&icirc;che et piquante qui rafra&icirc;chit et revitalise !</p>', NULL, NULL, 0, NULL, 0, NULL, 1, 'LQ000394', 0, 1, 1, NULL, NULL, '2024-01-17 09:22:21', '2024-02-12 11:35:03'),
