(479, '66599df37423d', 'PRO000479', 0, 'Clansman Blended Scotch Whisky', '<p><span style=\"font-family: Karla, Arial, Helvetica, sans-serif; font-size: 14px;\">High Commissioner Blended Scotch Whisky was first founded in 1856 and opened for the first time in 1866. It&#39;s known for its balance of flavour, making softly fruity whisky with a touch of caramel and a whisper of peat. Originally founded by the Bulloch family, this blended malt whisky has kept its original recipe.</span></p>', 'High Commissioner Blended Scotch Whisky was first founded in 1856 and opened for the first time in 1866.', 15, '', NULL, 48, 179, '', 'CLANSMAN BLENDED SCOTCH WHISKY', 'High Commissioner Blended Scotch Whisky was first founded in 1856 and opened for the first time in 1866.', '<p><span style=\"font-family: Karla, Arial, Helvetica, sans-serif; font-size: 14px;\">High Commissioner Blended Scotch Whisky was first founded in 1856 and opened for the first time in 1866. It&#39;s known for its balance of flavour, making softly fruity whisky with a touch of caramel and a whisper of peat. Originally founded by the Bulloch family, this blended malt whisky has kept its original recipe.</span></p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000479', 0, 0, 1, NULL, NULL, '2024-05-31 09:52:51', '2024-06-11 11:48:18'),
(480, '66599f81be6cd', 'PRO000480', 0, 'Clansman Blended Scotch Whisky', '<p><span style=\"color: rgb(37, 37, 37); font-family: Poppins; font-size: 15px;\">A blend&nbsp;of Highland malt&nbsp;and grain whiskies, Clansman&nbsp;has a soft fruit and vanilla character with a hint of peat. Extremely smooth and can be enjoyed neat, over ice, with water&nbsp;</span></p>', 'A blend of Highland malt and grain whiskies, Clansman has a soft fruit and vanilla character with a hint of peat.', 15, '', NULL, 48, 179, '', 'CLANSMAN BLENDED SCOTCH WHISKY', 'A blend of Highland malt and grain whiskies, Clansman has a soft fruit and vanilla character with a hint of peat.', '<p><span style=\"color: rgb(37, 37, 37); font-family: Poppins; font-size: 15px;\">A blend&nbsp;of Highland malt&nbsp;and grain whiskies, Clansman&nbsp;has a soft fruit and vanilla character with a hint of peat. Extremely smooth and can be enjoyed neat, over ice, with water&nbsp;</span></p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000480', 0, 0, 1, NULL, NULL, '2024-05-31 09:59:29', '2024-06-11 11:47:12'),
(481, '6659a199cef50', 'PRO000481', 0, 'Grants Triple Wood Stand Fast', '<p style=\"box-sizing: border-box; margin: 0px 0px 1.5rem; padding: 0px; color: rgb(66, 66, 66); font-family: Helvetica, Arial, Helvetica, sans-serif; font-size: 14px;\">Grant&#39;s Triple Wood features whisky drawn from three types of cask - Virgin Oak cask provides spicy robustness, American Oak lends subtle vanilla smoothness and Bourbon refill offers brown sugar sweetness, resulting in a smoother, richer, mellower taste.</p>\r\n\r\n<p style=\"box-sizing: border-box; margin: 0px 0px 1.5rem; padding: 0px; color: rgb(66, 66, 66); font-family: Helvetica, Arial, Helvetica, sans-serif; font-size: 14px;\">An approachable blended Scotch whisky from the world-famous brand. A true Grant&#39;s flagship expression.</p>', 'Grant\'s Triple Wood features whisky drawn from three types of cask', 15, '', NULL, 48, 127, '', 'Grants Triple Wood Stand Fast', 'Grant\'s Triple Wood features whisky drawn from three types of cask', '<p style=\"box-sizing: border-box; margin: 0px 0px 1.5rem; padding: 0px; color: rgb(66, 66, 66); font-family: Helvetica, Arial, Helvetica, sans-serif; font-size: 14px;\">Grant&#39;s Triple Wood features whisky drawn from three types of cask - Virgin Oak cask provides spicy robustness, American Oak lends subtle vanilla smoothness and Bourbon refill offers brown sugar sweetness, resulting in a smoother, richer, mellower taste.</p>\r\n\r\n<p style=\"box-sizing: border-box; margin: 0px 0px 1.5rem; padding: 0px; color: rgb(66, 66, 66); font-family: Helvetica, Arial, Helvetica, sans-serif; font-size: 14px;\">An approachable blended Scotch whisky from the world-famous brand. A true Grant&#39;s flagship expression.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000481', 0, 0, 1, NULL, NULL, '2024-05-31 10:08:25', '2024-06-11 11:53:19'),
(482, '6659b349530b6', 'PRO000482', 0, 'The Kurayoshi 8 Years Pure Malt Japanese Whisky', '<p><span style=\"color: rgb(128, 128, 128); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 14px;\">Matured in a Bourbon cask. Amber gold. Opens a little shy, but develops with a spicy fruity interplay (dried fruits, plums, apricots) perhaps a touch of grapefruit, then more nutty and sweet-spicy. All very subtle. Silky and mellow beyond its age statement. A deft burst of spice seals the finish. Possibly less fruity than the 3 year old but with a plusher texture. Quite lovely malt.</span></p>', 'Matured in a Bourbon cask. Amber gold. Opens a little shy, but develops with a spicy fruity interplay', 37, '', NULL, 57, 180, '', 'THE KURAYOSHI 8 YEARS PURE MALT JAPANESE WHISKY', 'Matured in a Bourbon cask. Amber gold. Opens a little shy, but develops with a spicy fruity interplay', '<p><span style=\"color: rgb(128, 128, 128); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 14px;\">Matured in a Bourbon cask. Amber gold. Opens a little shy, but develops with a spicy fruity interplay (dried fruits, plums, apricots) perhaps a touch of grapefruit, then more nutty and sweet-spicy. All very subtle. Silky and mellow beyond its age statement. A deft burst of spice seals the finish. Possibly less fruity than the 3 year old but with a plusher texture. Quite lovely malt.</span></p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000482', 0, 0, 1, NULL, NULL, '2024-05-31 11:23:53', '2024-05-31 11:52:26'),
(483, '6659b5469bd5e', 'PRO000483', 0, 'THE HAKUSHU SINGLE MALT JAPANESE WHISKY DISTILLER\'S RESERVE', '<p><span style=\"color: rgb(42, 42, 42); font-family: &quot;Fira Sans&quot;, sans-serif; font-size: 15px;\">From the Hakushu distillery in the foothills of Mount Kaikomagatake comes their Distiller&#39;s Reserve single malt whisky, a no-age-statement expression, that captures the smoky, herbaceous characteristics of their whiskies. Both lightly-peated and heavily-peated malts were used for this complex and deeply enjoyable whisky. One of two Spring 2014 release from Suntory.</span></p>', 'From the Hakushu distillery in the foothills of Mount Kaikomagatake comes their Distiller\'s Reserve single malt whisky', 37, '', NULL, 57, 181, '', 'THE HAKUSHU SINGLE MALT JAPANESE WHISKY DISTILLER\'S RESERVE', 'From the Hakushu distillery in the foothills of Mount Kaikomagatake comes their Distiller\'s Reserve single malt whisky', '<p><span style=\"color: rgb(42, 42, 42); font-family: &quot;Fira Sans&quot;, sans-serif; font-size: 15px;\">From the Hakushu distillery in the foothills of Mount Kaikomagatake comes their Distiller&#39;s Reserve single malt whisky, a no-age-statement expression, that captures the smoky, herbaceous characteristics of their whiskies. Both lightly-peated and heavily-peated malts were used for this complex and deeply enjoyable whisky. One of two Spring 2014 release from Suntory.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000483', 0, NULL, 2, NULL, NULL, '2024-05-31 11:32:22', '2024-05-31 11:49:06'),
(484, '6659b77eb39ed', 'PRO000484', 0, 'The Hakushu Single Malt Japanese Whisky Distiller\'s Reserve', '<p><span style=\"color: rgb(42, 42, 42); font-family: &quot;Fira Sans&quot;, sans-serif; font-size: 15px;\">From the Hakushu distillery in the foothills of Mount Kaikomagatake comes their Distiller&#39;s Reserve single malt whisky, a no-age-statement expression, that captures the smoky, herbaceous characteristics of their whiskies. Both lightly-peated and heavily-peated malts were used for this complex and deeply enjoyable whisky. One of two Spring 2014 release from Suntory.</span></p>', 'From the Hakushu distillery in the foothills of Mount Kaikomagatake comes their Distiller\'s Reserve single malt whisky', 37, '', NULL, 57, 181, '', 'The Hakushu Single Malt Japanese Whisky Distiller\'s Reserve', 'From the Hakushu distillery in the foothills of Mount Kaikomagatake comes their Distiller\'s Reserve single malt whisky', '<p><span style=\"color: rgb(42, 42, 42); font-family: &quot;Fira Sans&quot;, sans-serif; font-size: 15px;\">From the Hakushu distillery in the foothills of Mount Kaikomagatake comes their Distiller&#39;s Reserve single malt whisky, a no-age-statement expression, that captures the smoky, herbaceous characteristics of their whiskies. Both lightly-peated and heavily-peated malts were used for this complex and deeply enjoyable whisky. One of two Spring 2014 release from Suntory.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000484', 0, NULL, 1, NULL, NULL, '2024-05-31 11:41:50', '2024-05-31 11:41:50'),
(485, '6659ddc8db17d', 'PRO000485', 0, 'Hibiki Suntory Japanese Harmony Blended Whisky 43%', '<p style=\"margin: 0px 0px 15px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-stretch: inherit; font-size: 17px; line-height: 1.8em; font-family: Helvetica, &quot;Helvetica Neue&quot;, Arial, &quot;Lucida Grande&quot;, sans-serif; font-optical-sizing: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; color: rgb(119, 119, 119);\">HIBIKI (響) in Japanese means harmony, and so the name symbolises this unique marriage of malts that has created this highly sought after whisky from Japan.</p>\r\n\r\n<p style=\"margin: 0px 0px 15px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-stretch: inherit; font-size: 17px; line-height: 1.8em; font-family: Helvetica, &quot;Helvetica Neue&quot;, Arial, &quot;Lucida Grande&quot;, sans-serif; font-optical-sizing: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; color: rgb(119, 119, 119);\">Harmony - a rather apt word to describe this well-balanced Japanese blended whisky from the Hibiki range. Hibiki Japanese Harmony is made with malt whiskies from the Yamazaki and Hakushu distilleries, as well as grain whisky from the Chita distillery. The whiskies are drawn from 5 different types of cask, including American white oak casks, Sherry casks and Mizunara oak casks. The blend itself was crafted by the Suntory Whisky blending team, led by Master Blender Shingo Torii. An elegant expression, with wafts of honey, orange, a herbaceous touch or two and light oak.</p>', 'HIBIKI (響) in Japanese means harmony, and so the name symbolises this unique marriage of malts', 37, '', NULL, 57, 182, '', 'Hibiki Suntory Japanese Harmony Blended Whisky 43%', 'HIBIKI (響) in Japanese means harmony, and so the name symbolises this unique marriage of malts', '<p style=\"margin: 0px 0px 15px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-stretch: inherit; font-size: 17px; line-height: 1.8em; font-family: Helvetica, &quot;Helvetica Neue&quot;, Arial, &quot;Lucida Grande&quot;, sans-serif; font-optical-sizing: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; color: rgb(119, 119, 119);\">HIBIKI (響) in Japanese means harmony, and so the name symbolises this unique marriage of malts that has created this highly sought after whisky from Japan.</p>\r\n\r\n<p style=\"margin: 0px 0px 15px; padding: 0px; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-variant-alternates: inherit; font-variant-position: inherit; font-stretch: inherit; font-size: 17px; line-height: 1.8em; font-family: Helvetica, &quot;Helvetica Neue&quot;, Arial, &quot;Lucida Grande&quot;, sans-serif; font-optical-sizing: inherit; font-kerning: inherit; font-feature-settings: inherit; font-variation-settings: inherit; color: rgb(119, 119, 119);\">Harmony - a rather apt word to describe this well-balanced Japanese blended whisky from the Hibiki range. Hibiki Japanese Harmony is made with malt whiskies from the Yamazaki and Hakushu distilleries, as well as grain whisky from the Chita distillery. The whiskies are drawn from 5 different types of cask, including American white oak casks, Sherry casks and Mizunara oak casks. The blend itself was crafted by the Suntory Whisky blending team, led by Master Blender Shingo Torii. An elegant expression, with wafts of honey, orange, a herbaceous touch or two and light oak.</p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000485', 0, NULL, 1, NULL, NULL, '2024-05-31 14:25:12', '2024-05-31 14:25:12'),
(486, '6659df190373e', 'PRO000486', 0, 'Suntory Kakubin Japanese Whisky', '<p><span style=\"color: rgb(66, 66, 66); font-family: Helvetica, Arial, Helvetica, sans-serif; font-size: 14px;\">Kakubin Yellow Label is Suntory&#39;s flagship blended whisky. Produced since 1937, its name means &#39;square bottle&#39;. A blend of bourbon-cask whisky from Yamazaki and Hakushu, this is a classic example of lighter Japanese whisky and is great in a highball with soda.</span></p>', 'Kakubin Yellow Label is Suntory\'s flagship blended whisky.', 37, '', NULL, 57, 183, '', 'Suntory Kakubin Japanese Whisky', 'Kakubin Yellow Label is Suntory\'s flagship blended whisky.', '<p><span style=\"color: rgb(66, 66, 66); font-family: Helvetica, Arial, Helvetica, sans-serif; font-size: 14px;\">Kakubin Yellow Label is Suntory&#39;s flagship blended whisky. Produced since 1937, its name means &#39;square bottle&#39;. A blend of bourbon-cask whisky from Yamazaki and Hakushu, this is a classic example of lighter Japanese whisky and is great in a highball with soda.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000486', 0, NULL, 1, NULL, NULL, '2024-05-31 14:30:49', '2024-05-31 14:30:49'),
(487, '6659e1c33c6e1', 'PRO000487', 0, 'Togouchi 15 Years Japanese Blended Whisky 43.8%', '<p><span style=\"color: rgb(0, 0, 0); font-family: Muli, sans-serif; font-size: 19px;\">A 15 year old blended whisky from the Togouchi range, produced by the little-known Chugoku Jozo in Japan. They source whisky from Scotland and Canada, and then age it in a railway tunnel before bottling it at 43.8% ABV.</span></p>', 'A 15 year old blended whisky from the Togouchi range, produced by the little-known Chugoku Jozo', 37, '', NULL, 57, 184, '', 'Togouchi 15 Years Japanese Blended Whisky 43.8%', 'A 15 year old blended whisky from the Togouchi range, produced by the little-known Chugoku Jozo', '<p><span style=\"color: rgb(0, 0, 0); font-family: Muli, sans-serif; font-size: 19px;\">A 15 year old blended whisky from the Togouchi range, produced by the little-known Chugoku Jozo in Japan. They source whisky from Scotland and Canada, and then age it in a railway tunnel before bottling it at 43.8% ABV.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000487', 0, NULL, 1, NULL, NULL, '2024-05-31 14:42:11', '2024-05-31 14:42:11'),
(488, '6659e3742c274', 'PRO000488', 0, 'Togouchi 15 Years Japanese Blended Whisky 43.8%', '<p><span style=\"color: rgb(0, 0, 0); font-family: Muli, sans-serif; font-size: 19px;\">A 15 year old blended whisky from the Togouchi range, produced by the little-known Chugoku Jozo in Japan. They source whisky from Scotland and Canada, and then age it in a railway tunnel before bottling it at 43.8% ABV.</span></p>', 'A 15 year old blended whisky from the Togouchi range.', 37, '', NULL, 57, 184, '', 'Togouchi 15 Years Japanese Blended Whisky 43.8%', 'A 15 year old blended whisky from the Togouchi range.', '<p><span style=\"color: rgb(0, 0, 0); font-family: Muli, sans-serif; font-size: 19px;\">A 15 year old blended whisky from the Togouchi range, produced by the little-known Chugoku Jozo in Japan. They source whisky from Scotland and Canada, and then age it in a railway tunnel before bottling it at 43.8% ABV.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000488', 0, NULL, 2, NULL, NULL, '2024-05-31 14:49:24', '2024-05-31 14:50:38'),
(489, '6659e492c727f', 'PRO000489', 0, 'Toki Suntory whisky', '<p style=\"box-sizing: border-box; margin: 20px 0px 0px; font-size: 17px; line-height: 2; font-family: &quot;Open Sans&quot;;\">t&rsquo;s a concept rich in meaning the world over, but particularly in Japan where respect for tradition and reinvention sparks a powerful creative energy.</p>\r\n\r\n<p style=\"box-sizing: border-box; margin: 20px 0px 0px; font-size: 17px; line-height: 2; font-family: &quot;Open Sans&quot;;\">Inspired by that interplay, Suntory Whisky Toki&trade; brings together old and new -the House of Suntory&rsquo;s proud heritage and its innovative spirit- to create blended Japanese whisky that is both groundbreaking and timeless.</p>', 't’s a concept rich in meaning the world over, but particularly in Japan', 37, '', NULL, 57, 144, '', 'Toki Suntory whisky', 't’s a concept rich in meaning the world over, but particularly in Japan', '<p style=\"box-sizing: border-box; margin: 20px 0px 0px; font-size: 17px; line-height: 2; font-family: &quot;Open Sans&quot;;\">t&rsquo;s a concept rich in meaning the world over, but particularly in Japan where respect for tradition and reinvention sparks a powerful creative energy.</p>\r\n\r\n<p style=\"box-sizing: border-box; margin: 20px 0px 0px; font-size: 17px; line-height: 2; font-family: &quot;Open Sans&quot;;\">Inspired by that interplay, Suntory Whisky Toki&trade; brings together old and new -the House of Suntory&rsquo;s proud heritage and its innovative spirit- to create blended Japanese whisky that is both groundbreaking and timeless.</p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000489', 0, NULL, 1, NULL, NULL, '2024-05-31 14:54:10', '2024-05-31 14:54:10');
