(490, '6659e661dbb74', 'PRO000490', 0, 'Kujira 8 Years Ryukyu Whisky', '<p><span style=\"color: rgb(47, 47, 43); font-family: Poppins, Arial, Helvetica, sans-serif; font-size: 14px;\">Exceptionally malted, fermented, and distilled by craftsman in the distillery, the Ryukyu Whiskey is made from best quality Indica rice and unique Okinawa&rsquo;s black koji, and then reserved in Spanish Sherry casks and selected American Kentucky bourbon casks for more than 8 years.</span></p>', 'Exceptionally malted, fermented, and distilled by craftsman in the distillery, the Ryukyu Whiskey.', 37, '', NULL, 57, 185, '', 'Kujira 8 Years Ryukyu Whisky', 'Exceptionally malted, fermented, and distilled by craftsman in the distillery, the Ryukyu Whiskey.', '<p><span style=\"color: rgb(47, 47, 43); font-family: Poppins, Arial, Helvetica, sans-serif; font-size: 14px;\">Exceptionally malted, fermented, and distilled by craftsman in the distillery, the Ryukyu Whiskey is made from best quality Indica rice and unique Okinawa&rsquo;s black koji, and then reserved in Spanish Sherry casks and selected American Kentucky bourbon casks for more than 8 years.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000490', 0, NULL, 1, NULL, NULL, '2024-05-31 15:01:53', '2024-05-31 15:01:53'),
(491, '6659e8548ee00', 'PRO000491', 0, 'Ichiro Malt & Grain Worl Whisky Limited Edition', '<p style=\"box-sizing: border-box; color: rgb(109, 109, 109); margin: 0px 0px 19.4444px; font-family: Montserrat; font-size: 18px;\">Introducing the exceptional Ichiro&#39;s Malt &amp; Grain Limited Edition World Blended Whisky, a true masterpiece that brings together the finest whiskies from around the world. This 750ml bottle is a one-of-a-kind expression that embodies the essence of Japanese craftsmanship and the art of blending.</p>\r\n\r\n<p style=\"box-sizing: border-box; color: rgb(109, 109, 109); margin: 0px 0px 19.4444px; font-family: Montserrat; font-size: 18px;\">Ichiro&#39;s Malt &amp; Grain is a true testament to the creativity and passion of its creator, Ichiro Akuto. With a meticulous attention to detail and an unwavering commitment to quality, this limited edition whisky is a result of years of experimentation, blending and maturation.</p>', 'Introducing the exceptional Ichiro\'s Malt & Grain Limited Edition World Blended Whisky', 37, '', NULL, 57, 186, '', 'Ichiro Malt & Grain Worl Whisky Limited Edition', 'Introducing the exceptional Ichiro\'s Malt & Grain Limited Edition World Blended Whisky', '<p style=\"box-sizing: border-box; color: rgb(109, 109, 109); margin: 0px 0px 19.4444px; font-family: Montserrat; font-size: 18px;\">Introducing the exceptional Ichiro&#39;s Malt &amp; Grain Limited Edition World Blended Whisky, a true masterpiece that brings together the finest whiskies from around the world. This 750ml bottle is a one-of-a-kind expression that embodies the essence of Japanese craftsmanship and the art of blending.</p>\r\n\r\n<p style=\"box-sizing: border-box; color: rgb(109, 109, 109); margin: 0px 0px 19.4444px; font-family: Montserrat; font-size: 18px;\">Ichiro&#39;s Malt &amp; Grain is a true testament to the creativity and passion of its creator, Ichiro Akuto. With a meticulous attention to detail and an unwavering commitment to quality, this limited edition whisky is a result of years of experimentation, blending and maturation.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000491', 0, 0, 1, NULL, NULL, '2024-05-31 15:10:12', '2024-05-31 15:12:49'),
(492, '6659ea7c09c97', 'PRO000492', 0, 'Nikka Coffey Grain Whisky', '<p><span style=\"color: rgb(0, 0, 0); font-family: Nunito, Arial, Helvetica, sans-serif; font-size: large;\">After becoming well acquainted with Miyagikyo&#39;s magnificent single grains through their highly sought after single cask releases, in 2011 we advised Nikka to develop a more accessible expression which continued to focus on their grain whiskies. Nine months later Nikka Coffey Grain was born! The result exceeded our expectations. Somewhere between a Bourbon and a Scotch, it can be enjoyed neat, on the rocks, served long with still water mizuwari-style, topped with soda in a highball or as the base of classic cocktails such as a perfect Manhattan.</span></p>', 'After becoming well acquainted with Miyagikyo\'s magnificent single grains', 37, '', NULL, 57, 187, '', 'Nikka Coffey Grain Whisky', 'After becoming well acquainted with Miyagikyo\'s magnificent single grains', '<p><span style=\"color: rgb(0, 0, 0); font-family: Nunito, Arial, Helvetica, sans-serif; font-size: large;\">After becoming well acquainted with Miyagikyo&#39;s magnificent single grains through their highly sought after single cask releases, in 2011 we advised Nikka to develop a more accessible expression which continued to focus on their grain whiskies. Nine months later Nikka Coffey Grain was born! The result exceeded our expectations. Somewhere between a Bourbon and a Scotch, it can be enjoyed neat, on the rocks, served long with still water mizuwari-style, topped with soda in a highball or as the base of classic cocktails such as a perfect Manhattan.</span></p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000492', 0, 0, 1, NULL, NULL, '2024-05-31 15:19:24', '2024-05-31 15:21:43'),
(493, '6659ec2f6f179', 'PRO000493', 0, 'Yamazakura Blended Whisky', '<p><span style=\"color: rgb(18, 38, 47); font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Ubuntu, &quot;Helvetica Neue&quot;, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 14px;\">This blended whisky is crafted by combining malt whiskies, including those from the Asaka distillery, with grain whisky made from corn. It contains 20% malted barley and has been aged for three years in first-fill ex-Bourbon casks, ex-Oloroso casks, and ex-Pedro Xim&eacute;nez casks, resulting in a rich and complex flavor profile.</span></p>', 'This blended whisky is crafted by combining malt whiskies, including those from the Asaka distillery', 37, '', NULL, 57, 188, '', 'Yamazakura Blended Whisky', 'This blended whisky is crafted by combining malt whiskies, including those from the Asaka distillery', '<p><span style=\"color: rgb(18, 38, 47); font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Ubuntu, &quot;Helvetica Neue&quot;, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Symbol&quot;; font-size: 14px;\">This blended whisky is crafted by combining malt whiskies, including those from the Asaka distillery, with grain whisky made from corn. It contains 20% malted barley and has been aged for three years in first-fill ex-Bourbon casks, ex-Oloroso casks, and ex-Pedro Xim&eacute;nez casks, resulting in a rich and complex flavor profile.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000493', 0, NULL, 1, NULL, NULL, '2024-05-31 15:26:39', '2024-05-31 15:26:39'),
(494, '6659eec405ba8', 'PRO000494', 0, 'Mars Maltage Cosmo Blended Malt Whisky', '<p><span style=\"color: rgb(0, 0, 0); font-family: Ovo, serif; font-size: 17px;\">Mars Maltage Cosmo&nbsp;is integrating the permanent range of Mars Whisky. This blended malt whisky expresses a rich and intensely greedy aromatic profile, which will bring you into a charming Japanese and Scottish taste universe, carefully built around the two producing countries craftmanship.</span></p>', 'Mars Maltage Cosmo is integrating the permanent range of Mars Whisky.', 37, '', NULL, 57, 189, '', 'Mars Maltage Cosmo Blended Malt Whisky', 'Mars Maltage Cosmo is integrating the permanent range of Mars Whisky.', '<p><span style=\"color: rgb(0, 0, 0); font-family: Ovo, serif; font-size: 17px;\">Mars Maltage Cosmo&nbsp;is integrating the permanent range of Mars Whisky. This blended malt whisky expresses a rich and intensely greedy aromatic profile, which will bring you into a charming Japanese and Scottish taste universe, carefully built around the two producing countries craftmanship.</span></p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000494', 0, 0, 1, NULL, NULL, '2024-05-31 15:37:40', '2024-05-31 15:46:34'),
(495, '6659f2e8a6536', 'PRO000495', 0, 'Nikka Coffey Malt Whisky', '<div class=\"text\" style=\"box-sizing: border-box; color: rgb(28, 28, 28); font-family: Luxia-Display; font-size: 14px; background-color: rgb(246, 246, 246);\">\r\n<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 0px; font-family: &quot;Open Sans&quot;, sans-serif;\">This unique expression was developed in 2013 as a result of Nikka&rsquo;s continuous experiments to widen the variety and offer more excitements to aficionados. Made from 100% malted barley, whisky distilled in a Coffey still is matured in old casks to enhance the rich maltiness, complexity and a silky texture. This expression is not categorized as &ldquo;malt whisky&rdquo; but as &ldquo;grain whisky&rdquo; since it is not distilled in a pot still.</p>\r\n</div>\r\n\r\n<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 1rem; font-family: &quot;Open Sans&quot;, sans-serif; color: rgb(28, 28, 28); font-size: 14px; background-color: rgb(246, 246, 246);\">ABV- 45%</p>', 'This unique expression was developed in 2013 as a result of Nikka’s continuous experiments', 37, '', NULL, 57, 187, '', 'Nikka Coffey Malt Whisky', 'This unique expression was developed in 2013 as a result of Nikka’s continuous experiments', '<div class=\"text\" style=\"box-sizing: border-box; color: rgb(28, 28, 28); font-family: Luxia-Display; font-size: 14px; background-color: rgb(246, 246, 246);\">\r\n<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 0px; font-family: &quot;Open Sans&quot;, sans-serif;\">This unique expression was developed in 2013 as a result of Nikka&rsquo;s continuous experiments to widen the variety and offer more excitements to aficionados. Made from 100% malted barley, whisky distilled in a Coffey still is matured in old casks to enhance the rich maltiness, complexity and a silky texture. This expression is not categorized as &ldquo;malt whisky&rdquo; but as &ldquo;grain whisky&rdquo; since it is not distilled in a pot still.</p>\r\n</div>\r\n\r\n<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 1rem; font-family: &quot;Open Sans&quot;, sans-serif; color: rgb(28, 28, 28); font-size: 14px; background-color: rgb(246, 246, 246);\">ABV- 45%</p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000495', 0, NULL, 1, NULL, NULL, '2024-05-31 15:55:20', '2024-05-31 15:55:20'),
(496, '6659f66373795', 'PRO000496', 0, 'The Yamazaki Single Malt Japanese Whisky Limited Edition 2022', '<p style=\"box-sizing: inherit; -webkit-font-smoothing: antialiased; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); margin-top: 0.9375rem; margin-bottom: 0.9375rem; color: rgb(17, 17, 17); font-family: Slate, sans-serif; font-size: 15px;\">The Yamazaki Distillery is Japan&rsquo;s first and oldest malt whisky distillery founded in 1923 by Suntory&#39;s founder Shinjiro Torii. Yamazaki is not only the soul place of Suntory Whisky but the birthplace of Japanese Whisky. Inspired by traditional Scottish whisky, it is said that Torii selected the land of Yamazaki at the foot of Mt. Tennozan, for its high-quality water source and natural environment ideal for whisky making.</p>\r\n\r\n<p style=\"box-sizing: inherit; -webkit-font-smoothing: antialiased; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); margin-top: 0.9375rem; margin-bottom: 0.9375rem; color: rgb(17, 17, 17); font-family: Slate, sans-serif; font-size: 15px;\">Yamazaki was born from the surprising, delicate yet profound experience of a Japanese single malt whisky. Multi-layered with fruit and Mizunara aromas, Yamazaki whiskies are complex and deep. Made at Yamazaki Distillery, the birthplace of Japanese whisky, its signature multi-layered taste is highly praised by whisky connoisseurs all over the world.&nbsp;The House of Suntory honors the birthplace of Japanese whisky, capturing and celebrating the pioneering roots of one of the world&rsquo;s greatest whiskies from the place Shinjiro Torii chose to begin the illustrious journey of Japanese whisky. Fifth generation Chief Blender Shinji Fukuyo has returned to the roots of what made Yamazaki Single Malt quintessentially Yamazaki: deep, complex and multi-layered with fruit and Mizunara notes.</p>', 'The Yamazaki Distillery is Japan’s first and oldest malt whisky distillery founded in 1923 by Suntory\'s founder Shinjiro Torii.', 37, '', NULL, 57, 190, '', 'The Yamazaki Single Malt Japanese Whisky Limited Edition 2022', 'The Yamazaki Distillery is Japan’s first and oldest malt whisky distillery founded in 1923 by Suntory\'s founder Shinjiro Torii.', '<p style=\"box-sizing: inherit; -webkit-font-smoothing: antialiased; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); margin-top: 0.9375rem; margin-bottom: 0.9375rem; color: rgb(17, 17, 17); font-family: Slate, sans-serif; font-size: 15px;\">The Yamazaki Distillery is Japan&rsquo;s first and oldest malt whisky distillery founded in 1923 by Suntory&#39;s founder Shinjiro Torii. Yamazaki is not only the soul place of Suntory Whisky but the birthplace of Japanese Whisky. Inspired by traditional Scottish whisky, it is said that Torii selected the land of Yamazaki at the foot of Mt. Tennozan, for its high-quality water source and natural environment ideal for whisky making.</p>\r\n\r\n<p style=\"box-sizing: inherit; -webkit-font-smoothing: antialiased; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); margin-top: 0.9375rem; margin-bottom: 0.9375rem; color: rgb(17, 17, 17); font-family: Slate, sans-serif; font-size: 15px;\">Yamazaki was born from the surprising, delicate yet profound experience of a Japanese single malt whisky. Multi-layered with fruit and Mizunara aromas, Yamazaki whiskies are complex and deep. Made at Yamazaki Distillery, the birthplace of Japanese whisky, its signature multi-layered taste is highly praised by whisky connoisseurs all over the world.&nbsp;The House of Suntory honors the birthplace of Japanese whisky, capturing and celebrating the pioneering roots of one of the world&rsquo;s greatest whiskies from the place Shinjiro Torii chose to begin the illustrious journey of Japanese whisky. Fifth generation Chief Blender Shinji Fukuyo has returned to the roots of what made Yamazaki Single Malt quintessentially Yamazaki: deep, complex and multi-layered with fruit and Mizunara notes.</p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000496', 0, NULL, 1, NULL, NULL, '2024-05-31 16:10:11', '2024-05-31 16:10:11'),
(497, '6659f86314e82', 'PRO000497', 0, 'Nikka Yoichi Discovery Single Malt Japanese Whisky 47%', '<p style=\"box-sizing: inherit; -webkit-font-smoothing: antialiased; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); margin-top: 0.9375rem; margin-bottom: 0.9375rem; color: rgb(17, 17, 17); font-family: Slate, sans-serif; font-size: 15px;\">In 1918, a young Japanese man with an ambition to make genuine whisky went alone to Scotland to unveil the secret of whisky making. He is Masataka Taketsuru, the founder of Nikka Whisky.</p>\r\n\r\n<p style=\"box-sizing: inherit; -webkit-font-smoothing: antialiased; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); margin-top: 0.9375rem; margin-bottom: 0.9375rem; color: rgb(17, 17, 17); font-family: Slate, sans-serif; font-size: 15px;\">Yoichi Single Malt is a range of single malt expressions from the Yoichi Distillery, Nikka&#39;s first distillery built in 1934. The founder Masataka Taketsuru chose the town of Yoichi in Hokkaido because of the similar environmental conditions to Scotland, where he learned whisky-making. Yoichi malts are described as bold and strong with refined peaty notes and smokiness brought by the traditional direct coal-fired distillation. Sea breeze from the Ishikari Bay delivers a briny hint to the whisky during maturation.&nbsp;</p>', 'In 1918, a young Japanese man with an ambition to make genuine whisky went alone to Scotland', 37, '', NULL, 57, 187, '', 'Nikka Yoichi Discovery Single Malt Japanese Whisky 47%', 'In 1918, a young Japanese man with an ambition to make genuine whisky went alone to Scotland', '<p style=\"box-sizing: inherit; -webkit-font-smoothing: antialiased; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); margin-top: 0.9375rem; margin-bottom: 0.9375rem; color: rgb(17, 17, 17); font-family: Slate, sans-serif; font-size: 15px;\">In 1918, a young Japanese man with an ambition to make genuine whisky went alone to Scotland to unveil the secret of whisky making. He is Masataka Taketsuru, the founder of Nikka Whisky.</p>\r\n\r\n<p style=\"box-sizing: inherit; -webkit-font-smoothing: antialiased; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); margin-top: 0.9375rem; margin-bottom: 0.9375rem; color: rgb(17, 17, 17); font-family: Slate, sans-serif; font-size: 15px;\">Yoichi Single Malt is a range of single malt expressions from the Yoichi Distillery, Nikka&#39;s first distillery built in 1934. The founder Masataka Taketsuru chose the town of Yoichi in Hokkaido because of the similar environmental conditions to Scotland, where he learned whisky-making. Yoichi malts are described as bold and strong with refined peaty notes and smokiness brought by the traditional direct coal-fired distillation. Sea breeze from the Ishikari Bay delivers a briny hint to the whisky during maturation.&nbsp;</p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000497', 0, NULL, 1, NULL, NULL, '2024-05-31 16:18:43', '2024-05-31 16:18:43'),
(498, '6659fa85b06b1', 'PRO000498', 0, 'Suntory Old The Japanese Tradition Whisky', '<p style=\"box-sizing: inherit; -webkit-font-smoothing: antialiased; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); margin-top: 0.9375rem; margin-bottom: 0.9375rem; color: rgb(5, 5, 5); font-family: Lato, sans-serif; font-size: 15px;\">Suntory Whisky OLD was introduced in 1950 to be Suntory&#39;s first luxurious blended whisky. Harmonious and rich, the smooth flavor along with its floral aroma blends into Suntory&#39;s Whisky OLD.</p>\r\n\r\n<p style=\"box-sizing: inherit; -webkit-font-smoothing: antialiased; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); margin-top: 0.9375rem; margin-bottom: 0.9375rem; color: rgb(5, 5, 5); font-family: Lato, sans-serif; font-size: 15px;\">It is a true classic, celebrated and embraced till this day as the standard of a Japanese premium whisky.</p>', 'Suntory Whisky OLD was introduced in 1950 to be Suntory\'s first luxurious blended whisky.', 37, '', NULL, 57, 183, '', 'Suntory Old The Japanese Tradition Whisky', 'Suntory Whisky OLD was introduced in 1950 to be Suntory\'s first luxurious blended whisky.', '<p style=\"box-sizing: inherit; -webkit-font-smoothing: antialiased; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); margin-top: 0.9375rem; margin-bottom: 0.9375rem; color: rgb(5, 5, 5); font-family: Lato, sans-serif; font-size: 15px;\">Suntory Whisky OLD was introduced in 1950 to be Suntory&#39;s first luxurious blended whisky. Harmonious and rich, the smooth flavor along with its floral aroma blends into Suntory&#39;s Whisky OLD.</p>\r\n\r\n<p style=\"box-sizing: inherit; -webkit-font-smoothing: antialiased; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); margin-top: 0.9375rem; margin-bottom: 0.9375rem; color: rgb(5, 5, 5); font-family: Lato, sans-serif; font-size: 15px;\">It is a true classic, celebrated and embraced till this day as the standard of a Japanese premium whisky.</p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000498', 0, NULL, 1, NULL, NULL, '2024-05-31 16:27:49', '2024-05-31 16:27:49'),
(499, '6659ffbf15bbe', 'PRO000499', 0, 'Suntory Torys Extra Whisky', '<p><span style=\"color: rgb(33, 33, 33); font-family: Nunito, sans-serif; font-size: 15px;\">&quot;Torys&quot; is a whisky series from Suntory, which was launched shortly after the Second World War with the slogan &quot;Good Taste, Good Value&quot;. &quot;Torys&quot; was designed as a whisky for beginners and made its debut in Japan in 1946. As whisky was an absolute luxury item at the time, &quot;Torys&quot; quickly became very popular, offering fine taste at a good price. In 1958, &quot;Uncle Torys&quot; debuted as a brand icon on the bottle. It symbolized the typical office worker who enjoyed a glass of whiskey at the end of the day to unwind from a hard day&#39;s work. Uncle Torys was very popular at the time of rapid economic growth in Japan and became Suntory&#39;s corporate mascot. In addition to commercials, Uncle Torys can still be found on labels and packaging of individual Torys series.</span></p>', '\"Torys\" is a whisky series from Suntory, which was launched shortly after the Second World War with the slogan \"Good Taste', 37, '', NULL, 57, 183, '', 'Suntory Torys Extra Whisky', '\"Torys\" is a whisky series from Suntory, which was launched shortly after the Second World War with the slogan \"Good Taste', '<p><span style=\"color: rgb(33, 33, 33); font-family: Nunito, sans-serif; font-size: 15px;\">&quot;Torys&quot; is a whisky series from Suntory, which was launched shortly after the Second World War with the slogan &quot;Good Taste, Good Value&quot;. &quot;Torys&quot; was designed as a whisky for beginners and made its debut in Japan in 1946. As whisky was an absolute luxury item at the time, &quot;Torys&quot; quickly became very popular, offering fine taste at a good price. In 1958, &quot;Uncle Torys&quot; debuted as a brand icon on the bottle. It symbolized the typical office worker who enjoyed a glass of whiskey at the end of the day to unwind from a hard day&#39;s work. Uncle Torys was very popular at the time of rapid economic growth in Japan and became Suntory&#39;s corporate mascot. In addition to commercials, Uncle Torys can still be found on labels and packaging of individual Torys series.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000499', 0, NULL, 1, NULL, NULL, '2024-05-31 16:50:07', '2024-05-31 16:50:07'),
(500, '665a02f191520', 'PRO000500', 0, 'Bushmills The Original Irish Whisky', '<p><span style=\"color: rgb(33, 37, 41); font-family: Barlow, sans-serif; font-size: 16px;\">Ireland&#39;s oldest whisky, Bushmills Original Irish is a blend of triple distilled malt whiskey and a lighter grain whiskey. You&#39;ll notice it&#39;s rich, smooth warming taste almost instantly. It&#39;s an easy drinking, versatile whiskey that can be enjoyed neat, over ice or with your favourite mixer.</span></p>', 'Ireland\'s oldest whisky, Bushmills Original Irish is a blend of triple distilled malt whiskey and a lighter grain whiskey.', 37, '', NULL, 41, 173, '', 'Bushmills The Original Irish Whisky', 'Ireland\'s oldest whisky, Bushmills Original Irish is a blend of triple distilled malt whiskey and a lighter grain whiskey.', '<p><span style=\"color: rgb(33, 37, 41); font-family: Barlow, sans-serif; font-size: 16px;\">Ireland&#39;s oldest whisky, Bushmills Original Irish is a blend of triple distilled malt whiskey and a lighter grain whiskey. You&#39;ll notice it&#39;s rich, smooth warming taste almost instantly. It&#39;s an easy drinking, versatile whiskey that can be enjoyed neat, over ice or with your favourite mixer.</span></p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000500', 0, 0, 1, NULL, NULL, '2024-05-31 17:03:45', '2024-05-31 17:20:29'),
(501, '665a07c19a991', 'PRO000501', 0, 'Jameson Black Barrel', '<p><span style=\"font-family: Arial, Helvetica, sans-serif; font-size: 14px;\">A super release from Jameson, with a high proportion of Irish pot still whiskey as well as small batch grain. The result is an increased body and level of richness when compared to the core expression. It&rsquo;s aged in double charred first fill bourbon casks (black barrels). Well worth a look. Rich and fruity with notes of tropical fruits, coconut, nectarines in yoghurt, guava and a thick core of sweet cereals. Thick and full on the palate, with an intense, unctuous creaminess, alongside dates, walnuts and peels. Good peach and coconut notes, and a little cinnamon. Long finish, and very fruity with notes of cinnamon and nutmeg and hints of potpourri.</span></p>', 'A super release from Jameson, with a high proportion of Irish pot still whiskey as well as small batch grain.', 37, '', NULL, 41, 42, '', 'Jameson Black Barrel', 'A super release from Jameson, with a high proportion of Irish pot still whiskey as well as small batch grain.', '<p><span style=\"font-family: Arial, Helvetica, sans-serif; font-size: 14px;\">A super release from Jameson, with a high proportion of Irish pot still whiskey as well as small batch grain. The result is an increased body and level of richness when compared to the core expression. It&rsquo;s aged in double charred first fill bourbon casks (black barrels). Well worth a look. Rich and fruity with notes of tropical fruits, coconut, nectarines in yoghurt, guava and a thick core of sweet cereals. Thick and full on the palate, with an intense, unctuous creaminess, alongside dates, walnuts and peels. Good peach and coconut notes, and a little cinnamon. Long finish, and very fruity with notes of cinnamon and nutmeg and hints of potpourri.</span></p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000501', 0, 0, 1, NULL, NULL, '2024-05-31 17:24:17', '2024-05-31 17:27:59'),
(502, '665a099f3b6ad', 'PRO000502', 0, 'Jameson Triple Distilled Irish Whiskey', '<p><span style=\"color: rgb(102, 102, 102); font-family: &quot;TESCO Modern&quot;, Arial, sans-serif; font-size: 16px; white-space-collapse: preserve-breaks;\">Jameson Irish whiskey is a triple-distilled blended Irish whiskey, as versatile as it is smooth. Whiskey like Jameson isn&#39;t just born smooth and balanced. First, we take the best of pot still and fine grain whiskeys. Then we triple distil them. Not because we have to, because we want to. This gives Jameson its signature smoothness. This tradition began in 1780 with John Jameson, and we continue his legacy to this day. Finally, we age our whiskey in oak casks for a minimum of 4 years. The result? A unique whiskey with a perfect balance of spicy, nutty and vanilla notes with hints of sweet sherry. Simply enjoy neat, poured over ice, or in any of your favourite whiskey cocktails.</span></p>', 'Jameson Irish whiskey is a triple-distilled blended Irish whiskey, as versatile as it is smooth.', 37, '', NULL, 41, 42, '', 'Jameson Triple Distilled Irish Whiskey', 'Jameson Irish whiskey is a triple-distilled blended Irish whiskey, as versatile as it is smooth.', '<p><span style=\"color: rgb(102, 102, 102); font-family: &quot;TESCO Modern&quot;, Arial, sans-serif; font-size: 16px; white-space-collapse: preserve-breaks;\">Jameson Irish whiskey is a triple-distilled blended Irish whiskey, as versatile as it is smooth. Whiskey like Jameson isn&#39;t just born smooth and balanced. First, we take the best of pot still and fine grain whiskeys. Then we triple distil them. Not because we have to, because we want to. This gives Jameson its signature smoothness. This tradition began in 1780 with John Jameson, and we continue his legacy to this day. Finally, we age our whiskey in oak casks for a minimum of 4 years. The result? A unique whiskey with a perfect balance of spicy, nutty and vanilla notes with hints of sweet sherry. Simply enjoy neat, poured over ice, or in any of your favourite whiskey cocktails.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000502', 0, NULL, 1, NULL, NULL, '2024-05-31 17:32:15', '2024-05-31 17:32:15'),
(503, '665a0ea9d7dc8', 'PRO000503', 0, 'Bushmills Black Bush Irish Whiskey', '<p><span style=\"font-family: &quot;helvetica lt 45&quot;, sans-serif; font-size: 16px;\">A rich, dark, Irish blend, Black Bush contains a high proportion of triple-distilled single malt, aged in Oloroso sherry casks for around 8-10 years before marriage with the grain. Picked up the top prize in its category at the World Whisky Awards 2010.</span></p>', 'A rich, dark, Irish blend, Black Bush contains a high proportion of triple-distilled single malt', 37, '', NULL, 41, 173, '', 'Bushmills Black Bush Irish Whiskey', 'A rich, dark, Irish blend, Black Bush contains a high proportion of triple-distilled single malt', '<p><span style=\"font-family: &quot;helvetica lt 45&quot;, sans-serif; font-size: 16px;\">A rich, dark, Irish blend, Black Bush contains a high proportion of triple-distilled single malt, aged in Oloroso sherry casks for around 8-10 years before marriage with the grain. Picked up the top prize in its category at the World Whisky Awards 2010.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000503', 0, NULL, 1, NULL, NULL, '2024-05-31 17:53:45', '2024-05-31 17:53:45'),
(504, '665d8f901dae5', 'PRO000504', 0, 'Angel\'s Envy Bourbon Whiskey 43.3%', '<p><span style=\"color: rgb(0, 0, 0); font-family: Montserrat, sans-serif;\">Angel?s Envy is an exceptional Kentucky straight bourbon finished in port wine barrels. Given the Highest Recommendation by Spirit Journal, celebrated by Whisky Advocate, The Bourbon Review, and awarded Wine Enthusiast?s highest bourbon rating, Angel?s Envy is unlike any other whiskey you?ve ever tasted.</span></p>', 'Angel\'s Envy is an exceptional Kentucky straight bourbon finished in port wine barrels.', 37, '', NULL, 49, 191, '', 'Angel\'s Envy Bourbon Whiskey 43.3%', 'Angel\'s Envy is an exceptional Kentucky straight bourbon finished in port wine barrels.', '<p><span style=\"color: rgb(0, 0, 0); font-family: Montserrat, sans-serif;\">Angel&#39;s Envy is an exceptional Kentucky straight bourbon finished in port wine barrels. Given the Highest Recommendation by Spirit Journal, celebrated by Whisky Advocate, The Bourbon Review, and awarded Wine Enthusiast&#39;s highest bourbon rating, Angel?s Envy is unlike any other whiskey you?ve ever tasted.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000504', 0, NULL, 1, NULL, NULL, '2024-06-03 09:40:32', '2024-06-03 09:40:32'),
(505, '665d91346d15c', 'PRO000505', 0, 'Elijah Craig Barrel Proof Bourbon Whiskey 68.3%', '<p><span style=\"color: rgb(28, 29, 29); font-family: &quot;Avenir Next&quot;, sans-serif; font-size: 17px; letter-spacing: 0.425px;\">Released for the first time in the March 2013, each batch is a an uncut, unfiltered selection of Elijah Craig 12 Year. Each batch will vary both in&nbsp;flavour&nbsp;and in proof as is the nature of such releases. The &quot;code&quot; for the batches is as follows: The first letter of each batch indicates the order of the release for that year beginning with the letter &quot;A&quot; for the first batch, &quot;B&quot; for the second, and so on. Next is a number which reflects the month of the release, so &quot;1&quot; for January for example. The third and fourth digits reflect the year of the release. This batch number is printed on the front of each bottle along with the proof.</span></p>', 'Released for the first time in the March 2013, each batch is a an uncut, unfiltered selection of Elijah Craig 12 Year.', 37, '', NULL, 49, 192, '', 'Elijah Craig Barrel Proof Bourbon Whiskey 68.3%', 'Released for the first time in the March 2013, each batch is a an uncut, unfiltered selection of Elijah Craig 12 Year.', '<p><span style=\"color: rgb(28, 29, 29); font-family: &quot;Avenir Next&quot;, sans-serif; font-size: 17px; letter-spacing: 0.425px;\">Released for the first time in the March 2013, each batch is a an uncut, unfiltered selection of Elijah Craig 12 Year. Each batch will vary both in&nbsp;flavour&nbsp;and in proof as is the nature of such releases. The &quot;code&quot; for the batches is as follows: The first letter of each batch indicates the order of the release for that year beginning with the letter &quot;A&quot; for the first batch, &quot;B&quot; for the second, and so on. Next is a number which reflects the month of the release, so &quot;1&quot; for January for example. The third and fourth digits reflect the year of the release. This batch number is printed on the front of each bottle along with the proof.</span></p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000505', 0, 0, 1, NULL, NULL, '2024-06-03 09:47:32', '2024-06-03 09:49:01'),
(506, '665d94868533b', 'PRO000506', 0, 'Jack Daniels Whisky', '<p><span style=\"color: rgb(28, 27, 27); font-family: &quot;Nunito Sans&quot;, sans-serif; font-size: 14px; background-color: rgb(250, 250, 250);\">Jack Daniels Old No. 7 is mellowed drop by drop through 10-feet of sugar maple charcoal, then matured in handcrafted barrels. This amber coloured Tennessee Whisky boasts a well balanced character of sweet and oaky aromas and flavours. Its full-bodied texture, gives this a smooth and sweet finish.&nbsp;</span></p>', 'Jack Daniels Old No. 7 is mellowed drop by drop through 10-feet of sugar maple charcoal, then matured in handcrafted barrels.', 37, '', NULL, 61, 93, '', 'Jack Daniels Whisky', 'Jack Daniels Old No. 7 is mellowed drop by drop through 10-feet of sugar maple charcoal, then matured in handcrafted barrels.', '<p><span style=\"color: rgb(28, 27, 27); font-family: &quot;Nunito Sans&quot;, sans-serif; font-size: 14px; background-color: rgb(250, 250, 250);\">Jack Daniels Old No. 7 is mellowed drop by drop through 10-feet of sugar maple charcoal, then matured in handcrafted barrels. This amber coloured Tennessee Whisky boasts a well balanced character of sweet and oaky aromas and flavours. Its full-bodied texture, gives this a smooth and sweet finish.&nbsp;</span></p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000506', 0, 0, 1, NULL, NULL, '2024-06-03 10:01:42', '2024-06-05 14:02:44'),
(507, '665d964a5ae5f', 'PRO000507', 0, 'Jack Daniel\'s Boubon Whisky', '<p><span style=\"color: rgb(17, 17, 17); font-family: Slate, sans-serif; font-size: 15px;\">Jack Daniels it&#39;s a legend in the world of whiskey. This iconic brand has become synonymous with quality, tradition, and a taste that can satisfy even the most discerning palate. The story of Jack Daniels begins back in the 19th century, in the small town of Lynchburg, Tennessee.</span></p>', 'Jack Daniels it\'s a legend in the world of whiskey.', 37, '', NULL, 49, 93, '', 'Jack Daniel\'s Boubon Whisky', 'Jack Daniels it\'s a legend in the world of whiskey.', '<p><span style=\"color: rgb(17, 17, 17); font-family: Slate, sans-serif; font-size: 15px;\">Jack Daniels it&#39;s a legend in the world of whiskey. This iconic brand has become synonymous with quality, tradition, and a taste that can satisfy even the most discerning palate. The story of Jack Daniels begins back in the 19th century, in the small town of Lynchburg, Tennessee.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000507', 0, NULL, 1, NULL, NULL, '2024-06-03 10:09:14', '2024-06-03 10:09:14'),
(508, '665d9a36e2925', 'PRO000508', 0, 'Jack Daniel Whiskey', '<p><span style=\"color: rgb(17, 17, 17); font-family: Slate, sans-serif; font-size: 15px;\">Jack Daniels it&#39;s a legend in the world of whiskey. This iconic brand has become synonymous with quality, tradition, and a taste that can satisfy even the most discerning palate. The story of Jack Daniels begins back in the 19th century, in the small town of Lynchburg, Tennessee.</span></p>', 'Jack Daniels it\'s a legend in the world of whiskey.', 37, '', NULL, 61, 93, '', 'Jack Daniel Whiskey', 'Jack Daniels it\'s a legend in the world of whiskey.', '<p><span style=\"color: rgb(17, 17, 17); font-family: Slate, sans-serif; font-size: 15px;\">Jack Daniels it&#39;s a legend in the world of whiskey. This iconic brand has become synonymous with quality, tradition, and a taste that can satisfy even the most discerning palate. The story of Jack Daniels begins back in the 19th century, in the small town of Lynchburg, Tennessee.</span></p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000508', 0, 0, 1, NULL, NULL, '2024-06-03 10:25:58', '2024-06-05 14:01:34'),
(509, '665d9c1f8ca4b', 'PRO000509', 0, 'Jack Daniel Single Barrel', '<p><span style=\"color: rgb(28, 28, 28); font-family: &quot;Harmonia Sans&quot;, sans-serif; font-size: 16px; letter-spacing: 0.4px;\">Jack Daniel&rsquo;s Tennessee Whiskey comes from the United States oldest registered distillery and is charcoal mellowed through 10 feet of sugar maple charcoal. The Distillery, founded in 1866 by Mr. Jack Daniel in Lynchburg, Tennessee, is one of the most well-known producers of whiskey in the world. Jack Daniel&rsquo;s Tennessee Whiskey is made with the finest corn, rye and barley malt. Its distinctive character is a result of natural fermentation, careful distillation, and use of the Distillery&rsquo;s iron-free water from the Cave Spring that runs at a constant 56&deg; F.</span></p>', 'Tennessee, is one of the most well-known producers of whiskey in the world.', 37, '', NULL, 61, 93, '', 'Jack Daniel Single Barrel', 'Tennessee, is one of the most well-known producers of whiskey in the world.', '<p><span style=\"color: rgb(28, 28, 28); font-family: &quot;Harmonia Sans&quot;, sans-serif; font-size: 16px; letter-spacing: 0.4px;\">Jack Daniel&rsquo;s Tennessee Whiskey comes from the United States oldest registered distillery and is charcoal mellowed through 10 feet of sugar maple charcoal. The Distillery, founded in 1866 by Mr. Jack Daniel in Lynchburg, Tennessee, is one of the most well-known producers of whiskey in the world. Jack Daniel&rsquo;s Tennessee Whiskey is made with the finest corn, rye and barley malt. Its distinctive character is a result of natural fermentation, careful distillation, and use of the Distillery&rsquo;s iron-free water from the Cave Spring that runs at a constant 56&deg; F.</span></p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000509', 0, 0, 1, NULL, NULL, '2024-06-03 10:34:07', '2024-06-05 14:01:06'),
(510, '665d9dfc2c094', 'PRO000510', 0, 'Jack Daniels Apple 35%', '<p style=\"box-sizing: inherit; color: rgb(17, 21, 22); font-family: Ubuntu, Helvetica, Arial, sans-serif; font-size: 16px;\">Jack Daniel&rsquo;s Tennessee Apple is a delicious, complex Jack. It delivers the unique character of Jack Daniel&rsquo;s Tennessee Whiskey coupled with the taste of crisp, green apple.</p>\r\n\r\n<p style=\"box-sizing: inherit; color: rgb(17, 21, 22); font-family: Ubuntu, Helvetica, Arial, sans-serif; font-size: 16px;\">Described by our master distiller Chris Fletcher, as &ldquo;Like a freshly picked apple in a glass of Jack.</p>', 'Jack Daniel’s Tennessee Apple is a delicious, complex Jack.', 37, '', NULL, 61, 93, '', 'Jack Daniels Apple 35%', 'Jack Daniel’s Tennessee Apple is a delicious, complex Jack.', '<p style=\"box-sizing: inherit; color: rgb(17, 21, 22); font-family: Ubuntu, Helvetica, Arial, sans-serif; font-size: 16px;\">Jack Daniel&rsquo;s Tennessee Apple is a delicious, complex Jack. It delivers the unique character of Jack Daniel&rsquo;s Tennessee Whiskey coupled with the taste of crisp, green apple.</p>\r\n\r\n<p style=\"box-sizing: inherit; color: rgb(17, 21, 22); font-family: Ubuntu, Helvetica, Arial, sans-serif; font-size: 16px;\">Described by our master distiller Chris Fletcher, as &ldquo;Like a freshly picked apple in a glass of Jack.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000510', 0, 0, 1, NULL, NULL, '2024-06-03 10:42:04', '2024-06-05 13:59:59'),
(511, '665da58f73270', 'PRO000511', 0, 'Royal Stag Whisky 40%', '<p><span style=\"color: rgb(35, 31, 32); font-family: Roboto, sans-serif; font-size: 17px; letter-spacing: 1px;\">Royal Stag Whisky 75.00 Cl&nbsp; /&nbsp;&nbsp; Aroma : Leafy [like cut grass], woody fruity [tropical fruit] with a touch of smoke [like burnt wood] &bull; Taste: Medium bodied, rounded &bull; Mouth feel: Smooth with a touch of smoke</span></p>', 'Medium bodied, rounded • Mouth feel: Smooth with a touch of smoke', 37, '', NULL, 63, 193, '', 'Royal Stag Whisky 40%', 'Medium bodied, rounded • Mouth feel: Smooth with a touch of smoke', '<p><span style=\"color: rgb(35, 31, 32); font-family: Roboto, sans-serif; font-size: 17px; letter-spacing: 1px;\">Royal Stag Whisky 75.00 Cl&nbsp; /&nbsp;&nbsp; Aroma : Leafy [like cut grass], woody fruity [tropical fruit] with a touch of smoke [like burnt wood] &bull; Taste: Medium bodied, rounded &bull; Mouth feel: Smooth with a touch of smoke</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000511', 0, NULL, 1, NULL, NULL, '2024-06-03 11:14:23', '2024-06-03 11:14:23'),
(512, '665da70c2eb81', 'PRO000512', 0, 'Royal Stag Whisky 40%', '<p><span style=\"color: rgb(35, 31, 32); font-family: Roboto, sans-serif; font-size: 17px; letter-spacing: 1px;\">Royal Stag Whisky 18.00 Cl&nbsp; /&nbsp;&nbsp; Aroma : Leafy [like cut grass], woody fruity [tropical fruit] with a touch of smoke [like burnt wood] &bull; Taste: Medium bodied, rounded &bull; Mouth feel: Smooth with a touch of smoke</span></p>', 'Medium bodied, rounded • Mouth feel: Smooth with a touch of smoke', 37, '', NULL, 63, 193, '', 'Royal Stag Whisky 40%', 'Medium bodied, rounded • Mouth feel: Smooth with a touch of smoke', '<p><span style=\"color: rgb(35, 31, 32); font-family: Roboto, sans-serif; font-size: 17px; letter-spacing: 1px;\">Royal Stag Whisky 18</span><span style=\"color: rgb(35, 31, 32); font-family: Roboto, sans-serif; font-size: 17px; letter-spacing: 1px;\">.00 Cl&nbsp; /&nbsp;&nbsp; Aroma : Leafy [like cut grass], woody fruity [tropical fruit] with a touch of smoke [like burnt wood] &bull; Taste: Medium bodied, rounded &bull; Mouth feel: Smooth with a touch of smoke</span></p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000512', 0, 0, 1, NULL, NULL, '2024-06-03 11:20:44', '2024-06-03 11:22:18'),
(513, '665da9132f1a7', 'PRO000513', 0, 'Royal Challenge Finest Premium Whiskey', '<p><span style=\"color: rgb(122, 122, 122); font-family: Roboto, sans-serif; font-size: 16px;\">A full-bodied blend of imported scotch &amp; select Indian malt.</span><br style=\"box-sizing: border-box; color: rgb(122, 122, 122); font-family: Roboto, sans-serif; font-size: 16px;\" />\r\n<span style=\"color: rgb(122, 122, 122); font-family: Roboto, sans-serif; font-size: 16px;\">Carefully matured in imported white oak casks to attain the unique blend which makes Royal Challenge.</span><br style=\"box-sizing: border-box; color: rgb(122, 122, 122); font-family: Roboto, sans-serif; font-size: 16px;\" />\r\n<span style=\"color: rgb(122, 122, 122); font-family: Roboto, sans-serif; font-size: 16px;\">An intensely smooth blend made with the finest Scotch, premium Indian grain, and malts that have been matured in charred American oak casks.</span></p>', 'A full-bodied blend of imported scotch & select Indian malt.', 37, '', NULL, 63, 77, '', 'Royal Challenge Finest Premium Whiskey', 'A full-bodied blend of imported scotch & select Indian malt.', '<p><span style=\"color: rgb(122, 122, 122); font-family: Roboto, sans-serif; font-size: 16px;\">A full-bodied blend of imported scotch &amp; select Indian malt.</span><br style=\"box-sizing: border-box; color: rgb(122, 122, 122); font-family: Roboto, sans-serif; font-size: 16px;\" />\r\n<span style=\"color: rgb(122, 122, 122); font-family: Roboto, sans-serif; font-size: 16px;\">Carefully matured in imported white oak casks to attain the unique blend which makes Royal Challenge.</span><br style=\"box-sizing: border-box; color: rgb(122, 122, 122); font-family: Roboto, sans-serif; font-size: 16px;\" />\r\n<span style=\"color: rgb(122, 122, 122); font-family: Roboto, sans-serif; font-size: 16px;\">An intensely smooth blend made with the finest Scotch, premium Indian grain, and malts that have been matured in charred American oak casks.</span></p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000513', 0, 0, 1, NULL, NULL, '2024-06-03 11:29:23', '2024-06-03 11:37:30'),
(514, '665db3a2b05e9', 'PRO000514', 0, 'Antiquity Blue ultra Premium whiskey', '<p style=\"box-sizing: inherit; margin-bottom: 1.5em; font-size: 16px; line-height: 1.875; margin-top: 0px; color: rgb(64, 64, 64); font-family: Poppins;\">Antiquity Blue embodies the timeless traditions of making whisky. In 1826, a Scotsman Robert Stein pioneered the art of grain whisky at Cameronbridge Distillery.</p>\r\n\r\n<p style=\"box-sizing: inherit; margin-bottom: 1.5em; font-size: 16px; line-height: 1.875; color: rgb(64, 64, 64); font-family: Poppins;\">Today, Antiquity Blue is blended with scotch from the same distillery, made using the identical process of grain distillation in copper pot stills that Stein invented.</p>', 'Antiquity Blue embodies the timeless traditions of making whisky.', 37, '', NULL, 63, 194, '', 'Antiquity Blue ultra Premium whiskey', 'Antiquity Blue embodies the timeless traditions of making whisky.', '<p style=\"box-sizing: inherit; margin-bottom: 1.5em; font-size: 16px; line-height: 1.875; margin-top: 0px; color: rgb(64, 64, 64); font-family: Poppins;\">Antiquity Blue embodies the timeless traditions of making whisky. In 1826, a Scotsman Robert Stein pioneered the art of grain whisky at Cameronbridge Distillery.</p>\r\n\r\n<p style=\"box-sizing: inherit; margin-bottom: 1.5em; font-size: 16px; line-height: 1.875; color: rgb(64, 64, 64); font-family: Poppins;\">Today, Antiquity Blue is blended with scotch from the same distillery, made using the identical process of grain distillation in copper pot stills that Stein invented.</p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000514', 0, NULL, 1, NULL, NULL, '2024-06-03 12:14:26', '2024-06-03 12:14:26'),
(515, '665dca4d9bc76', 'PRO000515', 0, 'Imperial Blue Whisky', '<p><span style=\"color: rgb(91, 91, 91); font-family: &quot;Helvetica Neue&quot;, Helvetica, Arial, sans-serif; font-size: 18px;\">A perfect blend of Indian grain spirits and imported scotch malts, Imperial Blue is known for its exquisite smoothness.</span></p>', 'A perfect blend of Indian grain spirits and imported scotch malts', 37, '', NULL, 63, 195, '', 'Imperial Blue Whisky', 'A perfect blend of Indian grain spirits and imported scotch malts', '<p><span style=\"color: rgb(91, 91, 91); font-family: &quot;Helvetica Neue&quot;, Helvetica, Arial, sans-serif; font-size: 18px;\">A perfect blend of Indian grain spirits and imported scotch malts, Imperial Blue is known for its exquisite smoothness.</span></p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000515', 0, 0, 1, NULL, NULL, '2024-06-03 13:51:09', '2024-06-03 13:55:13'),
(516, '665dcc74aca61', 'PRO000516', 0, 'Imperial Blue Whisky', '<p><span style=\"color: rgb(91, 91, 91); font-family: &quot;Helvetica Neue&quot;, Helvetica, Arial, sans-serif; font-size: 18px;\">A perfect blend of Indian grain spirits and imported scotch malts, Imperial Blue is known for its exquisite smoothness.</span></p>', 'A perfect blend of Indian grain spirits and imported scotch malts', 37, '', NULL, 63, 195, '', 'Imperial Blue Whisky', 'A perfect blend of Indian grain spirits and imported scotch malts', '<p><span style=\"color: rgb(91, 91, 91); font-family: &quot;Helvetica Neue&quot;, Helvetica, Arial, sans-serif; font-size: 18px;\">A perfect blend of Indian grain spirits and imported scotch malts, Imperial Blue is known for its exquisite smoothness.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000516', 0, NULL, 1, NULL, NULL, '2024-06-03 14:00:20', '2024-06-03 14:00:20'),
(517, '665dce9acb6e7', 'PRO000517', 0, 'Imperial Blue Whisky', '<p><span style=\"color: rgb(91, 91, 91); font-family: &quot;Helvetica Neue&quot;, Helvetica, Arial, sans-serif; font-size: 18px;\">A perfect blend of Indian grain spirits and imported scotch malts, Imperial Blue is known for its exquisite smoothness.</span></p>', 'A perfect blend of Indian grain spirits and imported scotch malts', 37, '', NULL, 63, 195, '', 'Imperial Blue Whisky', 'A perfect blend of Indian grain spirits and imported scotch malts', '<p><span style=\"color: rgb(91, 91, 91); font-family: &quot;Helvetica Neue&quot;, Helvetica, Arial, sans-serif; font-size: 18px;\">A perfect blend of Indian grain spirits and imported scotch malts, Imperial Blue is known for its exquisite smoothness.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000517', 0, NULL, 1, NULL, NULL, '2024-06-03 14:09:30', '2024-06-03 14:09:30');
