(518, '665ddc30946ab', 'PRO000518', 0, 'Legend Premium Whisky', '<p style=\"padding: 0px; margin: 0px 0px 15px; box-sizing: border-box; color: rgb(0, 0, 0); font-family: &quot;albert sans&quot;, sans-serif; font-size: 16px;\">Legend Premium Classic Whisky is a blended Scotch whisky that is produced in Scotland. The brand is owned by Amrut Distilleries Ltd., an Indian company that specializes in producing high-quality whiskies.</p>\r\n\r\n<p style=\"padding: 0px; margin: 0px 0px 15px; box-sizing: border-box; color: rgb(0, 0, 0); font-family: &quot;albert sans&quot;, sans-serif; font-size: 16px;\">Legend Premium Classic Whisky is a smooth and well-balanced whisky that has a rich and mellow flavor. It is made from a blend of malt and grain whiskies that have been aged in oak barrels. The whisky has a golden color and a smooth, velvety texture that is perfect for sipping.</p>\r\n\r\n<p style=\"padding: 0px; margin: 0px 0px 15px; box-sizing: border-box; color: rgb(0, 0, 0); font-family: &quot;albert sans&quot;, sans-serif; font-size: 16px;\">Overall, Legend Premium Classic Whisky is a premium whisky that is enjoyed by whisky enthusiasts around the world. However, it is important to drink responsibly and in moderation.</p>', 'Legend Premium Classic Whisky is a blended Scotch whisky that is produced in Scotland.', 37, '', NULL, 63, 196, '', 'Legend Premium Whisky', 'Legend Premium Classic Whisky is a blended Scotch whisky that is produced in Scotland.', '<p style=\"padding: 0px; margin: 0px 0px 15px; box-sizing: border-box; color: rgb(0, 0, 0); font-family: &quot;albert sans&quot;, sans-serif; font-size: 16px;\">Legend Premium Classic Whisky is a blended Scotch whisky that is produced in Scotland. The brand is owned by Amrut Distilleries Ltd., an Indian company that specializes in producing high-quality whiskies.</p>\r\n\r\n<p style=\"padding: 0px; margin: 0px 0px 15px; box-sizing: border-box; color: rgb(0, 0, 0); font-family: &quot;albert sans&quot;, sans-serif; font-size: 16px;\">Legend Premium Classic Whisky is a smooth and well-balanced whisky that has a rich and mellow flavor. It is made from a blend of malt and grain whiskies that have been aged in oak barrels. The whisky has a golden color and a smooth, velvety texture that is perfect for sipping.</p>\r\n\r\n<p style=\"padding: 0px; margin: 0px 0px 15px; box-sizing: border-box; color: rgb(0, 0, 0); font-family: &quot;albert sans&quot;, sans-serif; font-size: 16px;\">Overall, Legend Premium Classic Whisky is a premium whisky that is enjoyed by whisky enthusiasts around the world. However, it is important to drink responsibly and in moderation.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000518', 0, 0, 1, NULL, NULL, '2024-06-03 15:07:28', '2024-06-03 15:40:32'),
(519, '665de94a06d8a', 'PRO000519', 0, 'Hennessy VS', '<p><span style=\"color: rgb(77, 77, 77); font-family: Lato, Arial, Helvetica, sans-serif; font-size: 10.001px;\">World&rsquo;s most popular cognac meaning Very Special. Modern day equivalent of the original Hennessy Three-Star created in 1865. Selected from 4 premier growing areas. Hennessy V.S brings together an intense and fruity character with pleasantly oaky notes. Powerful flavors suggest grilled almonds, supported by lively notes reminiscent of fresh grapes.</span></p>', 'World’s most popular cognac meaning Very Special. Modern day equivalent of the original Hennessy Three-Star created in 1865', 21, '', NULL, 43, 72, '', 'Hennessy VS', 'World’s most popular cognac meaning Very Special. Modern day equivalent of the original Hennessy Three-Star created in 1865', '<p><span style=\"color: rgb(77, 77, 77); font-family: Lato, Arial, Helvetica, sans-serif; font-size: 10.001px;\">World&rsquo;s most popular cognac meaning Very Special. Modern day equivalent of the original Hennessy Three-Star created in 1865. Selected from 4 premier growing areas. Hennessy V.S brings together an intense and fruity character with pleasantly oaky notes. Powerful flavors suggest grilled almonds, supported by lively notes reminiscent of fresh grapes.</span></p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000519', 0, 0, 1, NULL, NULL, '2024-06-03 16:03:22', '2024-06-03 16:14:41'),
