(532, '665ee1d99b50d', 'PRO000532', 0, 'Martell Vs Single Distillery', '<p><span style=\"color: rgb(28, 27, 27); font-family: &quot;Nunito Sans&quot;, sans-serif; font-size: 14px; background-color: rgb(250, 250, 250);\">Remarkably smooth and fruity, Martell VS is perfect to be enjoyed in cocktails. Distilled from clear wines, this cognac offers a richer aromatic experience.</span></p>', 'Remarkably smooth and fruity, Martell VS is perfect to be enjoyed in cocktails.', 21, '', NULL, 43, 46, '', 'Martell Vs Single Distillery', 'Remarkably smooth and fruity, Martell VS is perfect to be enjoyed in cocktails.', '<p><span style=\"color: rgb(28, 27, 27); font-family: &quot;Nunito Sans&quot;, sans-serif; font-size: 14px; background-color: rgb(250, 250, 250);\">Remarkably smooth and fruity, Martell VS is perfect to be enjoyed in cocktails. Distilled from clear wines, this cognac offers a richer aromatic experience.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000532', 0, NULL, 1, NULL, NULL, '2024-06-04 09:43:53', '2024-06-04 09:43:53'),
(533, '665ee47fabe7d', 'PRO000533', 0, 'Martell XO', '<p><span style=\"color: rgb(34, 34, 34); font-family: &quot;Crimson Text&quot;, serif; font-size: 17px;\">Premium cognac from the house of Martell, one of the oldest cognac producers in France</span><br style=\"box-sizing: inherit; color: rgb(34, 34, 34); font-family: &quot;Crimson Text&quot;, serif; font-size: 17px;\" />\r\n<span style=\"color: rgb(34, 34, 34); font-family: &quot;Crimson Text&quot;, serif; font-size: 17px;\">Aged for up to 30 years in French Limousin oak casks</span><br style=\"box-sizing: inherit; color: rgb(34, 34, 34); font-family: &quot;Crimson Text&quot;, serif; font-size: 17px;\" />\r\n<span style=\"color: rgb(34, 34, 34); font-family: &quot;Crimson Text&quot;, serif; font-size: 17px;\">Complex aromas with notes of candied fruit, vanilla, cinnamon and ginger</span></p>', 'Premium cognac from the house of Martell, one of the oldest cognac producers in France', 21, '', NULL, 43, 46, '', 'Martell XO', 'Premium cognac from the house of Martell, one of the oldest cognac producers in France', '<p><span style=\"color: rgb(34, 34, 34); font-family: &quot;Crimson Text&quot;, serif; font-size: 17px;\">Premium cognac from the house of Martell, one of the oldest cognac producers in France</span><br style=\"box-sizing: inherit; color: rgb(34, 34, 34); font-family: &quot;Crimson Text&quot;, serif; font-size: 17px;\" />\r\n<span style=\"color: rgb(34, 34, 34); font-family: &quot;Crimson Text&quot;, serif; font-size: 17px;\">Aged for up to 30 years in French Limousin oak casks</span><br style=\"box-sizing: inherit; color: rgb(34, 34, 34); font-family: &quot;Crimson Text&quot;, serif; font-size: 17px;\" />\r\n<span style=\"color: rgb(34, 34, 34); font-family: &quot;Crimson Text&quot;, serif; font-size: 17px;\">Complex aromas with notes of candied fruit, vanilla, cinnamon and ginger</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000533', 0, NULL, 1, NULL, NULL, '2024-06-04 09:55:11', '2024-06-04 09:55:11'),
(534, '665eea181096a', 'PRO000534', 0, 'Remy Martin VSOP', '<p><span style=\"color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\">&quot;R&eacute;my Martin VSOP embodies the perfect harmony of powerful and elegant aromas. It is the symbol of the Cellar Master&rsquo;s art of blending.&nbsp;</span><br style=\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\" />\r\n<br style=\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\" />\r\n<span style=\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); font-weight: bolder; color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\">NOSE&nbsp;</span><br style=\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\" />\r\n<span style=\"color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\">Dominant notes of vanilla thanks to longer ageing in French Limousin oak barrels, followed by ripe apricot, baked apple, and an elegant floral note.&nbsp;</span><br style=\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\" />\r\n<br style=\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\" />\r\n<span style=\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); font-weight: bolder; color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\">TASTE&nbsp;</span><br style=\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\" />\r\n<span style=\"color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\">A perfect harmony between the firm character of ripe fruit and subtle notes of liquorice, offering a great complexity of elegant and powerful aromas.&nbsp;</span><br style=\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\" />\r\n<br style=\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\" />\r\n<span style=\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); font-weight: bolder; color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\">BODY&nbsp;</span><br style=\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\" />\r\n<span style=\"color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\">Well-balanced, structured, and multi-layered, it combines the roundness of ripe fruit with a silky texture.&nbsp;</span><br style=\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\" />\r\n&nbsp;</p>', '\"Rémy Martin VSOP embodies the perfect harmony of powerful and elegant aromas.', 21, '', NULL, 43, 101, '', 'Remy Martin VSOP', '\"Rémy Martin VSOP embodies the perfect harmony of powerful and elegant aromas.', '<p><span style=\"color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\">&quot;R&eacute;my Martin VSOP embodies the perfect harmony of powerful and elegant aromas. It is the symbol of the Cellar Master&rsquo;s art of blending.&nbsp;</span><br style=\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\" />\r\n<br style=\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\" />\r\n<span style=\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); font-weight: bolder; color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\">NOSE&nbsp;</span><br style=\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\" />\r\n<span style=\"color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\">Dominant notes of vanilla thanks to longer ageing in French Limousin oak barrels, followed by ripe apricot, baked apple, and an elegant floral note.&nbsp;</span><br style=\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\" />\r\n<br style=\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\" />\r\n<span style=\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); font-weight: bolder; color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\">TASTE&nbsp;</span><br style=\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\" />\r\n<span style=\"color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\">A perfect harmony between the firm character of ripe fruit and subtle notes of liquorice, offering a great complexity of elegant and powerful aromas.&nbsp;</span><br style=\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\" />\r\n<br style=\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\" />\r\n<span style=\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); font-weight: bolder; color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\">BODY&nbsp;</span><br style=\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\" />\r\n<span style=\"color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\">Well-balanced, structured, and multi-layered, it combines the roundness of ripe fruit with a silky texture.&nbsp;</span><br style=\"box-sizing: border-box; margin: 0px; padding: 0px; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); color: rgb(84, 84, 83); font-family: Arial, Helvetica, sans-serif; font-size: 14px;\" />\r\n&nbsp;</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000534', 0, 0, 1, NULL, NULL, '2024-06-04 10:19:04', '2024-06-04 10:31:34'),
(535, '665eefde51201', 'PRO000535', 0, 'Remy Martin VSOP', '<p style=\"box-sizing: border-box; -webkit-font-smoothing: antialiased; margin-top: 0px; font-size: 14px; margin-bottom: 1.6em; color: rgb(28, 27, 27); font-family: &quot;Nunito Sans&quot;, sans-serif; background-color: rgb(250, 250, 250);\">The iconic<span style=\"box-sizing: border-box; -webkit-font-smoothing: antialiased;\">&nbsp;</span><span class=\"nowrap\" style=\"box-sizing: border-box; -webkit-font-smoothing: antialiased;\">R&eacute;my Martin</span><span style=\"box-sizing: border-box; -webkit-font-smoothing: antialiased;\">&nbsp;</span>VSOP cognac embodies the signature style of the House, with a vibrant gold color, revealing dominant notes of vanilla, ripe apricot and baked apple.</p>\r\n\r\n<p style=\"box-sizing: border-box; -webkit-font-smoothing: antialiased; margin-top: 0px; font-size: 14px; margin-bottom: 1.6em; color: rgb(28, 27, 27); font-family: &quot;Nunito Sans&quot;, sans-serif; background-color: rgb(250, 250, 250);\"><span class=\"nowrap\" style=\"box-sizing: border-box; -webkit-font-smoothing: antialiased;\">R&eacute;my Martin</span><span style=\"box-sizing: border-box; -webkit-font-smoothing: antialiased;\">&nbsp;</span>VSOP is highly versatile thanks to the complexity and elegancy of its aromas.</p>\r\n\r\n<p class=\"p1\" style=\"box-sizing: border-box; -webkit-font-smoothing: antialiased; margin-top: 0px; font-size: 14px; margin-bottom: 1.6em; color: rgb(28, 27, 27); font-family: &quot;Nunito Sans&quot;, sans-serif; background-color: rgb(250, 250, 250);\">This versatility made it enjoyable neat, on the rocks, frozen, or in a cocktail, such as a R&eacute;my Ginger cocktail.</p>', 'The iconic Rémy Martin VSOP cognac embodies the signature style of the House, with a vibrant gold color', 21, '', NULL, 43, 101, '', 'Remy Martin VSOP', 'The iconic Rémy Martin VSOP cognac embodies the signature style of the House, with a vibrant gold color', '<p style=\"box-sizing: border-box; -webkit-font-smoothing: antialiased; margin-top: 0px; font-size: 14px; margin-bottom: 1.6em; color: rgb(28, 27, 27); font-family: &quot;Nunito Sans&quot;, sans-serif; background-color: rgb(250, 250, 250);\">The iconic<span style=\"box-sizing: border-box; -webkit-font-smoothing: antialiased;\">&nbsp;</span><span class=\"nowrap\" style=\"box-sizing: border-box; -webkit-font-smoothing: antialiased;\">R&eacute;my Martin</span><span style=\"box-sizing: border-box; -webkit-font-smoothing: antialiased;\">&nbsp;</span>VSOP cognac embodies the signature style of the House, with a vibrant gold color, revealing dominant notes of vanilla, ripe apricot and baked apple.</p>\r\n\r\n<p style=\"box-sizing: border-box; -webkit-font-smoothing: antialiased; margin-top: 0px; font-size: 14px; margin-bottom: 1.6em; color: rgb(28, 27, 27); font-family: &quot;Nunito Sans&quot;, sans-serif; background-color: rgb(250, 250, 250);\"><span class=\"nowrap\" style=\"box-sizing: border-box; -webkit-font-smoothing: antialiased;\">R&eacute;my Martin</span><span style=\"box-sizing: border-box; -webkit-font-smoothing: antialiased;\">&nbsp;</span>VSOP is highly versatile thanks to the complexity and elegancy of its aromas.</p>\r\n\r\n<p class=\"p1\" style=\"box-sizing: border-box; -webkit-font-smoothing: antialiased; margin-top: 0px; font-size: 14px; margin-bottom: 1.6em; color: rgb(28, 27, 27); font-family: &quot;Nunito Sans&quot;, sans-serif; background-color: rgb(250, 250, 250);\">This versatility made it enjoyable neat, on the rocks, frozen, or in a cocktail, such as a R&eacute;my Ginger cocktail.</p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000535', 0, NULL, 1, NULL, NULL, '2024-06-04 10:43:42', '2024-06-04 10:43:42'),
(536, '665ef0ff4ff78', 'PRO000536', 0, 'Remy Martin XO 70CL', '<p><span style=\"color: rgb(11, 11, 14); font-family: Poppins, Quicksand, &quot;Helvetica Neue&quot;, Arial, sans-serif; font-size: 16px;\">Remy Martin XO cognac; A fine champagne containing 85% Grande champagne eaux-de-vie which is slowly and lovingly aged over 37 years to produce a wonderful, smooth cognac which is delightfully rich and mellow</span></p>', 'Remy Martin XO cognac; A fine champagne containing 85% Grande champagne eaux-de-vie', 21, '', NULL, 43, 101, '', 'Remy Martin XO 70CL', 'Remy Martin XO cognac; A fine champagne containing 85% Grande champagne eaux-de-vie', '<p><span style=\"color: rgb(11, 11, 14); font-family: Poppins, Quicksand, &quot;Helvetica Neue&quot;, Arial, sans-serif; font-size: 16px;\">Remy Martin XO cognac; A fine champagne containing 85% Grande champagne eaux-de-vie which is slowly and lovingly aged over 37 years to produce a wonderful, smooth cognac which is delightfully rich and mellow</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000536', 0, NULL, 1, NULL, NULL, '2024-06-04 10:48:31', '2024-06-04 10:48:31'),
(537, '665ef2659f294', 'PRO000537', 0, 'Camus Intensely Aromatic Vsop', '<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 1rem; font-size: 1rem; color: rgb(68, 71, 74); font-family: Poppins, Inter, sans-serif;\"><span style=\"box-sizing: border-box;\">Camus is the fifth largest cognac distillery and is based in Cognac, France. The distillery is the only one of the large cognac producers that is still family-owned.</span></p>\r\n\r\n<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 1rem; font-size: 1rem; color: rgb(68, 71, 74); font-family: Poppins, Inter, sans-serif;\"><span style=\"box-sizing: border-box;\">CAMUS VSOP is a cognac with an intense aroma, whose floral and fruity bouquet with spicy oak and vanilla notes from carefully selected brandy reflects the quintessence of the well-known Cru of Borderies growing area, among other things. All the barrels used for the maturation process are &quot;of fine structure&quot; and have a low tannin content. Thanks to the special &quot;French Light Toasting&quot; process, the oak aroma can harmonize with the fresh notes.</span></p>', 'Camus is the fifth largest cognac distillery and is based in Cognac, France.', 21, '', NULL, 43, 114, '', 'Camus Intensely Aromatic Vsop', 'Camus is the fifth largest cognac distillery and is based in Cognac, France.', '<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 1rem; font-size: 1rem; color: rgb(68, 71, 74); font-family: Poppins, Inter, sans-serif;\"><span style=\"box-sizing: border-box;\">Camus is the fifth largest cognac distillery and is based in Cognac, France. The distillery is the only one of the large cognac producers that is still family-owned.</span></p>\r\n\r\n<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 1rem; font-size: 1rem; color: rgb(68, 71, 74); font-family: Poppins, Inter, sans-serif;\"><span style=\"box-sizing: border-box;\">CAMUS VSOP is a cognac with an intense aroma, whose floral and fruity bouquet with spicy oak and vanilla notes from carefully selected brandy reflects the quintessence of the well-known Cru of Borderies growing area, among other things. All the barrels used for the maturation process are &quot;of fine structure&quot; and have a low tannin content. Thanks to the special &quot;French Light Toasting&quot; process, the oak aroma can harmonize with the fresh notes.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000537', 0, NULL, 1, NULL, NULL, '2024-06-04 10:54:29', '2024-06-04 10:54:29'),
(538, '665ef35bd6f56', 'PRO000538', 0, 'Hennessy Pure White', '<p><span style=\"color: rgb(53, 53, 53); font-family: Roboto; font-size: 16px; background-color: rgba(212, 197, 226, 0.4);\">Hennessy Pure White expresses the qualities of the white wines from which they are distilled. They are produced with the finest white grapes from the sunny Cognac region. The Cognac double distillation accounts for its flowery aromas and powerful character.&nbsp;To enjoy the sheer aromas of Hennessy Pure White, let the bottle cool in ice for a while and drink it on the rocks in a tumbler or as a long drink. Because of its outstanding character, the smooth and flowery aromas will be fully brought out.</span></p>', 'Hennessy Pure White expresses the qualities of the white wines from which they are distilled.', 21, '', NULL, 43, 72, '', 'Hennessy Pure White', 'Hennessy Pure White expresses the qualities of the white wines from which they are distilled.', '<p><span style=\"color: rgb(53, 53, 53); font-family: Roboto; font-size: 16px; background-color: rgba(212, 197, 226, 0.4);\">Hennessy Pure White expresses the qualities of the white wines from which they are distilled. They are produced with the finest white grapes from the sunny Cognac region. The Cognac double distillation accounts for its flowery aromas and powerful character.&nbsp;To enjoy the sheer aromas of Hennessy Pure White, let the bottle cool in ice for a while and drink it on the rocks in a tumbler or as a long drink. Because of its outstanding character, the smooth and flowery aromas will be fully brought out.</span></p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000538', 0, 0, 1, NULL, NULL, '2024-06-04 10:58:35', '2024-06-04 11:00:29'),
(539, '665ef5c658220', 'PRO000539', 0, 'Cognac D`USSE VSOP 40%', '<p><span style=\"color: rgb(82, 45, 109); font-family: &quot;Century Gothic&quot;, sans-serif; font-size: 15px; letter-spacing: 0.75px;\">Naturally aged for at least four and a half years, the bold and full-bodied blend of D&rsquo;USSÉ VSOP Cognac is made from a selection of the finest eaux-de-vie, including some that were carefully matured in the cellars of the Château de Cognac. The result is a uniquely powerful Cognac that begins with bold intensity and finishes pleasantly smooth and balanced. Enjoy neat, on the rocks and in exquisite cocktail offerings.</span></p>', 'Naturally aged for at least four and a half years, the bold and full-bodied blend of D’USSÉ VSOP Cognac', 21, '', NULL, 43, 117, '', 'Cognac D`USSE VSOP 40%', 'Naturally aged for at least four and a half years, the bold and full-bodied blend of D’USSÉ VSOP Cognac', '<p><span style=\"color: rgb(82, 45, 109); font-family: &quot;Century Gothic&quot;, sans-serif; font-size: 15px; letter-spacing: 0.75px;\">Naturally aged for at least four and a half years, the bold and full-bodied blend of D&rsquo;USSÉ VSOP Cognac is made from a selection of the finest eaux-de-vie, including some that were carefully matured in the cellars of the Château de Cognac. The result is a uniquely powerful Cognac that begins with bold intensity and finishes pleasantly smooth and balanced. Enjoy neat, on the rocks and in exquisite cocktail offerings.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000539', 0, NULL, 1, NULL, NULL, '2024-06-04 11:08:54', '2024-06-04 11:08:54'),
(540, '665ef751d4941', 'PRO000540', 0, 'Remy Martin 1738', '<p><span style=\"color: rgb(0, 0, 0); font-family: Roboto, sans-serif; font-size: 14px; text-align: center;\">It was created to sit between their VSOP and XO by Remy Martin&rsquo;s 1738 Accord Royal Cognac. It is named in honor of the Royal Agreement granted to R&eacute;my Martin in 1738 by King Louis XV, enabling the company to use its land to plant vines. This is a cognac that is rich and strong.</span></p>', 'It was created to sit between their VSOP and XO by Remy Martin’s 1738 Accord Royal Cognac.', 21, '', NULL, 43, 101, '', 'Remy Martin 1738', 'It was created to sit between their VSOP and XO by Remy Martin’s 1738 Accord Royal Cognac.', '<p><span style=\"color: rgb(0, 0, 0); font-family: Roboto, sans-serif; font-size: 14px; text-align: center;\">It was created to sit between their VSOP and XO by Remy Martin&rsquo;s 1738 Accord Royal Cognac. It is named in honor of the Royal Agreement granted to R&eacute;my Martin in 1738 by King Louis XV, enabling the company to use its land to plant vines. This is a cognac that is rich and strong.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000540', 0, NULL, 1, NULL, NULL, '2024-06-04 11:15:29', '2024-06-04 11:15:29'),
(541, '665efb0a6143e', 'PRO000541', 0, 'Sainte Croix Vs Cognac', '<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 1rem; color: rgb(134, 134, 134); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 14px;\"><span style=\"box-sizing: border-box;\">Taste</span></p>\r\n\r\n<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 1rem; color: rgb(134, 134, 134); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 14px;\">It is balanced and well-rounded, with vanilla, pear, and white peach aromas.</p>\r\n\r\n<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 1rem; color: rgb(134, 134, 134); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 14px;\"><span style=\"box-sizing: border-box;\">Bouquet</span></p>\r\n\r\n<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 1rem; color: rgb(134, 134, 134); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 14px;\">An intense, tempting bouquet with floral, fruity notes, and a hint of oak.</p>\r\n\r\n<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 1rem; color: rgb(134, 134, 134); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 14px;\"><span style=\"box-sizing: border-box;\">Colour</span></p>\r\n\r\n<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 1rem; color: rgb(134, 134, 134); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 14px;\">A pale gold, with brilliant flashes of amber.</p>\r\n\r\n<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 1rem; color: rgb(134, 134, 134); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 14px;\">This VS is highly versatile and partners very well with a variety of mixers. This&nbsp;<a href=\"https://cognac-saintecroix.com/the-exclusive-cognac-collection/\" rel=\"noopener\" style=\"box-sizing: border-box; color: rgb(0, 0, 0); text-decoration-line: none; background-color: transparent;\" target=\"_blank\">Cognac</a>&nbsp;is best enjoyed &ldquo;On the rocks&rdquo;, with Cola, or in one of our creative cocktails mixers.</p>', 'It is balanced and well-rounded, with vanilla, pear, and white peach aromas.', 21, '', NULL, 43, 197, '', 'Sainte Croix Vs Cognac', 'It is balanced and well-rounded, with vanilla, pear, and white peach aromas.', '<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 1rem; color: rgb(134, 134, 134); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 14px;\"><span style=\"box-sizing: border-box;\">Taste</span></p>\r\n\r\n<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 1rem; color: rgb(134, 134, 134); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 14px;\">It is balanced and well-rounded, with vanilla, pear, and white peach aromas.</p>\r\n\r\n<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 1rem; color: rgb(134, 134, 134); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 14px;\"><span style=\"box-sizing: border-box;\">Bouquet</span></p>\r\n\r\n<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 1rem; color: rgb(134, 134, 134); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 14px;\">An intense, tempting bouquet with floral, fruity notes, and a hint of oak.</p>\r\n\r\n<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 1rem; color: rgb(134, 134, 134); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 14px;\"><span style=\"box-sizing: border-box;\">Colour</span></p>\r\n\r\n<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 1rem; color: rgb(134, 134, 134); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 14px;\">A pale gold, with brilliant flashes of amber.</p>\r\n\r\n<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 1rem; color: rgb(134, 134, 134); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 14px;\">This VS is highly versatile and partners very well with a variety of mixers. This&nbsp;<a href=\"https://cognac-saintecroix.com/the-exclusive-cognac-collection/\" rel=\"noopener\" style=\"box-sizing: border-box; color: rgb(0, 0, 0); text-decoration-line: none; background-color: transparent;\" target=\"_blank\">Cognac</a>&nbsp;is best enjoyed &ldquo;On the rocks&rdquo;, with Cola, or in one of our creative cocktails mixers.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000541', 0, 0, 1, NULL, NULL, '2024-06-04 11:31:22', '2024-06-04 11:37:27'),
(542, '665efe9498706', 'PRO000542', 0, 'Tesseron Lot 76 Cognac', '<div class=\"commentaire-ft left padding--80-b box active\" style=\"box-sizing: inherit; margin: 0px; float: left; color: rgb(0, 0, 0); font-family: &quot;Harmonia Sans&quot;; font-size: 16px;\">\r\n<p style=\"box-sizing: inherit; margin: 0px 0px 10px; font-size: var(--font-size);\">An exceptional blend of reserve stocks of Grande Champagne Cognac, matured to perfection in old casks. Lot n&deg;76 immediately establishes its quality on the nose, which exhibits a wealth of caramelised peaches, almond and candied fruit aromas. This carries on magnificently through to the palate, with rich, delicate flavours of nuts and dried fruits &ndash; a wonderful range of tasteful sensations.</p>\r\n</div>\r\n\r\n<p class=\"datas margin box active\" style=\"box-sizing: inherit; margin: 0px 0px 10px; font-size: 16px; color: rgb(0, 0, 0); font-family: &quot;Harmonia Sans&quot;;\">&nbsp;</p>', 'An exceptional blend of reserve stocks of Grande Champagne Cognac, matured to perfection in old casks.', 21, '', NULL, 43, 198, '', 'Tesseron Lot 76 Cognac', 'An exceptional blend of reserve stocks of Grande Champagne Cognac, matured to perfection in old casks.', '<div class=\"commentaire-ft left padding--80-b box active\" style=\"box-sizing: inherit; margin: 0px; float: left; color: rgb(0, 0, 0); font-family: &quot;Harmonia Sans&quot;; font-size: 16px;\">\r\n<p style=\"box-sizing: inherit; margin: 0px 0px 10px; font-size: var(--font-size);\">An exceptional blend of reserve stocks of Grande Champagne Cognac, matured to perfection in old casks. Lot n&deg;76 immediately establishes its quality on the nose, which exhibits a wealth of caramelised peaches, almond and candied fruit aromas. This carries on magnificently through to the palate, with rich, delicate flavours of nuts and dried fruits &ndash; a wonderful range of tasteful sensations.</p>\r\n</div>\r\n\r\n<p class=\"datas margin box active\" style=\"box-sizing: inherit; margin: 0px 0px 10px; font-size: 16px; color: rgb(0, 0, 0); font-family: &quot;Harmonia Sans&quot;;\">&nbsp;</p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000542', 0, NULL, 1, NULL, NULL, '2024-06-04 11:46:28', '2024-06-04 11:46:28'),
(543, '665effdd3afdc', 'PRO000543', 0, 'Tesseron Lot 90 Cognac', '<div class=\"commentaire-ft left padding--80-b box active\" style=\"box-sizing: inherit; margin: 0px; float: left; color: rgb(0, 0, 0); font-family: &quot;Harmonia Sans&quot;; font-size: 16px;\">\r\n<p style=\"box-sizing: inherit; margin: 0px 0px 10px; font-size: var(--font-size);\"><span style=\"color: rgb(0, 0, 0); font-family: &quot;Harmonia Sans&quot;; font-size: 16px;\">An exceptional blend of reserve stocks of Grande Champagne Cognac, matured to perfection in old casks.</span> Lot n&deg;76 immediately establishes its quality on the nose, which exhibits a wealth of caramelised peaches, almond and candied fruit aromas. This carries on magnificently through to the palate, with rich, delicate flavours of nuts and dried fruits &ndash; a wonderful range of tasteful sensations.</p>\r\n</div>\r\n\r\n<p class=\"datas margin box active\" style=\"box-sizing: inherit; margin: 0px 0px 10px; font-size: 16px; color: rgb(0, 0, 0); font-family: &quot;Harmonia Sans&quot;;\">&nbsp;</p>', 'An exceptional blend of reserve stocks of Grande Champagne Cognac, matured to perfection in old casks.', 21, '', NULL, 43, 198, '', 'Tesseron Lot 90 Cognac', 'An exceptional blend of reserve stocks of Grande Champagne Cognac, matured to perfection in old casks.', '<div class=\"commentaire-ft left padding--80-b box active\" style=\"box-sizing: inherit; margin: 0px; float: left; color: rgb(0, 0, 0); font-family: &quot;Harmonia Sans&quot;; font-size: 16px;\">\r\n<p style=\"box-sizing: inherit; margin: 0px 0px 10px; font-size: var(--font-size);\">An exceptional blend of reserve stocks of Grande Champagne Cognac, matured to perfection in old casks. Lot n&deg;76 immediately establishes its quality on the nose, which exhibits a wealth of caramelised peaches, almond and candied fruit aromas. This carries on magnificently through to the palate, with rich, delicate flavours of nuts and dried fruits &ndash; a wonderful range of tasteful sensations.</p>\r\n</div>\r\n\r\n<p class=\"datas margin box active\" style=\"box-sizing: inherit; margin: 0px 0px 10px; font-size: 16px; color: rgb(0, 0, 0); font-family: &quot;Harmonia Sans&quot;;\">&nbsp;</p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000543', 0, NULL, 1, NULL, NULL, '2024-06-04 11:51:57', '2024-06-04 11:51:57'),
(544, '665f02fd346e2', 'PRO000544', 0, 'Tesseron Lot 53 Cognac', '<div class=\"commentaire-ft left padding--80-b box active\" style=\"box-sizing: inherit; margin: 0px; float: left; color: rgb(0, 0, 0); font-family: &quot;Harmonia Sans&quot;; font-size: 16px;\">\r\n<p style=\"box-sizing: inherit; margin: 0px 0px 10px; font-size: var(--font-size);\">An exceptional blend of reserve stocks of Grande Champagne Cognac, matured to perfection in old casks. Lot n&deg;76 immediately establishes its quality on the nose, which exhibits a wealth of caramelised peaches, almond and candied fruit aromas. This carries on magnificently through to the palate, with rich, delicate flavours of nuts and dried fruits &ndash; a wonderful range of tasteful sensations.</p>\r\n</div>\r\n\r\n<p class=\"datas margin box active\" style=\"box-sizing: inherit; margin: 0px 0px 10px; font-size: 16px; color: rgb(0, 0, 0); font-family: &quot;Harmonia Sans&quot;;\">&nbsp;</p>', 'An exceptional blend of reserve stocks of Grande Champagne Cognac, matured to perfection in old casks.', 21, '', NULL, 43, 198, '', 'Tesseron Lot 53 Cognac', 'An exceptional blend of reserve stocks of Grande Champagne Cognac, matured to perfection in old casks.', '<div class=\"commentaire-ft left padding--80-b box active\" style=\"box-sizing: inherit; margin: 0px; float: left; color: rgb(0, 0, 0); font-family: &quot;Harmonia Sans&quot;; font-size: 16px;\">\r\n<p style=\"box-sizing: inherit; margin: 0px 0px 10px; font-size: var(--font-size);\">An exceptional blend of reserve stocks of Grande Champagne Cognac, matured to perfection in old casks. Lot n&deg;76 immediately establishes its quality on the nose, which exhibits a wealth of caramelised peaches, almond and candied fruit aromas. This carries on magnificently through to the palate, with rich, delicate flavours of nuts and dried fruits &ndash; a wonderful range of tasteful sensations.</p>\r\n</div>\r\n\r\n<p class=\"datas margin box active\" style=\"box-sizing: inherit; margin: 0px 0px 10px; font-size: 16px; color: rgb(0, 0, 0); font-family: &quot;Harmonia Sans&quot;;\">&nbsp;</p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000544', 0, NULL, 1, NULL, NULL, '2024-06-04 12:05:17', '2024-06-04 12:05:17'),
(545, '665f046e642f3', 'PRO000545', 0, 'Hine Cognac Vsop 40%', '<p><span style=\"color: rgba(2, 9, 18, 0.75); font-family: Quicksand, sans-serif; font-size: 16.8px; letter-spacing: 0.63px; background-color: rgb(252, 252, 252);\">HINE VSOP H by Hine Cognac is crafted from a meticulous blend of eaux-de-vie from Grande and Petite Champagne, promising a wealth of flavors that resonate in perfect symphony. Subtle hints of jasmine and autumn fruits blend with nuances of vanilla and oak to offer a voluptuous tasting experience, with a sweet and persistent finish.</span></p>', 'HINE VSOP H by Hine Cognac is crafted from a meticulous blend of eaux-de-vie from Grande and Petite', 21, '', NULL, 43, 199, '', 'Hine Cognac Vsop 40%', 'HINE VSOP H by Hine Cognac is crafted from a meticulous blend of eaux-de-vie from Grande and Petite', '<p><span style=\"color: rgba(2, 9, 18, 0.75); font-family: Quicksand, sans-serif; font-size: 16.8px; letter-spacing: 0.63px; background-color: rgb(252, 252, 252);\">HINE VSOP H by Hine Cognac is crafted from a meticulous blend of eaux-de-vie from Grande and Petite Champagne, promising a wealth of flavors that resonate in perfect symphony. Subtle hints of jasmine and autumn fruits blend with nuances of vanilla and oak to offer a voluptuous tasting experience, with a sweet and persistent finish.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000545', 0, NULL, 1, NULL, NULL, '2024-06-04 12:11:26', '2024-06-04 12:11:26'),
(546, '665f1c92c7a75', 'PRO000546', 0, 'Hine Antique Cognac Xo 40%', '<p><span style=\"color: rgb(68, 68, 68); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 16px;\">Blended with eaux-de-vie exclusively from the premier cru, Grande Champagne, this&nbsp;</span><span style=\"box-sizing: border-box; font-weight: bolder; color: rgb(68, 68, 68); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 16px;\">Hine XO Antique Grande Champagne Cognac</span><span style=\"color: rgb(68, 68, 68); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 16px;\">&nbsp;is innovation, a relic from the times of Georges Hine brought to life for the modern Cognac connoisseur. The recipe was developed in 1920 by Hine himself, and was relaunched in 2010 by the Cognac house as a single cru XO. The 40 different Grande Champagne eaux-de-vie have been aged for a minimum of 10 years in traditional French Limousin oak casks, a homage to Hine&rsquo;s heritage and the Cognac house&rsquo;s history of fine craftsmanship.</span></p>', 'Blended with eaux-de-vie exclusively from the premier cru, Grande Champagne, this Hine XO Antique Grande Champagne', 21, '', NULL, 43, 199, '', 'Hine Antique Cognac Xo 40%', 'Blended with eaux-de-vie exclusively from the premier cru, Grande Champagne, this Hine XO Antique Grande Champagne', '<p><span style=\"color: rgb(68, 68, 68); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 16px;\">Blended with eaux-de-vie exclusively from the premier cru, Grande Champagne, this&nbsp;</span><span style=\"box-sizing: border-box; font-weight: bolder; color: rgb(68, 68, 68); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 16px;\">Hine XO Antique Grande Champagne Cognac</span><span style=\"color: rgb(68, 68, 68); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 16px;\">&nbsp;is innovation, a relic from the times of Georges Hine brought to life for the modern Cognac connoisseur. The recipe was developed in 1920 by Hine himself, and was relaunched in 2010 by the Cognac house as a single cru XO. The 40 different Grande Champagne eaux-de-vie have been aged for a minimum of 10 years in traditional French Limousin oak casks, a homage to Hine&rsquo;s heritage and the Cognac house&rsquo;s history of fine craftsmanship.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000546', 0, NULL, 1, NULL, NULL, '2024-06-04 13:54:26', '2024-06-04 13:54:26'),
(547, '665f1ec57b6ea', 'PRO000547', 0, 'Hine Cigar Reserve Xo Cognac 40%', '<div class=\"page\" style=\"box-sizing: border-box; margin: 0px; color: rgb(0, 0, 0); font-family: &quot;Nunito Sans&quot;; font-size: 16px; letter-spacing: 0.8px;\" title=\"Page 1\">Bernard Hine, sixth generation of the Hine family and Nicholas Freeman, the late Chairman of UK Havana Cigar importers Hunters &amp; Frankau, first met in 1986. From this initial encounter an enduring friendship began. It was a friendship that would eventually lead to the creation of a classic and lasting match between a cognac and a fine handmade cigar.&nbsp;</div>\r\n\r\n<div class=\"page\" style=\"box-sizing: border-box; margin: 0px; color: rgb(0, 0, 0); font-family: &quot;Nunito Sans&quot;; font-size: 16px; letter-spacing: 0.8px;\" title=\"Page 1\">&nbsp;</div>\r\n\r\n<div class=\"page\" style=\"box-sizing: border-box; margin: 0px; color: rgb(0, 0, 0); font-family: &quot;Nunito Sans&quot;; font-size: 16px; letter-spacing: 0.8px;\" title=\"Page 1\">In 1996, after ten years of sharing their knowledge and expertise, as well as countless cigars and glasses of cognac, the Hine Cigar Reserve was born.&nbsp;</div>', 'Bernard Hine, sixth generation of the Hine family and Nicholas Freeman, the late Chairman of UK Havana Cigar importers', 21, '', NULL, 43, 199, '', 'Hine Cigar Reserve Xo Cognac 40%', 'Bernard Hine, sixth generation of the Hine family and Nicholas Freeman, the late Chairman of UK Havana Cigar importers', '<div class=\"page\" style=\"box-sizing: border-box; margin: 0px; color: rgb(0, 0, 0); font-family: &quot;Nunito Sans&quot;; font-size: 16px; letter-spacing: 0.8px;\" title=\"Page 1\">Bernard Hine, sixth generation of the Hine family and Nicholas Freeman, the late Chairman of UK Havana Cigar importers Hunters &amp; Frankau, first met in 1986. From this initial encounter an enduring friendship began. It was a friendship that would eventually lead to the creation of a classic and lasting match between a cognac and a fine handmade cigar.&nbsp;</div>\r\n\r\n<div class=\"page\" style=\"box-sizing: border-box; margin: 0px; color: rgb(0, 0, 0); font-family: &quot;Nunito Sans&quot;; font-size: 16px; letter-spacing: 0.8px;\" title=\"Page 1\">&nbsp;</div>\r\n\r\n<div class=\"page\" style=\"box-sizing: border-box; margin: 0px; color: rgb(0, 0, 0); font-family: &quot;Nunito Sans&quot;; font-size: 16px; letter-spacing: 0.8px;\" title=\"Page 1\">In 1996, after ten years of sharing their knowledge and expertise, as well as countless cigars and glasses of cognac, the Hine Cigar Reserve was born.&nbsp;</div>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000547', 0, NULL, 1, NULL, NULL, '2024-06-04 14:03:49', '2024-06-04 14:03:49'),
(548, '665f20ec747e2', 'PRO000548', 0, 'Hine Rare Cognac 40%', '<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 1rem; font-family: lato, sans-serif; font-size: 18px;\">Hine Original Rare&nbsp;Cognac is crafted using a blend of eaux-de-vie from the Grande and Petite Champagne regions. Around 20 different eaux-de-vie make their way into this expression, resulting in a flavour profile that boasts waves of floral breeze, fresh fruit and warming woody spices.</p>\r\n\r\n<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 1rem; font-family: lato, sans-serif; font-size: 18px;\">Suave yet delicate, Rare is a classic expression of the House of Hine and a benchmark for our entire collection of Cognacs. It reinterprets the fruity flavours characteristic of the white wines produced from Charente vines, particularly from the Grande and Petite Champagne varieties.</p>', 'Hine Original Rare Cognac is crafted using a blend of eaux-de-vie from the Grande and Petite Champagne', 21, '', NULL, 43, 199, '', 'Hine Rare Cognac 40%', 'Hine Original Rare Cognac is crafted using a blend of eaux-de-vie from the Grande and Petite Champagne', '<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 1rem; font-family: lato, sans-serif; font-size: 18px;\">Hine Original Rare&nbsp;Cognac is crafted using a blend of eaux-de-vie from the Grande and Petite Champagne regions. Around 20 different eaux-de-vie make their way into this expression, resulting in a flavour profile that boasts waves of floral breeze, fresh fruit and warming woody spices.</p>\r\n\r\n<p style=\"box-sizing: border-box; margin-top: 0px; margin-bottom: 1rem; font-family: lato, sans-serif; font-size: 18px;\">Suave yet delicate, Rare is a classic expression of the House of Hine and a benchmark for our entire collection of Cognacs. It reinterprets the fruity flavours characteristic of the white wines produced from Charente vines, particularly from the Grande and Petite Champagne varieties.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000548', 0, 0, 1, NULL, NULL, '2024-06-04 14:13:00', '2024-06-04 14:16:26'),
(549, '665f25578bb26', 'PRO000549', 0, 'Davidoff Cognac Vs 40%', '<p><span style=\"color: rgb(68, 68, 68); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 16px;\">An original Cognac from the Swiss-based family brand founded by Zino Davidoff. Their philosophy exudes elegance and an appreciation for the finer things in life. Such is the</span><span style=\"box-sizing: border-box; font-weight: bolder; color: rgb(68, 68, 68); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 16px;\">&nbsp;Davidoff Cognac Sp&eacute;cial VS,</span><span style=\"color: rgb(68, 68, 68); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 16px;\">&nbsp;which is all about the special selection of eaux-de-vie. It is a smooth, soft blend with a blend of over 15 different eaux-de-vie made from Ugni Blanc grapes from the likes of the Bons Bois, Petite Champagne, and Fins Bois terroirs. The youngest is 2 years, and the average age is 3 years. This is a modern and contemporary Very Special Cognac to allow consumers to enjoy the moment fully. Davidoff Cognac works closely with over 50 winegrowers that have been carefully selected and 4 distillers. This guarantees the highest quality of blends. This is a young Cognac with plenty of zest and aroma.</span></p>', 'An original Cognac from the Swiss-based family brand founded by Zino Davidoff.', 21, '', NULL, 43, 200, '', 'Davidoff Cognac Vs 40%', 'An original Cognac from the Swiss-based family brand founded by Zino Davidoff.', '<p><span style=\"color: rgb(68, 68, 68); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 16px;\">An original Cognac from the Swiss-based family brand founded by Zino Davidoff. Their philosophy exudes elegance and an appreciation for the finer things in life. Such is the</span><span style=\"box-sizing: border-box; font-weight: bolder; color: rgb(68, 68, 68); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 16px;\">&nbsp;Davidoff Cognac Sp&eacute;cial VS,</span><span style=\"color: rgb(68, 68, 68); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 16px;\">&nbsp;which is all about the special selection of eaux-de-vie. It is a smooth, soft blend with a blend of over 15 different eaux-de-vie made from Ugni Blanc grapes from the likes of the Bons Bois, Petite Champagne, and Fins Bois terroirs. The youngest is 2 years, and the average age is 3 years. This is a modern and contemporary Very Special Cognac to allow consumers to enjoy the moment fully. Davidoff Cognac works closely with over 50 winegrowers that have been carefully selected and 4 distillers. This guarantees the highest quality of blends. This is a young Cognac with plenty of zest and aroma.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000549', 0, NULL, 1, NULL, NULL, '2024-06-04 14:31:51', '2024-06-04 14:31:51');
INSERT INTO `product` (`id`, `uniqid`, `product_item_id`, `supplier_id`, `product_name`, `description`, `short_description`, `category_id`, `product_image`, `images`, `subcategory_id`, `brand_id`, `video`, `product_name_fr`, `short_description_fr`, `page_content_fr`, `product_qty`, `tech_data_sheet`, `retail_price`, `discount_price`, `is_admin_approve`, `most_view`, `is_product_bestseller`, `sku`, `average_rating`, `offer`, `status`, `in_store`, `in_online`, `created_at`, `updated_at`) VALUES
(550, '665f3ee935ff9', 'PRO000550', 0, 'Hennessy Paradis Rare Cognac', '<p><span style=\"color: rgb(68, 68, 68); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 16px;\">The Hennessy Paradis is indeed the most sensual facet of the classic Hennessy house. Dating back to the 19th century, the Cognac Hennessy Paradis is&nbsp;a&nbsp;</span><a href=\"https://www.cognac-expert.com/hors-d-age-cognac/\" style=\"box-sizing: border-box; color: rgb(221, 153, 51); text-decoration-line: none; transition: opacity 0.2s cubic-bezier(0.7, 0, 0.3, 1) 0s, color 0.2s cubic-bezier(0.7, 0, 0.3, 1) 0s; vertical-align: top; font-family: &quot;Open Sans&quot;, sans-serif; font-size: 16px;\">Hors d&#39;Age&nbsp;</a><span style=\"color: rgb(68, 68, 68); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 16px;\">Cognac.&nbsp;This Cognac comes directly from Paradise, at least that&rsquo;s what one could think reading the name. In fact, the paradis refers to the maison&rsquo;s oldest and most precious cellar, where the cask of the finest eaux-de-vie are stored. In 1979 Maurice Fillioux, Cognac Master, curated the Hennessy Paradis. It is with this very collection, that the sixth generation craftsman created what can only be described as his very own symphony of notes. Within this blend, tributes are evidently made to the treasure trove of spirits that his ancestors had previously assembled. An extremely fine blend, Fillioux combined his ear for music and 30 years of artisan craft by&nbsp;fusing&nbsp;over 100 different eaux-de-vie to create a delicate melody of notes that will play upon the taster&rsquo;s senses. Some of them even go as far back as 1880. By assembling a structure of notes from his grandfather&#39;s&rsquo; rarest collection, Fillioux has created this carefully refined Cognac.</span></p>', 'The Hennessy Paradis is indeed the most sensual facet of the classic Hennessy house.', 21, '', NULL, 43, 72, '', 'Hennessy Paradis Rare Cognac', 'The Hennessy Paradis is indeed the most sensual facet of the classic Hennessy house.', '<p><span style=\"color: rgb(68, 68, 68); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 16px;\">The Hennessy Paradis is indeed the most sensual facet of the classic Hennessy house. Dating back to the 19th century, the Cognac Hennessy Paradis is&nbsp;a&nbsp;</span><a href=\"https://www.cognac-expert.com/hors-d-age-cognac/\" style=\"color: rgb(221, 153, 51); box-sizing: border-box; text-decoration-line: none; transition: opacity 0.2s cubic-bezier(0.7, 0, 0.3, 1) 0s, color 0.2s cubic-bezier(0.7, 0, 0.3, 1) 0s; vertical-align: top; font-family: &quot;Open Sans&quot;, sans-serif; font-size: 16px;\">Hors d&#39;Age&nbsp;</a><span style=\"color: rgb(68, 68, 68); font-family: &quot;Open Sans&quot;, sans-serif; font-size: 16px;\">Cognac.&nbsp;This Cognac comes directly from Paradise, at least that&rsquo;s what one could think reading the name. In fact, the paradis refers to the maison&rsquo;s oldest and most precious cellar, where the cask of the finest eaux-de-vie are stored. In 1979 Maurice Fillioux, Cognac Master, curated the Hennessy Paradis. It is with this very collection, that the sixth generation craftsman created what can only be described as his very own symphony of notes. Within this blend, tributes are evidently made to the treasure trove of spirits that his ancestors had previously assembled. An extremely fine blend, Fillioux combined his ear for music and 30 years of artisan craft by&nbsp;fusing&nbsp;over 100 different eaux-de-vie to create a delicate melody of notes that will play upon the taster&rsquo;s senses. Some of them even go as far back as 1880. By assembling a structure of notes from his grandfather&#39;s&rsquo; rarest collection, Fillioux has created this carefully refined Cognac.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000550', 0, NULL, 1, NULL, NULL, '2024-06-04 16:20:57', '2024-06-04 16:20:57'),
(551, '665f4b90c0206', 'PRO000551', 0, 'Remy Martin Cognac Louis Xiii', '<p style=\"box-sizing: inherit; margin: 0px 0px 10px; font-size: 16px; color: rgb(0, 0, 0); font-family: &quot;Harmonia Sans&quot;;\">The LOUIS XIII Classic decanter has remained the ultimate expression of our finest eaux-de-vie blend since 1874, containing up to 1,200 eaux-de-vie from Grande Champagne terroir.</p>\r\n\r\n<p style=\"box-sizing: inherit; margin: 0px 0px 10px; font-size: 16px; color: rgb(0, 0, 0); font-family: &quot;Harmonia Sans&quot;;\">Up to 1,200 eaux-de-vie, made using grapes grown in Grande Champagne &ndash; the premier cru of the Cognac region &ndash; are carefully blended over the years to create the cognac inside every LOUIS XIII Classic decanter. Provenance and time are the very essence of LOUIS XIII cognac. Each drop represents a finely tuned craft passed down from one generation of Cellar Master to the next.<br style=\"box-sizing: inherit; margin: 0px;\" />\r\nThe eaux-de-vie are slowly aged in old Limousin tier&ccedil;ons (traditional aged French oak casks). Every sip is a taste of time.</p>', 'The LOUIS XIII Classic decanter has remained the ultimate expression of our finest eaux-de-vie blend since 1874', 21, '', NULL, 43, 101, '', 'Remy Martin Cognac Louis Xiii 700 Ml', 'The LOUIS XIII Classic decanter has remained the ultimate expression of our finest eaux-de-vie blend since 1874', '<p style=\"box-sizing: inherit; margin: 0px 0px 10px; font-size: 16px; color: rgb(0, 0, 0); font-family: &quot;Harmonia Sans&quot;;\">The LOUIS XIII Classic decanter has remained the ultimate expression of our finest eaux-de-vie blend since 1874, containing up to 1,200 eaux-de-vie from Grande Champagne terroir.</p>\r\n\r\n<p style=\"box-sizing: inherit; margin: 0px 0px 10px; font-size: 16px; color: rgb(0, 0, 0); font-family: &quot;Harmonia Sans&quot;;\">Up to 1,200 eaux-de-vie, made using grapes grown in Grande Champagne &ndash; the premier cru of the Cognac region &ndash; are carefully blended over the years to create the cognac inside every LOUIS XIII Classic decanter. Provenance and time are the very essence of LOUIS XIII cognac. Each drop represents a finely tuned craft passed down from one generation of Cellar Master to the next.<br style=\"box-sizing: inherit; margin: 0px;\" />\r\nThe eaux-de-vie are slowly aged in old Limousin tier&ccedil;ons (traditional aged French oak casks). Every sip is a taste of time.</p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000551', 0, 0, 1, NULL, NULL, '2024-06-04 17:14:56', '2024-06-04 17:17:09'),
(552, '665f561a12ed1', 'PRO000552', 0, 'Courvoisier Xo', '<p><span style=\"color: rgb(69, 69, 69); font-family: &quot;Cera Regular&quot;, sans-serif; font-size: 15px; letter-spacing: 1.2px;\">Rich and full-bodied, yet still exceptionally smooth, this luxurious XO contains long-aged eaux-de-vie from Grande &amp; Petite Champagne for grace &amp; flavour, plus a little Borderies for structure and depth. A perennial award-winner.</span></p>', 'Rich and full-bodied, yet still exceptionally smooth', 21, '', NULL, 43, 201, '', 'Courvoisier Xo', 'Rich and full-bodied, yet still exceptionally smooth', '<p><span style=\"color: rgb(69, 69, 69); font-family: &quot;Cera Regular&quot;, sans-serif; font-size: 15px; letter-spacing: 1.2px;\">Rich and full-bodied, yet still exceptionally smooth, this luxurious XO contains long-aged eaux-de-vie from Grande &amp; Petite Champagne for grace &amp; flavour, plus a little Borderies for structure and depth. A perennial award-winner.</span></p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000552', 0, 0, 1, NULL, NULL, '2024-06-04 17:59:54', '2024-06-05 09:55:35'),
(553, '666049a3c699a', 'PRO000553', 0, 'Hennessy Vsop Nba With Box', '<p data-mce-fragment=\"1\" style=\"box-sizing: border-box; -webkit-font-smoothing: antialiased; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); margin-top: 1.125rem; margin-bottom: 1.125rem; color: rgb(29, 29, 29); font-family: &quot;Harmonia Sans&quot;, sans-serif; font-size: 18px; background-color: rgb(243, 243, 243); outline: 0px !important;\"><span data-mce-fragment=\"1\" style=\"box-sizing: border-box; -webkit-font-smoothing: antialiased; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); outline: 0px !important;\">Introducing the Hennessy V.S.O.P Limited Edition crafted for the NBA 22-21 season.</span></p>\r\n\r\n<p data-mce-fragment=\"1\" style=\"box-sizing: border-box; -webkit-font-smoothing: antialiased; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); margin-top: 1.125rem; margin-bottom: 1.125rem; color: rgb(29, 29, 29); font-family: &quot;Harmonia Sans&quot;, sans-serif; font-size: 18px; background-color: rgb(243, 243, 243); outline: 0px !important;\"><span data-mce-fragment=\"1\" style=\"box-sizing: border-box; -webkit-font-smoothing: antialiased; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); outline: 0px !important;\">Hennessy V.S.O.P is a balanced cognac, expressing 200 years of Hennessy&#39;s know-how. The fruit of nature&rsquo;s uncertainties, this unique blend has tamed the elements to craft and embody the original concept of cognac. The emotion awakened by the pleasure of tasting it continually reveals new facets of its personality.</span></p>', 'Hennessy V.S.O.P is a balanced cognac, expressing 200 years of Hennessy\'s know-how.', 21, '', NULL, 43, 72, '', 'Hennessy Vsop Nba With Box', 'Hennessy V.S.O.P is a balanced cognac, expressing 200 years of Hennessy\'s know-how.', '<p data-mce-fragment=\"1\" style=\"box-sizing: border-box; -webkit-font-smoothing: antialiased; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); margin-top: 1.125rem; margin-bottom: 1.125rem; color: rgb(29, 29, 29); font-family: &quot;Harmonia Sans&quot;, sans-serif; font-size: 18px; background-color: rgb(243, 243, 243); outline: 0px !important;\"><span data-mce-fragment=\"1\" style=\"box-sizing: border-box; -webkit-font-smoothing: antialiased; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); outline: 0px !important;\">Introducing the Hennessy V.S.O.P Limited Edition crafted for the NBA 22-21 season.</span></p>\r\n\r\n<p data-mce-fragment=\"1\" style=\"box-sizing: border-box; -webkit-font-smoothing: antialiased; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); margin-top: 1.125rem; margin-bottom: 1.125rem; color: rgb(29, 29, 29); font-family: &quot;Harmonia Sans&quot;, sans-serif; font-size: 18px; background-color: rgb(243, 243, 243); outline: 0px !important;\"><span data-mce-fragment=\"1\" style=\"box-sizing: border-box; -webkit-font-smoothing: antialiased; text-size-adjust: none; -webkit-tap-highlight-color: rgba(0, 0, 0, 0); outline: 0px !important;\">Hennessy V.S.O.P is a balanced cognac, expressing 200 years of Hennessy&#39;s know-how. The fruit of nature&rsquo;s uncertainties, this unique blend has tamed the elements to craft and embody the original concept of cognac. The emotion awakened by the pleasure of tasting it continually reveals new facets of its personality.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000553', 0, NULL, 1, NULL, NULL, '2024-06-05 11:18:59', '2024-06-05 11:18:59'),
(554, '666052c52344f', 'PRO000554', 0, 'Hennessy Vs Gold With Box Holiday Edition', '<p><span style=\"color: rgb(33, 37, 41); font-family: Montserrat, sans-serif; font-size: 16px;\">Hennessy VS Limited 2022 The celebrated Hennessy VS Cognac has been given a makeover for this limited edition Holiday 2022 version. In festive gold colours, and with an equally dazzling presentation box, this ought to make a fantastic gift for fans of the full-bodied, spice-laden Cognac.</span></p>', 'In festive gold colors, and with an equally dazzling presentation box', 21, '', NULL, 43, 72, '', 'Hennessy Vs Gold With Box Holiday Edition', 'In festive gold colors, and with an equally dazzling presentation box', '<p><span style=\"color: rgb(33, 37, 41); font-family: Montserrat, sans-serif; font-size: 16px;\">Hennessy VS Limited 2022 The celebrated Hennessy VS Cognac has been given a makeover for this limited edition Holiday 2022 version. In festive gold colours, and with an equally dazzling presentation box, this ought to make a fantastic gift for fans of the full-bodied, spice-laden Cognac.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000554', 0, NULL, 1, NULL, NULL, '2024-06-05 11:57:57', '2024-06-05 11:57:57'),
(555, '666060a4a7030', 'PRO000555', 0, 'Morpheus Xo Premium Brandy 40%', '<p><span style=\"color: rgba(0, 0, 0, 0.87); font-family: Roboto, sans-serif; font-size: 18px;\">Produced by the Indian company of Radico Khaitan, Morpheus is one of the best brands of Brandy within the category of reasonably-priced bottles. This Brandy comes with multiple layers of rich flavours, and a stellar quality that one can only get from prolonged ageing. Morpheous is named after the Greek god of dreams, and its excellent taste is evidenced by the five Gold medals it was accorded at the prestigious Monde Selection.&nbsp;</span></p>', 'This Brandy comes with multiple layers of rich flavors, and a stellar quality', 21, '', NULL, 42, 202, '', 'Morpheus Xo Premium Brandy 40%', 'This Brandy comes with multiple layers of rich flavors, and a stellar quality', '<p><span style=\"color: rgba(0, 0, 0, 0.87); font-family: Roboto, sans-serif; font-size: 18px;\">Produced by the Indian company of Radico Khaitan, Morpheus is one of the best brands of Brandy within the category of reasonably-priced bottles. This Brandy comes with multiple layers of rich flavours, and a stellar quality that one can only get from prolonged ageing. Morpheous is named after the Greek god of dreams, and its excellent taste is evidenced by the five Gold medals it was accorded at the prestigious Monde Selection.&nbsp;</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000555', 0, NULL, 1, NULL, NULL, '2024-06-05 12:57:08', '2024-06-05 12:57:08'),
(556, '6660634879dd1', 'PRO000556', 0, 'Sophia Brandy 38%', '<p style=\"box-sizing: border-box; margin: 0px 0px 1.313em; color: rgb(34, 34, 34); font-family: Raleway, sans-serif; font-size: 14px; text-align: justify; background-color: rgba(255, 255, 255, 0.9);\">Made from vintage spirits. It has fine flavor with pleasant vanilla nuances.</p>\r\n\r\n<p style=\"box-sizing: border-box; margin: 0px 0px 1.313em; color: rgb(34, 34, 34); font-family: Raleway, sans-serif; font-size: 14px; text-align: justify; background-color: rgba(255, 255, 255, 0.9);\">Balanced flavor with an elegant finish.</p>', 'Made from vintage spirits. It has fine flavor with pleasant vanilla nuances.', 21, '', NULL, 42, 203, '', 'Sophia Brandy 38%', 'Made from vintage spirits. It has fine flavor with pleasant vanilla nuances.', '<p style=\"box-sizing: border-box; margin: 0px 0px 1.313em; color: rgb(34, 34, 34); font-family: Raleway, sans-serif; font-size: 14px; text-align: justify; background-color: rgba(255, 255, 255, 0.9);\">Made from vintage spirits. It has fine flavor with pleasant vanilla nuances.</p>\r\n\r\n<p style=\"box-sizing: border-box; margin: 0px 0px 1.313em; color: rgb(34, 34, 34); font-family: Raleway, sans-serif; font-size: 14px; text-align: justify; background-color: rgba(255, 255, 255, 0.9);\">Balanced flavor with an elegant finish.</p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000556', 0, NULL, 1, NULL, NULL, '2024-06-05 13:08:24', '2024-06-05 13:08:24'),
(557, '66606920e8fc0', 'PRO000557', 0, 'Old Admiral Brandy 30%', '<p><span style=\"color: rgb(60, 60, 60); font-family: &quot;PingFang SC&quot;, PingFangSC-Semibold; font-size: 12px;\">Made especially for the men with pride, honor and courage, the splendid taste of this spectacular brandy celebrates the achievement of greatness and passion for all the good things in life. The classic taste perfectly blended with rich sensations and enthralling aroma ensures that it is savored the way it is desired and truly deserved. Old Admiral Brandy is ranked as the worlds 5th largest selling brandy by the Drinks International, Millionaires Club 2018 Rankings</span></p>', 'Made especially for the men with pride, honor and courage, the splendid taste of this spectacular brandy', 21, '', NULL, 42, 204, '', 'Old Admiral Brandy 30%', 'Made especially for the men with pride, honor and courage, the splendid taste of this spectacular brandy', '<p><span style=\"color: rgb(60, 60, 60); font-family: &quot;PingFang SC&quot;, PingFangSC-Semibold; font-size: 12px;\">Made especially for the men with pride, honor and courage, the splendid taste of this spectacular brandy celebrates the achievement of greatness and passion for all the good things in life. The classic taste perfectly blended with rich sensations and enthralling aroma ensures that it is savored the way it is desired and truly deserved. Old Admiral Brandy is ranked as the worlds 5th largest selling brandy by the Drinks International, Millionaires Club 2018 Rankings</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000557', 0, NULL, 1, NULL, NULL, '2024-06-05 13:33:20', '2024-06-05 13:33:20'),
(558, '66606b98bd089', 'PRO000558', 0, 'Paul Masson Grande Amber', '<p><span style=\"font-family: Poppins, &quot;Open Sans&quot;, &quot;Helvetica Neue&quot;, Helvetica, Arial, sans-serif; font-size: 16px; background-color: rgb(247, 247, 247);\">VS (Very Special) brandy is aged in oak for three years one year longer than required for extra smoothness. Additional aging creates fine aromas and flavor that sets our VS Brandy apart from traditional brandies. The resulting taste profile is slightly sweet with notes of caramel and vanilla. From the blending of Brandy at the turn of the century by Paul Masson himself, the knowledge and craftsmanship of over 100 years make Paul Masson Grande Amber Brandy unrivaled. Taking pride from the vineyard to the bottle, it is only fitting that Paul Masson could develop a brandy with the look, feel and smoothness of the finest Cognacs</span></p>', 'VS (Very Special) brandy is aged in oak for three years one year longer than required for extra smoothness.', 21, '', NULL, 42, 205, '', 'Paul Masson Grande Amber', 'VS (Very Special) brandy is aged in oak for three years one year longer than required for extra smoothness.', '<p><span style=\"font-family: Poppins, &quot;Open Sans&quot;, &quot;Helvetica Neue&quot;, Helvetica, Arial, sans-serif; font-size: 16px; background-color: rgb(247, 247, 247);\">VS (Very Special) brandy is aged in oak for three years one year longer than required for extra smoothness. Additional aging creates fine aromas and flavor that sets our VS Brandy apart from traditional brandies. The resulting taste profile is slightly sweet with notes of caramel and vanilla. From the blending of Brandy at the turn of the century by Paul Masson himself, the knowledge and craftsmanship of over 100 years make Paul Masson Grande Amber Brandy unrivaled. Taking pride from the vineyard to the bottle, it is only fitting that Paul Masson could develop a brandy with the look, feel and smoothness of the finest Cognacs</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000558', 0, NULL, 1, NULL, NULL, '2024-06-05 13:43:52', '2024-06-05 13:43:52'),
(559, '66606d86b070c', 'PRO000559', 0, 'Lamborghini Brandy Vsop 40%', '<p class=\"preFade fadeIn\" style=\"margin: 1rem 0px; line-height: var(--body-font-line-height); box-sizing: border-box; transition-property: opacity; color: rgb(0, 0, 0); font-family: Spectral; font-size: 15.6px; letter-spacing: -0.312px; white-space-collapse: preserve; background-color: rgb(250, 250, 250); transition-timing-function: ease; transition-duration: 1.5s; transition-delay: 0.177273s; opacity: 1 !important;\"><strong><span style=\"font-weight: 700; box-sizing: border-box;\"><em style=\"box-sizing: border-box;\">Obtained from the distillation of grapes grown and vinified in northern and central Italy, this Brandy can rightly be declared &ldquo; Traditional Italian Brandy &ldquo;.</em></span></strong></p>\r\n\r\n<p class=\"preFade fadeIn\" style=\"margin: 1rem 0px; line-height: var(--body-font-line-height); box-sizing: border-box; transition-property: opacity; color: rgb(0, 0, 0); font-family: Spectral; font-size: 15.6px; letter-spacing: -0.312px; white-space-collapse: preserve; background-color: rgb(250, 250, 250); transition-timing-function: ease; transition-duration: 1.5s; transition-delay: 0.184091s; opacity: 1 !important;\"><strong><span style=\"font-weight: 700; box-sizing: border-box;\"><em style=\"box-sizing: border-box;\">Distilled in small traditional alembics over a discontinuous fire and then matured for 5 years first in oak barrels called &quot;carati&quot; and then in small barriques, this Brandy takes its aroma and flavour precisely from the contact with the ageing barrels previously used for cherry.</em></span></strong></p>', 'Distilled in small traditional alembics over a discontinuous fire and then matured for 5 years first in oak barrels called \"carati\"', 21, '', NULL, 42, 206, '', 'Lamborghini Brandy Vsop 40%', 'Distilled in small traditional alembics over a discontinuous fire and then matured for 5 years first in oak barrels called \"carati\"', '<p class=\"preFade fadeIn\" style=\"white-space-collapse: preserve; margin: 1rem 0px; line-height: var(--body-font-line-height); box-sizing: border-box; transition-property: opacity; color: rgb(0, 0, 0); font-family: Spectral; font-size: 15.6px; letter-spacing: -0.312px; background-color: rgb(250, 250, 250); transition-timing-function: ease; transition-duration: 1.5s; transition-delay: 0.177273s; opacity: 1 !important;\"><strong><span style=\"box-sizing: border-box;\"><em style=\"box-sizing: border-box;\">Obtained from the distillation of grapes grown and vinified in northern and central Italy, this Brandy can rightly be declared &ldquo; Traditional Italian Brandy &ldquo;.</em></span></strong></p>\r\n\r\n<p class=\"preFade fadeIn\" style=\"white-space-collapse: preserve; margin: 1rem 0px; line-height: var(--body-font-line-height); box-sizing: border-box; transition-property: opacity; color: rgb(0, 0, 0); font-family: Spectral; font-size: 15.6px; letter-spacing: -0.312px; background-color: rgb(250, 250, 250); transition-timing-function: ease; transition-duration: 1.5s; transition-delay: 0.184091s; opacity: 1 !important;\"><strong><span style=\"box-sizing: border-box;\"><em style=\"box-sizing: border-box;\">Distilled in small traditional alembics over a discontinuous fire and then matured for 5 years first in oak barrels called &quot;carati&quot; and then in small barriques, this Brandy takes its aroma and flavour precisely from the contact with the ageing barrels previously used for cherry.</em></span></strong></p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000559', 0, 0, 1, NULL, NULL, '2024-06-05 13:52:06', '2024-06-05 13:57:17'),
(560, '66607d5a84591', 'PRO000560', 0, 'Absolute Elyx', '<p><span style=\"color: rgb(28, 28, 28); font-family: &quot;Harmonia Sans&quot;, sans-serif; font-size: 16px; letter-spacing: 0.4px;\">Indulge in the premium experience of Absolut Elyx Vodka in the 700ml. Crafted by Absolut in Ahus, Sweden, this vodka represents the epitome of Swedish craftsmanship, offering a smooth and sophisticated taste.</span></p>', 'Indulge in the premium experience of Absolut Elyx Vodka in the 700ml', 21, '', NULL, 29, 207, '', 'Absolute Elyx', 'Indulge in the premium experience of Absolut Elyx Vodka in the 700ml', '<p><span style=\"color: rgb(28, 28, 28); font-family: &quot;Harmonia Sans&quot;, sans-serif; font-size: 16px; letter-spacing: 0.4px;\">Indulge in the premium experience of Absolut Elyx Vodka in the 700ml. Crafted by Absolut in Ahus, Sweden, this vodka represents the epitome of Swedish craftsmanship, offering a smooth and sophisticated taste.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000560', 0, NULL, 1, NULL, NULL, '2024-06-05 14:59:38', '2024-06-05 14:59:38'),
(561, '6660849030fdf', 'PRO000561', 0, 'Grey Goose Essences Strawberry & Lemongrass Vodka', '<p style=\"box-sizing: border-box; margin: 0px 0px 2rem; padding: 0px; color: rgb(0, 0, 0); font-family: Roboto, Arial, Helvetica, sans-serif; font-size: 14px;\">Bright and citrusy nose. Juicy and sweet on the palate with a light and refreshing finish.</p>\r\n\r\n<p style=\"box-sizing: border-box; margin: 0px 0px 2rem; padding: 0px; color: rgb(0, 0, 0); font-family: Roboto, Arial, Helvetica, sans-serif; font-size: 14px;\">The subtle taste of freshly picked strawberries meets aromatic notes of lemongrass for a cocktail experience like no other.</p>\r\n\r\n<p style=\"box-sizing: border-box; margin: 0px 0px 2rem; padding: 0px; color: rgb(0, 0, 0); font-family: Roboto, Arial, Helvetica, sans-serif; font-size: 14px;\">Made with all-natural ingredients and crafted with Grey Goose Vodka, these botanically-infused spirits have unique and vibrant flavours and are the perfect base for cocktails or simply mixed with soda. Available in three flavours: Strawberry &amp; Lemongrass, Watermelon &amp; Basil, and White Peach &amp; Rosemary; you&#39;ll be savoring every sip!&nbsp;</p>', 'Bright and citrusy nose. Juicy and sweet on the palate with a light and refreshing finish.', 21, '', NULL, 29, 37, '', 'Grey Goose Essences Strawberry & Lemongrass Vodka', 'Bright and citrusy nose. Juicy and sweet on the palate with a light and refreshing finish.', '<p style=\"box-sizing: border-box; margin: 0px 0px 2rem; padding: 0px; color: rgb(0, 0, 0); font-family: Roboto, Arial, Helvetica, sans-serif; font-size: 14px;\">Bright and citrusy nose. Juicy and sweet on the palate with a light and refreshing finish.</p>\r\n\r\n<p style=\"box-sizing: border-box; margin: 0px 0px 2rem; padding: 0px; color: rgb(0, 0, 0); font-family: Roboto, Arial, Helvetica, sans-serif; font-size: 14px;\">The subtle taste of freshly picked strawberries meets aromatic notes of lemongrass for a cocktail experience like no other.</p>\r\n\r\n<p style=\"box-sizing: border-box; margin: 0px 0px 2rem; padding: 0px; color: rgb(0, 0, 0); font-family: Roboto, Arial, Helvetica, sans-serif; font-size: 14px;\">Made with all-natural ingredients and crafted with Grey Goose Vodka, these botanically-infused spirits have unique and vibrant flavours and are the perfect base for cocktails or simply mixed with soda. Available in three flavours: Strawberry &amp; Lemongrass, Watermelon &amp; Basil, and White Peach &amp; Rosemary; you&#39;ll be savoring every sip!&nbsp;</p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000561', 0, NULL, 1, NULL, NULL, '2024-06-05 15:30:24', '2024-06-05 15:30:24'),
(562, '66608620da2d4', 'PRO000562', 0, 'Absolute Original', '<p><span style=\"color: rgb(82, 45, 109); font-family: &quot;Century Gothic&quot;, sans-serif; font-size: 15px; letter-spacing: 0.75px;\">Absolut Vodka has completely redefined the premium vodka landscape, becoming synonymous with art, culture and nightlife. By starting a revolution in cocktail creation and launching a range of flavors never before seen on the market, Absolut has become an icon in its own right. It has been produced at the famous old distilleries near Ahus in accordance with more than 400 years of Swedish tradition. In 1879, Lars Olsson Smith, introduced the continuous distillation with which he made Absolut. Instead of the usual three or four times, the vodka was distilled an infinite number of times.</span></p>', 'Absolut Vodka has completely redefined the premium vodka landscape, becoming synonymous with art', 21, '', NULL, 29, 207, '', 'Absolute Original', 'Absolut Vodka has completely redefined the premium vodka landscape, becoming synonymous with art', '<p><span style=\"color: rgb(82, 45, 109); font-family: &quot;Century Gothic&quot;, sans-serif; font-size: 15px; letter-spacing: 0.75px;\">Absolut Vodka has completely redefined the premium vodka landscape, becoming synonymous with art, culture and nightlife. By starting a revolution in cocktail creation and launching a range of flavors never before seen on the market, Absolut has become an icon in its own right. It has been produced at the famous old distilleries near Ahus in accordance with more than 400 years of Swedish tradition. In 1879, Lars Olsson Smith, introduced the continuous distillation with which he made Absolut. Instead of the usual three or four times, the vodka was distilled an infinite number of times.</span></p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000562', 0, 0, 1, NULL, NULL, '2024-06-05 15:37:04', '2024-06-05 15:40:52'),
(563, '66608afa62245', 'PRO000563', 0, 'Absolute Kurrant', '<p><span style=\"color: rgb(91, 91, 91); font-family: Rubik, Arial, Helvetica, sans-serif; font-size: 14px;\">The story behind the name Absolut Kurant is black currant, a typical Swedish berry from which the flavor is taken. When launched in 1992 it was a tribute to the Swedish origin of Absolut Vodka. Originally it was even supposed to be called Absolut Vinb&auml;r since the Swedish word for black currant is vinb&auml;r. Only thing was that the English pronunciation would have been wine bar.</span></p>', 'The story behind the name Absolut Kurant is black currant, a typical Swedish berry from which the flavor is taken.', 21, '', NULL, 29, 207, '', 'Absolute Kurrant', 'The story behind the name Absolut Kurant is black currant, a typical Swedish berry from which the flavor is taken.', '<p><span style=\"color: rgb(91, 91, 91); font-family: Rubik, Arial, Helvetica, sans-serif; font-size: 14px;\">The story behind the name Absolut Kurant is black currant, a typical Swedish berry from which the flavor is taken. When launched in 1992 it was a tribute to the Swedish origin of Absolut Vodka. Originally it was even supposed to be called Absolut Vinb&auml;r since the Swedish word for black currant is vinb&auml;r. Only thing was that the English pronunciation would have been wine bar.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000563', 0, NULL, 1, NULL, NULL, '2024-06-05 15:57:46', '2024-06-05 15:57:46'),
(564, '6660947b7ffe0', 'PRO000564', 0, 'Magic Moment Vodka Rasbery 37.5%', '<p><span style=\"color: rgb(119, 119, 119); font-family: Hind, Arial, Helvetica, sans-serif; font-size: 16px;\">Magic Moments grain Vodka 75 cl is an irresistible blend of imported vodka and the rich taste of cream. It is a triple distilled grain spirit manufactured in one of India&rsquo;s largest factories, Radico Khaitan Ltd. It has an alcohol percentage of 37.5%. magic moments has a smooth and perfect blend of teasing ingredients giving an enriched taste .It has a clean and fresh taste with subtle aroma of neutral grain spirit and neutral taste.</span></p>', 'Magic Moments grain Vodka 75 cl is an irresistible blend of imported vodka and the rich taste of cream.', 21, '', NULL, 29, 208, '', 'Magic Moment Vodka Rasbery 37.5%', 'Magic Moments grain Vodka 75 cl is an irresistible blend of imported vodka and the rich taste of cream.', '<p><span style=\"color: rgb(119, 119, 119); font-family: Hind, Arial, Helvetica, sans-serif; font-size: 16px;\">Magic Moments grain Vodka 75 cl is an irresistible blend of imported vodka and the rich taste of cream. It is a triple distilled grain spirit manufactured in one of India&rsquo;s largest factories, Radico Khaitan Ltd. It has an alcohol percentage of 37.5%. magic moments has a smooth and perfect blend of teasing ingredients giving an enriched taste .It has a clean and fresh taste with subtle aroma of neutral grain spirit and neutral taste.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000564', 0, NULL, 1, NULL, NULL, '2024-06-05 16:38:19', '2024-06-05 16:38:19'),
