(566, '6661864456692', 'PRO000566', 0, 'Russian Bear Vodka Pineapple', '<p><span style=\"color: rgb(119, 119, 119); font-family: Roboto, sans-serif; font-size: 18.72px;\">Russian Bear Pineapple is a blend of Russian Bear Premium Vodka and pineapple extract to create a flavourful and smooth vodka. Best enjoyed with soda water or lemonade.</span></p>', 'Russian Bear Pineapple is a blend of Russian Bear Premium Vodka', 21, '', NULL, 29, 209, '', 'Russian Bear Vodka Pineapple', 'Russian Bear Pineapple is a blend of Russian Bear Premium Vodka', '<p><span style=\"color: rgb(119, 119, 119); font-family: Roboto, sans-serif; font-size: 18.72px;\">Russian Bear Pineapple is a blend of Russian Bear Premium Vodka and pineapple extract to create a flavourful and smooth vodka. Best enjoyed with soda water or lemonade.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000566', 0, NULL, 1, NULL, NULL, '2024-06-06 09:49:56', '2024-06-06 09:49:56'),
(567, '666189f1daa8b', 'PRO000567', 0, 'Russian Bear Vodka Spiced Vanilla', '<p><span style=\"color: rgb(29, 29, 29); font-family: &quot;Nunito Sans&quot;, sans-serif; font-size: 16px;\">Unique from other Vodka infusions, Russian Bear Vanilla is actually distilled with specially selected flavours added before distillation. This results in a richer, more pure flavoured vodka that is best enjoyed in cocktails, with apple juice or as an ice-cold shot. Or simply mix with Cola, Sparkling Apple Juice or Energy Drinks.</span></p>', 'Unique from other Vodka infusions, Russian Bear Vanilla is actually distilled with specially selected flavors', 21, '', NULL, 29, 209, '', 'Russian Bear Vodka Spiced Vanilla', 'Unique from other Vodka infusions, Russian Bear Vanilla is actually distilled with specially selected flavors', '<p><span style=\"color: rgb(29, 29, 29); font-family: &quot;Nunito Sans&quot;, sans-serif; font-size: 16px;\">Unique from other Vodka infusions, Russian Bear Vanilla is actually distilled with specially selected flavours added before distillation. This results in a richer, more pure flavoured vodka that is best enjoyed in cocktails, with apple juice or as an ice-cold shot. Or simply mix with Cola, Sparkling Apple Juice or Energy Drinks.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000567', 0, NULL, 1, NULL, NULL, '2024-06-06 10:05:37', '2024-06-06 10:05:37'),
(568, '66618cf245700', 'PRO000568', 0, 'Russian Bear Vodka Wild Berry', '<p><span style=\"color: rgb(29, 29, 29); font-family: &quot;Nunito Sans&quot;, sans-serif; font-size: 16px;\">Unique from other Vodka infusions, Russian Bear Vanilla is actually distilled with specially selected flavours added before distillation. This results in a richer, more pure flavoured vodka that is best enjoyed in cocktails, with apple juice or as an ice-cold shot. Or simply mix with Cola, Sparkling Apple Juice or Energy Drinks.</span></p>', 'Unique from other Vodka infusions, Russian Bear Vanilla is actually distilled with specially selected flavours', 21, '', NULL, 29, 209, '', 'Russian Bear Vodka Wild Berry', 'Unique from other Vodka infusions, Russian Bear Vanilla is actually distilled with specially selected flavours', '<p><span style=\"color: rgb(29, 29, 29); font-family: &quot;Nunito Sans&quot;, sans-serif; font-size: 16px;\">Unique from other Vodka infusions, Russian Bear Vanilla is actually distilled with specially selected flavours added before distillation. This results in a richer, more pure flavoured vodka that is best enjoyed in cocktails, with apple juice or as an ice-cold shot. Or simply mix with Cola, Sparkling Apple Juice or Energy Drinks.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000568', 0, NULL, 1, NULL, NULL, '2024-06-06 10:18:26', '2024-06-06 10:18:26'),
(569, '666193dfdbf4e', 'PRO000569', 0, 'Kamasutra Ginseng & Vodka', '<p><span style=\"font-family: Nudista, sans-serif; font-size: 16px;\">Kamastura Ginseng &amp; Vodka owes its exotic taste to the stimulants found in ginseng roots, which were used as aphrodisiacs at the Chinese Imperial Court more than 2,000 years ago. It tastes great with ice, but also in drinks.</span></p>', 'Kamasutra Ginseng & Vodka owes its exotic taste to the stimulants found in ginseng roots', 21, '', NULL, 29, 210, '', 'Kamasutra Ginseng & Vodka 500', 'Kamasutra Ginseng & Vodka owes its exotic taste to the stimulants found in ginseng roots', '<p><span style=\"font-family: Nudista, sans-serif; font-size: 16px;\">Kamastura Ginseng &amp; Vodka owes its exotic taste to the stimulants found in ginseng roots, which were used as aphrodisiacs at the Chinese Imperial Court more than 2,000 years ago. It tastes great with ice, but also in drinks.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000569', 0, NULL, 1, NULL, NULL, '2024-06-06 10:47:59', '2024-06-06 10:47:59'),
(570, '6661a97dcf49a', 'PRO000570', 0, 'Stolichnaya Vodka', '<p><span style=\"color: rgb(102, 102, 102); font-family: Poppins; font-size: 14px;\">Stoli Vodka is a classically styled, exceptionally smooth vodka. Crystal clear in color with marshmallow, mineral and mild fruit peel aromas, a soft, supple entry leads to a smooth, medium bodied palate with pastry frosting, talc and citrus rind flavors. It finishes with a clean, lightly sweet, sugar dust, wet straw and balanced pepper fade.</span></p>', 'Stoli Vodka is a classically styled, exceptionally smooth vodka.', 21, '', NULL, 29, 211, '', 'Stolichnaya Vodka', 'Stoli Vodka is a classically styled, exceptionally smooth vodka.', '<p><span style=\"color: rgb(102, 102, 102); font-family: Poppins; font-size: 14px;\">Stoli&nbsp;</span><span style=\"color: rgb(102, 102, 102); font-family: Poppins; font-size: 14px;\">Vodka is a classically styled, exceptionally smooth vodka. Crystal clear in color with marshmallow, mineral and mild fruit peel aromas, a soft, supple entry leads to a smooth, medium bodied palate with pastry frosting, talc and citrus rind flavors. It finishes with a clean, lightly sweet, sugar dust, wet straw and balanced pepper fade.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000570', 0, NULL, 1, NULL, NULL, '2024-06-06 12:20:13', '2024-06-06 12:20:13'),
(571, '6661ae0d3b60c', 'PRO000571', 0, 'Absolute Raspberri', '<p><span style=\"color: rgb(119, 119, 119); font-family: Roboto, sans-serif; font-size: 18.72px;\">Absolut Raspberri vodka is rich and intense with the fresh and fruity taste of ripened raspberries harvested in the Swedish hillsides. This raspberry flavoured vodka is made exclusively from natural ingredients, and unlike other flavoured vodkas, it doesn&rsquo;t contain any added sugar, making it perfect for mixing.</span></p>', 'Absolut Raspberri vodka is rich and intense with the fresh and fruity taste of ripened raspberries', 21, '', NULL, 29, 207, '', 'Absolute Raspberri', 'Absolut Raspberri vodka is rich and intense with the fresh and fruity taste of ripened raspberries', '<p><span style=\"color: rgb(119, 119, 119); font-family: Roboto, sans-serif; font-size: 18.72px;\">Absolut Raspberri vodka is rich and intense with the fresh and fruity taste of ripened raspberries harvested in the Swedish hillsides. This raspberry flavoured vodka is made exclusively from natural ingredients, and unlike other flavoured vodkas, it doesn&rsquo;t contain any added sugar, making it perfect for mixing.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000571', 0, NULL, 1, NULL, NULL, '2024-06-06 12:39:41', '2024-06-06 12:39:41'),
(572, '6661b030ad9cc', 'PRO000572', 0, 'Au Black Grape Vodka 35.2%', '<p><span style=\"color: rgb(11, 11, 14); font-family: Poppins, Quicksand, &quot;Helvetica Neue&quot;, Arial, sans-serif; font-size: 16px;\">Au has combined its award-winning recipe with the highest quality black grapes to create a sweet &amp; unique vodka. Blending the finest British black grapes with natural spring water from deep in the South Down hills. Au Black Grape is sippable on the rocks, paired with lemonade or breathing character into any cocktail.</span></p>', 'Au has combined its award-winning recipe with the highest quality black grapes to create a sweet & unique vodka.', 21, '', NULL, 29, 212, '', 'Au Black Grape Vodka 35.2%', 'Au has combined its award-winning recipe with the highest quality black grapes to create a sweet & unique vodka.', '<p><span style=\"color: rgb(11, 11, 14); font-family: Poppins, Quicksand, &quot;Helvetica Neue&quot;, Arial, sans-serif; font-size: 16px;\">Au has combined its award-winning recipe with the highest quality black grapes to create a sweet &amp; unique vodka. Blending the finest British black grapes with natural spring water from deep in the South Down hills. Au Black Grape is sippable on the rocks, paired with lemonade or breathing character into any cocktail.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000572', 0, NULL, 1, NULL, NULL, '2024-06-06 12:48:48', '2024-06-06 12:48:48'),
(573, '6661b18299002', 'PRO000573', 0, 'Au Blue Raspberry Vodka 35.2%', '<p><span style=\"color: rgb(102, 102, 102); font-family: Jost, Arial, Helvetica, sans-serif; font-size: 14px;\">Au&nbsp;presents a new flavour to be tried by alcohol connoisseurs alike, with the new AU Vodka&nbsp;Blue Raspberry&nbsp;flavour.&nbsp;Be among one of the first AU Vodka owners to try this new and exclusive flavour! Au&nbsp;is the symbol for Gold on the periodic table, where the company gets its name from.&nbsp;Au&nbsp;re-defines the definition of the symbol by providing award-winning combinations of natural fruits and flavours, encapsulated in their unique Vodka, to create exotic tastes. Specifications Net Content 700ml Alcohol By Volume 35.2% ABV / 70cl Country of Origin England</span></p>', 'Au presents a new flavor to be tried by alcohol connoisseurs alike, with the new AU Vodka Blue Raspberry flavor.', 21, '', NULL, 29, 212, '', 'Au Blue Raspberry Vodka 35.2%', 'Au presents a new flavor to be tried by alcohol connoisseurs alike, with the new AU Vodka Blue Raspberry flavor.', '<p><span style=\"color: rgb(102, 102, 102); font-family: Jost, Arial, Helvetica, sans-serif; font-size: 14px;\">Au&nbsp;presents a new flavour to be tried by alcohol connoisseurs alike, with the new AU Vodka&nbsp;Blue Raspberry&nbsp;flavour.&nbsp;Be among one of the first AU Vodka owners to try this new and exclusive flavour! Au&nbsp;is the symbol for Gold on the periodic table, where the company gets its name from.&nbsp;Au&nbsp;re-defines the definition of the symbol by providing award-winning combinations of natural fruits and flavours, encapsulated in their unique Vodka, to create exotic tastes. Specifications Net Content 700ml Alcohol By Volume 35.2% ABV / 70cl Country of Origin England</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000573', 0, NULL, 1, NULL, NULL, '2024-06-06 12:54:26', '2024-06-06 12:54:26'),
(574, '6661b38e68014', 'PRO000574', 0, 'Beluga Allure Vodka', '<p><span style=\"color: rgb(11, 11, 14); font-family: Poppins, Quicksand, &quot;Helvetica Neue&quot;, Arial, sans-serif; font-size: 16px;\">Beluga Allure is made with pride. A special edition dedicated to the successful Beluga Polo Team. Small amounts of maple syrup and fig extract have been added to the vodka for a touch of subtle sweetness.</span></p>', 'Beluga Allure is made with pride. A special edition dedicated to the successful Beluga Polo Team.', 21, '', NULL, 29, 213, '', 'Beluga Allure Vodka', 'Beluga Allure is made with pride. A special edition dedicated to the successful Beluga Polo Team.', '<p><span style=\"color: rgb(11, 11, 14); font-family: Poppins, Quicksand, &quot;Helvetica Neue&quot;, Arial, sans-serif; font-size: 16px;\">Beluga Allure is made with pride. A special edition dedicated to the successful Beluga Polo Team. Small amounts of maple syrup and fig extract have been added to the vodka for a touch of subtle sweetness.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000574', 0, NULL, 1, NULL, NULL, '2024-06-06 13:03:10', '2024-06-06 13:03:10'),
