(576, '6661bfd4c3b39', 'PRO000576', 0, 'Svedka Vodka', '<p><span style=\"color: rgb(70, 71, 74); font-family: Bogle, &quot;Helvetica Neue&quot;, Helvetica, Arial, sans-serif; font-size: 14px; font-weight: 700;\">SVEDKA Vodka is a smooth-drinking vodka infused with a subtle, rounded sweetness, making it an ideal addition to countless vodka cocktails. Now made in the USA, this unflavored vodka is distilled four times to remove impurities, using a continuous distillation process to ensure that ingredients never stall or pool. The result is a clean, clear taste with a balanced body and a crisp finish, making this 80 proof vodka a bold, crowd-pleasing choice. Mix this popular vodka alcohol into cosmopolitans or vodka martinis, or chill this 750 mL vodka bottle and pour over ice to enjoy a vodka on the rocks, savoring the crisp finish. Go Responsibly. Svedka&reg; &copy; 2024 Spirits Marque One, San Francisco, CA Vodka distilled from grain 40% alc/vol</span></p>', 'SVEDKA Vodka is a smooth-drinking vodka infused with a subtle, rounded sweetness, making it an ideal addition to countless vodka cocktails', 21, '', NULL, 29, 214, '', 'Svedka Vodka', 'SVEDKA Vodka is a smooth-drinking vodka infused with a subtle, rounded sweetness, making it an ideal addition to countless vodka cocktails', '<p><span style=\"color: rgb(70, 71, 74); font-family: Bogle, &quot;Helvetica Neue&quot;, Helvetica, Arial, sans-serif; font-size: 14px; font-weight: 700;\">SVEDKA Vodka is a smooth-drinking vodka infused with a subtle, rounded sweetness, making it an ideal addition to countless vodka cocktails. Now made in the USA, this unflavored vodka is distilled four times to remove impurities, using a continuous distillation process to ensure that ingredients never stall or pool. The result is a clean, clear taste with a balanced body and a crisp finish, making this 80 proof vodka a bold, crowd-pleasing choice. Mix this popular vodka alcohol into cosmopolitans or vodka martinis, or chill this 750 mL vodka bottle and pour over ice to enjoy a vodka on the rocks, savoring the crisp finish. Go Responsibly. Svedka&reg; &copy; 2024 Spirits Marque One, San Francisco, CA Vodka distilled from grain 40% alc/vol</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000576', 0, NULL, 1, NULL, NULL, '2024-06-06 13:55:32', '2024-06-06 13:55:32'),
(577, '6661c1c0a7a51', 'PRO000577', 0, 'Vusa Vodka 40%', '<p><span style=\"color: rgb(119, 119, 119); font-family: Roboto, sans-serif; font-size: 16.32px;\">Vusa is crafted at the Midlands Distillery, in Kwazulu-Natal, located in the south eastern region of South Africa. There it is triple distilled through a copper pot still and filtered once through charred activated charcoal, a carbon filtration method originated in Africa.</span></p>', 'Vusa is crafted at the Midlands Distillery, in Kwazulu-Natal, located in the south eastern region of South Africa.', 21, '', NULL, 29, 215, '', 'Vusa Vodka 40%', 'Vusa is crafted at the Midlands Distillery, in Kwazulu-Natal, located in the south eastern region of South Africa.', '<p><span style=\"color: rgb(119, 119, 119); font-family: Roboto, sans-serif; font-size: 16.32px;\">Vusa is crafted at the Midlands Distillery, in Kwazulu-Natal, located in the south eastern region of South Africa. There it is triple distilled through a copper pot still and filtered once through charred activated charcoal, a carbon filtration method originated in Africa.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000577', 0, NULL, 1, NULL, NULL, '2024-06-06 14:03:44', '2024-06-06 14:03:44'),
