(585, '6661e33c9fbde', 'PRO000585', 0, 'Tale Hibiscus Ale 5%', '<p><span style=\"color: rgb(51, 50, 54); font-family: acumin-rpro, helvetica, arial, sans-serif; font-size: 16px;\">100% natural brew crafted from local (in Ghana) ingredients and bursting with flavors that captivate beer enthusiasts.</span><br style=\"box-sizing: inherit; color: rgb(51, 50, 54); font-family: acumin-rpro, helvetica, arial, sans-serif; font-size: 16px;\" />\r\n<span style=\"color: rgb(51, 50, 54); font-family: acumin-rpro, helvetica, arial, sans-serif; font-size: 16px;\">This Farmhouse Ale stands out as a meticulously fermented beer, featuring a special yeast blend. This thirst-quenching delight boasts a distinctive hoppiness and a citrusy allure, thanks to the infusion of farm-grown lemongrass and lime leaves during the brewing process.</span></p>', '100% natural brew crafted from local (in Ghana) ingredients and bursting with flavors that captivate beer enthusiasts.', 11, '', NULL, 32, 220, '', 'Tale Hibiscus Ale 5%', '100% natural brew crafted from local (in Ghana) ingredients and bursting with flavors that captivate beer enthusiasts.', '<p><span style=\"color: rgb(51, 50, 54); font-family: acumin-rpro, helvetica, arial, sans-serif; font-size: 16px;\">100% natural brew crafted from local (in Ghana) ingredients and bursting with flavors that captivate beer enthusiasts.</span><br style=\"box-sizing: inherit; color: rgb(51, 50, 54); font-family: acumin-rpro, helvetica, arial, sans-serif; font-size: 16px;\" />\r\n<span style=\"color: rgb(51, 50, 54); font-family: acumin-rpro, helvetica, arial, sans-serif; font-size: 16px;\">This Farmhouse Ale stands out as a meticulously fermented beer, featuring a special yeast blend. This thirst-quenching delight boasts a distinctive hoppiness and a citrusy allure, thanks to the infusion of farm-grown lemongrass and lime leaves during the brewing process.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000585', 0, NULL, 1, NULL, NULL, '2024-06-06 16:26:36', '2024-06-06 16:26:36'),
(586, '6661ef7b063cb', 'PRO000586', 0, 'Stella Artois', '<p><span style=\"color: rgb(58, 42, 47); font-family: &quot;Source Sans Pro&quot;, sans-serif; font-size: 15px;\">With its wonderful floral aroma, well-balanced malt sweetness, crisp hop bitterness, and a soft dry finish, Stella Artois is the perfect beer to pair with food and friends. Winner of the 2019 World Beer Award for World&rsquo;s Best International Lager.</span></p>', 'With its wonderful floral aroma, well-balanced malt sweetness, crisp hop bitterness, and a soft dry finish', 11, '', NULL, 32, 221, '', 'Stella Artois', 'With its wonderful floral aroma, well-balanced malt sweetness, crisp hop bitterness, and a soft dry finish', '<p><span style=\"color: rgb(58, 42, 47); font-family: &quot;Source Sans Pro&quot;, sans-serif; font-size: 15px;\">With its wonderful floral aroma, well-balanced malt sweetness, crisp hop bitterness, and a soft dry finish, Stella Artois is the perfect beer to pair with food and friends. Winner of the 2019 World Beer Award for World&rsquo;s Best International Lager.</span></p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000586', 0, 0, 1, NULL, NULL, '2024-06-06 17:18:51', '2024-06-06 17:20:03'),
(587, '6661f11549a36', 'PRO000587', 0, 'Tale Ginger Triple 7%', '<p><span style=\"color: rgb(28, 29, 29); font-family: Protipo; font-size: 15px; background-color: rgb(255, 249, 237);\">Triple is a strong ale with a bright golden appearance. The name &lsquo;triple&rsquo; is sometimes said to refer to having 3 portions of malt to generate an extra strong beer. Our interpretation of this Belgian classic is even more powerful, as we boosted it with a very tasteful natural ingredient from our backyard. Tale 7 or Golden Tale is a strong triple ale, top-fermented as are all our beers, and spiced up with fresh ginger to create an extra body. Much of its flavours are derived from the complex interplay between the wort and the unique yeast used in the fermentation process.</span></p>', 'Triple is a strong ale with a bright golden appearance.', 11, '', NULL, 32, 220, '', 'Tale Ginger Triple 7%', 'Triple is a strong ale with a bright golden appearance.', '<p><span style=\"color: rgb(28, 29, 29); font-family: Protipo; font-size: 15px; background-color: rgb(255, 249, 237);\">Triple is a strong ale with a bright golden appearance. The name &lsquo;triple&rsquo; is sometimes said to refer to having 3 portions of malt to generate an extra strong beer. Our interpretation of this Belgian classic is even more powerful, as we boosted it with a very tasteful natural ingredient from our backyard. Tale 7 or Golden Tale is a strong triple ale, top-fermented as are all our beers, and spiced up with fresh ginger to create an extra body. Much of its flavours are derived from the complex interplay between the wort and the unique yeast used in the fermentation process.</span></p>', NULL, NULL, 0, NULL, 0, NULL, NULL, 'LQ000587', 0, NULL, 1, NULL, NULL, '2024-06-06 17:25:41', '2024-06-06 17:25:41'),
