(591, '6662f19d195a1', 'PRO000591', 0, 'Budweiser Beer', '<p><span style=\"color: rgb(0, 0, 0); font-family: Poppins, sans-serif; font-size: 16px;\">An iconic beer, Budweiser Lager is medium-bodied and full of flavour. Fresh rice and carefully filtered water combine with premium barley malt, a blend of exceptional hop varieties, and traditional Beechwood ageing technqiues to give Budweiser it&#39;s unique American flavour.</span></p>', 'An iconic beer, Budweiser Lager is medium-bodied and full of flavor.', 11, '', NULL, 32, 223, '', 'Budweiser Beer', 'An iconic beer, Budweiser Lager is medium-bodied and full of flavor.', '<p><span style=\"color: rgb(0, 0, 0); font-family: Poppins, sans-serif; font-size: 16px;\">An iconic beer, Budweiser Lager is medium-bodied and full of flavour. Fresh rice and carefully filtered water combine with premium barley malt, a blend of exceptional hop varieties, and traditional Beechwood ageing technqiues to give Budweiser it&#39;s unique American flavour.</span></p>', NULL, NULL, 0, NULL, 0, NULL, 0, 'LQ000591', 0, 0, 1, NULL, NULL, '2024-06-07 11:40:13', '2024-06-07 12:09:25'),
